import json
from datetime import datetime
from typing import Any, Dict, List, Optional

def process_dataset(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _normalize_date(val: Any) -> Optional[str]:
        if val is None:
            return None
        if isinstance(val, datetime):
            return val.isoformat()
        try:
            return datetime.fromisoformat(str(val)).isoformat()
        except Exception:
            return None

    def _validate_row(row: Dict[str, Any]) -> bool:
        required = ["id", "timestamp", "value"]
        for key in required:
            if key not in row:
                return False
        if not isinstance(row["id"], int):
            return False
        if _normalize_date(row["timestamp"]) is None:
            return False
        if not isinstance(row["value"], (int, float)):
            return False
        return True

    def _aggregate(rows: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {
            "count": 0,
            "sum": 0.0,
            "min": None,
            "max": None,
        }
        for r in rows:
            val = r["value"]
            stats["count"] += 1
            stats["sum"] += val
            if stats["min"] is None or val < stats["min"]:
                stats["min"] = val
            if stats["max"] is None or val > stats["max"]:
                stats["max"] = val
        if stats["count"] > 0:
            stats["average"] = stats["sum"] / stats["count"]
        else:
            stats["average"] = None
        return stats

    valid_rows: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append({"index": idx, "error": "not a dict"})
            continue
        if not _validate_row(rec):
            errors.append({"index": idx, "error": "validation failed"})
            continue
        rec_copy = dict(rec)
        rec_copy["timestamp"] = _normalize_date(rec_copy["timestamp"])
        valid_rows.append(rec_copy)

    stats = _aggregate(valid_rows)

    by_date: Dict[str, List[Dict[str, Any]]] = {}
    for r in valid_rows:
        date_key = r["timestamp"][:10]
        if date_key not in by_date:
            by_date[date_key] = []
        by_date[date_key].append(r)

    daily_stats: Dict[str, Any] = {}
    for date, rows in by_date.items():
        daily_stats[date] = _aggregate(rows)

    result = {
        "total_records": len(records),
        "valid_records": len(valid_rows),
        "invalid_records": len(errors),
        "errors": errors,
        "overall_stats": stats,
        "daily_stats": daily_stats,
    }

    return result

