import datetime
from typing import Any, Dict, List


def process_transactions(transactions: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate(tx: Dict[str, Any]) -> None:
        required = ["id", "amount", "type", "date"]
        for field in required:
            if field not in tx:
                raise ValueError(f"Missing required field: {field}")
        if not isinstance(tx["amount"], (int, float)):
            raise TypeError("Amount must be numeric")
        if tx["type"] not in {"debit", "credit"}:
            raise ValueError("Type must be 'debit' or 'credit'")
        try:
            datetime.datetime.strptime(tx["date"], "%Y-%m-%d")
        except Exception:
            raise ValueError("Date must be YYYY-MM-DD")

    def _compute_amount(tx: Dict[str, Any]) -> float:
        amt = float(tx["amount"])
        if tx["type"] == "debit":
            return -amt
        return amt

    def _categorize(tx: Dict[str, Any]) -> str:
        mapping = {
            "food": ["groceries", "restaurant"],
            "transport": ["bus", "taxi", "train"],
            "utilities": ["electricity", "water", "gas"],
        }
        tags = tx.get("tags", [])
        for cat, keywords in mapping.items():
            if any(k in tags for k in keywords):
                return cat
        return "other"

    errors: List[Dict[str, Any]] = []
    totals: Dict[str, float] = {}
    processed: List[Dict[str, Any]] = []

    for tx in transactions:
        try:
            _validate(tx)
            amt = _compute_amount(tx)
            cat = _categorize(tx)
            totals[cat] = totals.get(cat, 0.0) + amt
            processed.append({"id": tx["id"], "amount": amt, "category": cat})
        except Exception as exc:
            errors.append({"id": tx.get("id"), "error": str(exc)})

    report: Dict[str, Any] = {
        "total_transactions": len(transactions),
        "processed": len(processed),
        "errors": len(errors),
        "totals_by_category": totals,
        "details": processed,
    }
    return report

