import json
from typing import Any, Dict, List, Tuple, Optional


def process_data(records: List[Dict[str, Any]], schema: Dict[str, type], key_field: str) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors = []
        for field, typ in schema.items():
            if field not in rec:
                errors.append("Missing field " + field)
            else:
                if not isinstance(rec[field], typ):
                    errors.append("Field " + field + " expected " + typ.__name__ + ", got " + type(rec[field]).__name__)
        return (len(errors) == 0, errors)

    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        norm = {}
        for k, v in rec.items():
            if isinstance(v, str):
                norm[k] = v.strip()
            else:
                norm[k] = v
        return norm

    def _group_by_key(recs: List[Dict[str, Any]]) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for r in recs:
            k = r.get(key_field)
            if k not in groups:
                groups[k] = []
            groups[k].append(r)
        return groups

    def _compute_stats(groups: Dict[Any, List[Dict[str, Any]]]) -> Dict[str, Any]:
        stats = {}
        for k, grp in groups.items():
            stats[k] = {
                "count": len(grp),
                "fields_present": {f: all(f in r for r in grp) for f in schema.keys()}
            }
        return stats

    def _detect_duplicates(recs: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        seen: Dict[Any, Dict[str, Any]] = {}
        duplicates: List[Dict[str, Any]] = []
        for r in recs:
            k = r.get(key_field)
            if k in seen:
                duplicates.append(r)
            else:
                seen[k] = r
        return duplicates

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Tuple[Dict[str, Any], List[str]]] = []

    for rec in records:
        is_valid, errs = _validate_record(rec)
        if is_valid:
            valid_records.append(_normalize(rec))
        else:
            invalid_records.append((rec, errs))

    grouped = _group_by_key(valid_records)
    stats = _compute_stats(grouped)
    duplicates = _detect_duplicates(valid_records)

    summary = {
        "total_records": len(records),
        "valid_records": len(valid_records),
        "invalid_records": len(invalid_records),
        "groups": len(grouped),
        "duplicates": len(duplicates),
    }

    detailed = {}
    for k, grp in grouped.items():
        detailed[k] = {
            "count": len(grp),
            "sample": grp[0] if grp else None,
            "stats": stats.get(k),
        }

    result = {
        "summary": summary,
        "details": detailed,
        "invalids": [
            {"record": rec, "errors": errs} for rec, errs in invalid_records
        ],
        "duplicates": duplicates,
    }

    json_output = json.dumps(result, indent=2, sort_keys=True)
    return result

