import json
from typing import Any, Dict, List, Optional

def process_data(
    data: List[Dict[str, Any]],
    filter_key: str,
    filter_value: Any,
    transform_func: Optional[Any] = None,
    max_items: Optional[int] = None,
) -> Dict[str, Any]:
    def _validate_item(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        return filter_key in item

    def _apply_transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func is None:
            return item
        try:
            return transform_func(item)
        except Exception:
            return item

    def _collect_stats(items: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {"count": len(items), "keys": set()}
        for it in items:
            stats["keys"].update(it.keys())
        stats["unique_keys"] = len(stats["keys"])
        return stats

    filtered: List[Dict[str, Any]] = []
    for entry in data:
        if not _validate_item(entry):
            continue
        if entry.get(filter_key) != filter_value:
            continue
        transformed = _apply_transform(entry)
        filtered.append(transformed)
        if max_items is not None and len(filtered) >= max_items:
            break

    stats = _collect_stats(filtered)

    result: Dict[str, Any] = {
        "filtered": filtered,
        "stats": stats,
        "original_count": len(data),
        "filtered_count": len(filtered),
    }
    return result

