import json
import re
import datetime
from typing import Any, Dict, List, Optional


def process_data_pipeline(data: List[Dict[str, Any]]) -> Dict[str, Any]:
    # Validate and normalize each record
    def validate_record(rec: Dict[str, Any]) -> bool:
        required = ['id', 'timestamp', 'value']
        for key in required:
            if key not in rec:
                return False
        if not isinstance(rec['id'], int):
            return False
        if not isinstance(rec['timestamp'], str):
            return False
        if not isinstance(rec['value'], (int, float)):
            return False
        return True

    def normalize_date(ts: str) -> Optional[datetime.datetime]:
        patterns = [
            r'(?P<year>\d{4})-(?P<month>\d{2})-(?P<day>\d{2})[ T](?P<hour>\d{2}):(?P<minute>\d{2}):(?P<second>\d{2})',
            r'(?P<year>\d{4})/(?P<month>\d{2})/(?P<day>\d{2})',
            r'(?P<month>\d{2})/(?P<day>\d{2})/(?P<year>\d{4})',
        ]
        for pat in patterns:
            m = re.match(pat, ts)
            if m:
                try:
                    parts = m.groupdict()
                    year = int(parts['year'])
                    month = int(parts['month'])
                    day = int(parts['day'])
                    hour = int(parts.get('hour', 0))
                    minute = int(parts.get('minute', 0))
                    second = int(parts.get('second', 0))
                    return datetime.datetime(year, month, day, hour, minute, second)
                except Exception:
                    continue
        return None

    def compute_metrics(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        if not records:
            return {'count': 0, 'average': None, 'max': None, 'min': None}
        values = [rec['value'] for rec in records]
        count = len(values)
        total = sum(values)
        average = total / count
        maximum = max(values)
        minimum = min(values)
        return {
            'count': count,
            'average': average,
            'max': maximum,
            'min': minimum,
        }

    cleaned: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for rec in data:
        if not validate_record(rec):
            errors.append({'record': rec, 'error': 'validation_failed'})
            continue
        ts_obj = normalize_date(rec['timestamp'])
        if ts_obj is None:
            errors.append({'record': rec, 'error': 'invalid_timestamp'})
            continue
        cleaned.append({
            'id': rec['id'],
            'timestamp': ts_obj.isoformat(),
            'value': rec['value'],
        })

    metrics = compute_metrics(cleaned)

    # Group by year
    groups: Dict[int, List[Dict[str, Any]]] = {}
    for rec in cleaned:
        year = datetime.datetime.fromisoformat(rec['timestamp']).year
        groups.setdefault(year, []).append(rec)

    # Serialize groups to JSON strings
    serialized_groups: Dict[int, str] = {}
    for year, recs in groups.items():
        try:
            serialized_groups[year] = json.dumps(recs, default=str)
        except Exception as e:
            serialized_groups[year] = f'{{\'error\':\'serialization_failed\',\'details\':\'{str(e)}\'}}'

    result = {
        'metrics': metrics,
        'groups': serialized_groups,
        'errors': errors,
        'summary': {
            'total_records': len(data),
            'cleaned_records': len(cleaned),
            'error_records': len(errors),
        },
    }

    return result

