import json
from typing import Any, Dict, List, Optional

def process_data(records: List[Dict[str, Any]], required_fields: List[str], max_retries: int = 3) -> Dict[str, Any]:
    def validate_record(rec: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in rec or rec[field] is None:
                return False
        return True

    def clean_value(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip()
        return val

    def retry_operation(op, *args, **kwargs):
        attempts = 0
        while attempts < max_retries:
            try:
                return op(*args, **kwargs)
            except Exception:
                attempts += 1
                if attempts >= max_retries:
                    raise
                continue

    cleaned_records: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append({"index": idx, "error": "not a dict"})
            continue
        if not validate_record(rec):
            errors.append({"index": idx, "error": "missing required fields"})
            continue
        cleaned: Dict[str, Any] = {}
        for k, v in rec.items():
            cleaned[k] = clean_value(v)
        cleaned_records.append(cleaned)

    def serialize_to_json(data: List[Dict[str, Any]]) -> str:
        return json.dumps(data, ensure_ascii=False, indent=2)

    json_output = retry_operation(serialize_to_json, cleaned_records)

    result = {
        "processed_count": len(cleaned_records),
        "error_count": len(errors),
        "errors": errors,
        "data_json": json_output,
    }
    return result

