import typing
from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_data_pipeline(
    data_source: Iterable[Dict[str, Any]],
    config: Dict[str, Any],
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = config.get("required_fields", [])
        for field in required:
            if field not in rec:
                return False
        return True

    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        transformed = {}
        for key, value in rec.items():
            if isinstance(value, str):
                transformed[key] = value.strip().lower()
            else:
                transformed[key] = value
        return transformed

    def _aggregate(acc: Dict[str, Any], rec: Dict[str, Any]) -> None:
        for key, value in rec.items():
            if key not in acc:
                acc[key] = []
            acc[key].append(value)

    processed: List[Dict[str, Any]] = []
    aggregation: Dict[str, List[Any]] = {}
    errors: List[str] = []

    for idx, raw in enumerate(data_source):
        if not isinstance(raw, dict):
            errors.append(f"Item {idx} is not a dict")
            continue
        if not _validate_record(raw):
            errors.append(f"Item {idx} missing required fields")
            continue
        transformed = _transform(raw)
        processed.append(transformed)
        _aggregate(aggregation, transformed)

    summary = {
        "total_records": len(processed),
        "unique_keys": len(aggregation),
        "errors": errors,
    }

    if config.get("include_raw", False):
        summary["raw"] = list(data_source)

    return {
        "processed": processed,
        "aggregation": aggregation,
        "summary": summary,
    }

