import re
from collections import Counter
from typing import List, Dict, Tuple, Iterable, Optional, Any

def process_text_data(
    documents: Iterable[str],
    stopwords: Optional[Iterable[str]] = None,
    min_length: int = 3,
    max_length: int = 20,
    top_n: int = 10,
) -> Dict[str, Any]:
    # nested functions
    def _normalize(text: str) -> str:
        return re.sub(r'\\s+', ' ', text.strip().lower())
    def _tokenize(text: str) -> List[str]:
        return re.findall(r'\\b\\w+\\b', text)
    def _filter(tokens: List[str]) -> List[str]:
        sw = set(stopwords or [])
        return [t for t in tokens if t not in sw and min_length <= len(t) <= max_length]
    def _count(tokens: List[str]) -> Counter:
        return Counter(tokens)
    def _top(counter: Counter, n: int) -> List[Tuple[str, int]]:
        return counter.most_common(n)
    # main logic
    all_tokens: List[str] = []
    doc_counts: Dict[str, Counter] = {}
    for idx, doc in enumerate(documents):
        if not isinstance(doc, str):
            continue
        norm = _normalize(doc)
        toks = _tokenize(norm)
        filt = _filter(toks)
        all_tokens.extend(filt)
        doc_counts[f'doc_{idx}'] = _count(filt)
    global_counter = _count(all_tokens)
    top_terms = _top(global_counter, top_n)
    # build result
    result: Dict[str, Any] = {
        'global_counts': dict(global_counter),
        'top_terms': top_terms,
        'per_doc_counts': {k: dict(v) for k, v in doc_counts.items()},
        'total_docs': len(doc_counts),
        'total_tokens': len(all_tokens),
    }
    # optional: compute tf-idf
    import math
    N = len(doc_counts)
    tf_idf: Dict[str, Dict[str, float]] = {}
    for doc_id, counter in doc_counts.items():
        tf_idf[doc_id] = {}
        for term, freq in counter.items():
            df = sum(1 for c in doc_counts.values() if term in c)
            idf = math.log((N + 1) / (df + 1)) + 1
            tf = freq / sum(counter.values())
            tf_idf[doc_id][term] = tf * idf
    result['tf_idf'] = tf_idf
    return result

