import json
from typing import Any, Dict, Iterable, List, Optional


def process_data(records: List[Dict[str, Any]], key: str, threshold: Optional[int] = None) -> Dict[str, Any]:
    # Nested helper to normalize values
    def _normalize(value: Any) -> str:
        if value is None:
            return ""
        return str(value).strip().lower()

    # Validate a single record
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if key not in record:
            return False
        if not isinstance(record[key], (str, int, float)):
            return False
        return True

    # Group records by normalized key value
    def _group(records: Iterable[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in records:
            if not _validate(rec):
                continue
            k = _normalize(rec[key])
            groups.setdefault(k, []).append(rec)
        return groups

    # Compute median of numeric values
    def _median(values: List[float]) -> Optional[float]:
        if not values:
            return None
        sorted_vals = sorted(values)
        n = len(sorted_vals)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2
        else:
            return sorted_vals[mid]

    # Compute statistics for a group
    def _summarize_group(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        count = len(group)
        values = [rec.get("value") for rec in group if isinstance(rec.get("value"), (int, float))]
        avg = sum(values) / count if values else None
        med = _median(values) if values else None
        return {"count": count, "average": avg, "median": med}

    groups = _group(records)

    summary: Dict[str, Any] = {}
    for k, g in groups.items():
        if threshold is not None and len(g) < threshold:
            continue
        summary[k] = _summarize_group(g)

    # Compute overall statistics
    total_records = len(records)
    valid_records = sum(len(g) for g in groups.values())
    all_values = [rec.get("value") for rec in records if isinstance(rec.get("value"), (int, float))]
    overall_avg = sum(all_values) / len(all_values) if all_values else None

    result = {
        "total_records": total_records,
        "valid_records": valid_records,
        "groups": summary,
        "overall_average": overall_avg,
    }
    return result

# Helper to write JSON to file

def _write_json(data: Any, path: str) -> None:
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, indent=2)

# Load records from a JSON lines file

def load_json_lines(path: str) -> List[Dict[str, Any]]:
    data: List[Dict[str, Any]] = []
    with open(path, "r", encoding="utf-8") as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            try:
                obj = json.loads(line)
                data.append(obj)
            except json.JSONDecodeError:
                continue
    return data

# Filter records by date range

def filter_by_date(records: List[Dict[str, Any]], start: str, end: str) -> List[Dict[str, Any]]:
    from datetime import datetime
    def _parse(d: str) -> datetime:
        return datetime.strptime(d, "%Y-%m-%d")
    start_dt = _parse(start)
    end_dt = _parse(end)
    filtered: List[Dict[str, Any]] = []
    for rec in records:
        date_str = rec.get("date")
        if not date_str:
            continue
        try:
            d = _parse(date_str)
        except ValueError:
            continue
        if start_dt <= d <= end_dt:
            filtered.append(rec)
    return filtered

# Main processing function that ties everything together

def process_and_write(records: List[Dict[str, Any]], key: str, output_path: str, threshold: Optional[int] = None) -> None:
    result = process_data(records, key, threshold)
    _write_json(result, output_path)

