from typing import Any, Dict, Iterable, List, Optional, Tuple

def analyze_dataset(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    filter_predicate: Optional[Any] = None,
    max_items: Optional[int] = None,
) -> Dict[str, Any]:
    # nested helper functions
    def _normalize_key(v: Any) -> str:
        if v is None:
            return ""
        return str(v).strip().lower()

    def _extract_value(rec: Dict[str, Any]) -> Any:
        return rec.get(value_field)

    def _apply_filter(rec: Dict[str, Any]) -> bool:
        if filter_predicate is None:
            return True
        try:
            return bool(filter_predicate(rec))
        except Exception:
            return False

    # main processing
    stats: Dict[str, Any] = {
        "total_records": 0,
        "unique_keys": 0,
        "value_counts": {},
        "key_to_values": {},
        "errors": [],
    }

    key_counts: Dict[str, int] = {}
    key_to_vals: Dict[str, List[Any]] = {}

    for rec in records:
        stats["total_records"] += 1
        try:
            key = _normalize_key(rec.get(key_field))
            if not _apply_filter(rec):
                continue
            val = _extract_value(rec)
            key_counts[key] = key_counts.get(key, 0) + 1
            key_to_vals.setdefault(key, []).append(val)
        except Exception as e:
            stats["errors"].append({"record": rec, "error": str(e)})

        if max_items is not None and stats["total_records"] >= max_items:
            break

    stats["unique_keys"] = len(key_counts)
    stats["value_counts"] = {k: len(v) for k, v in key_to_vals.items()}
    stats["key_to_values"] = key_to_vals

    # compute top keys by frequency
    top_keys = sorted(key_counts.items(), key=lambda kv: (-kv[1], kv[0]))[:10]
    stats["top_keys"] = [{"key": k, "count": c} for k, c in top_keys]

    # optional JSON serialization
    try:
        stats["summary_json"] = json.dumps(stats, indent=2, default=str)
    except Exception as e:
        stats["summary_json"] = f"serialization error: {e}"

    return stats

