import json
from typing import List, Dict, Any, Iterable

def process_dataset(records: Iterable[Dict[str, Any]], required_fields: List[str], max_records: int = 1000) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _clean(record: Dict[str, Any]) -> Dict[str, Any]:
        cleaned = {}
        for k, v in record.items():
            if isinstance(v, str):
                v = v.strip()
                if v == '':
                    continue
            cleaned[k] = v
        return cleaned

    def _aggregate(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg = {}
        for rec in records:
            for k, v in rec.items():
                if isinstance(v, (int, float)):
                    agg.setdefault(k, 0)
                    agg[k] += v
        return agg

    processed: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    count = 0
    for rec in records:
        if count >= max_records:
            break
        if not isinstance(rec, dict):
            errors.append({'error':'not a dict','record':rec})
            continue
        if not _validate(rec):
            errors.append({'error':'missing field','record':rec})
            continue
        cleaned = _clean(rec)
        processed.append(cleaned)
        count += 1

    summary = {
        'total_records': count,
        'errors': len(errors),
        'fields': list(required_fields),
        'aggregate': _aggregate(processed)
    }

    return {
        'processed': processed,
        'summary': summary,
        'errors': errors
    }

