import json
from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_and_validate_records(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    field_types: Dict[str, type],
    numeric_fields: List[str],
    max_records: Optional[int] = None,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors: List[str] = []
        for field in required_fields:
            if field not in record:
                errors.append(f"missing field {field}")
        for field, expected_type in field_types.items():
            if field in record and not isinstance(record[field], expected_type):
                errors.append(f"field {field} expected {expected_type.__name__}")
        return (len(errors) == 0, errors)

    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        norm: Dict[str, Any] = {}
        for key, value in record.items():
            if isinstance(value, str):
                norm[key] = value.strip()
            else:
                norm[key] = value
        return norm

    def _compute_stats(values: List[float]) -> Dict[str, float]:
        if not values:
            return {"count": 0, "mean": 0.0, "min": 0.0, "max": 0.0}
        total = sum(values)
        count = len(values)
        mean = total / count
        min_val = min(values)
        max_val = max(values)
        return {"count": count, "mean": mean, "min": min_val, "max": max_val}

    processed: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    numeric_accumulator: Dict[str, List[float]] = {field: [] for field in numeric_fields}
    count = 0

    for rec in records:
        if max_records is not None and count >= max_records:
            break
        if not isinstance(rec, dict):
            errors.append({"record": rec, "error": "not a dict"})
            continue
        is_valid, err_list = _validate(rec)
        if not is_valid:
            errors.append({"record": rec, "error": err_list})
            continue
        norm_rec = _normalize(rec)
        for nfield in numeric_fields:
            val = norm_rec.get(nfield)
            if isinstance(val, (int, float)):
                numeric_accumulator[nfield].append(float(val))
        processed.append(norm_rec)
        count += 1

    stats: Dict[str, Dict[str, float]] = {}
    for nfield, vals in numeric_accumulator.items():
        stats[nfield] = _compute_stats(vals)

    summary = {
        "total_records": count + len(errors),
        "processed": count,
        "errors": len(errors),
        "error_details": errors,
        "numeric_stats": stats,
    }

    return {"summary": summary, "data": processed}

