from typing import List, Dict, Any, Optional

def analyze_transactions(transactions: List[Dict[str, Any]], *, min_amount: float = 0.0, categories: Optional[List[str]] = None) -> Dict[str, Any]:
    # Validate input
    def _validate(tx):
        if not isinstance(tx, dict):
            return False
        required = ['id', 'amount', 'category', 'timestamp']
        for key in required:
            if key not in tx:
                return False
        if not isinstance(tx['amount'], (int, float)):
            return False
        if tx['amount'] < min_amount:
            return False
        if categories is not None and tx['category'] not in categories:
            return False
        return True

    # Normalize transaction
    def _normalize(tx):
        return {
            'id': str(tx['id']),
            'amount': float(tx['amount']),
            'category': tx['category'].strip(),
            'timestamp': tx['timestamp']
        }

    # Group by category
    def _group_by_category(txs):
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for tx in txs:
            cat = tx['category']
            groups.setdefault(cat, []).append(tx)
        return groups

    # Compute stats per group
    def _compute_stats(group):
        total = 0.0
        count = 0
        min_val = None
        max_val = None
        for tx in group:
            amt = tx['amount']
            total += amt
            count += 1
            if min_val is None or amt < min_val:
                min_val = amt
            if max_val is None or amt > max_val:
                max_val = amt
        avg = total / count if count else 0.0
        return {
            'count': count,
            'total': total,
            'average': avg,
            'min': min_val,
            'max': max_val
        }

    # Main processing
    valid_txs = []
    errors = []
    for idx, tx in enumerate(transactions):
        if _validate(tx):
            valid_txs.append(_normalize(tx))
        else:
            errors.append({'index': idx, 'transaction': tx})

    grouped = _group_by_category(valid_txs)

    stats = {}
    for cat, group in grouped.items():
        stats[cat] = _compute_stats(group)

    # Summary
    summary = {
        'total_transactions': len(transactions),
        'valid_transactions': len(valid_txs),
        'invalid_transactions': len(errors),
        'categories': list(grouped.keys()),
        'stats': stats
    }

    return {
        'summary': summary,
        'errors': errors
    }

