import json
from typing import Any, Dict, Iterable, List, Optional, Set

def process_records(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    max_records: Optional[int] = None,
    allow_duplicates: bool = False,
) -> Dict[str, Any]:
    # Helper to validate presence of required fields
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    # Helper to normalize string fields
    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        norm: Dict[str, Any] = {}
        for k, v in record.items():
            if isinstance(v, str):
                norm[k] = v.strip()
            else:
                norm[k] = v
        return norm

    # Helper to aggregate numeric values and collect unique strings
    def _aggregate(acc: Dict[str, Any], rec: Dict[str, Any]) -> None:
        for k, v in rec.items():
            if isinstance(v, (int, float)):
                acc.setdefault(k, 0)
                acc[k] += v
            else:
                acc.setdefault(k, set()).add(v)

    # Helper to log errors (simple print for this example)
    def _log_error(msg: str) -> None:
        print(f"[ERROR] {msg}")

    # Helper to deduplicate records based on a composite key
    def _dedupe(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        seen: Set[str] = set()
        unique: List[Dict[str, Any]] = []
        for rec in records:
            key = json.dumps({k: rec[k] for k in required_fields if k in rec}, sort_keys=True)
            if key in seen:
                continue
            seen.add(key)
            unique.append(rec)
        return unique

    processed: List[Dict[str, Any]] = []
    aggregates: Dict[str, Any] = {}
    seen_keys: Set[str] = set()
    count = 0

    for raw in records:
        if max_records is not None and count >= max_records:
            break
        if not isinstance(raw, dict):
            _log_error("Encountered non-dict record")
            continue
        if not _validate(raw):
            _log_error("Record missing required fields")
            continue
        norm = _normalize(raw)
        key = json.dumps({k: norm[k] for k in required_fields if k in norm}, sort_keys=True)
        if not allow_duplicates and key in seen_keys:
            _log_error("Duplicate record detected")
            continue
        seen_keys.add(key)
        processed.append(norm)
        _aggregate(aggregates, norm)
        count += 1

    if not allow_duplicates:
        processed = _dedupe(processed)

    # Convert set aggregates to sorted lists
    for k, v in aggregates.items():
        if isinstance(v, set):
            aggregates[k] = sorted(v)

    return {
        "processed_count": count,
        "records": processed,
        "aggregates": aggregates,
    }

