def process_records(records: List[Dict[str, Any]], required_fields: List[str], max_depth: int = 3) -> Dict[str, Any]:
    import json
    from typing import List, Dict, Any, Tuple

    def _validate_record(rec: Dict[str, Any], depth: int = 0) -> bool:
        if depth > max_depth:
            return False
        for field in required_fields:
            if field not in rec:
                return False
        if isinstance(rec.get("metadata"), dict):
            return _validate_record(rec["metadata"], depth + 1)
        return True

    def _flatten(rec: Dict[str, Any], parent_key: str = "", sep: str = "_") -> Dict[str, Any]:
        items: List[Tuple[str, Any]] = []
        for k, v in rec.items():
            new_key = f"{parent_key}{sep}{k}" if parent_key else k
            if isinstance(v, dict):
                items.extend(_flatten(v, new_key, sep=sep).items())
            else:
                items.append((new_key, v))
        return dict(items)

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []

    for rec in records:
        if _validate_record(rec):
            flat = _flatten(rec)
            valid_records.append(flat)
        else:
            invalid_records.append(rec)

    # aggregate statistics
    stats: Dict[str, Any] = {
        "total": len(records),
        "valid": len(valid_records),
        "invalid": len(invalid_records),
        "fields_present": {},
    }

    for flat in valid_records:
        for key in flat.keys():
            stats["fields_present"].setdefault(key, 0)
            stats["fields_present"][key] += 1

    # compute field value frequencies
    field_frequencies: Dict[str, Dict[Any, int]] = {}
    for flat in valid_records:
        for key, value in flat.items():
            field_frequencies.setdefault(key, {}).setdefault(value, 0)
            field_frequencies[key][value] += 1

    # find most common values per field
    most_common: Dict[str, Tuple[Any, int]] = {}
    for key, freqs in field_frequencies.items():
        most = max(freqs.items(), key=lambda kv: kv[1])
        most_common[key] = most

    # produce output
    output: Dict[str, Any] = {
        "summary": stats,
        "most_common": most_common,
        "records": valid_records,
    }

    # optional: write to file if path provided
    def _write_json(path: str, data: Any) -> None:
        with open(path, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2)

    return output

