import json

def analyze_dataset(
    data: list,
    filter_field: str,
    filter_value: any,
    group_field: str,
    numeric_field: str,
    top_n: int = 5
) -> dict:
    # Normalize string values
    def _norm(val):
        if isinstance(val, str):
            return val.strip().lower()
        return val

    # Determine if record passes filter
    def _passes(rec):
        return rec.get(filter_field) == filter_value

    # Add record to group
    def _add_to_group(rec, groups):
        key = _norm(rec.get(group_field))
        if key not in groups:
            groups[key] = {"records": [], "sum": 0, "count": 0}
        groups[key]["records"].append(rec)
        num = rec.get(numeric_field)
        if isinstance(num, (int, float)):
            groups[key]["sum"] += num
            groups[key]["count"] += 1

    # Compute median from list of numbers
    def _median(nums):
        n = len(nums)
        if n == 0:
            return None
        nums_sorted = sorted(nums)
        mid = n // 2
        if n % 2 == 0:
            return (nums_sorted[mid - 1] + nums_sorted[mid]) / 2
        return nums_sorted[mid]

    groups: dict = {}
    filtered: list = []

    for rec in data:
        if not isinstance(rec, dict):
            continue
        if _passes(rec):
            filtered.append(rec)
            _add_to_group(rec, groups)

    # Build summary per group
    summary: dict = {}
    for key, info in groups.items():
        avg = info["sum"] / info["count"] if info["count"] > 0 else None
        nums = [r.get(numeric_field) for r in info["records"] if isinstance(r.get(numeric_field), (int, float))]
        med = _median(nums)
        summary[key] = {
            "count": info["count"],
            "average": avg,
            "median": med,
            "sample": info["records"][0] if info["records"] else None
        }

    # Detect anomalies: groups with average below threshold
    anomalies: list = []
    for key, stats in summary.items():
        if stats["average"] is not None and stats["average"] < 10:
            anomalies.append(key)

    # Sort groups by count descending
    sorted_keys = sorted(summary.keys(), key=lambda k: summary[k]["count"], reverse=True)

    # Prepare top N groups
    top_groups = sorted_keys[:top_n]

    result = {
        "total_records": len(data),
        "filtered_records": len(filtered),
        "group_count": len(groups),
        "summary": summary,
        "anomalies": anomalies,
        "top_groups": top_groups,
        "errors": []
    }

    # Validate numeric consistency
    for key, info in groups.items():
        for rec in info["records"]:
            val = rec.get(numeric_field)
            if not isinstance(val, (int, float)):
                result["errors"].append(f"non-numeric {numeric_field} in group {key}")

    return result

