import json
from typing import List, Dict, Any, Callable, Optional

def process_data(
    records: List[Dict[str, Any]],
    *,
    key: str,
    transform: Callable[[Any], Any] = lambda x: x,
    aggregate: Callable[[List[Any]], Any] = sum,
    date_filter: Optional[Dict[str, Any]] = None,
) -> Dict[str, Any]:
    # validate record structure
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        return True

    # transform a single value
    def _transform_value(val: Any) -> Any:
        try:
            return transform(val)
        except Exception:
            return None

    # aggregate a list of values
    def _aggregate(vals: List[Any]) -> Any:
        try:
            return aggregate(vals)
        except Exception:
            return None

    # optional date filtering
    def _filter_by_date(rec: Dict[str, Any]) -> bool:
        if not date_filter:
            return True
        date_key = date_filter.get('date_key')
        start = date_filter.get('start')
        end = date_filter.get('end')
        if date_key not in rec:
            return False
        val = rec[date_key]
        try:
            if start is not None and val < start:
                return False
            if end is not None and val > end:
                return False
            return True
        except Exception:
            return False

    # compute percentiles for numeric values
    def _compute_percentiles(vals: List[float], percentiles: List[float]) -> Dict[float, float]:
        if not vals:
            return {p: None for p in percentiles}
        sorted_vals = sorted(vals)
        n = len(sorted_vals)
        result = {}
        for p in percentiles:
            k = (n - 1) * p / 100.0
            f = int(k)
            c = k - f
            if f + 1 < n:
                result[p] = sorted_vals[f] + c * (sorted_vals[f + 1] - sorted_vals[f])
            else:
                result[p] = sorted_vals[f]
        return result

    # log progress
    def _log_progress(count: int, total: int) -> None:
        if count % 100 == 0 or count == total:
            print(f'Processed {count}/{total} records')

    # error handling
    def _handle_error(msg: str) -> None:
        report['errors'].append(msg)

    validated: List[Dict[str, Any]] = []
    transformed: List[Any] = []

    total = len(records)
    for idx, rec in enumerate(records, start=1):
        if not _validate(rec):
            _handle_error(f'invalid record at index {idx}')
            continue
        if not _filter_by_date(rec):
            continue
        val = rec[key]
        tval = _transform_value(val)
        if tval is None:
            _handle_error(f'failed transform at index {idx}')
            continue
        validated.append(rec)
        transformed.append(tval)
        _log_progress(idx, total)

    agg_result = _aggregate(transformed)

    report: Dict[str, Any] = {
        'total_records': total,
        'valid_records': len(validated),
        'transformed_count': len(transformed),
        'aggregate': agg_result,
        'errors': [],
    }

    # field statistics
    stats: Dict[str, Dict[str, Any]] = {}
    for rec in validated:
        for k, v in rec.items():
            if k == key:
                continue
            if k not in stats:
                stats[k] = {'count': 0, 'type': type(v).__name__}
            stats[k]['count'] += 1

    report['field_stats'] = stats

    # percentiles for numeric transformed values
    numeric_vals = [v for v in transformed if isinstance(v, (int, float))]
    percentiles = _compute_percentiles(numeric_vals, [25, 50, 75, 90])
    report['percentiles'] = percentiles

    # optional JSON serialization
    try:
        report_json = json.dumps(report, indent=2)
        report['report_json'] = report_json
    except Exception as e:
        report['report_json'] = f'serialization_error: {e}'

    return report

