import json
from typing import Any, Dict, Iterable, List, Optional


def process_dataset(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Dict[str, Any],
    batch_size: int = 100,
    verbose: bool = False,
) -> Dict[str, Any]:
    def _log(msg: str) -> None:
        if verbose:
            print(msg)

    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        out = {}
        for key, func in transform_map.items():
            if key in record:
                try:
                    out[key] = func(record[key])
                except Exception:
                    out[key] = None
            else:
                out[key] = None
        return out

    def _aggregate(stats: Dict[str, Any], record: Dict[str, Any]) -> None:
        for k, v in record.items():
            if isinstance(v, (int, float)):
                stats.setdefault(k, 0)
                stats[k] += v

    processed: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {}
    errors: List[Dict[str, Any]] = []
    batch: List[Dict[str, Any]] = []

    for idx, rec in enumerate(records, 1):
        if not isinstance(rec, dict):
            errors.append({"index": idx, "error": "not a dict"})
            continue
        if not _validate(rec):
            errors.append({"index": idx, "error": "missing required fields"})
            continue
        transformed = _transform(rec)
        _aggregate(stats, transformed)
        batch.append(transformed)
        if len(batch) >= batch_size:
            processed.extend(batch)
            _log(f"Processed {idx} records, batch size reached {batch_size}")
            batch = []

    if batch:
        processed.extend(batch)
        _log(f"Final batch processed, total records: {len(processed)}")

    result = {
        "processed_count": len(processed),
        "errors_count": len(errors),
        "stats": stats,
        "errors": errors,
