import json
from typing import Any, Dict, Iterable, List, Optional

def process_dataset(
    data: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    filter_func: Optional[Any] = None,
    transform_func: Optional[Any] = None,
    batch_size: int = 1000,
) -> Dict[str, Any]:
    def _normalize_key(v: Any) -> str:
        if v is None:
            return ''
        return str(v).strip().lower()

    def _aggregate(batch: List[Dict[str, Any]]) -> Dict[str, List[Any]]:
        agg: Dict[str, List[Any]] = {}
        for item in batch:
            if not isinstance(item, dict):
                continue
            k = _normalize_key(item.get(key_field))
            if k == '':
                continue
            val = item.get(value_field)
            if val is None:
                continue
            if k not in agg:
                agg[k] = []
            agg[k].append(val)
        return agg

    def _process_batch(batch: List[Dict[str, Any]]) -> Dict[str, List[Any]]:
        if filter_func:
            batch = [x for x in batch if filter_func(x)]
        if transform_func:
            batch = [transform_func(x) for x in batch]
        return _aggregate(batch)

    results: Dict[str, List[Any]] = {}
    batch: List[Dict[str, Any]] = []
    total_processed = 0
    for record in data:
        batch.append(record)
        if len(batch) >= batch_size:
            partial = _process_batch(batch)
            for k, vals in partial.items():
                if k not in results:
                    results[k] = []
                results[k].extend(vals)
            total_processed += len(batch)
            batch.clear()
    if batch:
        partial = _process_batch(batch)
        for k, vals in partial.items():
            if k not in results:
                results[k] = []
            results[k].extend(vals)
        total_processed += len(batch)

    stats = {
        'total_records': total_processed,
        'unique_keys': len(results),
        'average_values_per_key': sum(len(v) for v in results.values()) / len(results) if results else 0,
    }

    try:
        json.dumps(results)
    except (TypeError, OverflowError):
        results_str = {k: [str(v) for v in vals] for k, vals in results.items()}
        json.dumps(results_str)

    return {
        'aggregated': results,
        'statistics': stats,
        'batch_size': batch_size,
    }

