def process_customer_data(
    customers: List[Dict[str, Any]],
    min_age: int = 18,
    max_age: int = 99,
    include_inactive: bool = False,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        required = {"id", "name", "email", "age", "country", "active"}
        if not isinstance(record, dict):
            return False
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["id"], int):
            return False
        if not isinstance(record["name"], str) or not record["name"]:
            return False
        if not isinstance(record["email"], str) or "@" not in record["email"]:
            return False
        if not isinstance(record["age"], int):
            return False
        if not isinstance(record["country"], str) or not record["country"]:
            return False
        if not isinstance(record["active"], bool):
            return False
        return True

    def _compute_age(record: Dict[str, Any]) -> int:
        return record["age"]

    def _group_by_country(records: Iterable[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in records:
            country = rec["country"].upper()
            groups.setdefault(country, []).append(rec)
        return groups

    def _aggregate_stats(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = len(group)
        active = sum(1 for r in group if r["active"])
        inactive = total - active
        ages = [r["age"] for r in group]
        avg_age = sum(ages) / total if total else 0
        return {
            "total": total,
            "active": active,
            "inactive": inactive,
            "average_age": round(avg_age, 2),
        }

    def _filter_records(records: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for rec in records:
            if not _validate(rec):
                continue
            age = _compute_age(rec)
            if age < min_age or age > max_age:
                continue
            if not include_inactive and not rec["active"]:
                continue
            filtered.append(rec)
        return filtered

    def _summarize(groups: Dict[str, List[Dict[str, Any]]]) -> Dict[str, Any]:
        summary: Dict[str, Any] = {}
        for country, recs in groups.items():
            summary[country] = _aggregate_stats(recs)
        return summary

    # Main pipeline
    valid_customers = _filter_records(customers)
    country_groups = _group_by_country(valid_customers)
    stats = _summarize(country_groups)
    result = {
        "total_customers": len(valid_customers),
        "countries": len(country_groups),
        "statistics": stats,
        "sample_records": valid_customers[:5],
    }
    return result

