from typing import Any, Dict, List


def process_records(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = {'id', 'value', 'tags'}
        if not isinstance(rec, dict):
            return False
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec['id'], int):
            return False
        if not isinstance(rec['value'], (int, float)):
            return False
        if not isinstance(rec['tags'], list):
            return False
        return True
    def _normalize_tag(tag: Any) -> str:
        if not isinstance(tag, str):
            return ''
        return tag.strip().lower()
    def _compute_median(values: List[float]) -> float:
        sorted_vals = sorted(values)
        n = len(sorted_vals)
        if n == 0:
            return 0.0
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]
    def _compute_percentile(values: List[float], percentile: float) -> float:
        if not values:
            return 0.0
        sorted_vals = sorted(values)
        k = (len(sorted_vals)-1) * percentile / 100.0
        f = int(k)
        c = k - f
        if f + 1 < len(sorted_vals):
            return sorted_vals[f] + c * (sorted_vals[f+1] - sorted_vals[f])
        return sorted_vals[f]
    valid_records = []
    errors = []
    for idx, rec in enumerate(records):
        if _validate_record(rec):
            valid_records.append(rec)
        else:
            errors.append(f'Record at index {idx} failed validation')
    groups = {}
    for rec in valid_records:
        groups.setdefault(rec['id'], []).append(rec)
    aggregated = []
    for gid, recs in groups.items():
        total_value = 0.0
        tag_counts = {}
        for r in recs:
            total_value += float(r['value'])
            for t in r['tags']:
                nt = _normalize_tag(t)
                if nt:
                    tag_counts[nt] = tag_counts.get(nt, 0) + 1
        most_common_tag = None
        max_count = 0
        for t, c in tag_counts.items():
            if c > max_count:
                max_count = c
                most_common_tag = t
        aggregated.append({
            'id': gid,
            'count': len(recs),
            'total_value': total_value,
            'most_common_tag': most_common_tag,
            'tag_distribution': tag_counts,
        })
    aggregated.sort(key=lambda x: x['total_value'], reverse=True)
    total_values = [g['total_value'] for g in aggregated]
    median_total = _compute_median(total_values)
    percentile_90 = _compute_percentile(total_values, 90)
    summary = {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'invalid_records': len(errors),
        'groups': len(groups),
        'top_group_by_value': aggregated[0]['id'] if aggregated else None,
        'median_total_value': median_total,
        '90th_percentile_value': percentile_90,
    }
    return {
        'summary': summary,
        'data': aggregated,
        'errors': errors,
    }

