def process_transactions(transactions: List[Dict[str, Any]]) -> Dict[str, Any]:
    # Validate each transaction
    def _validate(tx):
        required = ['id', 'amount', 'currency', 'region', 'category']
        for key in required:
            if key not in tx:
                return False
        if not isinstance(tx['amount'], (int, float)):
            return False
        if tx['amount'] < 0:
            return False
        return True

    # Normalize amount to float
    def _normalize_amount(val):
        try:
            return float(val)
        except Exception:
            return 0.0

    # Group by key
    def _group_by(items, key):
        groups = {}
        for item in items:
            k = item.get(key)
            if k is None:
                continue
            groups.setdefault(k, []).append(item)
        return groups

    # Compute statistics
    def _stats(items):
        total = 0.0
        count = 0
        min_val = None
        max_val = None
        for it in items:
            amt = _normalize_amount(it.get('amount'))
            total += amt
            count += 1
            if min_val is None or amt < min_val:
                min_val = amt
            if max_val is None or amt > max_val:
                max_val = amt
        avg = total / count if count else 0.0
        return {'total': total, 'count': count, 'min': min_val, 'max': max_val, 'avg': avg}

    # Median calculation
    def _median(values):
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    # Weighted average by amount
    def _weighted_avg(items):
        total_weight = 0.0
        weighted_sum = 0.0
        for it in items:
            amt = _normalize_amount(it.get('amount'))
            weight = amt
            weighted_sum += amt * weight
            total_weight += weight
        return weighted_sum / total_weight if total_weight else 0.0

    # Filter valid transactions
    valid_txs = [tx for tx in transactions if _validate(tx)]

    # Group by region
    region_groups = _group_by(valid_txs, 'region')

    # Compute region stats
    region_stats = {}
    for region, items in region_groups.items():
        stats = _stats(items)
        stats['median'] = _median([_normalize_amount(it.get('amount')) for it in items])
        stats['weighted_avg'] = _weighted_avg(items)
        region_stats[region] = stats

    # Group by category
    category_groups = _group_by(valid_txs, 'category')

    # Compute category stats
    category_stats = {}
    for cat, items in category_groups.items():
        stats = _stats(items)
        stats['median'] = _median([_normalize_amount(it.get('amount')) for it in items])
        category_stats[cat] = stats

    # Overall stats
    overall = _stats(valid_txs)
    overall['median'] = _median([_normalize_amount(it.get('amount')) for it in valid_txs])
    overall['weighted_avg'] = _weighted_avg(valid_txs)

    return {
        'by_region': region_stats,
        'by_category': category_stats,
        'overall': overall,
        'valid_count': len(valid_txs),
        'invalid_count': len(transactions) - len(valid_txs),
    }

