def process_data(
    records: List[Dict[str, Any]],
    key_field: str,
    value_field: str,
    filter_func: Optional[Any] = None,
    transform_func: Optional[Any] = None,
    group_by: Optional[Any] = None,
) -> Dict[str, Any]:
    # Validate inputs
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        return True

    def _apply_filter(rec: Dict[str, Any]) -> bool:
        if filter_func is None:
            return True
        try:
            return bool(filter_func(rec))
        except Exception:
            return False

    def _apply_transform(rec: Dict[str, Any]) -> Any:
        if transform_func is None:
            return rec[value_field]
        try:
            return transform_func(rec)
        except Exception:
            return None

    def _group_key(rec: Dict[str, Any]) -> Any:
        if group_by is None:
            return None
        try:
            return group_by(rec)
        except Exception:
            return None

    processed: List[Tuple[Any, Any]] = []
    for rec in records:
        if not _validate_record(rec):
            continue
        if not _apply_filter(rec):
            continue
        val = _apply_transform(rec)
        if val is None:
            continue
        grp = _group_key(rec)
        processed.append((grp, val))

    # Aggregate
    result: Dict[Any, List[Any]] = {}
    for grp, val in processed:
        if grp not in result:
            result[grp] = []
        result[grp].append(val)

    # Compute statistics
    stats: Dict[str, Any] = {}
    stats['total_records'] = len(records)
    stats['valid_records'] = len(processed)
    stats['groups'] = len(result)
    stats['group_sizes'] = {k: len(v) for k, v in result.items()}

    # Prepare output
    output: Dict[str, Any] = {
        'processed': result,
        'statistics': stats,
    }

    return output

