import json
from typing import Any, Dict, List, Iterable, Optional

def process_data_pipeline(
    raw_data: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Optional[Dict[str, Any]] = None,
    max_items: Optional[int] = None,
) -> Dict[str, Any]:
    # Inner helper to validate a single record
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        for field in required_fields:
            if field not in rec:
                return False
        return True

    # Inner helper to apply transformations
    def _transform_record(rec: Dict[str, Any]) -> Dict[str, Any]:
        if not transform_map:
            return rec
        transformed = {}
        for key, value in rec.items():
            if key in transform_map:
                try:
                    transformed[key] = transform_map[key](value)
                except Exception:
                    transformed[key] = value
            else:
                transformed[key] = value
        return transformed

    # Inner helper to aggregate results
    def _aggregate(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for rec in records:
            for k, v in rec.items():
                if isinstance(v, (int, float)):
                    agg[k] = agg.get(k, 0) + v
                else:
                    agg.setdefault(k, []).append(v)
        return agg

    processed: List[Dict[str, Any]] = []
    errors: List[str] = []
    count = 0

    for raw in raw_data:
        if max_items is not None and count >= max_items:
            break
        if not _validate_record(raw):
            errors.append(f"Invalid record at index {count}")
            continue
        try:
            transformed = _transform_record(raw)
        except Exception as e:
            errors.append(f"Transformation error at index {count}: {e}")
            continue
        processed.append(transformed)
        count += 1

    # Compute summary statistics
    summary = _aggregate(processed)

    # Prepare final result
    result: Dict[str, Any] = {
        "processed_count": len(processed),
        "errors": errors,
        "summary": summary,
        "raw_count": count,
    }

    # Optional: serialize to JSON for external use
    try:
        result["json"] = json.dumps(result, default=str)
    except Exception:
        result["json"] = None

    return result

