    # Assemble result
    result: Dict[str, Any] = {
        "total_users": len(users),
        "valid_users": len(valid_users),
        "invalid_users": len(errors),
        "average_age": avg_age,
        "top_email_domains": [{"domain": d, "count": c} for d, c in top_domains],
        "age_brackets": brackets,
        "errors": errors,
    }

