def process_records(records: List[Dict[str, Any]], key: str, required_fields: List[str], max_items: Optional[int] = None) -> Dict[str, Any]:
    # inner functions
    def _validate_record(rec: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in rec or rec[field] is None:
                return False
        return True

    def _normalize_value(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip()
        return val

    def _group_by_key(recs: List[Dict[str, Any]]) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for r in recs:
            k = _normalize_value(r.get(key))
            if k not in groups:
                groups[k] = []
            groups[k].append(r)
        return groups

    def _aggregate_group(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for rec in group:
            for k, v in rec.items():
                if k not in agg:
                    agg[k] = v
                else:
                    if isinstance(agg[k], list):
                        agg[k].append(v)
                    else:
                        agg[k] = [agg[k], v]
        return agg

    valid_records: List[Dict[str, Any]] = []
    errors: List[str] = []

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append(f"Record {idx} is not a dict")
            continue
        if not _validate_record(rec):
            errors.append(f"Record {idx} missing required fields")
            continue
        for k, v in rec.items():
            rec[k] = _normalize_value(v)
        valid_records.append(rec)

    grouped = _group_by_key(valid_records)

    aggregated: List[Dict[str, Any]] = []
    for gkey, group in grouped.items():
        if max_items is not None and len(group) > max_items:
            errors.append(f"Group {gkey} has {len(group)} items exceeding max {max_items}")
            continue
        aggregated.append(_aggregate_group(group))

    result: Dict[str, Any] = {
        "aggregated": aggregated,
        "errors": errors,
        "summary": {
            "total_records": len(records),
            "valid_records": len(valid_records),
            "groups": len(grouped),
        },
    }
    return result

