def process_records(records: List[Dict[str, Any]], key: str, group_by: str, threshold: int) -> Dict[str, Any]:
    # Validate inputs
    if not isinstance(records, list):
        raise TypeError("records must be a list")
    if not isinstance(key, str) or not key:
        raise ValueError("key must be a non-empty string")
    if not isinstance(group_by, str) or not group_by:
        raise ValueError("group_by must be a non-empty string")
    if not isinstance(threshold, int) or threshold < 0:
        raise ValueError("threshold must be a non-negative integer")

    # Helper to validate a single record
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec or group_by not in rec:
            return False
        if not isinstance(rec[key], (int, float)):
            return False
        if not isinstance(rec[group_by], str):
            return False
        return True

    # Filter valid records
    valid_records = []
    invalid_count = 0
    for r in records:
        if _validate_record(r):
            valid_records.append(r)
        else:
            invalid_count += 1

    # Group records by group_by field
    def _group_records(recs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in recs:
            grp = rec[group_by]
            groups.setdefault(grp, []).append(rec)
        return groups

    grouped = _group_records(valid_records)

    # Compute statistics per group
    def _compute_stats(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = sum(rec[key] for rec in group)
        count = len(group)
        avg = total / count if count else 0
        return {"count": count, "total": total, "average": avg}

    stats_per_group: Dict[str, Dict[str, Any]] = {}
    for grp, recs in grouped.items():
        stats_per_group[grp] = _compute_stats(recs)

    # Filter groups by threshold
    filtered_groups = {g: s for g, s in stats_per_group.items() if s["total"] >= threshold}

    # Format output
    def _format_output() -> Dict[str, Any]:
        output: Dict[str, Any] = {
            "total_records": len(records),
            "valid_records": len(valid_records),
            "invalid_records": invalid_count,
            "groups": [],
        }
        for grp, stats in filtered_groups.items():
            output["groups"].append({
                "group": grp,
                "count": stats["count"],
                "total": stats["total"],
                "average": stats["average"],
            })
        output["groups"].sort(key=lambda x: x["total"], reverse=True)
        return output

    return _format_output()

