from typing import Any, Dict, List, Optional, Tuple, Iterable


def process_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: int = 0,
    max_group_size: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]]]:
    # Validate input types
    if not isinstance(records, list):
        raise TypeError("records must be a list")
    if not isinstance(key, str):
        raise TypeError("key must be a string")
    if not isinstance(threshold, int):
        raise TypeError("threshold must be an int")
    if max_group_size is not None and not isinstance(max_group_size, int):
        raise TypeError("max_group_size must be an int or None")

    def _normalize_value(val: Any) -> str:
        if val is None:
            return ""
        return str(val).strip().lower()

    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        return True

    def _group_by(records: Iterable[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in records:
            if not _validate_record(rec):
                continue
            k = _normalize_value(rec[key])
            groups.setdefault(k, []).append(rec)
        return groups

    def _filter_group(group: List[Dict[str, Any]]) -> bool:
        return len(group) >= threshold

    def _truncate_group(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        if max_group_size is None:
            return group
        return group[:max_group_size]

    grouped = _group_by(records)
    valid_groups: List[Dict[str, Any]] = []
    invalid_groups: List[Dict[str, Any]] = []

    for k, group in grouped.items():
        if not _filter_group(group):
            invalid_groups.append({"key": k, "records": group})
            continue
        truncated = _truncate_group(group)
        valid_groups.append({"key": k, "records": truncated})

    # Post-processing: sort valid groups by number of records descending
    valid_groups.sort(key=lambda g: len(g["records"]), reverse=True)

    # Build summary
    summary: Dict[str, Any] = {
        "total_records": len(records),
        "total_groups": len(grouped),
        "valid_groups": len(valid_groups),
        "invalid_groups": len(invalid_groups),
    }

    # Attach summary to result
    result_valid = [
        {
            "key": g["key"],
            "count": len(g["records"]),
            "records": g["records"],
        }
        for g in valid_groups
    ]
    result_invalid = [
        {
            "key": g["key"],
            "count": len(g["records"]),
            "records": g["records"],
        }
        for g in invalid_groups
    ]

    # Return both lists and summary
    return result_valid, result_invalid, summary

