def process_data(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[float] = None,
    max_items: int = 1000,
) -> Dict[str, Any]:
    # Helper to normalize keys
    def _normalize(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip().lower()
        return val

    # Predicate to decide if a record should be kept
    def _filter(record: Dict[str, Any]) -> bool:
        val = record.get(value_field)
        if val is None:
            return False
        if threshold is not None and isinstance(val, (int, float)):
            return val >= threshold
        return True

    # Accumulate values per key
    def _aggregate(acc: Dict[str, List[Any]], record: Dict[str, Any]) -> None:
        key = _normalize(record.get(key_field))
        if key not in acc:
            acc[key] = []
        acc[key].append(record.get(value_field))

    aggregated: Dict[str, List[Any]] = {}
    processed = 0

    for rec in records:
        if not isinstance(rec, dict):
            continue
        if not _filter(rec):
            continue
        _aggregate(aggregated, rec)
        processed += 1
        if processed >= max_items:
            break

    # Build summary statistics
    summary: Dict[str, Any] = {}
    for k, vals in aggregated.items():
        if not vals:
            continue
        if all(isinstance(v, (int, float)) for v in vals):
            avg = sum(vals) / len(vals)
            summary[k] = {"count": len(vals), "average": avg}
        else:
            summary[k] = {"count": len(vals), "sample": vals[:3]}

    return {
        "total_processed": processed,
        "unique_keys": len(aggregated),
        "summary": summary,
        "raw_aggregated": aggregated,
    }

