import json
from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_dataset(
    data: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    filter_func: Optional[Any] = None,
    group_by: Optional[str] = None,
    limit: Optional[int] = None,
) -> Dict[str, Any]:
    # validate inputs
    if not isinstance(data, Iterable):
        raise TypeError("data must be iterable")
    if not isinstance(key_field, str) or not isinstance(value_field, str):
        raise TypeError("key_field and value_field must be strings")
    if filter_func is not None and not callable(filter_func):
        raise TypeError("filter_func must be callable")
    if group_by is not None and not isinstance(group_by, str):
        raise TypeError("group_by must be a string or None")
    if limit is not None and (not isinstance(limit, int) or limit <= 0):
        raise ValueError("limit must be positive integer or None")

    # internal helper to extract safe value
    def _safe_get(item: Dict[str, Any], field: str) -> Any:
        return item.get(field)

    # internal helper to apply filter
    def _apply_filter(item: Dict[str, Any]) -> bool:
        if filter_func is None:
            return True
        try:
            return bool(filter_func(item))
        except Exception:
            return False

    # internal helper to accumulate stats
    stats: Dict[str, Any] = {
        "total_items": 0,
        "filtered_items": 0,
        "group_counts": {},
        "value_sums": {},
        "value_counts": {},
    }

    # main loop
    for idx, record in enumerate(data):
        if not isinstance(record, dict):
            continue
        stats["total_items"] += 1
        if not _apply_filter(record):
            continue
        stats["filtered_items"] += 1
        key = _safe_get(record, key_field)
        value = _safe_get(record, value_field)
        if key is None or value is None:
            continue
        try:
            numeric_value = float(value)
        except Exception:
            continue
        if group_by:
            group_key = _safe_get(record, group_by)
            if group_key is None:
                group_key = "ungrouped"
            stats["group_counts"][group_key] = stats["group_counts"].get(group_key, 0) + 1
            stats["value_sums"][group_key] = stats["value_sums"].get(group_key, 0.0) + numeric_value
            stats["value_counts"][group_key] = stats["value_counts"].get(group_key, 0) + 1
        else:
            stats["value_sums"][key] = stats["value_sums"].get(key, 0.0) + numeric_value
            stats["value_counts"][key] = stats["value_counts"].get(key, 0) + 1

        if limit is not None and stats["filtered_items"] >= limit:
            break

    # compute averages
    averages: Dict[str, float] = {}
    for k in stats["value_sums"]:
        count = stats["value_counts"].get(k, 0)
        if count > 0:
            averages[k] = stats["value_sums"][k] / count
        else:
            averages[k] = 0.0

    # prepare result
    result: Dict[str, Any] = {
        "summary": {
            "total_items": stats["total_items"],
            "filtered_items": stats["filtered_items"],
            "group_counts": stats["group_counts"],
            "averages": averages,
        },
        "details": {
            "value_sums": stats["value_sums"],
            "value_counts": stats["value_counts"],
        },
    }

    return result

