import typing

def process_transactions(transactions: List[Dict[str, Any]]) -> Dict[str, Any]:
    # Validate input
    def _validate(tx):
        if not isinstance(tx, dict):
            return False
        required = {"id", "amount", "type", "timestamp"}
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], int):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if tx["type"] not in {"debit", "credit"}:
            return False
        if not isinstance(tx["timestamp"], str):
            return False
        return True

    # Group by type
    def _group_by_type(valid_txs):
        groups: Dict[str, List[Dict[str, Any]]] = {"debit": [], "credit": []}
        for tx in valid_txs:
            groups[tx["type"]].append(tx)
        return groups

    # Compute totals
    def _compute_totals(groups):
        totals = {}
        for ttype, txs in groups.items():
            totals[ttype] = sum(tx["amount"] for tx in txs)
        return totals

    # Detect anomalies
    def _detect_anomalies(groups):
        anomalies = []
        for ttype, txs in groups.items():
            for tx in txs:
                if tx["amount"] < 0:
                    anomalies.append({"id": tx["id"], "issue": "negative amount"})
        return anomalies

    # Main processing
    valid_transactions = [tx for tx in transactions if _validate(tx)]
    groups = _group_by_type(valid_transactions)
    totals = _compute_totals(groups)
    anomalies = _detect_anomalies(groups)

    # Prepare report
    report = {
        "total_transactions": len(transactions),
        "valid_transactions": len(valid_transactions),
        "invalid_transactions": len(transactions) - len(valid_transactions),
        "totals": totals,
        "anomalies": anomalies,
    }

    # Optional: sort anomalies by id
    report["anomalies"].sort(key=lambda a: a["id"])

    return report

