import typing

def process_data(records: typing.List[typing.Dict[str, typing.Any]], key: str, threshold: int = 0) -> typing.Dict[str, typing.Any]:
    # nested functions
    def _validate_record(rec):
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        return True

    def _aggregate(records):
        agg = {}
        for rec in records:
            k = rec[key]
            agg.setdefault(k, []).append(rec)
        return agg

    def _filter_by_threshold(grouped):
        return {k: v for k, v in grouped.items() if len(v) >= threshold}

    def _compute_stats(grouped):
        stats = {}
        for k, v in grouped.items():
            stats[k] = {
                'count': len(v),
                'fields': sorted(set().union(*(rec.keys() for rec in v)))
            }
        return stats

    if not isinstance(records, list):
        raise TypeError('records must be a list')

    valid_records = [rec for rec in records if _validate_record(rec)]

    grouped = _aggregate(valid_records)

    filtered = _filter_by_threshold(grouped)

    stats = _compute_stats(filtered)

    # produce output
    output = {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'groups': len(filtered),
        'stats': stats,
    }

    # optional: sort groups by count descending
    sorted_groups = sorted(filtered.items(), key=lambda kv: len(kv[1]), reverse=True)
    output['sorted_group_keys'] = [k for k, _ in sorted_groups]

    # compute overall field distribution
    field_counts: typing.Dict[str, int] = {}
    for rec in valid_records:
        for f in rec:
            field_counts[f] = field_counts.get(f, 0) + 1

    output['field_counts'] = field_counts

    # compute missing fields per group
    missing_per_group: typing.Dict[str, typing.List[str]] = {}
    for k, recs in filtered.items():
        all_fields = set().union(*(rec.keys() for rec in recs))
        missing = [f for f in field_counts if f not in all_fields]
        missing_per_group[k] = missing

    output['missing_fields_per_group'] = missing_per_group

    # return final
    return output

