import datetime
from typing import List, Dict, Any, Optional

def process_transactions(transactions: List[Dict[str, Any]], threshold: float = 0.0) -> Dict[str, Any]:
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "amount", "timestamp", "type"}
        if not required.issubset(tx):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        try:
            datetime.datetime.fromisoformat(tx["timestamp"])
        except Exception:
            return False
        if tx["type"] not in {"debit", "credit"}:
            return False
        return True

    def _normalize(tx: Dict[str, Any]) -> Dict[str, Any]:
        tx = dict(tx)
        tx["amount"] = float(tx["amount"])
        tx["timestamp"] = datetime.datetime.fromisoformat(tx["timestamp"])
        return tx

    def _group_by_day(txs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for tx in txs:
            day = tx["timestamp"].date().isoformat()
            groups.setdefault(day, []).append(tx)
        return groups

    def _aggregate_day(day_txs: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        for tx in day_txs:
            total += tx["amount"]
            count += 1
        avg = total / count if count else 0.0
        return {"total": total, "count": count, "average": avg}

    valid_txs: List[Dict[str, Any]] = []
    invalid_ids: List[Any] = []

    for tx in transactions:
        if _validate(tx):
            valid_txs.append(_normalize(tx))
        else:
            invalid_ids.append(tx.get("id"))

    grouped = _group_by_day(valid_txs)

    summary: Dict[str, Any] = {}
    for day, day_txs in grouped.items():
        agg = _aggregate_day(day_txs)
        if agg["total"] >= threshold:
            summary[day] = agg

    result = {
        "summary": summary,
        "invalid_transactions": invalid_ids,
        "processed_count": len(valid_txs),
        "skipped_count": len(invalid_ids),
    }
    return result

