import csv
from typing import Dict, List, Tuple, Optional, Any

def process_sales_data(
    input_file: str,
    output_file: str,
    min_quantity: int = 1,
    region_filter: Optional[List[str]] = None,
) -> Dict[str, Any]:
    # inner helper functions
    def _parse_row(row: Dict[str, str]) -> Optional[Dict[str, Any]]:
        try:
            return {
                'order_id': row['order_id'],
                'region': row['region'],
                'product': row['product'],
                'quantity': int(row['quantity']),
                'price': float(row['price']),
                'date': row['date'],
            }
        except (KeyError, ValueError):
            return None

    def _aggregate(agg: Dict[str, Dict[str, int]], rec: Dict[str, Any]) -> None:
        region = rec['region']
        product = rec['product']
        qty = rec['quantity']
        if region not in agg:
            agg[region] = {}
        agg[region][product] = agg[region].get(product, 0) + qty

    def _write_output(agg: Dict[str, Dict[str, int]]) -> None:
        with open(output_file, 'w', newline='') as f:
            writer = csv.writer(f)
            writer.writerow(['region', 'product', 'total_quantity'])
            for region, products in agg.items():
                for product, total in products.items():
                    writer.writerow([region, product, total])

    # main logic
    aggregated: Dict[str, Dict[str, int]] = {}
    processed_count = 0
    skipped_count = 0

    with open(input_file, newline='') as f:
        reader = csv.DictReader(f)
        for raw_row in reader:
            rec = _parse_row(raw_row)
            if rec is None:
                skipped_count += 1
                continue
            if rec['quantity'] < min_quantity:
                skipped_count += 1
                continue
            if region_filter and rec['region'] not in region_filter:
                skipped_count += 1
                continue
            _aggregate(aggregated, rec)
            processed_count += 1

    _write_output(aggregated)

    return {
        'processed': processed_count,
        'skipped': skipped_count,
        'regions': list(aggregated.keys()),
        'products_per_region': {r: list(p.keys()) for r, p in aggregated.items()},
    }

