import datetime
from typing import Any, Dict, Iterable, List, Tuple


def process_transactions(
    transactions: List[Dict[str, Any]],
    start_date: str,
    end_date: str,
    categories: List[str],
    currency: str = "USD",
) -> Dict[str, Any]:
    # Parse date strings into datetime objects
    try:
        start_dt = datetime.datetime.strptime(start_date, "%Y-%m-%d")
        end_dt = datetime.datetime.strptime(end_date, "%Y-%m-%d")
    except Exception as e:
        return {"error": f"Invalid date format: {e}"}

    # Nested helper: validate a single transaction
    def _validate(tx: Dict[str, Any]) -> Tuple[bool, str]:
        if not isinstance(tx, dict):
            return False, "Transaction not a dict"
        required = {"date", "amount", "category"}
        if not required.issubset(tx):
            return False, "Missing required fields"
        try:
            tx_date = datetime.datetime.strptime(tx["date"], "%Y-%m-%d")
        except Exception:
            return False, "Invalid date in transaction"
        if not isinstance(tx["amount"], (int, float)):
            return False, "Amount not numeric"
        if tx["category"] not in categories:
            return False, f"Unknown category {tx['category']}"
        if tx_date < start_dt or tx_date > end_dt:
            return False, "Date out of range"
        return True, ""

    # Nested helper: format amount with currency
    def _format_amount(amount: float) -> str:
        return f"{currency} {amount:,.2f}"

    # Nested helper: compute average per category
    def _compute_average(total: float, count: int) -> float:
        return total / count if count > 0 else 0.0

    # Nested helper: sort categories by total amount descending
    def _sort_categories(totals: Dict[str, float]) -> List[Tuple[str, float]]:
        return sorted(totals.items(), key=lambda kv: kv[1], reverse=True)

    # Aggregation structures
    totals: Dict[str, float] = {cat: 0.0 for cat in categories}
    counts: Dict[str, int] = {cat: 0 for cat in categories}
    errors: List[str] = []

    # Process each transaction
    for idx, tx in enumerate(transactions):
        valid, msg = _validate(tx)
        if not valid:
            errors.append(f"Tx {idx}: {msg}")
            continue
        amt = float(tx["amount"])
        cat = tx["category"]
        totals[cat] += amt
        counts[cat] += 1

    # Compute overall totals
    overall_total = sum(totals.values())
    overall_count = sum(counts.values())

    # Compute averages per category
    averages: Dict[str, float] = {
        cat: _compute_average(totals[cat], counts[cat]) for cat in categories
    }

    # Build per-category summary
    per_category: Dict[str, Dict[str, Any]] = {}
    for cat in categories:
        per_category[cat] = {
            "amount": _format_amount(totals[cat]),
            "count": counts[cat],
            "average": _format_amount(averages[cat]),
        }

    # Sort categories by amount for reporting
    sorted_cats = _sort_categories(totals)
    sorted_summary = [
        {
            "category": cat,
            "amount": _format_amount(amount),
            "count": counts[cat],
            "average": _format_amount(averages[cat]),
        }
        for cat, amount in sorted_cats
    ]

    # Final result structure
    result = {
        "summary": {
            "total_amount": _format_amount(overall_total),
            "total_transactions": overall_count,
            "per_category": per_category,
            "sorted_by_amount": sorted_summary,
        },
        "errors": errors,
    }

    return result

