import json
from typing import Any, Dict, Iterable, List, Optional


def process_data(
    data: Iterable[Dict[str, Any]],
    filter_key: str,
    filter_value: Any,
    aggregate_keys: List[str],
    max_items: Optional[int] = None,
) -> Dict[str, Any]:
    # nested functions
    def _filter_item(item: Dict[str, Any]) -> bool:
        return item.get(filter_key) == filter_value

    def _aggregate(item: Dict[str, Any], acc: Dict[str, float]) -> None:
        for k in aggregate_keys:
            v = item.get(k)
            if isinstance(v, (int, float)):
                acc[k] = acc.get(k, 0.0) + float(v)

    def _serialize(item: Dict[str, Any]) -> Dict[str, Any]:
        return {k: v for k, v in item.items() if v is not None}

    filtered: List[Dict[str, Any]] = []
    aggregate_result: Dict[str, float] = {}
    count = 0
    for record in data:
        if not isinstance(record, dict):
            continue
        if _filter_item(record):
            filtered.append(_serialize(record))
            _aggregate(record, aggregate_result)
            count += 1
            if max_items is not None and count >= max_items:
                break

    # compute summary
    summary: Dict[str, Any] = {
        "total_records": count,
        "aggregate": aggregate_result,
        "unique_keys": sorted({k for r in filtered for k in r.keys()}),
    }

    # nested function for sorting
    def _sort_by(key: str, reverse: bool = False) -> List[Dict[str, Any]]:
        return sorted(filtered, key=lambda x: x.get(key, 0), reverse=reverse)

    # produce final structure
    result: Dict[str, Any] = {
        "filtered": filtered,
        "summary": summary,
        "sorted_by_first_key": _sort_by(aggregate_keys[0]) if aggregate_keys else filtered,
    }

    # optional JSON output
    try:
        result_json = json.dumps(result, indent=2, sort_keys=True)
        result["json"] = result_json
    except Exception:
        result["json"] = None

    return result

