from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_records(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    group_field: str,
    required_fields: List[str],
    max_group_size: int = 1000,
) -> Dict[str, Any]:
    # Validate input types
    if not isinstance(records, Iterable):
        raise TypeError("records must be an iterable of dicts")
    if not isinstance(key_field, str) or not isinstance(group_field, str):
        raise TypeError("key_field and group_field must be strings")
    if not isinstance(required_fields, list):
        raise TypeError("required_fields must be a list of strings")
    for rf in required_fields:
        if not isinstance(rf, str):
            raise TypeError("required_fields must contain only strings")

    # Helper to validate a single record
    def _validate(rec: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors: List[str] = []
        if not isinstance(rec, dict):
            errors.append("record is not a dict")
            return False, errors
        for field in required_fields:
            if field not in rec:
                errors.append(f"missing required field: {field}")
        if key_field not in rec:
            errors.append(f"missing key field: {key_field}")
        if group_field not in rec:
            errors.append(f"missing group field: {group_field}")
        return (len(errors) == 0), errors

    # Group records by group_field
    groups: Dict[Any, List[Dict[str, Any]]] = {}
    for rec in records:
        valid, errs = _validate(rec)
        if not valid:
            continue
        grp_val = rec.get(group_field)
        groups.setdefault(grp_val, []).append(rec)

    # Enforce max_group_size
    oversized: List[Any] = []
    for grp, recs in list(groups.items()):
        if len(recs) > max_group_size:
            oversized.append(grp)
            groups[grp] = recs[:max_group_size]

    # Compute statistics per group
    stats: Dict[Any, Dict[str, Any]] = {}
    for grp, recs in groups.items():
        count = len(recs)
        keys_present = set()
        for r in recs:
            keys_present.update(r.keys())
        stats[grp] = {
            "count": count,
            "unique_keys": len(keys_present),
            "sample_record": recs[0] if recs else None,
        }

    # Build final result
    result: Dict[str, Any] = {
        "total_records": sum(len(v) for v in groups.values()),
        "groups": groups,
        "stats": stats,
        "oversized_groups": oversized,
    }
    return result

