from typing import List, Dict, Any, Tuple

def process_data(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate(row: Dict[str, Any]) -> bool:
        required = {'id', 'value', 'category'}
        if not isinstance(row, dict):
            return False
        if not required.issubset(row.keys()):
            return False
        if not isinstance(row['id'], int):
            return False
        if not isinstance(row['value'], (int, float)):
            return False
        if not isinstance(row['category'], str):
            return False
        return True

    def _transform(row: Dict[str, Any]) -> Tuple[int, float, str]:
        id_ = row['id']
        value = float(row['value'])
        category = row['category'].strip().lower()
        return id_, value, category

    def _aggregate(acc: Dict[str, Any], transformed: Tuple[int, float, str]) -> Dict[str, Any]:
        id_, value, category = transformed
        acc['total'] += value
        acc['count'] += 1
        if category not in acc['by_category']:
            acc['by_category'][category] = {'sum': 0.0, 'count': 0}
        acc['by_category'][category]['sum'] += value
        acc['by_category'][category]['count'] += 1
        if id_ not in acc['ids']:
            acc['ids'].add(id_)
        return acc

    accumulator: Dict[str, Any] = {
        'total': 0.0,
        'count': 0,
        'by_category': {},
        'ids': set(),
    }

    errors: List[str] = []

    for idx, row in enumerate(records):
        if not _validate(row):
            errors.append(f'row {idx} invalid: {row}')
            continue
        try:
            transformed = _transform(row)
            accumulator = _aggregate(accumulator, transformed)
        except Exception as e:
            errors.append(f'row {idx} processing error: {e}')

    # Post-processing
    for cat, stats in accumulator['by_category'].items():
        avg = stats['sum'] / stats['count'] if stats['count'] else 0.0
        stats['average'] = avg

    result = {
        'summary': {
            'total_value': accumulator['total'],
            'record_count': accumulator['count'],
            'unique_ids': len(accumulator['ids']),
            'categories': len(accumulator['by_category']),
        },
        'details': accumulator['by_category'],
        'errors': errors,
    }

    return result

