import json
from typing import Any, Dict, List, Optional


def process_dataset(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    numeric_fields: List[str],
    max_records: Optional[int] = None,
) -> Dict[str, Any]:
    # Validate input types
    if not isinstance(records, list):
        raise TypeError("records must be a list")
    if not isinstance(required_fields, list):
        raise TypeError("required_fields must be a list")
    if not isinstance(numeric_fields, list):
        raise TypeError("numeric_fields must be a list")
    if max_records is not None and not isinstance(max_records, int):
        raise TypeError("max_records must be an int or None")

    # Helper to validate a single record
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        for field in required_fields:
            if field not in rec:
                return False
        for field in numeric_fields:
            val = rec.get(field)
            if val is not None and not isinstance(val, (int, float)):
                return False
        return True

    # Helper to compute numeric aggregates
    def _aggregate_numeric(recs: List[Dict[str, Any]]) -> Dict[str, Dict[str, float]]:
        agg: Dict[str, Dict[str, float]] = {}
        for field in numeric_fields:
            values = [rec[field] for rec in recs if field in rec and isinstance(rec[field], (int, float))]
            if values:
                agg[field] = {
                    "count": len(values),
                    "sum": sum(values),
                    "min": min(values),
                    "max": max(values),
                    "avg": sum(values) / len(values),
                }
            else:
                agg[field] = {
                    "count": 0,
                    "sum": 0.0,
                    "min": None,
                    "max": None,
                    "avg": None,
                }
        return agg

    # Main processing
    processed: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for idx, rec in enumerate(records):
        if max_records is not None and idx >= max_records:
            break
        if _validate_record(rec):
            processed.append(rec)
        else:
            errors.append({"index": idx, "record": rec})

    # Compute statistics
    stats = {
        "total_records": len(records),
        "processed_records": len(processed),
        "error_records": len(errors),
        "numeric_stats": _aggregate_numeric(processed),
    }

    # Optional: convert to JSON string if requested
    def _to_json(data: Any) -> str:
        try:
            return json.dumps(data, indent=2, sort_keys=True)
        except Exception as e:
            return f"Error serializing to JSON: {e}"

    result = {
        "summary": stats,
        "errors": errors,
        "processed_json": _to_json(processed),
    }

    return result

