from typing import List, Dict, Any, Optional

def process_transactions(
    transactions: List[Dict[str, Any]],
    *,
    min_amount: float = 0.0,
    max_amount: Optional[float] = None,
    currency: str = "USD",
) -> Dict[str, Any]:
    # Helper to normalize currency codes
    def _normalize_currency(code: str) -> str:
        if not isinstance(code, str):
            return "USD"
        return code.strip().upper()

    # Helper to validate a single transaction
    def _validate(tx: Dict[str, Any]) -> bool:
        if not isinstance(tx, dict):
            return False
        required_keys = {"id", "amount", "currency", "timestamp"}
        if not required_keys.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], (int, str)):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if not isinstance(tx["currency"], str):
            return False
        if not isinstance(tx["timestamp"], str):
            return False
        return True

    # Helper to filter by amount range
    def _in_range(amount: float) -> bool:
        if amount < min_amount:
            return False
        if max_amount is not None and amount > max_amount:
            return False
        return True

    # Helper to convert timestamp to epoch
    def _parse_timestamp(ts: str) -> int:
        try:
            import datetime
            dt = datetime.datetime.fromisoformat(ts)
            return int(dt.timestamp())
        except Exception:
            return 0

    # Process each transaction
    processed: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    totals: Dict[str, float] = {}
    count_by_currency: Dict[str, int] = {}

    for tx in transactions:
        if not _validate(tx):
            errors.append({"transaction": tx, "error": "invalid format"})
            continue
        amt = float(tx["amount"])
        cur = _normalize_currency(tx["currency"])
        if not _in_range(amt):
            errors.append({"transaction": tx, "error": "amount out of range"})
            continue
        epoch = _parse_timestamp(tx["timestamp"])
        if epoch == 0:
            errors.append({"transaction": tx, "error": "invalid timestamp"})
            continue
        processed_tx = {
            "id": tx["id"],
            "amount": amt,
            "currency": cur,
            "timestamp_epoch": epoch,
        }
        processed.append(processed_tx)
        totals[cur] = totals.get(cur, 0.0) + amt
        count_by_currency[cur] = count_by_currency.get(cur, 0) + 1

    # Compute overall summary
    summary: Dict[str, Any] = {
        "total_transactions": len(processed),
        "total_errors": len(errors),
        "totals_by_currency": totals,
        "count_by_currency": count_by_currency,
    }

    # Optional: serialize processed list to JSON string
    def _to_json(data: List[Dict[str, Any]]) -> str:
        try:
            return json.dumps(data, separators=(",", ":"))
        except Exception:
            return "[]"

    result: Dict[str, Any] = {
        "processed": processed,
        "errors": errors,
        "summary": summary,
        "processed_json": _to_json(processed),
    }

    return result

