from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_dataset(
    data: Iterable[Dict[str, Any]],
    required_fields: List[str],
    max_entries: Optional[int] = None,
    transform: Optional[Any] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _validate_row(row: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in row or row[field] is None:
                return False
        return True

    def _apply_transform(row: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return row
        try:
            return transform(row)
        except Exception:
            return row

    processed: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []
    stats: Dict[str, Any] = {
        "total": 0,
        "valid": 0,
        "invalid": 0,
        "transformed": 0,
    }

    for idx, entry in enumerate(data):
        stats["total"] += 1
        if not isinstance(entry, dict):
            errors.append((idx, "not a dict"))
            stats["invalid"] += 1
            continue
        if not _validate_row(entry):
            errors.append((idx, "missing required fields"))
            stats["invalid"] += 1
            continue
        new_entry = _apply_transform(entry)
        processed.append(new_entry)
        stats["valid"] += 1
        if new_entry is not entry:
            stats["transformed"] += 1
        if max_entries is not None and len(processed) >= max_entries:
            break

    stats["remaining"] = max_entries - len(processed) if max_entries is not None else None
    return processed, stats

