from typing import Any, Dict, List, Optional, Tuple


def process_dataset(
    data: List[Dict[str, Any]],
    required_fields: Optional[List[str]] = None,
    numeric_fields: Optional[List[str]] = None,
    max_rows: Optional[int] = None,
) -> Dict[str, Any]:
    if required_fields is None:
        required_fields = []
    if numeric_fields is None:
        numeric_fields = []

    def _is_valid_row(row: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in row or row[field] is None:
                return False
        return True

    def _extract_numeric(row: Dict[str, Any]) -> Dict[str, float]:
        nums: Dict[str, float] = {}
        for field in numeric_fields:
            val = row.get(field)
            try:
                nums[field] = float(val)
            except (TypeError, ValueError):
                nums[field] = 0.0
        return nums

    def _aggregate(rows: List[Dict[str, Any]]) -> Tuple[Dict[str, float], int]:
        sums: Dict[str, float] = {f: 0.0 for f in numeric_fields}
        count = 0
        for r in rows:
            nums = _extract_numeric(r)
            for f, v in nums.items():
                sums[f] += v
            count += 1
        return sums, count

    def _compute_stats(sums: Dict[str, float], count: int) -> Dict[str, float]:
        stats: Dict[str, float] = {}
        for f, total in sums.items():
            stats[f] = total / count if count else 0.0
        return stats

    def _filter_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for r in rows:
            if _is_valid_row(r):
                filtered.append(r)
        return filtered

    def _limit_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        if max_rows is not None and len(rows) > max_rows:
            return rows[:max_rows]
        return rows

    if not isinstance(data, list):
        raise TypeError("data must be a list of dicts")

    cleaned = _filter_rows(data)
    limited = _limit_rows(cleaned)

    sums, count = _aggregate(limited)
    stats = _compute_stats(sums, count)

    result: Dict[str, Any] = {
        "total_rows": len(data),
        "valid_rows": len(cleaned),
        "processed_rows": len(limited),
        "numeric_fields": numeric_fields,
        "sum": sums,
        "count": count,
        "average": stats,
    }

    if required_fields:
        missing = []
        for r in data:
            for f in required_fields:
                if f not in r:
                    missing.append(f)
        result["missing_fields"] = list(set(missing))

    return result

