import datetime
from typing import List, Dict, Any, Optional

def process_transactions(
    records: List[Dict[str, Any]],
    start_date: Optional[datetime.date] = None,
    end_date: Optional[datetime.date] = None,
    min_amount: Optional[float] = None,
    max_amount: Optional[float] = None,
) -> Dict[str, Any]:
    def _parse_date(d):
        if isinstance(d, datetime.date):
            return d
        if isinstance(d, str):
            try:
                return datetime.datetime.strptime(d, "%Y-%m-%d").date()
            except Exception:
                return None
        return None

    def _validate_record(rec):
        if not isinstance(rec, dict):
            return False
        required = ["id", "date", "amount", "type"]
        for k in required:
            if k not in rec:
                return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if rec["type"] not in ("debit", "credit"):
            return False
        if not _parse_date(rec["date"]):
            return False
        return True

    def _within_date_range(d):
        if start_date and d < start_date:
            return False
        if end_date and d > end_date:
            return False
        return True

    def _within_amount_range(a):
        if min_amount is not None and a < min_amount:
            return False
        if max_amount is not None and a > max_amount:
            return False
        return True

    filtered: List[Dict[str, Any]] = []
    for rec in records:
        if not _validate_record(rec):
            continue
        rec_date = _parse_date(rec["date"])
        if not _within_date_range(rec_date):
            continue
        if not _within_amount_range(rec["amount"]):
            continue
        filtered.append(rec)

    totals = {"debit": 0.0, "credit": 0.0}
    daily: Dict[datetime.date, Dict[str, float]] = {}
    for rec in filtered:
        amt = float(rec["amount"])
        totals[rec["type"]] += amt
        d = _parse_date(rec["date"])
        if d not in daily:
            daily[d] = {"debit": 0.0, "credit": 0.0}
        daily[d][rec["type"]] += amt

    def _format_daily(d):
        return {
            "date": d.isoformat(),
            "debit": round(daily[d]["debit"], 2),
            "credit": round(daily[d]["credit"], 2),
            "balance": round(daily[d]["credit"] - daily[d]["debit"], 2),
        }

    daily_report = [_format_daily(d) for d in sorted(daily)]

    overall_balance = round(totals["credit"] - totals["debit"], 2)

    return {
        "total_records": len(records),
        "filtered_records": len(filtered),
        "totals": totals,
        "overall_balance": overall_balance,
        "daily_report": daily_report,
