def process_data(records: list) -> dict:
    def _validate(record: dict) -> bool:
        required = {"id", "value", "tags"}
        if not isinstance(record, dict):
            return False
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["id"], int):
            return False
        if not isinstance(record["value"], (int, float)):
            return False
        if not isinstance(record["tags"], list):
            return False
        return True

    def _transform(record: dict) -> dict:
        new = {}
        new["identifier"] = record["id"]
        new["score"] = float(record["value"])
        new["labels"] = [t.strip().lower() for t in record["tags"] if isinstance(t, str)]
        new["metadata"] = {"original": record}
        return new

    def _aggregate(transformed: list) -> dict:
        agg = {"total_score": 0.0, "tag_counts": {}, "by_id": {}}
        scores = []
        for rec in transformed:
            agg["total_score"] += rec["score"]
            scores.append(rec["score"])
            for tag in rec["labels"]:
                agg["tag_counts"][tag] = agg["tag_counts"].get(tag, 0) + 1
            agg["by_id"][rec["identifier"]] = rec
        agg["average_score"] = agg["total_score"] / len(transformed) if transformed else 0.0
        agg["median_score"] = _median(scores)
        agg["top_tags"] = _top_tags(agg["tag_counts"], 5)
        return agg

    def _median(scores: list) -> float:
        n = len(scores)
        if n == 0:
            return 0.0
        sorted_scores = sorted(scores)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_scores[mid - 1] + sorted_scores[mid]) / 2.0
        return sorted_scores[mid]

    def _top_tags(tag_counts: dict, n: int = 5) -> list:
        return sorted(tag_counts.items(), key=lambda kv: kv[1], reverse=True)[:n]

    valid_records = []
    errors = []

    for idx, rec in enumerate(records):
        if _validate(rec):
            valid_records.append(rec)
        else:
            errors.append({"index": idx, "record": rec})

    transformed = [_transform(r) for r in valid_records]

    aggregation = _aggregate(transformed)

    result = {
        "count_valid": len(valid_records),
        "count_invalid": len(errors),
        "errors": errors,
        "aggregation": aggregation,
        "transformed": transformed,
    }

    return result

