def process_user_data(users: List[Dict[str, Any]], *, min_age: int = 18, include_inactive: bool = False) -> Dict[str, Any]:
    from collections import defaultdict
    import datetime

    def _validate(user: Dict[str, Any]) -> bool:
        if not isinstance(user, dict):
            return False
        required = {"id", "name", "age", "country", "active", "signup_date"}
        if not required.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int):
            return False
        if not isinstance(user["name"], str):
            return False
        if not isinstance(user["age"], int) or user["age"] < 0:
            return False
        if not isinstance(user["country"], str):
            return False
        if not isinstance(user["active"], bool):
            return False
        try:
            datetime.datetime.strptime(user["signup_date"], "%Y-%m-%d")
        except Exception:
            return False
        return True

    def _compute_score(user: Dict[str, Any]) -> float:
        base = user["age"] * 0.5
        if user["active"]:
            base += 10
        days_since_signup = (datetime.datetime.now() - datetime.datetime.strptime(user["signup_date"], "%Y-%m-%d")).days
        base += max(0, 30 - days_since_signup) * 0.2
        return base

    def _group_by_country(valid_users: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = defaultdict(list)
        for u in valid_users:
            groups[u["country"]].append(u)
        return groups

    filtered_users: List[Dict[str, Any]] = []
    for u in users:
        if not _validate(u):
            continue
        if u["age"] < min_age:
            continue
        if not include_inactive and not u["active"]:
            continue
        filtered_users.append(u)

    scored_users = []
    for u in filtered_users:
        score = _compute_score(u)
        u_copy = dict(u)
        u_copy["score"] = score
        scored_users.append(u_copy)

    grouped = _group_by_country(scored_users)

    country_stats: Dict[str, Dict[str, Any]] = {}
    for country, users_list in grouped.items():
        total_score = sum(u["score"] for u in users_list)
        avg_score = total_score / len(users_list) if users_list else 0
        country_stats[country] = {
            "user_count": len(users_list),
            "average_score": avg_score,
            "top_user": max(users_list, key=lambda x: x["score"]) if users_list else None,
        }

    overall = {
        "total_users": len(filtered_users),
        "countries": country_stats,
        "top_overall_user": max(scored_users, key=lambda x: x["score"]) if scored_users else None,
    }

    return overall

