def analyze_sales(
    records: List[Dict[str, Any]],
    min_quantity: int = 1,
    region_filter: Optional[List[str]] = None,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = {"order_id", "region", "product", "quantity", "price"}
        if not isinstance(rec, dict):
            return False
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["order_id"], (int, str)):
            return False
        if not isinstance(rec["region"], str):
            return False
        if not isinstance(rec["product"], str):
            return False
        if not isinstance(rec["quantity"], int) or rec["quantity"] < 0:
            return False
        if not isinstance(rec["price"], (int, float)) or rec["price"] < 0:
            return False
        return True

    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        return {
            "order_id": str(rec["order_id"]).strip(),
            "region": rec["region"].strip().title(),
            "product": rec["product"].strip().title(),
            "quantity": int(rec["quantity"]),
            "price": float(rec["price"]),
        }

    def _group_by_region(recs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in recs:
            reg = r["region"]
            groups.setdefault(reg, []).append(r)
        return groups

    def _aggregate_group(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total_qty = 0
        total_rev = 0.0
        product_counts: Dict[str, int] = {}
        for r in group:
            qty = r["quantity"]
            rev = r["quantity"] * r["price"]
            total_qty += qty
            total_rev += rev
            prod = r["product"]
            product_counts[prod] = product_counts.get(prod, 0) + qty
        top_product = None
        if product_counts:
            top_product = max(product_counts.items(), key=lambda kv: kv[1])[0]
        return {
            "total_quantity": total_qty,
            "total_revenue": round(total_rev, 2),
            "top_product": top_product,
            "product_breakdown": product_counts,
        }

    def _apply_filters(recs: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for r in recs:
            if r["quantity"] < min_quantity:
                continue
            if region_filter and r["region"] not in region_filter:
                continue
            filtered.append(r)
        return filtered

    valid_records: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []
    for idx, rec in enumerate(records):
        if _validate_record(rec):
            valid_records.append(_normalize(rec))
        else:
            errors.append((idx, "invalid record"))

    filtered_records = _apply_filters(valid_records)
    grouped = _group_by_region(filtered_records)
    summary: Dict[str, Any] = {}
    for reg, group in grouped.items():
        summary[reg] = _aggregate_group(group)

    overall = {
        "total_orders": len(filtered_records),
        "regions": list(grouped.keys()),
        "summary_by_region": summary,
        "errors": errors,
    }
    return overall

