import datetime
from typing import List, Dict, Any, Optional


def process_transactions(transactions: List[Dict[str, Any]], *, threshold: float = 0.0, date_format: str = '%Y-%m-%d') -> Dict[str, Any]:
    def _parse_date(d: Any) -> Optional[datetime.date]:
        if isinstance(d, datetime.date):
            return d
        if isinstance(d, str):
            try:
                return datetime.datetime.strptime(d, date_format).date()
            except Exception:
                return None
        return None

    def _validate(tx: Dict[str, Any]) -> bool:
        required = {'id', 'amount', 'date', 'currency'}
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx['id'], (int, str)):
            return False
        if not isinstance(tx['amount'], (int, float)):
            return False
        if _parse_date(tx['date']) is None:
            return False
        if not isinstance(tx['currency'], str) or len(tx['currency']) != 3:
            return False
        return True

    def _normalize(tx: Dict[str, Any]) -> Dict[str, Any]:
        norm = dict(tx)
        norm['id'] = str(tx['id'])
        norm['amount'] = float(tx['amount'])
        norm['date'] = _parse_date(tx['date'])
        norm['currency'] = tx['currency'].upper()
        return norm

    processed: List[Dict[str, Any]] = []
    totals: Dict[str, float] = {}
    errors: List[Dict[str, Any]] = []

    for idx, raw in enumerate(transactions):
        if not isinstance(raw, dict):
            errors.append({'index': idx, 'reason': 'not a dict'})
            continue
        if not _validate(raw):
            errors.append({'index': idx, 'reason': 'validation failed', 'data': raw})
            continue
        norm = _normalize(raw)
        processed.append(norm)
        amt = norm['amount']
        cur = norm['currency']
        totals[cur] = totals.get(cur, 0.0) + amt

    filtered = [t for t in processed if t['amount'] >= threshold]

    by_date: Dict[datetime.date, List[Dict[str, Any]]] = {}
    for t in filtered:
        d = t['date']
        if d not in by_date:
            by_date[d] = []
        by_date[d].append(t)

    daily_summary: List[Dict[str, Any]] = []
    for d, txs in sorted(by_date.items()):
        day_total = sum(tx['amount'] for tx in txs)
        day_counts = len(txs)
        daily_summary.append({'date': d.isoformat(), 'count': day_counts, 'total': day_total})

    result = {
        'total_transactions': len(transactions),
        'processed': len(processed),
        'filtered': len(filtered),
        'errors': errors,
        'currency_totals': totals,
        'daily_summary': daily_summary,
    }
    return result

