import json
from typing import Any, Dict, List, Tuple, Optional

def process_data(
    data: List[Dict[str, Any]],
    threshold: float = 0.5,
    *,
    verbose: bool = False
) -> Dict[str, Any]:
    def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        required = {"id", "value", "tags"}
        if not required.issubset(item.keys()):
            return False
        if not isinstance(item["id"], int):
            return False
        if not isinstance(item["value"], (int, float)):
            return False
        if not isinstance(item["tags"], list):
            return False
        return True

    def _compute_score(item: Dict[str, Any]) -> float:
        base = float(item["value"])
        tag_bonus = sum(1.0 for tag in item["tags"] if isinstance(tag, str))
        return base + tag_bonus

    def _aggregate(scores: List[float]) -> Tuple[float, float]:
        if not scores:
            return (0.0, 0.0)
        total = sum(scores)
        avg = total / len(scores)
        return (total, avg)

    valid_items: List[Dict[str, Any]] = []
    scores: List[float] = []
    for idx, entry in enumerate(data):
        if verbose:
            print(f"Processing entry {idx}: {entry.get('id', 'unknown')}")
        if not _validate(entry):
            if verbose:
                print(f"Invalid entry at index {idx}, skipping.")
            continue
        score = _compute_score(entry)
        if score < threshold:
            if verbose:
                print(f"Score {score} below threshold {threshold}, skipping.")
            continue
        valid_items.append(entry)
        scores.append(score)

    total_score, avg_score = _aggregate(scores)

    result: Dict[str, Any] = {
        "total_items": len(data),
        "valid_items": len(valid_items),
        "invalid_items": len(data) - len(valid_items),
        "total_score": total_score,
        "average_score": avg_score,
        "threshold": threshold,
        "details": [
            {"id": item["id"], "score": _compute_score(item)} for item in valid_items
        ],
    }

    if verbose:
        print("Processing complete.")
        print(json.dumps(result, indent=2))

    return result

