from typing import Any, Dict, List, Tuple, Optional


def process_user_records(records: List[Dict[str, Any]], required_fields: List[str]) -> Dict[str, Any]:
    def _normalize_email(email: str) -> str:
        return email.strip().lower()

    def _validate_record(rec: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors: List[str] = []
        for field in required_fields:
            if field not in rec or rec[field] is None:
                errors.append(f"missing {field}")
        if "email" in rec and rec["email"]:
            if not re.match(r"^[^@\s]+@[^@\s]+\.[^@\s]+$", rec["email"]):
                errors.append("invalid email format")
        return (len(errors) == 0, errors)

    def _compute_age_group(age: Optional[int]) -> str:
        if age is None:
            return "unknown"
        if age < 18:
            return "<18"
        if 18 <= age < 25:
            return "18-24"
        if 25 <= age < 35:
            return "25-34"
        if 35 <= age < 50:
            return "35-49"
        return ">=50"

    def _aggregate_by_country(recs: List[Dict[str, Any]]) -> Dict[str, int]:
        agg: Dict[str, int] = {}
        for r in recs:
            country = r.get("country", "Unknown")
            agg[country] = agg.get(country, 0) + 1
        return agg

    def _aggregate_by_age_group(recs: List[Dict[str, Any]]) -> Dict[str, int]:
        agg: Dict[str, int] = {}
        for r in recs:
            age = r.get("age")
            group = _compute_age_group(age)
            agg[group] = agg.get(group, 0) + 1
        return agg

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Tuple[Dict[str, Any], List[str]]] = []

    for rec in records:
        is_valid, errs = _validate_record(rec)
        if is_valid:
            rec["email"] = _normalize_email(rec.get("email", ""))
            valid_records.append(rec)
        else:
            invalid_records.append((rec, errs))

    country_counts = _aggregate_by_country(valid_records)
    age_group_counts = _aggregate_by_age_group(valid_records)

    summary = {
        "total": len(records),
        "valid": len(valid_records),
        "invalid": len(invalid_records),
        "countries": country_counts,
        "age_groups": age_group_counts,
    }

    return {
        "summary": summary,
        "valid_records": valid_records,
        "invalid_records": invalid_records,
    }

