import datetime
from typing import Any, Dict, Iterable, List, Optional


def analyze_transactions(
    transactions: List[Dict[str, Any]],
    threshold: float = 0.0,
    max_entries: Optional[int] = None,
) -> Dict[str, Any]:
    def _validate(tx: Dict[str, Any]) -> bool:
        if not isinstance(tx, dict):
            return False
        required = {"id", "amount", "date", "category"}
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if tx["amount"] < threshold:
            return False
        try:
            datetime.datetime.fromisoformat(tx["date"])
        except Exception:
            return False
        if not isinstance(tx["category"], str):
            return False
        return True

    def _categorize(tx: Dict[str, Any]) -> str:
        return tx["category"].strip().lower()

    def _aggregate_by_category(
        agg: Dict[str, Dict[str, Any]], tx: Dict[str, Any]
    ) -> None:
        cat = _categorize(tx)
        if cat not in agg:
            agg[cat] = {
                "count": 0,
                "total": 0.0,
                "ids": [],
                "max_amount": tx["amount"],
                "min_amount": tx["amount"],
            }
        entry = agg[cat]
        entry["count"] += 1
        entry["total"] += tx["amount"]
        entry["ids"].append(tx["id"])
        if tx["amount"] > entry["max_amount"]:
            entry["max_amount"] = tx["amount"]
        if tx["amount"] < entry["min_amount"]:
            entry["min_amount"] = tx["amount"]

    def _compute_summary(agg: Dict[str, Dict[str, Any]]) -> List[Dict[str, Any]]:
        summary: List[Dict[str, Any]] = []
        for cat, data in agg.items():
            avg = data["total"] / data["count"] if data["count"] else 0.0
            summary.append(
                {
                    "category": cat,
                    "count": data["count"],
                    "total": data["total"],
                    "average": avg,
                    "max": data["max_amount"],
                    "min": data["min_amount"],
                }
            )
        summary.sort(key=lambda x: x["total"], reverse=True)
        return summary

    validated: List[Dict[str, Any]] = []
    errors: List[str] = []
    for tx in transactions:
        if _validate(tx):
            validated.append(tx)
        else:
            errors.append(f"Invalid transaction: {tx.get('id', 'unknown')}")

    if max_entries is not None:
        validated = validated[:max_entries]

    agg: Dict[str, Dict[str, Any]] = {}
    for tx in validated:
        _aggregate_by_category(agg, tx)

    summary = _compute_summary(agg)

    result: Dict[str, Any] = {
        "total_transactions": len(transactions),
        "validated_transactions": len(validated),
        "invalid_transactions": len(errors),
        "categories": summary,
        "errors": errors,
    }
    return result

