import json
import re
from typing import Any, Dict, List, Tuple

def process_data(
    records: List[Dict[str, Any]],
    filter_pattern: str,
    max_depth: int,
    transform_map: Dict[str, str],
) -> Dict[str, Any]:
    # compile regex
    pattern = re.compile(filter_pattern)

    # nested helper to flatten nested dicts
    def _flatten(d: Dict[str, Any], parent_key: str = '', sep: str = '.') -> Dict[str, Any]:
        items: List[Tuple[str, Any]] = []
        for k, v in d.items():
            new_key = f'{parent_key}{sep}{k}' if parent_key else k
            if isinstance(v, dict):
                items.extend(_flatten(v, new_key, sep=sep).items())
            else:
                items.append((new_key, v))
        return dict(items)

    # nested helper to apply transform map
    def _apply_transform(flat: Dict[str, Any]) -> Dict[str, Any]:
        transformed: Dict[str, Any] = {}
        for k, v in flat.items():
            new_k = transform_map.get(k, k)
            transformed[new_k] = v
        return transformed

    # nested helper to filter keys by regex
    def _filter_keys(d: Dict[str, Any]) -> Dict[str, Any]:
        return {k: v for k, v in d.items() if pattern.search(k)}

    # nested helper to compute depth
    def _depth(d: Any, current: int = 0) -> int:
        if isinstance(d, dict):
            return max((_depth(v, current + 1) for v in d.values()), default=current)
        return current

    # main processing loop
    processed: List[Dict[str, Any]] = []
    errors: List[str] = []

    for idx, rec in enumerate(records):
        try:
            if not isinstance(rec, dict):
                raise ValueError('record not a dict')
            # flatten
            flat = _flatten(rec)
            # transform keys
            flat = _apply_transform(flat)
            # filter keys
            flat = _filter_keys(flat)
            # check depth
            depth = _depth(rec)
            if depth > max_depth:
                flat['depth_exceeded'] = True
            # add metadata
            flat['_original_index'] = idx
            processed.append(flat)
        except Exception as e:
            errors.append(f'index {idx}: {e}')

    # aggregate results
    summary = {
        'total_records': len(records),
        'processed': len(processed),
        'errors': len(errors),
        'max_depth': max_depth,
        'filter_pattern': filter_pattern,
    }

    # convert to JSON string for output
    output = {
        'summary': summary,
        'data': processed,
        'errors': errors,
    }

    return output

