def process_transactions(
    transactions: List[Dict[str, Any]],
    threshold: float = 0.0,
    top_n: int = 5,
) -> Dict[str, Any]:
    # Validate transaction fields
    def _validate(tx: Dict[str, Any]) -> None:
        required = ["id", "type", "amount", "timestamp"]
        for field in required:
            if field not in tx:
                raise ValueError(f"Missing field {field!r} in transaction {tx.get('id')}")
        if not isinstance(tx["amount"], (int, float)):
            raise TypeError(f"Amount must be numeric in transaction {tx.get('id')}")
        if not isinstance(tx["timestamp"], str):
            raise TypeError(f"Timestamp must be string in transaction {tx.get('id')}")
    # Categorize transaction
    def _categorize(tx: Dict[str, Any]) -> str:
        ttype = tx["type"]
        if ttype in ("purchase", "refund"):
            return "sales"
        if ttype in ("withdrawal", "deposit"):
            return "cash"
        return "other"
    # Aggregate totals
    def _aggregate(acc: Dict[str, Dict[str, Any]], tx: Dict[str, Any]) -> None:
        cat = _categorize(tx)
        amt = float(tx["amount"])
        if cat not in acc:
            acc[cat] = {"count": 0, "total": 0.0}
        acc[cat]["count"] += 1
        acc[cat]["total"] += amt
    # Compute top categories by total
    def _top_categories(acc: Dict[str, Dict[str, Any]], n: int) -> List[Tuple[str, float]]:
        items = [(cat, data["total"]) for cat, data in acc.items()]
        items.sort(key=lambda x: x[1], reverse=True)
        return items[:n]
    # Main processing
    valid_txs: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    for tx in transactions:
        try:
            _validate(tx)
            valid_txs.append(tx)
        except Exception as exc:
            errors.append({"transaction": tx, "error": str(exc)})
    # Aggregate
    aggregates: Dict[str, Dict[str, Any]] = {}
    for tx in valid_txs:
        _aggregate(aggregates, tx)
    # Compute averages
    for cat, data in aggregates.items():
        count = data["count"]
        total = data["total"]
        data["average"] = total / count if count else 0.0
    # Filter by threshold
    filtered: Dict[str, Dict[str, Any]] = {
        cat: data for cat, data in aggregates.items() if data["total"] >= threshold
    }
    # Determine top categories
    top: List[Tuple[str, float]] = _top_categories(aggregates, top_n)
    # Build result
    result: Dict[str, Any] = {
        "summary": aggregates,
        "filtered": filtered,
        "top_categories": top,
        "errors": errors,
    }
    return result

