from typing import List, Dict, Any, Optional, Iterable

def process_data(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_fields: List[str],
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    # Normalize key
    def _norm_key(val: Any) -> str:
        if val is None:
            return ""
        return str(val).strip().lower()

    # Validate record
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec:
            return False
        for vf in value_fields:
            if vf not in rec:
                return False
        return True

    # Aggregate values
    agg: Dict[str, List[float]] = {}
    for rec in records:
        if not _validate(rec):
            continue
        k = _norm_key(rec[key_field])
        if k not in agg:
            agg[k] = []
        for vf in value_fields:
            val = rec.get(vf)
            try:
                num = float(val)
            except (TypeError, ValueError):
                continue
            agg[k].append(num)

    # Compute statistics
    stats: Dict[str, Dict[str, float]] = {}
    for k, nums in agg.items():
        if not nums:
            continue
        total = sum(nums)
        count = len(nums)
        avg = total / count
        min_val = min(nums)
        max_val = max(nums)
        stats[k] = {
            "count": count,
            "sum": total,
            "avg": avg,
            "min": min_val,
            "max": max_val,
        }

    # Filter by threshold
    if threshold is not None:
        filtered = {k: v for k, v in stats.items() if v["avg"] >= threshold}
    else:
        filtered = stats

    # Prepare output
    output: Dict[str, Any] = {
        "total_keys": len(agg),
        "filtered_keys": len(filtered),
        "details": filtered,
    }

    # Optional: generate summary string
    def _summary() -> str:
        lines = []
        lines.append(f"Processed {len(agg)} unique keys.")
        lines.append(f"Filtered to {len(filtered)} keys with avg >= {threshold if threshold is not None else 'N/A'}.")
        for k, v in filtered.items():
            lines.append(f"Key: {k} | Count: {v['count']} | Avg: {v['avg']:.2f} | Min: {v['min']} | Max: {v['max']}")
        return "\\n".join(lines)

    output["summary"] = _summary()
    return output

