def process_data_pipeline(
    data: List[Dict[str, Any]],
    config: Dict[str, Any],
) -> Dict[str, Any]:
    # inner functions
    def _validate_item(item: Dict[str, Any]) -> bool:
        required = config.get('required_fields', [])
        for field in required:
            if field not in item:
                return False
        return True

    def _transform_item(item: Dict[str, Any]) -> Dict[str, Any]:
        transformed = {}
        for key, value in item.items():
            if isinstance(value, str):
                transformed[key] = value.strip()
            else:
                transformed[key] = value
        return transformed

    def _aggregate(items: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg = {}
        for item in items:
            for k, v in item.items():
                if isinstance(v, (int, float)):
                    agg[k] = agg.get(k, 0) + v
                else:
                    agg.setdefault(k, set()).add(v)
        for k, v in agg.items():
            if isinstance(v, set):
                agg[k] = list(v)
        return agg

    def _report(agg: Dict[str, Any]) -> str:
        lines = ['Aggregation Report:']
        for k, v in sorted(agg.items()):
            lines.append(f'  {k}: {v}')
        return '\\n'.join(lines)

    validated = []
    for item in data:
        if _validate_item(item):
            validated.append(_transform_item(item))
        else:
            # skip invalid
            pass

    aggregated = _aggregate(validated)
    report = _report(aggregated)

    result = {
        'count_valid': len(validated),
        'count_invalid': len(data) - len(validated),
        'aggregation': aggregated,
        'report': report,
        'config_used': config,
    }
    return result

