import typing
from typing import Any, Callable, Dict, Iterable, List, Optional

def process_records(
    records: List[Dict[str, Any]],
    filter_key: str,
    filter_value: Any,
    group_by: str,
    transform_func: Optional[Callable[[Dict[str, Any]], Dict[str, Any]]] = None,
) -> Dict[str, Any]:
    # Validate inputs
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if filter_key not in rec:
            return False
        return True

    # Apply optional transformation
    def _apply_transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func is None:
            return rec
        try:
            return transform_func(rec)
        except Exception:
            return rec

    # Aggregate results
    def _aggregate(grouped: Dict[Any, List[Dict[str, Any]]]) -> List[Dict[str, Any]]:
        result = []
        for key, recs in grouped.items():
            agg = {\"group\": key, \"count\": len(recs), \"records\": recs}
            result.append(agg)
        return result

    # Main processing
    filtered: List[Dict[str, Any]] = []
    for rec in records:
        if not _validate_record(rec):
            continue
        if rec.get(filter_key) != filter_value:
            continue
        transformed = _apply_transform(rec)
        filtered.append(transformed)

    # Group by
    grouped: Dict[Any, List[Dict[str, Any]]] = {}
    for rec in filtered:
        key = rec.get(group_by)
        if key is None:
            continue
        if key not in grouped:
            grouped[key] = []
        grouped[key].append(rec)

    # Aggregate
    aggregated = _aggregate(grouped)

    # Sort aggregated by count descending
    aggregated.sort(key=lambda x: x[\"count\"], reverse=True)

    # Build summary
    summary = {
        \"total_records\": len(records),
        \"filtered_records\": len(filtered),
        \"groups\": len(grouped),
        \"aggregated\": aggregated,
    }

    return summary

