def process_data(records: List[Dict[str, Any]], *, min_age: Optional[int] = None, group_by: Optional[str] = None):
    def _validate_record(rec):
        if not isinstance(rec, dict):
            return False
        if 'name' not in rec or 'age' not in rec:
            return False
        if not isinstance(rec['age'], int):
            return False
        return True

    def _filter(records):
        out = []
        for rec in records:
            if not _validate_record(rec):
                continue
            if min_age is not None and rec['age'] < min_age:
                continue
            out.append(rec)
        return out

    def _median(values):
        n = len(values)
        if n == 0:
            return None
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2
        else:
            return sorted_vals[mid]

    def _aggregate(records):
        result = {}
        for rec in records:
            key = rec.get(group_by) if group_by else 'all'
            if key not in result:
                result[key] = {'count':0, 'total_age':0, 'ages':[]}
            result[key]['count'] += 1
            result[key]['total_age'] += rec['age']
            result[key]['ages'].append(rec['age'])
        for key, stats in result.items():
            stats['average_age'] = stats['total_age'] / stats['count'] if stats['count'] else 0
            stats['median_age'] = _median(stats['ages'])
            del stats['total_age']
            del stats['ages']
        return result

    filtered = _filter(records)
    aggregated = _aggregate(filtered)
    return {
        'total_records': len(records),
        'filtered_records': len(filtered),
        'aggregated': aggregated
    }

