def process_records(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        required = {"id", "value", "timestamp"}
        if not isinstance(record, dict):
            return False
        return required.issubset(record.keys())

    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        rec = dict(record)
        rec["id"] = str(rec["id"]).strip()
        rec["value"] = float(rec["value"])
        rec["timestamp"] = int(rec["timestamp"])
        return rec

    def _aggregate(acc: Dict[str, Any], rec: Dict[str, Any]) -> None:
        key = rec["id"]
        if key not in acc:
            acc[key] = {"count": 0, "sum": 0.0, "min": rec["value"], "max": rec["value"], "timestamps": []}
        entry = acc[key]
        entry["count"] += 1
        entry["sum"] += rec["value"]
        if rec["value"] < entry["min"]:
            entry["min"] = rec["value"]
        if rec["value"] > entry["max"]:
            entry["max"] = rec["value"]
        entry["timestamps"].append(rec["timestamp"])

    results: Dict[str, Any] = {}
    errors: List[str] = []
    for idx, rec in enumerate(records):
        if not _validate(rec):
            errors.append(f"record {idx} invalid: missing required fields")
            continue
        try:
            norm = _normalize(rec)
        except Exception as e:
            errors.append(f"record {idx} normalization error: {e}")
            continue
        _aggregate(results, norm)

    # compute averages
    for key, entry in results.items():
        if entry["count"] > 0:
            entry["average"] = entry["sum"] / entry["count"]
        else:
            entry["average"] = None

    # sort timestamps per key
    for entry in results.values():
        entry["timestamps"].sort()

    return {"summary": results, "errors": errors, "total_records": len(records)}

