    if not isinstance(records, list):
        raise TypeError('records must be a list')
    # nested functions
    def _validate_record(rec):
        if not isinstance(rec, dict):
            return False
        required = {'id', 'value', 'tags'}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec['id'], int):
            return False
        if not isinstance(rec['value'], (int, float)):
            return False
        if not isinstance(rec['tags'], list):
            return False
        return True

    def _normalize(rec):
        rec = dict(rec)
        rec['value'] = float(rec['value'])
        rec['tags'] = [t.strip().lower() for t in rec['tags'] if isinstance(t, str)]
        return rec

    # main loop
    valid = []
    invalid_count = 0
    for r in records:
        if _validate_record(r):
            valid.append(_normalize(r))
        else:
            invalid_count += 1

    # compute stats
    total = len(valid)
    if total == 0:
        return {'valid': 0, 'invalid': invalid_count, 'stats': {}}

    values = [r['value'] for r in valid]
    avg = sum(values) / total
    min_val = min(values)
    max_val = max(values)

    # tag frequency
    tag_counts: Dict[str, int] = {}
    for r in valid:
        for t in r['tags']:
            tag_counts[t] = tag_counts.get(t, 0) + 1

    # top tags
    top_tags = sorted(tag_counts.items(), key=lambda kv: (-kv[1], kv[0]))[:5]

    # group by id parity
    even_ids = [r for r in valid if r['id'] % 2 == 0]
    odd_ids = [r for r in valid if r['id'] % 2 == 1]

    # nested function for grouping
    def _group_by_tag(tag):
        return [r for r in valid if tag in r['tags']]

    groups = {t: _group_by_tag(t) for t, _ in top_tags}

    # final result
    result = {
        'valid': total,
        'invalid': invalid_count,
        'stats': {
            'average': avg,
            'min': min_val,
            'max': max_val,
            'tag_counts': tag_counts,
            'top_tags': [{'tag': t, 'count': c} for t, c in top_tags],
            'even_id_count': len(even_ids),
            'odd_id_count': len(odd_ids),
        },
        'groups': groups,
    }
    return result

