def process_user_activity(
    activities: List[Dict[str, Any]],
    min_actions: int = 5,
    include_inactive: bool = False,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = {"user_id", "action", "timestamp"}
        if not isinstance(rec, dict):
            return False
        return required.issubset(rec.keys())

    def _parse_timestamp(ts: Any) -> float:
        try:
            return float(ts)
        except Exception:
            return 0.0

    user_stats: Dict[str, Dict[str, Any]] = {}
    for rec in activities:
        if not _validate_record(rec):
            continue
        uid = str(rec["user_id"])
        action = str(rec["action"])
        ts = _parse_timestamp(rec["timestamp"])
        if uid not in user_stats:
            user_stats[uid] = {
                "actions": [],
                "first_ts": ts,
                "last_ts": ts,
                "action_counts": {},
            }
        user_stats[uid]["actions"].append((ts, action))
        if ts < user_stats[uid]["first_ts"]:
            user_stats[uid]["first_ts"] = ts
        if ts > user_stats[uid]["last_ts"]:
            user_stats[uid]["last_ts"] = ts
        user_stats[uid]["action_counts"][action] = user_stats[uid]["action_counts"].get(action, 0) + 1

    active_users: List[Dict[str, Any]] = []
    inactive_users: List[Dict[str, Any]] = []

    for uid, stats in user_stats.items():
        total_actions = sum(stats["action_counts"].values())
        if total_actions < min_actions:
            if include_inactive:
                inactive_users.append({
                    "user_id": uid,
                    "total_actions": total_actions,
                    "first_ts": stats["first_ts"],
                    "last_ts": stats["last_ts"],
                })
            continue
        active_users.append({
            "user_id": uid,
            "total_actions": total_actions,
            "first_ts": stats["first_ts"],
            "last_ts": stats["last_ts"],
            "most_common_action": max(stats["action_counts"].items(), key=lambda kv: kv[1])[0],
            "action_distribution": stats["action_counts"],
        })

    def _sort_by_last(ts_list: List[Tuple[float, str]]) -> List[str]:
        return [act for _, act in sorted(ts_list, key=lambda kv: kv[0])]

    for user in active_users:
        uid = user["user_id"]
        user["action_sequence"] = _sort_by_last(user_stats[uid]["actions"])

    result = {
        "active_users": active_users,
        "inactive_users": inactive_users,
        "summary": {
            "total_users": len(user_stats),
            "active_count": len(active_users),
            "inactive_count": len(inactive_users),
        },
    }
    return result

