import datetime
from typing import List, Dict, Any, Optional

def process_transactions(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    # nested functions
    def validate(record: Dict[str, Any]) -> bool:
        required = {"id", "amount", "timestamp", "type"}
        if not isinstance(record, dict):
            return False
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["id"], int):
            return False
        if not isinstance(record["amount"], (int, float)):
            return False
        try:
            datetime.datetime.fromisoformat(record["timestamp"])
        except Exception:
            return False
        if record["type"] not in {"debit", "credit"}:
            return False
        return True

    def parse_timestamp(ts: str) -> datetime.datetime:
        return datetime.datetime.fromisoformat(ts)

    def categorize(amount: float) -> str:
        if amount > 1000:
            return "high"
        if amount > 100:
            return "medium"
        return "low"

    def compute_balance(trans: List[Dict[str, Any]]) -> float:
        bal = 0.0
        for t in trans:
            amt = float(t["amount"])
            if t["type"] == "credit":
                bal += amt
            else:
                bal -= amt
        return bal

    # Main processing
    valid_records: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for rec in records:
        if validate(rec):
            rec_copy = dict(rec)
            rec_copy["parsed_ts"] = parse_timestamp(rec_copy["timestamp"])
            rec_copy["category"] = categorize(rec_copy["amount"])
            valid_records.append(rec_copy)
        else:
            errors.append({"record": rec, "error": "validation_failed"})

    # sort by timestamp
    valid_records.sort(key=lambda r: r["parsed_ts"])

    # group by day
    daily: Dict[str, List[Dict[str, Any]]] = {}
    for rec in valid_records:
        day = rec["parsed_ts"].date().isoformat()
        daily.setdefault(day, []).append(rec)

    # compute daily summaries
    summaries: List[Dict[str, Any]] = []
    for day, trans in daily.items():
        total = sum(float(t["amount"]) for t in trans)
        count = len(trans)
        bal = compute_balance(trans)
        summaries.append({
            "date": day,
            "total_amount": total,
            "transaction_count": count,
            "balance": bal,
            "high_category_count": sum(1 for t in trans if t["category"] == "high"),
            "medium_category_count": sum(1 for t in trans if t["category"] == "medium"),
            "low_category_count": sum(1 for t in trans if t["category"] == "low"),
        })

    result = {
        "summary": summaries,
        "errors": errors,
        "total_transactions": len(records),
        "valid_transactions": len(valid_records),
    }

    return result

