    def _normalize(rec: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        if not isinstance(rec, dict):
            return None
        key = rec.get(key_field)
        val = rec.get(value_field)
        if key is None or val is None:
            return None
        if not isinstance(key, str):
            key = str(key)
        if not isinstance(val, (int, float)):
            try:
                val = float(val)
            except Exception:
                return None
        return {key_field: key.strip(), value_field: val}

    # Helper: aggregate values per key
    def _aggregate(normalized: List[Dict[str, Any]]) -> Dict[str, float]:
        agg: Dict[str, float] = {}
        for rec in normalized:
            k = rec[key_field]
            v = rec[value_field]
            agg[k] = agg.get(k, 0.0) + v
        return agg

    # Helper: filter aggregated results by threshold
    def _filter(agg: Dict[str, float]) -> List[Tuple[str, float]]:
        result: List[Tuple[str, float]] = []
        for k, v in agg.items():
            if threshold is None or v >= threshold:
                result.append((k, v))
        result.sort(key=lambda x: (-x[1], x[0]))
        return result

    # Helper: compute basic statistics on aggregated values
    def _stats(values: List[float]) -> Dict[str, float]:
        n = len(values)
        if n == 0:
            return {'count': 0, 'sum': 0.0, 'min': 0.0, 'max': 0.0, 'mean': 0.0, 'median': 0.0, 'stddev': 0.0}
        total = sum(values)
        mean = total / n
        sorted_vals = sorted(values)
        median = sorted_vals[n // 2] if n % 2 == 1 else (sorted_vals[n // 2 - 1] + sorted_vals[n // 2]) / 2.0
        var = sum((x - mean) ** 2 for x in values) / n
        stddev = var ** 0.5
        return {
            'count': n,
            'sum': total,
            'min': sorted_vals[0],
            'max': sorted_vals[-1],
            'mean': mean,
            'median': median,
            'stddev': stddev,
        }

    # Main pipeline: normalize records
    normalized: List[Dict[str, Any]] = []
    for rec in records:
        norm = _normalize(rec)
        if norm is not None:
            normalized.append(norm)

    # Aggregate values per key
    aggregated = _aggregate(normalized)

    # Compute statistics on aggregated values
    agg_values = list(aggregated.values())
    statistics = _stats(agg_values)

    # Filter aggregated results
    filtered = _filter(aggregated)

    # Build final output dictionary
    output: Dict[str, Any] = {
        'total_records': len(records),
        'valid_records': len(normalized),
        'unique_keys': len(aggregated),
        'filtered_count': len(filtered),
        'top': filtered[:10],
        'statistics': statistics,
    }
    return output

