def process_records(records: typing.List[typing.Dict[str, typing.Any]]) -> typing.Dict[str, typing.Any]:
    def _normalize(value: typing.Any) -> typing.Any:
        if isinstance(value, str):
            return value.strip().lower()
        return value

    def _validate(record: typing.Dict[str, typing.Any]) -> bool:
        required = {"id", "name", "score"}
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["id"], int):
            return False
        if not isinstance(record["score"], (int, float)):
            return False
        return True

    def _aggregate(acc: typing.Dict[str, typing.Any], record: typing.Dict[str, typing.Any]) -> None:
        cat = record.get("category", "uncategorized")
        if cat not in acc:
            acc[cat] = {"count": 0, "total_score": 0.0, "ids": []}
        acc[cat]["count"] += 1
        acc[cat]["total_score"] += record["score"]
        acc[cat]["ids"].append(record["id"])

    summary: typing.Dict[str, typing.Any] = {}
    errors: typing.List[str] = []
    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append(f"Record at index {idx} is not a dict")
            continue
        if not _validate(rec):
            errors.append(f"Record at index {idx} failed validation")
            continue
        rec = {k: _normalize(v) if isinstance(v, str) else v for k, v in rec.items()}
        _aggregate(summary, rec)

    for cat, data in summary.items():
        if data["count"] > 0:
            data["average_score"] = data["total_score"] / data["count"]
        else:
            data["average_score"] = None

    result = {
        "summary": summary,
        "errors": errors,
        "total_records": len(records),
        "valid_records": sum(d["count"] for d in summary.values()),
    }
    return result

