import csv
from typing import List, Dict, Any, Iterable, Tuple


def process_data(file_path: str, threshold: float = 0.5) -> Dict[str, Any]:
    def _load_csv(path: str) -> List[Dict[str, Any]]:
        rows = []
        with open(path, newline='', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            for row in reader:
                rows.append(row)
        return rows

    def _filter_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered = []
        for r in rows:
            try:
                val = float(r.get('value', 0))
            except (ValueError, TypeError):
                continue
            if val >= threshold:
                filtered.append(r)
        return filtered

    def _aggregate(rows: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg = {}
        for r in rows:
            key = r.get('category', 'unknown')
            val = float(r.get('value', 0))
            if key not in agg:
                agg[key] = {'count': 0, 'sum': 0.0}
            agg[key]['count'] += 1
            agg[key]['sum'] += val
        for k, v in agg.items():
            v['average'] = v['sum'] / v['count'] if v['count'] else 0.0
        return agg

    def _write_json(data: Dict[str, Any], out_path: str) -> None:
        with open(out_path, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2)

    rows = _load_csv(file_path)
    filtered = _filter_rows(rows)
    aggregated = _aggregate(filtered)
    output_path = file_path.rsplit('.', 1)[0] + '_summary.json'
    _write_json(aggregated, output_path)
    return {
        'total_rows': len(rows),
        'filtered_rows': len(filtered),
        'categories': len(aggregated),
        'output_file': output_path,
    }

