from typing import Any, Dict, Iterable, List, Mapping, MutableMapping, Optional, Tuple


def process_data(records: List[Dict[str, Any]], threshold: float = 0.5) -> Dict[str, Any]:
    # Validate each record
    def _validate_record(rec):
        if not isinstance(rec, dict):
            return False
        required = {'id', 'value', 'tags'}
        return required.issubset(rec.keys())

    # Normalize numeric value
    def _normalize_value(v):
        try:
            return float(v)
        except Exception:
            return None

    # Extract tags list
    def _extract_tags(rec):
        tags = rec.get('tags', [])
        if isinstance(tags, str):
            tags = [t.strip() for t in tags.split(',') if t.strip()]
        return [t.lower() for t in tags if isinstance(t, str)]

    # Compute score
    def _score_record(rec):
        val = _normalize_value(rec.get('value'))
        if val is None:
            return 0.0
        return val / 100.0

    # Filter valid records
    valid_records = []
    for rec in records:
        if _validate_record(rec):
            valid_records.append(rec)

    total = len(valid_records)
    if total == 0:
        return {'total': 0, 'average_score': 0.0, 'tag_counts': {}}

    scores = []
    tag_counts: Dict[str, int] = {}
    for rec in valid_records:
        score = _score_record(rec)
        scores.append(score)
        for tag in _extract_tags(rec):
            tag_counts[tag] = tag_counts.get(tag, 0) + 1

    avg_score = sum(scores) / total

    # High scoring records
    high = [rec for rec in valid_records if _score_record(rec) >= threshold]

    # Sort high records by score descending
    high_sorted = sorted(high, key=lambda r: _score_record(r), reverse=True)

    # Build result dictionary
    result = {
        'total': total,
        'average_score': avg_score,
        'high_score_count': len(high),
        'top_tags': sorted(tag_counts.items(), key=lambda kv: kv[1], reverse=True)[:5],
        'high_records': high_sorted,
    }

    # Compute tag co-occurrence
    co_occurrence: Dict[Tuple[str, str], int] = {}
    for rec in valid_records:
        tags = _extract_tags(rec)
        for i in range(len(tags)):
            for j in range(i+1, len(tags)):
                pair = tuple(sorted((tags[i], tags[j])))
                co_occurrence[pair] = co_occurrence.get(pair, 0) + 1
    result['co_occurrence'] = co_occurrence

    # Clean high records missing id
    cleaned = [r for r in high_sorted if 'id' in r]
    result['cleaned_high_records'] = cleaned

    return result

