from typing import Any, Dict, List, Optional, Tuple

def process_data(records: List[Dict[str, Any]], key: str, threshold: float = 0.5) -> Dict[str, Any]:
    def _normalize(val: Any) -> str:
        if val is None:
            return ''
        return str(val).strip().lower()

    def _validate(record: Dict[str, Any]) -> Tuple[bool, Optional[str]]:
        if not isinstance(record, dict):
            return False, 'not a dict'
        if key not in record:
            return False, f'missing key {key}'
        if not isinstance(record[key], (int, float)):
            return False, f'invalid type for {key}'
        return True, None

    def _aggregate(valid_records: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        for rec in valid_records:
            total += float(rec[key])
            count += 1
        avg = total / count if count else 0.0
        return {'total': total, 'count': count, 'average': avg}

    valid = []
    errors = []
    for idx, rec in enumerate(records):
        ok, err = _validate(rec)
        if not ok:
            errors.append({'index': idx, 'error': err})
            continue
        valid.append(rec)

    agg = _aggregate(valid)

    def _filter_by_threshold(agg_data: Dict[str, Any]) -> List[Dict[str, Any]]:
        threshold_value = agg_data['average'] * threshold
        filtered = [r for r in valid if float(r[key]) >= threshold_value]
        return filtered

    filtered = _filter_by_threshold(agg)

    def _to_json(data: Any) -> str:
        return json.dumps(data, indent=2)

    result = {
        'summary': agg,
        'filtered_records': filtered,
        'errors': errors,
        'json_summary': _to_json(agg),
        'json_filtered': _to_json(filtered),
    }

    return result

