import json
from typing import Any, Dict, List, Tuple, Optional


def process_dataset(
    data: List[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[float] = None,
    normalize: bool = False,
    max_items: int = 1000,
) -> Dict[str, Any]:
    def _validate_row(row: Dict[str, Any]) -> bool:
        if key_field not in row or value_field not in row:
            return False
        if not isinstance(row[key_field], str):
            return False
        if not isinstance(row[value_field], (int, float)):
            return False
        return True

    def _normalize_value(val: float, min_val: float, max_val: float) -> float:
        if max_val == min_val:
            return 0.0
        return (val - min_val) / (max_val - min_val)

    valid_rows: List[Dict[str, Any]] = []
    for r in data:
        if _validate_row(r):
            valid_rows.append(r)

    if not valid_rows:
        return {"error": "no valid rows"}

    values = [float(r[value_field]) for r in valid_rows]
    min_val, max_val = min(values), max(values)
    avg_val = sum(values) / len(values)

    if threshold is not None:
        filtered = [r for r in valid_rows if float(r[value_field]) >= threshold]
    else:
        filtered = valid_rows

    if normalize:
        for r in filtered:
            r[value_field] = _normalize_value(float(r[value_field]), min_val, max_val)

    groups: Dict[str, List[Dict[str, Any]]] = {}
    for r in filtered:
        k = r[key_field]
        groups.setdefault(k, []).append(r)

    summaries: List[Dict[str, Any]] = []
    for k, items in groups.items():
        vals = [float(item[value_field]) for item in items]
        group_min, group_max = min(vals), max(vals)
        group_avg = sum(vals) / len(vals)
        summaries.append({
            "key": k,
            "count": len(items),
            "min": group_min,
            "max": group_max,
            "avg": group_avg,
            "items": items[:max_items]
        })

    summaries.sort(key=lambda s: s["avg"], reverse=True)

    return {
        "total_rows": len(data),
        "valid_rows": len(valid_rows),
        "filtered_rows": len(filtered),
        "min_value": min_val,
        "max_value": max_val,
        "average_value": avg_val,
        "groups": summaries
    }

