from typing import Any, Dict, List, Optional, Tuple, Iterable

def process_transactions(transactions: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "amount", "currency", "type"}
        if not isinstance(tx, dict):
            return False
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], (int, str)):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if not isinstance(tx["currency"], str):
            return False
        if tx["type"] not in {"debit", "credit"}:
            return False
        return True

    def _categorize(amount: float) -> str:
        if amount < 0:
            return "negative"
        if amount == 0:
            return "zero"
        if amount > 10000:
            return "large"
        return "normal"

    balances: Dict[str, float] = {}
    categories: Dict[str, int] = {}
    errors: List[Tuple[int, str]] = []

    for idx, tx in enumerate(transactions):
        if not _validate(tx):
            errors.append((idx, "validation_failed"))
            continue
        amt = float(tx["amount"])
        cur = tx["currency"]
        typ = tx["type"]
        key = f"{cur}_{typ}"
        balances[key] = balances.get(key, 0.0) + amt
        cat = _categorize(amt)
        categories[cat] = categories.get(cat, 0) + 1

    def _format_balance(bal: float) -> str:
        if bal >= 0:
            return f"${bal:,.2f}"
        return f"-${abs(bal):,.2f}"

    summary: Dict[str, Any] = {
        "total_transactions": len(transactions),
        "valid_transactions": len(transactions) - len(errors),
        "errors": errors,
        "balances": {k: _format_balance(v) for k, v in balances.items()},
        "categories": categories,
    }

    def _compute_net(cur: str) -> float:
        debit_key = f"{cur}_debit"
        credit_key = f"{cur}_credit"
        debit = balances.get(debit_key, 0.0)
        credit = balances.get(credit_key, 0.0)
        return credit - debit

    net_balances: Dict[str, str] = {}
    for cur in set(k.split("_")[0] for k in balances.keys()):
        net = _compute_net(cur)
        net_balances[cur] = _format_balance(net)

    summary["net_balances"] = net_balances

    if errors:
        summary["status"] = "partial_success"
    else:
        summary["status"] = "success"

    return summary

