import json
from typing import Any, Dict, List, Optional


def process_data(
    records: List[Dict[str, Any]],
    filter_key: str,
    filter_value: Any,
    transform_func: Optional[Any] = None,
    batch_size: int = 100,
) -> Dict[str, Any]:
    def _filter(record):
        return record.get(filter_key) == filter_value

    def _transform(record):
        if transform_func is None:
            return record
        return transform_func(record)

    def _batch(iterable, size):
        batch = []
        for item in iterable:
            batch.append(item)
            if len(batch) == size:
                yield batch
                batch = []
        if batch:
            yield batch

    filtered = filter(_filter, records)
    transformed = map(_transform, filtered)

    batches = list(_batch(transformed, batch_size))

    result = {
        "total_records": len(records),
        "filtered_records": len(list(filter(_filter, records))),
        "batches_processed": len(batches),
        "batches": [],
    }

    for idx, batch in enumerate(batches, start=1):
        batch_summary = {
            "batch_number": idx,
            "size": len(batch),
            "sample": batch[0] if batch else None,
        }
        result["batches"].append(batch_summary)

    try:
        json_output = json.dumps(result, indent=2)
    except Exception as e:
        json_output = f"Error serializing result: {e}"

    return {"json": json_output, "status": "ok" if result["batches_processed"] > 0 else "no_data"}

