def analyze_sales_data(sales_records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        required = {"date", "region", "salesperson", "amount", "product"}
        if not isinstance(record, dict):
            return False
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["amount"], (int, float)):
            return False
        if record["amount"] < 0:
            return False
        return True

    def _parse_date(date_str: str) -> Optional[str]:
        try:
            parts = date_str.split("-")
            if len(parts) != 3:
                return None
            year, month, day = parts
            int(year); int(month); int(day)
            return f"{year}-{month}-{day}"
        except Exception:
            return None

    def _aggregate_by_region(records: List[Dict[str, Any]]) -> Dict[str, Dict[str, Any]]:
        region_stats: Dict[str, Dict[str, Any]] = {}
        for rec in records:
            region = rec["region"]
            amount = rec["amount"]
            if region not in region_stats:
                region_stats[region] = {"total": 0.0, "count": 0, "salespersons": set()}
            region_stats[region]["total"] += amount
            region_stats[region]["count"] += 1
            region_stats[region]["salespersons"].add(rec["salesperson"])
        for region, stats in region_stats.items():
            stats["average"] = stats["total"] / stats["count"] if stats["count"] else 0.0
            stats["salespersons"] = list(stats["salespersons"])
        return region_stats

    def _aggregate_by_product(records: List[Dict[str, Any]]) -> Dict[str, Dict[str, Any]]:
        product_stats: Dict[str, Dict[str, Any]] = {}
        for rec in records:
            product = rec["product"]
            amount = rec["amount"]
            if product not in product_stats:
                product_stats[product] = {"total": 0.0, "count": 0}
            product_stats[product]["total"] += amount
            product_stats[product]["count"] += 1
        for product, stats in product_stats.items():
            stats["average"] = stats["total"] / stats["count"] if stats["count"] else 0.0
        return product_stats

    def _filter_by_date(records: List[Dict[str, Any]], start: Optional[str], end: Optional[str]) -> List[Dict[str, Any]]:
        if start is None and end is None:
            return records
        filtered: List[Dict[str, Any]] = []
        for rec in records:
            date = rec.get("date")
            if date is None:
                continue
            if start and date < start:
                continue
            if end and date > end:
                continue
            filtered.append(rec)
        return filtered

    valid_records: List[Dict[str, Any]] = []
    errors: List[str] = []
    for idx, rec in enumerate(sales_records):
        if not _validate(rec):
            errors.append(f"Record {idx} invalid: {rec}")
            continue
        parsed_date = _parse_date(rec["date"])
        if parsed_date is None:
            errors.append(f"Record {idx} has bad date: {rec['date']}")
            continue
        rec["date"] = parsed_date
        valid_records.append(rec)

    region_stats = _aggregate_by_region(valid_records)
    product_stats = _aggregate_by_product(valid_records)

    overall_total = sum(r["total"] for r in region_stats.values())
    overall_count = sum(r["count"] for r in region_stats.values())
    overall_average = overall_total / overall_count if overall_count else 0.0

