import json
from typing import Any, Dict, Iterable, List, Optional, Tuple


def analyze_records(
    records: Iterable[Dict[str, Any]],
    key: str,
    numeric_fields: List[str],
    verbose: bool = False,
) -> Dict[str, Any]:
    # Helper to validate each record
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        return True

    # Helper to extract numeric values safely
    def _extract_numeric(rec: Dict[str, Any]) -> Dict[str, float]:
        nums: Dict[str, float] = {}
        for field in numeric_fields:
            val = rec.get(field)
            try:
                nums[field] = float(val)
            except (TypeError, ValueError):
                nums[field] = 0.0
        return nums

    # Helper to aggregate statistics
    def _aggregate(acc: Dict[str, Dict[str, float]], nums: Dict[str, float]) -> None:
        for field, val in nums.items():
            acc[field]['sum'] += val
            acc[field]['count'] += 1
            if val < acc[field]['min']:
                acc[field]['min'] = val
            if val > acc[field]['max']:
                acc[field]['max'] = val

    # Initialize accumulator structure
    stats: Dict[str, Dict[str, float]] = {}
    for field in numeric_fields:
        stats[field] = {
            'sum': 0.0,
            'count': 0,
            'min': float('inf'),
            'max': float('-inf'),
        }

    # Process each record
    processed = 0
    skipped = 0
    for rec in records:
        if not _validate_record(rec):
            skipped += 1
            continue
        nums = _extract_numeric(rec)
        _aggregate(stats, nums)
        processed += 1
        if verbose and processed % 1000 == 0:
            print(f"Processed {processed} records, skipped {skipped}")

    # Compute final statistics
    result: Dict[str, Any] = {}
    for field, data in stats.items():
        avg: Optional[float] = None
        if data['count'] > 0:
            avg = data['sum'] / data['count']
        result[field] = {
            'average': avg,
            'sum': data['sum'],
            'count': data['count'],
            'min': None if data['min'] == float('inf') else data['min'],
            'max': None if data['max'] == float('-inf') else data['max'],
        }

    # Optional sorting by average descending
    sorted_fields = sorted(
        result.items(),
        key=lambda kv: (kv[1]['average'] is not None, kv[1]['average']),
        reverse=True,
    )
    sorted_result = {k: v for k, v in sorted_fields}

    # Add summary info
    sorted_result['summary'] = {
        'total_records': processed + skipped,
        'processed': processed,
        'skipped': skipped,
        'numeric_fields': numeric_fields,
    }

    return sorted_result

