import datetime
from typing import Any, Dict, List, Optional, Tuple

def analyze_transactions(transactions: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _parse_date(date_str: str) -> Optional[datetime.date]:
        try:
            return datetime.datetime.strptime(date_str, "%Y-%m-%d").date()
        except Exception:
            return None

    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = {"id", "amount", "date", "type"}
        if not isinstance(rec, dict):
            return False
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if _parse_date(rec["date"]) is None:
            return False
        if rec["type"] not in {"debit", "credit"}:
            return False
        return True

    def _categorize(rec: Dict[str, Any]) -> str:
        amt = rec["amount"]
        if amt > 1000:
            return "high"
        if amt > 100:
            return "medium"
        return "low"

    totals: Dict[str, float] = {"debit": 0.0, "credit": 0.0}
    categories: Dict[str, int] = {"high": 0, "medium": 0, "low": 0}
    dates: Dict[datetime.date, int] = {}
    invalid_records: List[Dict[str, Any]] = []
    seen_ids: set[int] = set()
    duplicate_ids: set[int] = set()

    for rec in transactions:
        if not _validate_record(rec):
            invalid_records.append(rec)
            continue
        rec_id = rec["id"]
        if rec_id in seen_ids:
            duplicate_ids.add(rec_id)
        else:
            seen_ids.add(rec_id)
        amt = float(rec["amount"])
        totals[rec["type"]] += amt
        cat = _categorize(rec)
        categories[cat] += 1
        d = _parse_date(rec["date"])
        if d:
            dates[d] = dates.get(d, 0) + 1

    def _average_daily_transactions() -> float:
        if not dates:
            return 0.0
        return sum(dates.values()) / len(dates)

    def _top_n_dates(n: int = 5) -> List[Tuple[datetime.date, int]]:
        return sorted(dates.items(), key=lambda kv: kv[1], reverse=True)[:n]

    def _monthly_totals() -> Dict[str, Dict[str, float]]:
        monthly: Dict[str, Dict[str, float]] = {}
        for rec in transactions:
            if not _validate_record(rec):
                continue
            month = rec["date"][:7]
            if month not in monthly:
                monthly[month] = {"debit": 0.0, "credit": 0.0}
            monthly[month][rec["type"]] += float(rec["amount"])
        return monthly

    def _detect_duplicates() -> List[int]:
        return sorted(list(duplicate_ids))

    def _report() -> str:
        lines = []
        lines.append("Transaction Analysis Report")
        lines.append("--------------------------------")
        lines.append(f"Total records processed: {len(transactions)}")
        lines.append(f"Valid records: {len(transactions) - len(invalid_records)}")
        lines.append(f"Invalid records: {len(invalid_records)}")
        lines.append(f"Duplicate IDs found: {len(duplicate_ids)}")
        lines.append("")
        lines.append("Totals by type:")
        for t, amt in totals.items():
            lines.append(f"  {t.capitalize()}: {amt:.2f}")
        lines.append("")
        lines.append("Category counts:")
        for c, cnt in categories.items():
            lines.append(f"  {c.capitalize()}: {cnt}")
        lines.append("")
        lines.append(f"Average daily transactions: { _average_daily_transactions():.2f}")
        lines.append("Top 5 transaction dates:")
        for d, cnt in _top_n_dates():
            lines.append(f"  {d.isoformat()}: {cnt}")
        return "\n".join(lines)

    summary = {
        "total_transactions": len(transactions),
        "valid_transactions": len(transactions) - len(invalid_records),
        "invalid_transactions": len(invalid_records),
        "duplicate_ids": _detect_duplicates(),
        "totals": totals,
        "categories": categories,
        "average_daily_transactions": _average_daily_transactions(),
        "top_dates": _top_n_dates(),
        "monthly_totals": _monthly_totals(),
    }

    return {"summary": summary, "invalid_records": invalid_records, "report": _report()}

