import typing
from typing import Any, Dict, List, Iterable, Tuple

def process_records(
    records: List[Dict[str, Any]],
    threshold: int = 10,
    min_value: float = 0.0,
) -> Dict[str, Any]:
    # inner helper to normalize tags
    def _normalize_tag(tag: Any) -> str:
        if isinstance(tag, str):
            return tag.strip().lower()
        return str(tag).strip().lower()

    # validate a single record
    def _validate(record: Dict[str, Any]) -> Tuple[bool, str]:
        required_keys = {\"id\", \"value\", \"tags\"}
        if not required_keys.issubset(record.keys()):
            return False, \"missing_keys\"
        if not isinstance(record[\"tags\"], list):
            return False, \"tags_not_list\"
        if not isinstance(record[\"value\"], (int, float)):
            return False, \"invalid_value_type\"
        if record[\"value\"] < min_value:
            return False, \"value_below_min\"
        return True, \"\"

    # aggregate tags
    def _aggregate_tags(valid_records: List[Dict[str, Any]]) -> Dict[str, int]:
        agg: Dict[str, int] = {}
        for rec in valid_records:
            for tag in rec.get(\"tags\", []):
                norm = _normalize_tag(tag)
                agg[norm] = agg.get(norm, 0) + 1
        return agg

    # filter tags by threshold
    def _filter_tags(agg: Dict[str, int]) -> List[str]:
        return [tag for tag, count in agg.items() if count >= threshold]

    # compute average value
    def _average_value(valid_records: List[Dict[str, Any]]) -> float:
        if not valid_records:
            return 0.0
        total = sum(rec[\"value\"] for rec in valid_records)
        return total / len(valid_records)

    # main processing
    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []
    error_details: List[Tuple[Dict[str, Any], str]] = []

    for rec in records:
        is_valid, err = _validate(rec)
        if is_valid:
            valid_records.append(rec)
        else:
            invalid_records.append(rec)
            error_details.append((rec, err))

    aggregated_tags = _aggregate_tags(valid_records)
    frequent_tags = _filter_tags(aggregated_tags)
    avg_value = _average_value(valid_records)

    result: Dict[str, Any] = {
        \"total_records\": len(records),
        \"valid_records\": len(valid_records),
        \"invalid_records\": len(invalid_records),
        \"average_value\": avg_value,
        \"aggregated_tags\": aggregated_tags,
        \"frequent_tags\": frequent_tags,
        \"errors\": error_details,
    }
    return result

