import json
from datetime import datetime
from typing import Any, Dict, List

def process_data(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    # Validate input
    if not isinstance(records, list):
        raise TypeError('records must be a list')
    # Ensure each record is a dict
    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            raise ValueError(f'record at index {idx} is not a dict')
    # nested validation function
    def _validate_record(rec: Dict[str, Any]) -> bool:
        required_keys = {'id', 'timestamp', 'value'}
        if not required_keys.issubset(rec.keys()):
            return False
        if not isinstance(rec['id'], int):
            return False
        try:
            datetime.fromisoformat(rec['timestamp'])
        except Exception:
            return False
        if not isinstance(rec['value'], (int, float)):
            return False
        return True
    # filter valid records
    valid_records = [rec for rec in records if _validate_record(rec)]
    # nested transform function
    def _transform_record(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = rec.copy()
        new_rec['timestamp'] = datetime.fromisoformat(rec['timestamp'])
        new_rec['value'] = float(rec['value'])
        return new_rec
    transformed = [_transform_record(r) for r in valid_records]
    # nested aggregation
    def _aggregate(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        min_val = None
        max_val = None
        for r in records:
            val = r['value']
            total += val
            count += 1
            if min_val is None or val < min_val:
                min_val = val
            if max_val is None or val > max_val:
                max_val = val
        avg = total / count if count else None
        return {'count': count, 'total': total, 'average': avg, 'min': min_val, 'max': max_val}
    stats = _aggregate(transformed)
    # nested serialization
    def _serialize(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        out = []
        for r in records:
            out.append({
                'id': r['id'],
                'timestamp': r['timestamp'].isoformat(),
                'value': r['value']
            })
        return out
    serialized = _serialize(transformed)
    # final result
    result = {
        'metadata': {
            'processed_at': datetime.utcnow().isoformat() + 'Z',
            'total_records': len(records),
            'valid_records': len(valid_records),
            'invalid_records': len(records) - len(valid_records)
        },
        'statistics': stats,
        'data': serialized
    }
    # optional: write to file
    def _write_to_file(data: Dict[str, Any], path: str) -> None:
        with open(path, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=2, default=str)
    # if path provided in records? maybe skip
    return result

