def process_data(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    # inner helper to validate record
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        if not isinstance(rec[key_field], str):
            return False
        if not isinstance(rec[value_field], (int, float)):
            return False
        return True

    # inner helper to aggregate
    def _aggregate(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        min_val = None
        max_val = None
        for rec in group:
            val = float(rec[value_field])
            total += val
            count += 1
            if min_val is None or val < min_val:
                min_val = val
            if max_val is None or val > max_val:
                max_val = val
        avg = total / count if count else 0.0
        return {
            "count": count,
            "sum": total,
            "average": avg,
            "min": min_val,
            "max": max_val,
        }

    # main processing
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for rec in records:
        if not _validate(rec):
            continue
        key = rec[key_field]
        groups.setdefault(key, []).append(rec)

    results: Dict[str, Any] = {}
    for k, group in groups.items():
        agg = _aggregate(group)
        if threshold is not None and agg["average"] < threshold:
            continue
        results[k] = agg

    # post-processing: sort by average descending
    sorted_keys = sorted(
        results.keys(),
        key=lambda x: results[x]["average"],
        reverse=True,
    )
    sorted_results = {k: results[k] for k in sorted_keys}

    # compute overall stats
    overall = {
        "total_records": sum(r["count"] for r in results.values()),
        "overall_average": (
            sum(r["sum"] for r in results.values())
            / sum(r["count"] for r in results.values())
            if results
            else 0.0
        ),
        "groups": sorted_results,
    }

    return overall

