from typing import List, Dict, Any

def process_data(records: List[Dict[str, Any]], threshold: float) -> Dict[str, Any]:
    # Normalize string values
    def _normalize(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip().lower()
        return val

    # Validate a single record
    def _validate(record: Dict[str, Any]) -> bool:
        required = {'id', 'value', 'tags'}
        if not required.issubset(record):
            return False
        if not isinstance(record['id'], int):
            return False
        if not isinstance(record['value'], (int, float)):
            return False
        if not isinstance(record['tags'], list):
            return False
        return True

    # Aggregate records by id
    def _aggregate(records: List[Dict[str, Any]]) -> Dict[int, Dict[str, Any]]:
        agg: Dict[int, Dict[str, Any]] = {}
        for rec in records:
            rid = rec['id']
            if rid not in agg:
                agg[rid] = {'count': 0, 'total': 0.0, 'tags': set()}
            agg[rid]['count'] += 1
            agg[rid]['total'] += float(rec['value'])
            agg[rid]['tags'].update(rec['tags'])
        return agg

    # Filter aggregated data based on threshold
    def _filter(agg: Dict[int, Dict[str, Any]]) -> List[Dict[str, Any]]:
        result: List[Dict[str, Any]] = []
        for rid, data in agg.items():
            avg = data['total'] / data['count']
            if avg >= threshold:
                result.append({
                    'id': rid,
                    'average': avg,
                    'unique_tags': sorted(data['tags']),
                })
        return result

    # Sort results by average descending, then id ascending
    def _sort(results: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return sorted(results, key=lambda x: (-x['average'], x['id']))

    # Serialize to JSON
    def _serialize(results: List[Dict[str, Any]]) -> str:
        return json.dumps(results, indent=2)

    # Main processing pipeline
    valid_records = [rec for rec in records if _validate(rec)]
    agg = _aggregate(valid_records)
    filtered = _filter(agg)
    sorted_results = _sort(filtered)
    json_output = _serialize(sorted_results)
    return {
        'processed_count': len(valid_records),
        'output_json': json_output,
        'details': {
            'total_records': len(records),
            'valid_records': len(valid_records),
            'invalid_records': len(records) - len(valid_records),
        },
    }

