from typing import Any, Dict, List, Optional, Callable


def process_data(
    records: List[Dict[str, Any]],
    key: str,
    transform: Optional[Callable[[Any], Any]] = None,
    threshold: int = 0,
) -> Dict[str, Any]:
    # Validate input types
    if not isinstance(records, list):
        raise TypeError("records must be a list")
    if not isinstance(key, str):
        raise TypeError("key must be a string")
    if transform is not None and not callable(transform):
        raise TypeError("transform must be callable or None")

    # Helper to normalize values
    def _normalize(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip().lower()
        return val

    # Group records by key
    groups: Dict[Any, List[Dict[str, Any]]] = {}
    for rec in records:
        if not isinstance(rec, dict):
            continue
        raw_key = rec.get(key)
        if raw_key is None:
            continue
        norm_key = _normalize(raw_key)
        groups.setdefault(norm_key, []).append(rec)

    # Apply transform and filter
    results: List[Dict[str, Any]] = []
    for k, recs in groups.items():
        transformed_values: List[Any] = []
        for r in recs:
            val = r.get("value")
            if val is None:
                continue
            if transform:
                try:
                    val = transform(val)
                except Exception:
                    continue
            transformed_values.append(val)

        if not transformed_values:
            continue

        # Compute statistics
        count = len(transformed_values)
        total = sum(v for v in transformed_values if isinstance(v, (int, float)))
        avg = total / count if count else 0

        if count < threshold:
            continue

        results.append({
            "group_key": k,
            "count": count,
            "total": total,
            "average": avg,
            "sample": transformed_values[:5],
        })

    # Sort results by count descending
    results.sort(key=lambda x: x["count"], reverse=True)

    # Prepare summary
    summary = {
        "total_groups": len(groups),
        "filtered_groups": len(results),
        "records_processed": len(records),
        "threshold": threshold,
    }

    return {
        "summary": summary,
        "data": results,
    }

