import json
from typing import Any, Dict, List, Optional


def process_data(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    max_errors: int = 5,
    output_path: Optional[str] = None,
) -> Dict[str, Any]:
    errors: List[str] = []
    processed: List[Dict[str, Any]] = []
    field_counts: Dict[str, int] = {}
    numeric_sums: Dict[str, float] = {}
    numeric_counts: Dict[str, int] = {}

    def _log_error(msg: str) -> None:
        errors.append(msg)

    def _validate(record: Dict[str, Any]) -> bool:
        missing = [f for f in required_fields if f not in record or record[f] is None]
        if missing:
            _log_error(f"Missing fields {missing} in record {record.get('id', 'unknown')}")
            return False
        return True

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        new_rec: Dict[str, Any] = {}
        for k, v in record.items():
            if isinstance(v, str):
                new_rec[k] = v.strip()
            else:
                new_rec[k] = v
        return new_rec

    def _update_counts(record: Dict[str, Any]) -> None:
        for k in record.keys():
            field_counts[k] = field_counts.get(k, 0) + 1

    def _update_numeric_stats(record: Dict[str, Any]) -> None:
        for k, v in record.items():
            if isinstance(v, (int, float)):
                numeric_sums[k] = numeric_sums.get(k, 0.0) + float(v)
                numeric_counts[k] = numeric_counts.get(k, 0) + 1

    def _compute_averages() -> Dict[str, float]:
        averages: Dict[str, float] = {}
        for k in numeric_sums:
            count = numeric_counts.get(k, 0)
            if count:
                averages[k] = numeric_sums[k] / count
        return averages

    def _deduplicate(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        seen: set = set()
        unique: List[Dict[str, Any]] = []
        for rec in records:
            key = rec.get('id')
            if key is None:
                key = tuple(sorted(rec.items()))
            if key in seen:
                continue
            seen.add(key)
            unique.append(rec)
        return unique

    records = _deduplicate(records)

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            _log_error(f"Record at index {idx} is not a dict")
            if len(errors) >= max_errors:
                break
            continue
        if not _validate(rec):
            if len(errors) >= max_errors:
                break
            continue
        transformed = _transform(rec)
        _update_counts(transformed)
        _update_numeric_stats(transformed)
        processed.append(transformed)

    averages = _compute_averages()

    summary: Dict[str, Any] = {
        'total_records': len(records),
        'processed_records': len(processed),
        'errors': errors,
        'field_counts': field_counts,
        'numeric_averages': averages,
    }

    if output_path:
        try:
            with open(output_path, 'w', encoding='utf-8') as f:
                json.dump(processed, f, ensure_ascii=False, indent=2)
        except Exception as e:
            _log_error(f"Failed to write output file: {e}")
            summary['output_error'] = str(e)

    return summary

