import datetime
from typing import Any, Dict, List, Optional, Tuple

def process_records(records: List[Dict[str, Any]], required_fields: List[str], max_age: int) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> None:
        missing = [f for f in required_fields if f not in record]
        if missing:
            raise ValueError(f"Missing required fields: {missing}")
        if not isinstance(record.get("age"), int):
            raise TypeError("age must be int")
        if "signup_date" in record and not isinstance(record["signup_date"], str):
            raise TypeError("signup_date must be str")
    def _parse_date(date_str: str) -> datetime.datetime:
        try:
            return datetime.datetime.strptime(date_str, "%Y-%m-%d")
        except Exception:
            return datetime.datetime.min
    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        norm = dict(record)
        norm["age"] = int(norm["age"])
        if "signup_date" in norm:
            norm["signup_date"] = _parse_date(norm["signup_date"])
        else:
            norm["signup_date"] = datetime.datetime.min
        return norm
    def _group_by(record: Dict[str, Any]) -> str:
        return f"{record.get('country', 'unknown')}-{record.get('status', 'unknown')}"
    def _median(values: List[float]) -> float:
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]
    def _compute_statistics(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        ages = [rec["age"] for rec in group]
        signup_days = [(rec["signup_date"] - datetime.datetime.min).days for rec in group]
        return {
            "count": len(group),
            "avg_age": sum(ages) / len(ages) if ages else None,
            "median_age": _median(ages),
            "avg_signup_days": sum(signup_days) / len(signup_days) if signup_days else None,
            "median_signup_days": _median(signup_days),
        }
    validated: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    for rec in records:
        try:
            _validate(rec)
            norm = _normalize(rec)
            validated.append(norm)
        except Exception as exc:
            errors.append({"record": rec, "error": str(exc)})
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for rec in validated:
        key = _group_by(rec)
        groups.setdefault(key, []).append(rec)
    stats: Dict[str, Any] = {}
    for key, group in groups.items():
        stats[key] = _compute_statistics(group)
    filtered: Dict[str, List[Dict[str, Any]]] = {}
    for key, group in groups.items():
        if all(rec["age"] <= max_age for rec in group):
            filtered[key] = group
    sorted_group_keys = sorted(groups.keys(), key=lambda k: stats[k]["count"], reverse=True)
    sorted_groups = {k: groups[k] for k in sorted_group_keys}
    result = {
        "groups": sorted_groups,
        "filtered": filtered,
        "statistics": stats,
        "errors": errors,
        "metadata": {
            "total_records": len(records),
            "validated_records": len(validated),
            "error_count": len(errors),
            "max_age": max_age,
        },
    }
    return result

