from typing import List, Dict, Any, Tuple, Optional


def process_transactions(
    transactions: List[Dict[str, Any]],
    required_fields: List[str],
    currency: str = "USD",
    max_amount: Optional[float] = None,
) -> Dict[str, Any]:
    # nested helper functions
    def _validate(tx: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors = []
        for field in required_fields:
            if field not in tx:
                errors.append(f"missing field {field}")
        if "amount" in tx:
            try:
                amt = float(tx["amount"])
                if amt < 0:
                    errors.append("negative amount")
                if max_amount is not None and amt > max_amount:
                    errors.append(f"amount exceeds max {max_amount}")
            except (TypeError, ValueError):
                errors.append("invalid amount type")
        else:
            errors.append("missing amount")
        return (len(errors) == 0, errors)

    def _normalize(tx: Dict[str, Any]) -> Dict[str, Any]:
        norm = dict(tx)
        if "currency" in norm:
            norm["currency"] = norm["currency"].upper()
        else:
            norm["currency"] = currency.upper()
        if "timestamp" in norm:
            try:
                ts = int(norm["timestamp"])
                norm["timestamp"] = ts
            except (TypeError, ValueError):
                norm["timestamp"] = None
        else:
            norm["timestamp"] = None
        return norm

    def _aggregate(valid_txs: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        per_currency: Dict[str, float] = {}
        for tx in valid_txs:
            amt = float(tx["amount"])
            total += amt
            count += 1
            cur = tx.get("currency", currency).upper()
            per_currency[cur] = per_currency.get(cur, 0.0) + amt
        avg = total / count if count else 0.0
        return {
            "total_amount": total,
            "transaction_count": count,
            "average_amount": avg,
            "per_currency": per_currency,
        }

    if not isinstance(transactions, list):
        return {"error": "transactions must be a list"}

    valid: List[Dict[str, Any]] = []
    invalid: List[Tuple[Dict[str, Any], List[str]]] = []

    for tx in transactions:
        if not isinstance(tx, dict):
            invalid.append((tx, ["transaction not a dict"]))
            continue
        is_valid, errs = _validate(tx)
        if is_valid:
            norm_tx = _normalize(tx)
            valid.append(norm_tx)
        else:
            invalid.append((tx, errs))

    summary = _aggregate(valid)

    return {
        "summary": summary,
        "valid_transactions": valid,
        "invalid_transactions": [
            {"transaction": t, "errors": e} for t, e in invalid
        ],
        "validation_stats": {
            "total": len(transactions),
            "valid": len(valid),
            "invalid": len(invalid),
        },
    }

