import csv
import json
from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_data(
    csv_path: str,
    output_path: str,
    filter_func: Optional[Any] = None,
    transform_func: Optional[Any] = None,
    batch_size: int = 1000,
) -> Dict[str, Any]:
    # inner helper to read rows
    def _read_rows(path: str) -> Iterable[Dict[str, Any]]:
        with open(path, newline='', encoding='utf-8') as f:
            reader = csv.DictReader(f)
            for row in reader:
                yield row

    # inner helper to apply filter
    def _apply_filter(row: Dict[str, Any]) -> bool:
        if filter_func is None:
            return True
        try:
            return bool(filter_func(row))
        except Exception:
            return False

    # inner helper to apply transform
    def _apply_transform(row: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func is None:
            return row
        try:
            return transform_func(row)
        except Exception:
            return row

    # inner helper to write batch
    def _write_batch(batch: List[Dict[str, Any]], writer: csv.DictWriter) -> None:
        for item in batch:
            writer.writerow(item)

    # main logic
    processed_count = 0
    filtered_count = 0
    errors: List[str] = []

    try:
        rows = _read_rows(csv_path)
    except Exception as e:
        return {\"status\": \"error\", \"message\": f\"Failed to read CSV: {e}\"}

    # prepare output file
    try:
        out_file = open(output_path, 'w', newline='', encoding='utf-8')
    except Exception as e:
        return {\"status\": \"error\", \"message\": f\"Failed to open output: {e}\"}

    writer: Optional[csv.DictWriter] = None
    batch: List[Dict[str, Any]] = []

    for row in rows:
        if not _apply_filter(row):
            filtered_count += 1
            continue
        try:
            transformed = _apply_transform(row)
        except Exception as e:
            errors.append(f\"transform error on row {row}: {e}\")
            continue
        if writer is None:
            fieldnames = list(transformed.keys())
            writer = csv.DictWriter(out_file, fieldnames=fieldnames)
            writer.writeheader()
        batch.append(transformed)
        processed_count += 1
        if len(batch) >= batch_size:
            _write_batch(batch, writer)
            batch.clear()

    if batch:
        _write_batch(batch, writer)

    out_file.close()

    result: Dict[str, Any] = {
        \"status\": \"success\",
        \"processed\": processed_count,
        \"filtered\": filtered_count,
        \"errors\": errors,
        \"output\": output_path,
    }
    return result

