def analyze_records(records: typing.List[typing.Dict[str, typing.Any]]) -> typing.Dict[str, typing.Any]:
    # nested validation
    def _validate(record):
        if not isinstance(record, dict):
            return False
        required = {"id", "value", "tags"}
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["id"], int):
            return False
        if not isinstance(record["value"], (int, float)):
            return False
        if not isinstance(record["tags"], list):
            return False
        return True

    def _normalize(record):
        rec = record.copy()
        rec["tags"] = [t.strip().lower() for t in rec["tags"] if isinstance(t, str)]
        rec["value"] = float(rec["value"])
        return rec

    valid = []
    invalid = []
    for r in records:
        if _validate(r):
            valid.append(_normalize(r))
        else:
            invalid.append(r)

    # compute stats
    total = len(valid)
    if total == 0:
        return {"total": 0, "valid": 0, "invalid": len(invalid), "average": None, "tag_counts": {}}

    values = [r["value"] for r in valid]
    avg = sum(values) / total
    min_val = min(values)
    max_val = max(values)

    # tag frequency
    tag_counts: typing.Dict[str, int] = {}
    for r in valid:
        for t in r["tags"]:
            tag_counts[t] = tag_counts.get(t, 0) + 1

    # top tags
    top_tags = sorted(tag_counts.items(), key=lambda kv: kv[1], reverse=True)[:5]

    # group by id parity
    parity_groups: typing.Dict[str, typing.List[typing.Dict[str, typing.Any]]] = {"even": [], "odd": []}
    for r in valid:
        if r["id"] % 2 == 0:
            parity_groups["even"].append(r)
        else:
            parity_groups["odd"].append(r)

    # nested function to summarize group
    def _group_summary(group):
        g_vals = [r["value"] for r in group]
        if not g_vals:
            return {"count": 0, "avg": None}
        return {"count": len(g_vals), "avg": sum(g_vals) / len(g_vals)}

    even_summary = _group_summary(parity_groups["even"])
    odd_summary = _group_summary(parity_groups["odd"])

    result = {
        "total": total,
        "valid": total,
        "invalid": len(invalid),
        "average": avg,
        "min": min_val,
        "max": max_val,
        "tag_counts": tag_counts,
        "top_tags": [{"tag": t, "count": c} for t, c in top_tags],
        "parity_groups": {
            "even": {"count": even_summary["count"], "average": even_summary["avg"]},
            "odd": {"count": odd_summary["count"], "average": odd_summary["avg"]},
        },
    }
    return result

