import json
from typing import Any, Dict, Iterable, List, Optional

def process_dataset(
    data: Iterable[Dict[str, Any]],
    key_field: str,
    group_field: str,
    value_fields: List[str],
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    # Normalize string values
    def _normalize(val: Any) -> str:
        if val is None:
            return "\"\""
        return str(val).strip().lower()

    # Validate a single row
    def _validate_row(row: Dict[str, Any]) -> bool:
        if not isinstance(row, dict):
            return False
        if key_field not in row or group_field not in row:
            return False
        for vf in value_fields:
            if vf not in row:
                return False
        return True

    # Aggregate values per group
    def _aggregate_group(group_rows: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {vf: 0 for vf in value_fields}
        count = 0
        for r in group_rows:
            for vf in value_fields:
                try:
                    val = float(r.get(vf, 0))
                except (TypeError, ValueError):
                    val = 0
                agg[vf] += val
            count += 1
        if count > 0:
            for vf in value_fields:
                agg[vf] /= count
        return agg

    # Filter groups by threshold
    def _filter_by_threshold(group_key: str, agg_vals: Dict[str, Any]) -> bool:
        if threshold is None:
            return True
        for vf in value_fields:
            if agg_vals.get(vf, 0) < threshold:
                return False
        return True

    # Main processing
    groups: Dict[str, List[Dict[str, Any]]] = {}
    invalid_rows: List[Dict[str, Any]] = []
    for row in data:
        if not _validate_row(row):
            invalid_rows.append(row)
            continue
        gkey = _normalize(row[group_field])
        groups.setdefault(gkey, []).append(row)

    aggregated: Dict[str, Dict[str, Any]] = {}
    for gkey, rows in groups.items():
        agg_vals = _aggregate_group(rows)
        if _filter_by_threshold(gkey, agg_vals):
            aggregated[gkey] = agg_vals

    result: Dict[str, Any] = {
        "aggregated": aggregated,
        "invalid_rows": invalid_rows,
        "group_count": len(groups),
        "valid_group_count": len(aggregated),
    }

    # Serialize aggregated data to JSON string for external use
    result["aggregated_json"] = json.dumps(aggregated, indent=2)

    # Return the result dictionary
    return result

