def process_records(records: List[Dict[str, Any]], required_fields: List[str], max_items: Optional[int] = None) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        norm = {}
        for k, v in record.items():
            if isinstance(v, str):
                norm[k] = v.strip()
            else:
                norm[k] = v
        return norm

    def _compute_stats(valid: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats = {'count': len(valid), 'fields': {}}
        for rec in valid:
            for k, v in rec.items():
                if k not in stats['fields']:
                    stats['fields'][k] = {'unique': set(), 'nulls': 0}
                if v is None:
                    stats['fields'][k]['nulls'] += 1
                else:
                    stats['fields'][k]['unique'].add(v)
        for k, d in stats['fields'].items():
            d['unique_count'] = len(d['unique'])
            del d['unique']
        return stats

    processed: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for idx, rec in enumerate(records):
        if max_items is not None and idx >= max_items:
            break
        if not isinstance(rec, dict):
            errors.append({'index': idx, 'error': 'not a dict'})
            continue
        if not _validate(rec):
            errors.append({'index': idx, 'error': 'missing required fields'})
            continue
        norm_rec = _normalize(rec)
        processed.append(norm_rec)

    stats = _compute_stats(processed)

    result: Dict[str, Any] = {
        'processed': processed,
        'errors': errors,
        'stats': stats,
        'summary': {
            'total': len(records),
            'processed_count': len(processed),
            'error_count': len(errors),
            'max_items': max_items,
        },
    }
    return result

