def analyze_transactions(transactions: List[Dict[str, Any]], threshold: float = 1000.0) -> Dict[str, Any]:
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "amount", "currency", "timestamp", "type"}
        if not isinstance(tx, dict):
            return False
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], (int, str)):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if not isinstance(tx["currency"], str):
            return False
        if not isinstance(tx["timestamp"], str):
            return False
        if tx["type"] not in {"debit", "credit"}:
            return False
        return True

    def _categorize(tx: Dict[str, Any]) -> str:
        amt = tx["amount"]
        if amt >= threshold:
            return "high_value"
        elif amt <= threshold / 10:
            return "low_value"
        else:
            return "normal"

    def _aggregate(acc: Dict[str, Any], tx: Dict[str, Any]) -> None:
        cat = _categorize(tx)
        acc["total_count"] += 1
        acc["total_amount"] += tx["amount"]
        acc["categories"][cat] = acc["categories"].get(cat, 0) + 1
        if tx["type"] == "debit":
            acc["debit_amount"] += tx["amount"]
        else:
            acc["credit_amount"] += tx["amount"]
        acc["currency_counts"][tx["currency"]] = acc["currency_counts"].get(tx["currency"], 0) + 1

    def _detect_anomalies(acc: Dict[str, Any]) -> List[Dict[str, Any]]:
        anomalies = []
        avg = acc["total_amount"] / acc["total_count"] if acc["total_count"] else 0
        for cat, count in acc["categories"].items():
            if cat == "high_value" and count > acc["total_count"] * 0.05:
                anomalies.append({"issue": "high_value_spike", "count": count})
        if acc["debit_amount"] > acc["credit_amount"] * 1.5:
            anomalies.append({"issue": "debit_credit_disparity"})
        return anomalies

    summary: Dict[str, Any] = {
        "total_count": 0,
        "total_amount": 0.0,
        "debit_amount": 0.0,
        "credit_amount": 0.0,
        "categories": {},
        "currency_counts": {},
        "valid_transactions": 0,
        "invalid_transactions": 0,
    }

    for tx in transactions:
        if _validate(tx):
            _aggregate(summary, tx)
            summary["valid_transactions"] += 1
        else:
            summary["invalid_transactions"] += 1

    summary["average_amount"] = summary["total_amount"] / summary["valid_transactions"] if summary["valid_transactions"] else 0
    summary["anomalies"] = _detect_anomalies(summary)
    return summary

