import datetime
from typing import List, Dict, Any, Optional

def process_transactions(
    transactions: List[Dict[str, Any]],
    start_date: Optional[datetime.date] = None,
    end_date: Optional[datetime.date] = None,
    min_amount: float = 0.0,
) -> Dict[str, Any]:
    def _parse_date(d: Any) -> Optional[datetime.date]:
        if d is None:
            return None
        if isinstance(d, datetime.date):
            return d
        if isinstance(d, str):
            try:
                return datetime.datetime.strptime(d, "%Y-%m-%d").date()
            except ValueError:
                return None
        return None

    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "date", "amount", "currency"}
        if not required.issubset(tx):
            return False
        if not isinstance(tx["id"], (int, str)):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if not isinstance(tx["currency"], str):
            return False
        if _parse_date(tx["date"]) is None:
            return False
        return True

    def _filter(tx: Dict[str, Any]) -> bool:
        d = _parse_date(tx["date"])
        if start_date and d and d < start_date:
            return False
        if end_date and d and d > end_date:
            return False
        if tx["amount"] < min_amount:
            return False
        return True

    def _aggregate(acc: Dict[str, Any], tx: Dict[str, Any]) -> None:
        cur = tx["currency"]
        amt = float(tx["amount"])
        if cur not in acc:
            acc[cur] = {"count": 0, "total": 0.0}
        acc[cur]["count"] += 1
        acc[cur]["total"] += amt

    results: Dict[str, Any] = {
        "total_transactions": 0,
        "filtered_transactions": 0,
        "by_currency": {},
        "errors": [],
    }

    for tx in transactions:
        results["total_transactions"] += 1
        if not _validate(tx):
            results["errors"].append({"tx": tx, "reason": "validation_failed"})
            continue
        if not _filter(tx):
            continue
        results["filtered_transactions"] += 1
        _aggregate(results["by_currency"], tx)

    for cur, data in results["by_currency"].items():
        avg = data["total"] / data["count"] if data["count"] else 0.0
        data["average"] = round(avg, 2)

    return results

