def process_records(records: list, key: str, required_fields: list, numeric_fields: list) -> dict:
    # nested functions
    def _normalize(val):
        if isinstance(val, str):
            return val.strip().lower()
        return val

    def _validate(record):
        missing = [f for f in required_fields if f not in record]
        if missing:
            return False, missing
        return True, None

    def _group(records):
        groups = {}
        for r in records:
            k = _normalize(r.get(key))
            groups.setdefault(k, []).append(r)
        return groups

    def _compute_stats(group_recs):
        stats = {}
        for nf in numeric_fields:
            vals = [r.get(nf) for r in group_recs if isinstance(r.get(nf), (int, float))]
            if vals:
                stats[nf] = {
                    \"count\": len(vals),
                    \"sum\": sum(vals),
                    \"avg\": sum(vals)/len(vals),
                    \"min\": min(vals),
                    \"max\": max(vals)
                }
            else:
                stats[nf] = {\"count\": 0}
        return stats

    # main logic
    groups = _group(records)
    result = {}
    errors = []

    for k, recs in groups.items():
        valid_recs = []
        for r in recs:
            ok, missing = _validate(r)
            if ok:
                valid_recs.append(r)
            else:
                errors.append({\"key\": k, \"missing\": missing, \"record\": r})
        if valid_recs:
            result[k] = {
                \"records\": valid_recs,
                \"stats\": _compute_stats(valid_recs)
            }

    return {\"grouped\": result, \"errors\": errors}

