import typing


def process_data(
    data: typing.List[typing.Dict[str, typing.Any]],
    threshold: int = 10,
    mode: str = "sum",
) -> typing.Dict[str, typing.Any]:
    def _validate_record(rec: typing.Dict[str, typing.Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        required = {"id", "value", "tags"}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["value"], (int, float)):
            return False
        if not isinstance(rec["tags"], list):
            return False
        return True

    def _aggregate(records: typing.List[typing.Dict[str, typing.Any]]) -> typing.Dict[str, typing.Any]:
        result: typing.Dict[str, typing.Any] = {}
        for rec in records:
            key = rec["id"]
            val = rec["value"]
            if key not in result:
                result[key] = {"total": 0, "count": 0, "tags": set()}
            result[key]["total"] += val
            result[key]["count"] += 1
            result[key]["tags"].update(rec["tags"])
        return result

    def _filter_by_threshold(agg: typing.Dict[str, typing.Any]) -> typing.List[typing.Dict[str, typing.Any]]:
        output: typing.List[typing.Dict[str, typing.Any]] = []
        for key, stats in agg.items():
            avg = stats["total"] / stats["count"]
            if avg >= threshold:
                output.append({
                    "id": key,
                    "average": avg,
                    "tags": sorted(stats["tags"]),
                })
        return output

    def _sort_results(results: typing.List[typing.Dict[str, typing.Any]]) -> typing.List[typing.Dict[str, typing.Any]]:
        if mode == "sum":
            return sorted(results, key=lambda r: r["average"], reverse=True)
        elif mode == "tags":
            return sorted(results, key=lambda r: len(r["tags"]), reverse=True)
        else:
            return results

    if not isinstance(data, list):
        raise ValueError("data must be a list of records")

    valid_records: typing.List[typing.Dict[str, typing.Any]] = []
    for rec in data:
        if _validate_record(rec):
            valid_records.append(rec)

    aggregated = _aggregate(valid_records)
    filtered = _filter_by_threshold(aggregated)
    sorted_results = _sort_results(filtered)

    return {
        "total_records": len(data),
        "valid_records": len(valid_records),
        "aggregated_keys": len(aggregated),
        "filtered_count": len(filtered),
        "results": sorted_results,
    }

