import json
from typing import Any, Dict, List, Optional

def process_transactions(
    records: List[Dict[str, Any]],
    account_filter: Optional[List[str]] = None,
    min_amount: Optional[float] = None,
) -> Dict[str, Any]:
    # nested functions
    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = {"id", "account", "amount", "timestamp"}
        if not isinstance(rec, dict):
            return False
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["account"], str):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if not isinstance(rec["timestamp"], str):
            return False
        return True

    def _normalize_amount(amount: Any) -> float:
        try:
            return float(amount)
        except Exception:
            return 0.0

    def _group_by_account(recs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in recs:
            acc = r["account"]
            groups.setdefault(acc, []).append(r)
        return groups

    def _aggregate_group(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        min_val = None
        max_val = None
        for r in group:
            amt = _normalize_amount(r["amount"])
            total += amt
            count += 1
            if min_val is None or amt < min_val:
                min_val = amt
            if max_val is None or amt > max_val:
                max_val = amt
        avg = total / count if count else 0.0
        return {"count": count, "total": total, "average": avg, "min": min_val, "max": max_val}

    # main logic
    valid_records: List[Dict[str, Any]] = []
    errors: List[str] = []

    for rec in records:
        if not _validate_record(rec):
            errors.append(f\"invalid record id={rec.get('id', 'unknown')}\")
            continue
        if account_filter and rec["account"] not in account_filter:
            continue
        if min_amount is not None and _normalize_amount(rec["amount"]) < min_amount:
            continue
        valid_records.append(rec)

    grouped = _group_by_account(valid_records)

    summary: Dict[str, Any] = {}
    for acc, grp in grouped.items():
        summary[acc] = _aggregate_group(grp)

    result = {
        "summary": summary,
        "total_records": len(records),
        "valid_records": len(valid_records),
        "errors": errors,
    }

    return result

