def process_data(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate(rec):
        if not isinstance(rec, dict):
            return False
        required = {"id", "value", "tags"}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["value"], (int, float)):
            return False
        if not isinstance(rec["tags"], list):
            return False
        return True

    def _normalize(rec):
        rec = dict(rec)
        rec["value"] = float(rec["value"])
        rec["tags"] = [t.strip().lower() for t in rec["tags"] if isinstance(t, str)]
        return rec

    def _aggregate_by_tag(normalized):
        tag_map = {}
        for rec in normalized:
            for tag in rec["tags"]:
                tag_map.setdefault(tag, []).append(rec)
        return tag_map

    def _compute_stats(tag_map):
        stats = {}
        for tag, recs in tag_map.items():
            total = sum(r["value"] for r in recs)
            avg = total / len(recs) if recs else 0
            stats[tag] = {"count": len(recs), "total": total, "average": avg}
        return stats

    valid_records = []
    for r in records:
        if _validate(r):
            valid_records.append(_normalize(r))
    if not valid_records:
        return {"error": "no valid records"}

    tag_map = _aggregate_by_tag(valid_records)
    stats = _compute_stats(tag_map)

    # Build final output
    output = {
        "total_records": len(records),
        "valid_records": len(valid_records),
        "tags": list(tag_map.keys()),
        "stats": stats,
    }

    # Additional processing: find top tags by average
    top_by_avg = sorted(stats.items(), key=lambda kv: kv[1]["average"], reverse=True)[:5]
    output["top_by_average"] = [{"tag": t, "average": s["average"]} for t, s in top_by_avg]

    # Find tags with high variance
    def _variance(recs):
        n = len(recs)
        if n <= 1:
            return 0.0
        mean = sum(r["value"] for r in recs) / n
        var = sum((r["value"] - mean) ** 2 for r in recs) / (n - 1)
        return var

    var_stats = {}
    for tag, recs in tag_map.items():
        var_stats[tag] = _variance(recs)
    output["variance"] = var_stats

    # Filter tags with variance > threshold
    threshold = 10.0
    high_var_tags = [t for t, v in var_stats.items() if v > threshold]
    output["high_variance_tags"] = high_var_tags

    # Provide summary
    output["summary"] = {
        "max_average_tag": top_by_avg[0][0] if top_by_avg else None,
        "min_average_tag": top_by_avg[-1][0] if top_by_avg else None,
        "high_variance_count": len(high_var_tags),
    }

    return output

