from typing import List, Dict, Any, Optional

def process_user_records(records: List[Dict[str, Any]], *, min_age: int = 0, max_age: Optional[int] = None) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        required = {'id', 'name', 'email', 'age'}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec['id'], int) or rec['id'] <= 0:
            return False
        if not isinstance(rec['name'], str) or not rec['name'].strip():
            return False
        if '@' not in rec['email'] or not isinstance(rec['email'], str):
            return False
        if not isinstance(rec['age'], int) or rec['age'] < 0:
            return False
        return True

    def _normalize_email(email: str) -> str:
        return email.strip().lower()

    def _categorize_age(age: int) -> str:
        if age < 18:
            return 'minor'
        elif age < 65:
            return 'adult'
        else:
            return 'senior'

    valid_records: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for rec in records:
        if _validate_record(rec):
            rec_copy = dict(rec)
            rec_copy['email'] = _normalize_email(rec_copy['email'])
            rec_copy['age_category'] = _categorize_age(rec_copy['age'])
            if min_age is not None and rec_copy['age'] < min_age:
                errors.append({'id': rec_copy['id'], 'reason': 'below_min_age'})
                continue
            if max_age is not None and rec_copy['age'] > max_age:
                errors.append({'id': rec_copy['id'], 'reason': 'above_max_age'})
                continue
            valid_records.append(rec_copy)
        else:
            errors.append({'id': rec.get('id', None), 'reason': 'invalid_record'})

    summary: Dict[str, Any] = {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'invalid_records': len(errors),
        'age_distribution': {
            'minor': 0,
            'adult': 0,
            'senior': 0,
        },
        'errors': errors,
    }

    for rec in valid_records:
        cat = rec['age_category']
        summary['age_distribution'][cat] += 1

    def _compute_average_age() -> float:
        if not valid_records:
            return 0.0
        total = sum(rec['age'] for rec in valid_records)
        return total / len(valid_records)

    summary['average_age'] = _compute_average_age()

    def _most_common_email_domain() -> Optional[str]:
        if not valid_records:
            return None
        domain_counts: Dict[str, int] = {}
        for rec in valid_records:
            domain = rec['email'].split('@')[-1]
            domain_counts[domain] = domain_counts.get(domain, 0) + 1
        if not domain_counts:
            return None
        return max(domain_counts.items(), key=lambda kv: kv[1])[0]

    summary['most_common_domain'] = _most_common_email_domain()

    return summary

