import typing
from typing import Any, Dict, List, Iterable, Optional


def process_data_pipeline(
    records: List[Dict[str, Any]],
    config: Dict[str, Any],
) -> Dict[str, Any]:
    # Validate config
    def _validate_config(cfg: Dict[str, Any]) -> None:
        required = {"key_field", "transformations", "aggregation"}
        missing = required - cfg.keys()
        if missing:
            raise ValueError(f"Missing config keys: {missing}")
        if not isinstance(cfg["transformations"], list):
            raise TypeError("transformations must be a list")
        if not isinstance(cfg["aggregation"], str):
            raise TypeError("aggregation must be a string")

    # Normalize records
    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        norm = {}
        for k, v in record.items():
            if isinstance(v, str):
                norm[k] = v.strip()
            else:
                norm[k] = v
        return norm

    # Apply transformations
    def _apply_transformations(rec: Dict[str, Any], trans: List[Dict[str, Any]]) -> Dict[str, Any]:
        out = dict(rec)
        for t in trans:
            field = t.get("field")
            op = t.get("op")
            if field not in out:
                continue
            val = out[field]
            if op == "upper":
                out[field] = str(val).upper()
            elif op == "lower":
                out[field] = str(val).lower()
            elif op == "increment" and isinstance(val, (int, float)):
                out[field] = val + 1
            elif op == "decrement" and isinstance(val, (int, float)):
                out[field] = val - 1
            elif op == "prefix" and isinstance(val, str):
                prefix = t.get("value", "")
                out[field] = f"{prefix}{val}"
            elif op == "suffix" and isinstance(val, str):
                suffix = t.get("value", "")
                out[field] = f"{val}{suffix}"
        return out

    # Aggregate results
    def _aggregate(
        recs: Iterable[Dict[str, Any]],
        key: str,
        agg_func: str,
    ) -> Dict[Any, Any]:
        agg: Dict[Any, List[Any]] = {}
        for r in recs:
            k = r.get(key)
            if k is None:
                continue
            agg.setdefault(k, []).append(r)
        result: Dict[Any, Any] = {}
        for k, group in agg.items():
            if agg_func == "count":
                result[k] = len(group)
            elif agg_func == "sum":
                total = 0
                for r in group:
                    val = r.get("value")
                    if isinstance(val, (int, float)):
                        total += val
                result[k] = total
            elif agg_func == "avg":
                total = 0
                count = 0
                for r in group:
                    val = r.get("value")
                    if isinstance(val, (int, float)):
                        total += val
                        count += 1
                result[k] = total / count if count else None
        return result

    # Main processing
    _validate_config(config)
    key_field = config["key_field"]
    transformations = config["transformations"]
    aggregation = config["aggregation"]

    processed: List[Dict[str, Any]] = []
    for rec in records:
        norm_rec = _normalize(rec)
        transformed = _apply_transformations(norm_rec, transformations)
        processed.append(transformed)

    aggregated = _aggregate(processed, key_field, aggregation)

    return {
        "processed_records": processed,
        "aggregation": aggregated,
        "config_used": config,
    }

