import datetime

def process_data(records: list, required_fields: list, transform_map: dict, aggregate_by: str) -> dict:
    # Validate that records is a list
    if not isinstance(records, list):
        raise TypeError('records must be a list')
    # Validate required_fields is list of strings
    if not isinstance(required_fields, list) or not all(isinstance(f, str) for f in required_fields):
        raise TypeError('required_fields must be a list of strings')
    # Validate transform_map is dict
    if not isinstance(transform_map, dict):
        raise TypeError('transform_map must be a dict')
    # Validate aggregate_by is string
    if not isinstance(aggregate_by, str):
        raise TypeError('aggregate_by must be a string')
    # Inner function for validation
    def _validate(record: dict) -> bool:
        if not isinstance(record, dict):
            return False
        for field in required_fields:
            if field not in record:
                return False
        return True
    # Inner function for transformation
    def _transform(record: dict) -> dict:
        out = dict(record)
        for key, func in transform_map.items():
            if key in out:
                try:
                    out[key] = func(out[key])
                except Exception:
                    out[key] = None
        # Ensure timestamp is datetime
        ts = out.get('timestamp')
        if isinstance(ts, str):
            try:
                out['timestamp'] = datetime.datetime.fromisoformat(ts)
            except Exception:
                out['timestamp'] = None
        return out
    # Inner function for aggregation
    def _aggregate(acc: dict, record: dict) -> dict:
        key = record.get(aggregate_by)
        if key is None:
            return acc
        if key not in acc:
            acc[key] = {'count': 0, 'sum': 0}
        acc[key]['count'] += 1
        val = record.get('value')
        if isinstance(val, (int, float)):
            acc[key]['sum'] += val
        return acc
    # Process records
    valid_records = []
    errors = []
    for idx, rec in enumerate(records):
        if not _validate(rec):
            errors.append({'index': idx, 'reason': 'validation failed'})
            continue
        try:
            transformed = _transform(rec)
        except Exception as e:
            errors.append({'index': idx, 'reason': f'transform error: {e}'})
            continue
        valid_records.append(transformed)
    # Aggregate
    aggregation = {}
    for rec in valid_records:
        aggregation = _aggregate(aggregation, rec)
    # Compute averages
    for key, stats in aggregation.items():
        if stats['count'] > 0:
            stats['average'] = stats['sum'] / stats['count']
        else:
            stats['average'] = None
    # Prepare result
    result = {
        'processed': len(valid_records),
        'errors': errors,
        'aggregation': aggregation,
        'summary': {
            'total': len(records),
            'valid': len(valid_records),
            'invalid': len(errors),
        }
    }
    return result

