import json
from typing import Any, Dict, Iterable, List, Optional

def process_records(records: Iterable[Dict[str, Any]], required_fields: List[str], max_depth: int = 3) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record:
                return False
        return True

    def _flatten(d: Dict[str, Any], depth: int = 0) -> Dict[str, Any]:
        if depth > max_depth:
            return {}
        result = {}
        for k, v in d.items():
            if isinstance(v, dict):
                nested = _flatten(v, depth + 1)
                for nk, nv in nested.items():
                    result[f"{k}.{nk}"] = nv
            else:
                result[k] = v
        return result

    def _aggregate(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for rec in records:
            for k, v in rec.items():
                if k not in agg:
                    agg[k] = v
                else:
                    if isinstance(v, (int, float)) and isinstance(agg[k], (int, float)):
                        agg[k] += v
                    else:
                        agg[k] = [agg[k], v] if not isinstance(agg[k], list) else agg[k] + [v]
        return agg

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []

    for rec in records:
        if not isinstance(rec, dict):
            continue
        if _validate(rec):
            flat = _flatten(rec)
            valid_records.append(flat)
        else:
            invalid_records.append(rec)

    aggregated = _aggregate(valid_records)

    result = {
        "valid_count": len(valid_records),
        "invalid_count": len(invalid_records),
        "aggregated": aggregated,
        "details": {
            "max_depth": max_depth,
            "required_fields": required_fields,
        },
    }

    return result

