            return datetime.datetime.strptime(date_str, "%Y-%m-%d").date()
        except Exception:
            return None

    def _validate_row(row: Dict[str, str]) -> bool:
        required = ["order_id", "product", "quantity", "price", "date"]
        for field in required:
            if field not in row or not row[field]:
                return False
        if not row["quantity"].isdigit():
            return False
        try:
            float(row["price"])
        except Exception:
            return False
        if _parse_date(row["date"]) is None:
            return False
        return True

    def _aggregate_by_product(rows: List[Dict[str, str]]) -> Dict[str, Dict[str, Any]]:
        agg: Dict[str, Dict[str, Any]] = {}
        for r in rows:
            prod = r["product"]
            qty = int(r["quantity"])
            price = float(r["price"])
            if prod not in agg:
                agg[prod] = {"total_qty": 0, "total_sales": 0.0, "orders": 0}
            agg[prod]["total_qty"] += qty
            agg[prod]["total_sales"] += qty * price
            agg[prod]["orders"] += 1
        return agg

    def _compute_metrics(agg: Dict[str, Dict[str, Any]]) -> Dict[str, Any]:
        metrics: Dict[str, Any] = {}
        for prod, data in agg.items():
            avg_price = data["total_sales"] / data["total_qty"] if data["total_qty"] else 0.0
            metrics[prod] = {
                "total_quantity": data["total_qty"],
                "total_sales": round(data["total_sales"], 2),
                "average_price": round(avg_price, 2),
                "order_count": data["orders"],
            }
        return metrics

    import datetime
    valid_rows: List[Dict[str, str]] = []
    errors: List[Tuple[int, str]] = []

    for idx, row in enumerate(csv_rows):
        if _validate_row(row):
            valid_rows.append(row)
        else:
            errors.append((idx, f"invalid row at index {idx}"))

    agg = _aggregate_by_product(valid_rows)
    metrics = _compute_metrics(agg)

    summary = {
        "total_rows": len(csv_rows),
        "valid_rows": len(valid_rows),
        "invalid_rows": len(errors),
        "products": metrics,
        "errors": errors,
    }

    return summary

