import json
from typing import Any, Dict, Iterable, List, Optional

def process_records(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Optional[Dict[str, Any]] = None,
    batch_size: int = 100,
) -> Dict[str, Any]:
    # nested functions
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _apply_transform(record: Dict[str, Any]) -> Dict[str, Any]:
        if not transform_map:
            return record
        transformed = dict(record)
        for key, func in transform_map.items():
            if key in transformed:
                try:
                    transformed[key] = func(transformed[key])
                except Exception:
                    transformed[key] = None
        return transformed

    def _aggregate(batch: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {"count": 0, "sum": 0, "max": None, "min": None}
        for rec in batch:
            agg["count"] += 1
            val = rec.get("value")
            if isinstance(val, (int, float)):
                agg["sum"] += val
                if agg["max"] is None or val > agg["max"]:
                    agg["max"] = val
                if agg["min"] is None or val < agg["min"]:
                    agg["min"] = val
        return agg

    processed: List[Dict[str, Any]] = []
    batch: List[Dict[str, Any]] = []
    stats: List[Dict[str, Any]] = []

    for rec in records:
        if not isinstance(rec, dict):
            continue
        if not _validate(rec):
            continue
        rec = _apply_transform(rec)
        batch.append(rec)
        if len(batch) >= batch_size:
            agg = _aggregate(batch)
            stats.append(agg)
            processed.extend(batch)
            batch.clear()

    if batch:
        agg = _aggregate(batch)
        stats.append(agg)
        processed.extend(batch)

    result: Dict[str, Any] = {
        "total_records": len(processed),
        "batches": len(stats),
        "stats": stats,
        "data": processed,
    }

    try:
        json.dumps(result)
    except Exception:
        result["json_serializable"] = False
    else:
        result["json_serializable"] = True

    return result

