from typing import Any, Dict, Iterable, List, Optional

def process_records(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_funcs: Optional[Dict[str, Any]] = None,
    max_records: Optional[int] = None,
) -> Dict[str, Any]:
    # Validate input types
    if not isinstance(records, Iterable):
        raise TypeError("records must be an iterable of dicts")
    if not isinstance(required_fields, list):
        raise TypeError("required_fields must be a list")
    if transform_funcs is not None and not isinstance(transform_funcs, dict):
        raise TypeError("transform_funcs must be a dict or None")
    if max_records is not None and (not isinstance(max_records, int) or max_records <= 0):
        raise ValueError("max_records must be a positive integer or None")

    processed: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    count = 0

    def _validate_record(rec: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in rec:
                return False
        return True

    def _apply_transforms(rec: Dict[str, Any]) -> Dict[str, Any]:
        out = dict(rec)
        for key, func in (transform_funcs or {}).items():
            if key in out:
                try:
                    out[key] = func(out[key])
                except Exception:
                    out[key] = None
        return out

    for rec in records:
        if not isinstance(rec, dict):
            errors.append({"error": "record not a dict", "record": rec})
            continue
        if not _validate_record(rec):
            errors.append({"error": "missing required fields", "record": rec})
            continue
        transformed = _apply_transforms(rec)
        processed.append(transformed)
        count += 1
        if max_records is not None and count >= max_records:
            break

    summary = {
        "total_records": count,
        "errors": len(errors),
        "processed": processed,
        "error_details": errors,
    }

    return summary

