from typing import Any, Dict, List, Optional, Tuple


def process_sales_data(
    records: List[Dict[str, Any]],
    currency: str = "USD",
    min_amount: float = 0.0,
    max_amount: Optional[float] = None,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = {"id", "date", "amount", "currency", "region"}
        if not isinstance(rec, dict):
            return False
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], (int, str)):
            return False
        if not isinstance(rec["date"], str):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if not isinstance(rec["currency"], str):
            return False
        if not isinstance(rec["region"], str):
            return False
        return True

    def _normalize_date(date_str: str) -> str:
        parts = date_str.split("-")
        if len(parts) != 3:
            return date_str
        year, month, day = parts
        try:
            int(year)
            int(month)
            int(day)
        except ValueError:
            return date_str
        return f"{year}-{month.zfill(2)}-{day.zfill(2)}"

    def _convert_currency(amount: float, src: str, tgt: str) -> float:
        rates = {
            ("USD", "EUR"): 0.85,
            ("EUR", "USD"): 1.18,
            ("USD", "GBP"): 0.75,
            ("GBP", "USD"): 1.33,
        }
        if src == tgt:
            return amount
        key = (src, tgt)
        rate = rates.get(key)
        if rate is None:
            return amount
        return amount * rate

    def _aggregate_by_region(data: List[Dict[str, Any]]) -> Dict[str, Dict[str, Any]]:
        region_stats: Dict[str, Dict[str, Any]] = {}
        for rec in data:
            reg = rec["region"]
            amt = rec["amount"]
            if reg not in region_stats:
                region_stats[reg] = {"count": 0, "total": 0.0, "min": amt, "max": amt}
            stats = region_stats[reg]
            stats["count"] += 1
            stats["total"] += amt
            if amt < stats["min"]:
                stats["min"] = amt
            if amt > stats["max"]:
                stats["max"] = amt
        return region_stats

    def _filter_by_amount(data: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for rec in data:
            amt = rec["amount"]
            if amt < min_amount:
                continue
            if max_amount is not None and amt > max_amount:
                continue
            filtered.append(rec)
        return filtered

    cleaned: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, rec in enumerate(records):
        if not _validate_record(rec):
            errors.append((idx, "invalid structure"))
            continue
        rec["date"] = _normalize_date(rec["date"])
        rec["amount"] = _convert_currency(rec["amount"], rec["currency"], currency)
        rec["currency"] = currency
        cleaned.append(rec)

    cleaned = _filter_by_amount(cleaned)
    region_summary = _aggregate_by_region(cleaned)

    overall = {
        "total_records": len(records),
        "valid_records": len(cleaned),
        "errors": errors,
        "region_summary": region_summary,
        "currency": currency,
    }

    return overall

