from typing import List, Dict, Any, Optional, Tuple

def analyze_transactions(
    transactions: List[Dict[str, Any]],
    min_amount: float = 0.0,
    categories: Optional[List[str]] = None,
) -> Dict[str, Any]:
    def _normalize_amount(val: Any) -> float:
        try:
            return float(val)
        except Exception:
            return 0.0

    def _is_valid_transaction(tx: Dict[str, Any]) -> bool:
        required = {'id', 'amount', 'category', 'timestamp'}
        if not isinstance(tx, dict):
            return False
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx['id'], (int, str)):
            return False
        if _normalize_amount(tx['amount']) < min_amount:
            return False
        if categories is not None and tx['category'] not in categories:
            return False
        return True

    def _aggregate_by_category(
        acc: Dict[str, Dict[str, float]], tx: Dict[str, Any]
    ) -> None:
        cat = tx['category']
        amt = _normalize_amount(tx['amount'])
        if cat not in acc:
            acc[cat] = {'total': 0.0, 'count': 0}
        acc[cat]['total'] += amt
        acc[cat]['count'] += 1

    def _compute_summary(
        acc: Dict[str, Dict[str, float]]
    ) -> List[Dict[str, Any]]:
        result: List[Dict[str, Any]] = []
        for cat, data in acc.items():
            avg = data['total'] / data['count'] if data['count'] else 0.0
            result.append(
                {
                    'category': cat,
                    'total_amount': data['total'],
                    'transaction_count': data['count'],
                    'average_amount': avg,
                }
            )
        result.sort(key=lambda x: x['total_amount'], reverse=True)
        return result

    def _top_categories(
        summary: List[Dict[str, Any]], n: int = 5
    ) -> List[Dict[str, Any]]:
        return summary[:n]

    processed: List[Dict[str, Any]] = []
    for tx in transactions:
