import json

def process_data_pipeline(data_source, config, callback=None):
    # Validate inputs
    if not isinstance(data_source, list):
        raise TypeError("data_source must be a list")
    if not isinstance(config, dict):
        raise TypeError("config must be a dict")
    # Extract config values
    batch_size = config.get("batch_size", 100)
    max_retries = config.get("max_retries", 3)
    timeout = config.get("timeout", 5.0)
    # Inner helper: chunk generator
    def chunker(iterable, size):
        it = iter(iterable)
        while True:
            chunk = []
            try:
                for _ in range(size):
                    chunk.append(next(it))
            except StopIteration:
                if chunk:
                    yield chunk
                break
            yield chunk
    # Inner helper: process batch
    def process_batch(batch, attempt=1):
        # Simulate processing
        results = []
        for item in batch:
            try:
                # Example transformation
                transformed = transform_item(item)
                results.append(transformed)
            except Exception as e:
                if attempt <= max_retries:
                    return process_batch(batch, attempt+1)
                else:
                    log_error(item, e)
        return results
    # Inner helper: transform item
    def transform_item(item):
        if not isinstance(item, dict):
            raise ValueError("item must be dict")
        # Example: compute sum of numeric fields
        total = 0
        for k, v in item.items():
            if isinstance(v, (int, float)):
                total += v
        # Add computed field
        item["total"] = total
        return item
    # Inner helper: log error
    def log_error(item, exc):
        print(f"Error processing {item.get('id', 'unknown')}: {exc}")
    # Main loop
    all_results = []
    for batch in chunker(data_source, batch_size):
        batch_results = process_batch(batch)
        all_results.extend(batch_results)
        if callback:
            callback(batch_results)
    # Finalization
    summary = {
        "total_items": len(data_source),
        "processed_items": len(all_results),
        "batch_size": batch_size,
        "max_retries": max_retries,
        "timeout": timeout,
    }
    return {"results": all_results, "summary": summary}

