import json
from typing import Any, Dict, Iterable, List, Optional


def process_data(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    max_length: int = 255,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _truncate(record: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = {}
        for k, v in record.items():
            if isinstance(v, str) and len(v) > max_length:
                new_rec[k] = v[:max_length]
            else:
                new_rec[k] = v
        return new_rec

    def _compute_stats(valid_records: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {"count": len(valid_records), "fields": {}}
        for rec in valid_records:
            for k, v in rec.items():
                if k not in stats["fields"]:
                    stats["fields"][k] = {"type": type(v).__name__, "unique": set()}
                stats["fields"][k]["unique"].add(v)
        for k, info in stats["fields"].items():
            info["unique_count"] = len(info["unique"])
            del info["unique"]
        return stats

    def _serialize(records: List[Dict[str, Any]]) -> str:
        return json.dumps(records, ensure_ascii=False, indent=2)

    valid: List[Dict[str, Any]] = []
    invalid: List[Dict[str, Any]] = []

    for rec in records:
        if not isinstance(rec, dict):
            invalid.append({"error": "not a dict", "record": rec})
            continue
        if _validate(rec):
            truncated = _truncate(rec)
            valid.append(truncated)
        else:
            invalid.append({"error": "missing required field", "record": rec})

    stats = _compute_stats(valid)

    result: Dict[str, Any] = {
        "valid_count": len(valid),
        "invalid_count": len(invalid),
        "stats": stats,
        "valid_records": _serialize(valid),
        "invalid_records": _serialize(invalid),
    }

    return result

