from typing import Any, Dict, List, Tuple, Optional


def process_dataset(
    data: List[Dict[str, Any]],
    config: Dict[str, Any],
) -> Dict[str, Any]:
    # Helper to log messages
    def _log(msg: str) -> None:
        if config.get("verbose"):
            print(msg)

    # Validate a single row
    def _validate(row: Dict[str, Any]) -> None:
        required = config.get("required_fields", [])
        for field in required:
            if field not in row:
                raise ValueError(f\"Missing required field: {field}\")
        # Example type checks
        if "age" in row and not isinstance(row["age"], int):
            raise TypeError("age must be int")
        if "score" in row and not isinstance(row["score"], (int, float)):
            raise TypeError("score must be numeric")

    # Transform a row according to config
    def _transform(row: Dict[str, Any]) -> Dict[str, Any]:
        new_row = {}
        for key, val in row.items():
            if key in config.get("rename_fields", {}):
                new_key = config["rename_fields"][key]
            else:
                new_key = key
            # Normalize string fields
            if isinstance(val, str):
                val = val.strip().lower()
            new_row[new_key] = val
        # Add computed field
        if "age" in new_row:
            new_row["is_adult"] = new_row["age"] >= 18
        return new_row

    # Aggregate transformed rows
    def _aggregate(rows: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {}
        total_age = 0
        count_age = 0
        scores: List[float] = []
        for r in rows:
            if "age" in r:
                total_age += r["age"]
                count_age += 1
            if "score" in r:
                scores.append(float(r["score"]))
        stats["average_age"] = total_age / count_age if count_age else None
        stats["score_min"] = min(scores) if scores else None
        stats["score_max"] = max(scores) if scores else None
        stats["score_avg"] = sum(scores) / len(scores) if scores else None
        return stats

    # Main processing
    validated_rows: List[Dict[str, Any]] = []
    error_log: List[Dict[str, Any]] = []

    for idx, row in enumerate(data):
        try:
            _log(f\"Validating row {idx}\")
            _validate(row)
            validated_rows.append(row)
        except Exception as exc:
            _log(f\"Error in row {idx}: {exc}\")
            error_log.append({"index": idx, "error": str(exc)})

    _log(f\"Validated {len(validated_rows)} out of {len(data)} rows\")

    transformed_rows: List[Dict[str, Any]] = []
    for idx, row in enumerate(validated_rows):
        try:
            _log(f\"Transforming row {idx}\")
            transformed_rows.append(_transform(row))
        except Exception as exc:
            _log(f\"Transformation error in row {idx}: {exc}\")
            error_log.append({"index": idx, "error": f\"transform: {exc}\"})

    _log(f\"Transformed {len(transformed_rows)} rows\")

    aggregated_stats = _aggregate(transformed_rows)

    result: Dict[str, Any] = {
        "total_rows": len(data),
        "validated_rows": len(validated_rows),
        "transformed_rows": len(transformed_rows),
        "errors": error_log,
        "aggregated_stats": aggregated_stats,
    }

    _log("Processing complete")
    return result

