import json
from typing import Any, Dict, Iterable, List, Optional

def process_dataset(
    data: Iterable[Dict[str, Any]],
    required_fields: List[str],
    field_mappings: Optional[Dict[str, str]] = None,
    max_rows: Optional[int] = None,
) -> Dict[str, Any]:
    def _validate(row: Dict[str, Any]) -> bool:
        for f in required_fields:
            if f not in row or row[f] is None:
                return False
        return True

    def _transform(row: Dict[str, Any]) -> Dict[str, Any]:
        new_row: Dict[str, Any] = {}
        for k, v in row.items():
            new_key = field_mappings.get(k, k) if field_mappings else k
            if isinstance(v, str):
                new_row[new_key] = v.strip()
            else:
                new_row[new_key] = v
        return new_row

    def _aggregate(stats: Dict[str, Any], row: Dict[str, Any]) -> None:
        for k, v in row.items():
            if isinstance(v, (int, float)):
                stats[k] = stats.get(k, 0) + v
            else:
                stats.setdefault(k, set()).add(v)

    def _compute_median(values: List[float]) -> float:
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    def _log_error(msg: str) -> None:
        # Simple error logger; could be extended
        print(f"[ERROR] {msg}")

    processed: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {}
    numeric_acc: Dict[str, List[float]] = {}
    count = 0

    for r in data:
        try:
            if not _validate(r):
                continue
            t = _transform(r)
            processed.append(t)
            _aggregate(stats, t)
            for k, v in t.items():
                if isinstance(v, (int, float)):
                    numeric_acc.setdefault(k, []).append(float(v))
            count += 1
            if max_rows and count >= max_rows:
                break
        except Exception as e:
            _log_error(f"Failed to process row {r}: {e}")

    # Convert sets to lists in stats
    for k, v in stats.items():
        if isinstance(v, set):
            stats[k] = list(v)

    # Compute median for numeric fields
    for k, vals in numeric_acc.items():
        stats[f"{k}_median"] = _compute_median(vals)

    return {
        "processed_rows": processed,
        "row_count": count,
        "statistics": stats,
    }

