import json
from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_data(
    data: Iterable[Dict[str, Any]],
    key: str,
    value_key: str,
    threshold: Optional[float] = None,
    max_items: Optional[int] = None,
) -> Dict[str, Any]:
    # Validate inputs
    if not isinstance(data, Iterable):
        raise TypeError("data must be an iterable of dicts")
    if not isinstance(key, str) or not key:
        raise ValueError("key must be a non-empty string")
    if not isinstance(value_key, str) or not value_key:
        raise ValueError("value_key must be a non-empty string")
    if threshold is not None and not isinstance(threshold, (int, float)):
        raise TypeError("threshold must be a number or None")
    if max_items is not None and (not isinstance(max_items, int) or max_items <= 0):
        raise ValueError("max_items must be a positive integer or None")

    # Helper to extract numeric value
    def _extract_value(item: Dict[str, Any]) -> Optional[float]:
        val = item.get(value_key)
        try:
            return float(val)
        except (TypeError, ValueError):
            return None

    # Group items by key
    groups: Dict[Any, List[Dict[str, Any]]] = {}
    for item in data:
        if not isinstance(item, dict):
            continue
        k = item.get(key)
        if k is None:
            continue
        groups.setdefault(k, []).append(item)

    # Process each group
    results: List[Dict[str, Any]] = []
    for k, items in groups.items():
        numeric_vals = [_extract_value(it) for it in items]
        numeric_vals = [v for v in numeric_vals if v is not None]
        if not numeric_vals:
            continue
        avg = sum(numeric_vals) / len(numeric_vals)
        total = sum(numeric_vals)
        count = len(numeric_vals)
        max_val = max(numeric_vals)
        min_val = min(numeric_vals)
        # Apply threshold filter if provided
        if threshold is not None and avg < threshold:
            continue
        group_result = {
            "key": k,
            "count": count,
            "average": avg,
            "total": total,
            "max": max_val,
            "min": min_val,
            "sample": items[:3],
        }
        results.append(group_result)

    # Sort results by average descending
    results.sort(key=lambda r: r["average"], reverse=True)

    # Limit number of items if requested
    if max_items is not None:
        results = results[:max_items]

    # Prepare final output
    output = {
        "summary": {
            "total_groups": len(groups),
            "total_items": sum(len(v) for v in groups.values()),
            "filtered_groups": len(results),
        },
        "data": results,
    }
    return output

