import datetime
from typing import List, Dict, Any, Tuple, Optional

def process_transactions(
    transactions: List[Dict[str, Any]],
    start_date: Optional[datetime.date] = None,
    end_date: Optional[datetime.date] = None,
    min_amount: Optional[float] = None,
    max_amount: Optional[float] = None,
) -> Dict[str, Any]:
    def _parse_date(d):
        if isinstance(d, str):
            try:
                return datetime.datetime.strptime(d, "%Y-%m-%d").date()
            except ValueError:
                return None
        if isinstance(d, datetime.date):
            return d
        return None

    def _validate(tx):
        required = ["id", "date", "amount", "currency"]
        for r in required:
            if r not in tx:
                return False
        if not isinstance(tx["id"], int):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if not isinstance(tx["currency"], str):
            return False
        d = _parse_date(tx["date"])
        if d is None:
            return False
        return True

    def _filter(tx):
        d = _parse_date(tx["date"])
        if d is None:
            return False
        if start_date and d < start_date:
            return False
        if end_date and d > end_date:
            return False
        amt = float(tx["amount"])
        if min_amount is not None and amt < min_amount:
            return False
        if max_amount is not None and amt > max_amount:
            return False
        return True

    def _group_by_currency(txs):
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for t in txs:
            cur = t["currency"]
            groups.setdefault(cur, []).append(t)
        return groups

    def _aggregate(group):
        total = 0.0
        count = 0
        for t in group:
            total += float(t["amount"])
            count += 1
        avg = total / count if count else 0.0
        return {"count": count, "total": total, "average": avg}

    valid_txs: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for tx in transactions:
        if not _validate(tx):
            errors.append((tx.get("id", -1), "validation_failed"))
            continue
        if not _filter(tx):
            errors.append((tx["id"], "filter_failed"))
            continue
        valid_txs.append(tx)

    grouped = _group_by_currency(valid_txs)
    summary: Dict[str, Any] = {}
    for cur, group in grouped.items():
        summary[cur] = _aggregate(group)

    result = {
        "total_transactions": len(transactions),
        "valid_transactions": len(valid_txs),
        "invalid_transactions": len(errors),
        "summary_by_currency": summary,
        "errors": [{"id": e[0], "reason": e[1]} for e in errors],
    }
    return result

