import csv
from collections import defaultdict
from typing import Dict, List, Any, Tuple


def process_transactions(file_path: str, threshold: float = 0.0) -> Dict[str, Any]:
    def _validate_row(row: Dict[str, str]) -> Tuple[bool, str]:
        required = ['id', 'date', 'amount', 'category']
        for field in required:
            if field not in row or not row[field]:
                return False, f\"Missing field {field}\"
        try:
            float(row['amount'])
        except ValueError:
            return False, f\"Invalid amount {row['amount']}\"
        return True, ""

    def _parse_amount(val: str) -> float:
        try:
            return float(val)
        except ValueError:
            return 0.0

    def _categorize(amount: float) -> str:
        if amount < 0:
            return 'refund'
        elif amount < threshold:
            return 'small'
        else:
            return 'large'

    totals: Dict[str, float] = defaultdict(float)
    category_counts: Dict[str, int] = defaultdict(int)
    errors: List[str] = []
    processed: List[Dict[str, Any]] = []

    try:
        with open(file_path, newline='', encoding='utf-8') as csvfile:
            reader = csv.DictReader(csvfile)
            for idx, row in enumerate(reader, start=1):
                valid, msg = _validate_row(row)
                if not valid:
                    errors.append(f\"Row {idx}: {msg}\")
                    continue
                amt = _parse_amount(row['amount'])
                cat = _categorize(amt)
                totals[cat] += amt
                category_counts[cat] += 1
                processed.append({
                    'id': row['id'],
                    'date': row['date'],
                    'amount': amt,
                    'category': cat,
                    'original_category': row['category'],
                })
    except FileNotFoundError:
        return {
            'status': 'error',
            'message': f'File {file_path} not found',
            'errors': ['File not found'],
        }
    except Exception as e:
        return {
            'status': 'error',
            'message': str(e),
            'errors': [str(e)],
        }

    summary = {
        'total_transactions': len(processed),
        'total_amount': sum(totals.values()),
        'category_totals': dict(totals),
        'category_counts': dict(category_counts),
        'errors': errors,
    }
    return summary

