import datetime
from typing import Any, Dict, List, Optional


def analyze_transactions(transactions: List[Dict[str, Any]]) -> Dict[str, Any]:
    # Validate input type
    if not isinstance(transactions, list):
        raise TypeError("transactions must be a list")
    # Helper to validate a single transaction
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "amount", "timestamp", "type"}
        if not isinstance(tx, dict):
            return False
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], int):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        try:
            datetime.datetime.fromisoformat(tx["timestamp"])
        except Exception:
            return False
        if tx["type"] not in {"debit", "credit"}:
            return False
        return True
    # Separate valid and invalid transactions
    valid_txs: List[Dict[str, Any]] = []
    invalid_txs: List[Dict[str, Any]] = []
    for tx in transactions:
        if _validate(tx):
            valid_txs.append(tx)
        else:
            invalid_txs.append(tx)
    # Categorize transactions by type
    categories: Dict[str, List[Dict[str, Any]]] = {"debit": [], "credit": []}
    for tx in valid_txs:
        categories[tx["type"]].append(tx)
    # Compute totals per category
    totals: Dict[str, float] = {"debit": 0.0, "credit": 0.0}
    for cat, txs in categories.items():
        for tx in txs:
            totals[cat] += float(tx["amount"])
    # Detect duplicate transaction IDs
    def _detect_duplicates(txs: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        seen: Dict[int, Dict[str, Any]] = {}
        duplicates: List[Dict[str, Any]] = []
        for tx in txs:
            tid = tx["id"]
            if tid in seen:
                duplicates.append(tx)
            else:
                seen[tid] = tx
        return duplicates
    duplicate_txs = _detect_duplicates(valid_txs)
    # Aggregate by day
    def _aggregate_by_day(txs: List[Dict[str, Any]]) -> Dict[str, float]:
        day_totals: Dict[str, float] = {}
        for tx in txs:
            day = tx["timestamp"][:10]  # YYYY-MM-DD
            day_totals[day] = day_totals.get(day, 0.0) + float(tx["amount"])
        return day_totals
    day_totals = _aggregate_by_day(valid_txs)
    # Aggregate by month
    def _aggregate_by_month(txs: List[Dict[str, Any]]) -> Dict[str, float]:
        month_totals: Dict[str, float] = {}
        for tx in txs:
            month = tx["timestamp"][:7]  # YYYY-MM
            month_totals[month] = month_totals.get(month, 0.0) + float(tx["amount"])
        return month_totals
    month_totals = _aggregate_by_month(valid_txs)
    # Compute average transaction amount per category
    def _compute_average(txs: List[Dict[str, Any]]) -> float:
        if not txs:
            return 0.0
        total = sum(float(tx["amount"]) for tx in txs)
        return total / len(txs)
    averages: Dict[str, float] = {
        "debit": _compute_average(categories["debit"]),
        "credit": _compute_average(categories["credit"]),
    }
    # Detect anomalies: transactions exceeding threshold
    threshold = 10000.0
    anomalies: List[Dict[str, Any]] = []
    for cat, txs in categories.items():
        for tx in txs:
            if abs(float(tx["amount"])) > threshold:
                anomalies.append(tx)
    # Build report dictionary
    report: Dict[str, Any] = {
        "total_transactions": len(transactions),
        "valid_transactions": len(valid_txs),
        "invalid_transactions": len(invalid_txs),
        "duplicate_transactions": len(duplicate_txs),
        "totals": totals,
        "averages": averages,
        "day_totals": day_totals,
        "month_totals": month_totals,
        "anomalies": anomalies,
    }
    # Return the report
    return report

