    word_counts: Dict[str, int] = {}
    doc_word_lists: Dict[str, List[str]] = {}

    def _normalize(word: str) -> str:
        w = word.strip().lower()
        if len(w) < min_word_len or len(w) > max_word_len:
            return ""
        return w

    def _process_document(doc_id: str, words: Iterable[str]) -> None:
        local_set: set = set()
        local_list: List[str] = []
        for raw in words:
            w = _normalize(str(raw))
            if not w or w in stop_set:
                continue
            if w not in local_set:
                local_set.add(w)
                local_list.append(w)
                word_counts[w] = word_counts.get(w, 0) + 1
        doc_word_lists[doc_id] = local_list

    for doc_id, words in documents.items():
        _process_document(str(doc_id), words)

    total_docs = len(documents)
    total_unique_words = len(word_counts)

    def _top_words(n: int) -> List[Tuple[str, int]]:
        return sorted(word_counts.items(), key=lambda kv: (-kv[1], kv[0]))[:n]

    top_words = _top_words(top_n)

    def _compute_tf_idf(doc_id: str) -> Dict[str, float]:
        tf_idf: Dict[str, float] = {}
        doc_words = doc_word_lists.get(doc_id, [])
        doc_len = len(doc_words)
        if doc_len == 0:
