        for w in set(doc_words):
            tf = doc_words.count(w) / doc_len
            df = sum(1 for d in doc_word_lists.values() if w in d)
            idf = 0.0
            if df > 0:
                idf = math.log(total_docs / df)
            tf_idf[w] = tf * idf
        return tf_idf

    import math
    tf_idf_scores: Dict[str, Dict[str, float]] = {}
    for doc_id in documents:
        tf_idf_scores[doc_id] = _compute_tf_idf(doc_id)

    def _most_informative_words(n: int) -> List[Tuple[str, float]]:
        aggregate: Dict[str, float] = {}
        for scores in tf_idf_scores.values():
            for w, v in scores.items():
                aggregate[w] = aggregate.get(w, 0.0) + v
        return sorted(aggregate.items(), key=lambda kv: (-kv[1], kv[0]))[:n]

    most_informative = _most_informative_words(top_n)

    result: Dict[str, Any] = {
        "total_documents": total_docs,
        "total_unique_words": total_unique_words,
        "top_words_by_frequency": top_words,
        "most_informative_words": most_informative,
        "document_word_lists": doc_word_lists,
        "tf_idf_scores": tf_idf_scores,
    }
    return result

