                agg[tag]["count"] += 1
                agg[tag]["sum"] += rec["value"]
                agg[tag]["ids"].append(rec["id"])
        return agg

    def _compute_stats(agg: Dict[str, Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {}
        for tag, data in agg.items():
            avg = data["sum"] / data["count"] if data["count"] else 0.0
            stats[tag] = {"average": avg, "max_id": max(data["ids"]) if data["ids"] else None}
        return stats

    valid_records: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

