            valid_records.append(_normalize(rec))
        else:
            errors.append({"record": rec, "error": "validation_failed"})

    aggregated = _aggregate_by_tag(valid_records)
    statistics = _compute_stats(aggregated)

    result: Dict[str, Any] = {
