def process_transactions(file_path: str, threshold: float) -> Dict[str, Any]:
    import csv
    from collections import defaultdict
    from datetime import datetime

    def _parse_row(row: Dict[str, str]) -> Optional[Dict[str, Any]]:
        try:
            date = datetime.strptime(row["date"], "%Y-%m-%d")
            amount = float(row["amount"])
            category = row["category"].strip()
            if not category:
                return None
            return {"date": date, "amount": amount, "category": category}
        except (KeyError, ValueError):
            return None

    def _group_by_category(records: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups = defaultdict(list)
        for rec in records:
            groups[rec["category"]].append(rec)
        return groups

    def _summarize_group(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = sum(r["amount"] for r in records)
        count = len(records)
        avg = total / count if count else 0.0
        dates = [r["date"] for r in records]
        earliest = min(dates) if dates else None
        latest = max(dates) if dates else None
        return {
            "total": total,
            "count": count,
            "average": avg,
            "earliest": earliest.isoformat() if earliest else None,
            "latest": latest.isoformat() if latest else None,
        }

    records: List[Dict[str, Any]] = []
    with open(file_path, newline='', encoding='utf-8') as f:
        reader = csv.DictReader(f)
        for row in reader:
            rec = _parse_row(row)
            if rec:
                records.append(rec)

    groups = _group_by_category(records)
    summary: Dict[str, Any] = {}
    for cat, recs in groups.items():
        cat_summary = _summarize_group(recs)
        if cat_summary["total"] >= threshold:
            summary[cat] = cat_summary

    return {
        "file": file_path,
        "total_transactions": len(records),
        "categories": len(summary),
        "summary": summary,
    }

