        rec_date = _parse_date(rec["date"])
        if rec_date is None:
            return False
        if start and rec_date < start:
            return False
        if end and rec_date > end:
            return False
        return True

    def _filter_by_amount(rec: Dict[str, Any]) -> bool:
        return rec["amount"] >= min_amount

