        amt = float(rec["amount"])
        totals_by_category[cat] = totals_by_category.get(cat, 0.0) + amt
        d = rec["date"]
        daily_totals[d] = daily_totals.get(d, 0.0) + amt

    sorted_categories = sorted(
        totals_by_category.items(), key=lambda kv: kv[1], reverse=True
    )
    top_categories = [cat for cat, _ in sorted_categories[:5]]

    def _format_date(d: str) -> str:
        try:
            return datetime.datetime.strptime(d, "%Y-%m-%d").strftime("%b %d, %Y")
        except Exception:
            return d

    formatted_daily = { _format_date(k): v for k, v in daily_totals.items() }

    result = {
        "total_records": len(valid_records),
        "total_amount": sum(float(r["amount"]) for r in valid_records),
        "categories": totals_by_category,
        "top_categories": top_categories,
        "daily_totals": formatted_daily,
        "errors": {
            "invalid_records": len(sales_records) - len(valid_records),
        },
    }
    return result

