            return False
        required = {'id', 'category', 'value'}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec['id'], int):
            return False
        if not isinstance(rec['category'], str):
            return False
        if not isinstance(rec['value'], (int, float)):
            return False
        if rec['value'] < 0:
            return False
        return True
    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        rec = dict(rec)
        rec['category'] = rec['category'].strip().lower()
        return rec
    valid = [ _normalize(r) for r in records if _validate(r) ]
    def _group_by_category(rows: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in rows:
            cat = r['category']
            groups.setdefault(cat, []).append(r)
        return groups
    groups = _group_by_category(valid)
    def _stats_for_group(rows: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = sum(r['value'] for r in rows)
        count = len(rows)
        avg = total / count if count else 0.0
        max_val = max(r['value'] for r in rows) if rows else None
        min_val = min(r['value'] for r in rows) if rows else None
        return {'count': count, 'total': total, 'avg': avg, 'max': max_val, 'min': min_val}
    stats = {cat: _stats_for_group(rows) for cat, rows in groups.items()}
    def _top_n(rows: List[Dict[str, Any]], n: int = 5) -> List[Dict[str, Any]]:
        sorted_rows = sorted(rows, key=lambda r: r['value'], reverse=True)
        return sorted_rows[:n]
    all_rows = [r for rows in groups.values() for r in rows]
    top_overall = _top_n(all_rows, n=5)
    def _aggregate_by_id(rows: List[Dict[str, Any]]) -> Dict[int, float]:
        agg: Dict[int, float] = {}
        for r in rows:
            agg[r['id']] = agg.get(r['id'], 0.0) + r['value']
        return agg
    agg_by_id = _aggregate_by_id(all_rows)
    def _detect_duplicates(rows: List[Dict[str, Any]]) -> List[int]:
        seen: set[int] = set()
        dup: List[int] = []
        for r in rows:
            if r['id'] in seen:
                dup.append(r['id'])
            else:
                seen.add(r['id'])
        return dup
    duplicates = _detect_duplicates(all_rows)
    def _format_output() -> Dict[str, Any]:
        return {
            'summary': stats,
            'top_overall': top_overall,
            'aggregate_by_id': agg_by_id,
            'duplicates': duplicates,
            'total_records': len(valid),
            'invalid_records': len(records) - len(valid),
        }
    return _format_output()

