import json
from typing import Any, Dict, Iterable, List, Optional

def process_data_pipeline(
    data: Iterable[Dict[str, Any]],
    filter_func: Optional[Any] = None,
    transform_func: Optional[Any] = None,
    batch_size: int = 100,
) -> Dict[str, Any]:
    # Internal validation of each record
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        required_keys = {"id", "value", "timestamp"}
        if not required_keys.issubset(record.keys()):
            return False
        if not isinstance(record["id"], (int, str)):
            return False
        if not isinstance(record["value"], (int, float)):
            return False
        if not isinstance(record["timestamp"], (int, float)):
            return False
        return True

    # Apply optional filtering
    def _filter(record: Dict[str, Any]) -> bool:
        if filter_func is None:
            return True
        try:
            return bool(filter_func(record))
        except Exception:
            return False

    # Apply optional transformation
    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func is None:
            return record
        try:
            return transform_func(record)
        except Exception:
            return record

    # Batch records for processing
    def _batch(records: List[Dict[str, Any]]) -> List[List[Dict[str, Any]]]:
        batches: List[List[Dict[str, Any]]] = []
        current: List[Dict[str, Any]] = []
        for rec in records:
            current.append(rec)
            if len(current) >= batch_size:
                batches.append(current)
                current = []
        if current:
            batches.append(current)
        return batches

    # Aggregate results from batches
    def _aggregate(batches: List[List[Dict[str, Any]]]) -> Dict[str, Any]:
        total = 0
        sum_values = 0.0
        min_value = None
        max_value = None
        ids: List[Any] = []
        for batch in batches:
            for rec in batch:
                val = rec["value"]
                total += 1
                sum_values += val
                if min_value is None or val < min_value:
                    min_value = val
                if max_value is None or val > max_value:
                    max_value = val
                ids.append(rec["id"])
        avg = sum_values / total if total else None
        return {
            "count": total,
            "average": avg,
            "min": min_value,
            "max": max_value,
            "ids": ids,
        }

    # Main processing loop
    valid_records: List[Dict[str, Any]] = []
    for raw in data:
        if not _validate(raw):
            continue
        if not _filter(raw):
            continue
        transformed = _transform(raw)
        valid_records.append(transformed)

    # Create batches
    batches = _batch(valid_records)

    # Aggregate statistics
    stats = _aggregate(batches)

    # Prepare JSON serializable output
    output: Dict[str, Any] = {
        "statistics": stats,
        "batches_processed": len(batches),
        "batch_size": batch_size,
        "records_included": len(valid_records),
        "records_filtered": len(list(data)) - len(valid_records),
    }

    # Optionally serialize to JSON string
    try:
        output_json = json.dumps(output, indent=2)
        output["json"] = output_json
    except Exception:
        output["json_error"] = "serialization failed"

    return output

