import json
from typing import List, Dict, Any, Optional

def process_records(records: List[Dict[str, Any]], threshold: float = 0.5, *, include_meta: bool = False) -> Dict[str, Any]:
    # inner helper to normalize values
    def _normalize(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip().lower()
        if isinstance(val, (int, float)):
            return float(val)
        return val

    # inner helper to validate record
    def _is_valid(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if 'score' not in rec or 'id' not in rec:
            return False
        try:
            score = float(rec['score'])
        except (TypeError, ValueError):
            return False
        return score >= threshold

    # inner helper to aggregate
    def _aggregate(valid_recs: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for rec in valid_recs:
            key = _normalize(rec['id'])
            if key not in agg:
                agg[key] = {'count': 0, 'total_score': 0.0}
            agg[key]['count'] += 1
            agg[key]['total_score'] += float(rec['score'])
        # compute average
        for key, data in agg.items():
            data['average'] = data['total_score'] / data['count'] if data['count'] else 0.0
        return agg

    # main processing
    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []

    for rec in records:
        if _is_valid(rec):
            valid_records.append(rec)
        else:
            invalid_records.append(rec)

    aggregated = _aggregate(valid_records)

    # build result
    result: Dict[str, Any] = {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'invalid_records': len(invalid_records),
        'aggregated': aggregated,
    }

    # optional metadata
    if include_meta:
        meta = {
            'threshold': threshold,
            'normalized_ids': list(aggregated.keys()),
            'meta_processed': True,
        }
        result['meta'] = meta

    # final cleanup: remove records with zero count
    cleaned = {k: v for k, v in aggregated.items() if v['count'] > 0}

    result['aggregated'] = cleaned

    # return
    return result

