            return False
        if not isinstance(rec["date"], str):
            return False
        if _parse_date(rec["date"]) is None:
            return False
        return True

    def _normalize_currency(code: str) -> str:
        return code.strip().upper()

    def _aggregate_by_currency(records: List[Dict[str, Any]]) -> Dict[str, float]:
        agg: Dict[str, float] = {}
        for rec in records:
            cur = _normalize_currency(rec["currency"])
            amt = float(rec["amount"])
            agg[cur] = agg.get(cur, 0.0) + amt
        return agg

