def analyze_data(records: List[Dict[str, Any]], threshold: float = 0.5) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if "id" not in rec or "value" not in rec:
            return False
        if not isinstance(rec["id"], (int, str)):
            return False
        if not isinstance(rec["value"], (int, float)):
            return False
        return True

    def _normalize_value(val: Any) -> float:
        try:
            return float(val)
        except Exception:
            return 0.0

    def _compute_stats(vals: List[float]) -> Tuple[float, float, int]:
        if not vals:
            return 0.0, 0.0, 0
        total = sum(vals)
        count = len(vals)
        avg = total / count
        variance = sum((x - avg) ** 2 for x in vals) / count
        return avg, variance, count

    def _filter_by_threshold(vals: List[float], thr: float) -> List[float]:
        return [v for v in vals if v >= thr]

    def _group_by_category(recs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in recs:
            cat = r.get("category", "unknown")
            if cat not in groups:
                groups[cat] = []
            groups[cat].append(r)
        return groups

    valid_records: List[Dict[str, Any]] = []
    for rec in records:
        if _validate_record(rec):
            rec["value"] = _normalize_value(rec["value"])
            valid_records.append(rec)

    values = [r["value"] for r in valid_records]
    avg, var, count = _compute_stats(values)
    filtered_values = _filter_by_threshold(values, threshold)
    groups = _group_by_category(valid_records)

    group_stats: Dict[str, Dict[str, Any]] = {}
    for cat, recs in groups.items():
        cat_vals = [r["value"] for r in recs]
        cat_avg, cat_var, cat_count = _compute_stats(cat_vals)
        group_stats[cat] = {
            "average": cat_avg,
            "variance": cat_var,
            "count": cat_count,
            "ids": [r["id"] for r in recs],
