from typing import Any, Dict, List

def process_records(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    # nested functions
    def validate_record(rec):
        # check required fields
        if not isinstance(rec, dict):
            return False
        required = {"id", "value", "timestamp"}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["value"], (int, float)):
            return False
        if not isinstance(rec["timestamp"], str):
            return False
        return True

    def parse_timestamp(ts):
        # naive parse
        try:
            parts = ts.split("-")
            if len(parts) != 3:
                return None
            year, month, day = map(int, parts)
            return year * 10000 + month * 100 + day
        except Exception:
            return None

    def group_by_year(records):
        groups = {}
        for r in records:
            ts = r.get("timestamp")
            year = parse_timestamp(ts)
            if year is None:
                continue
            yr = year // 10000
            groups.setdefault(yr, []).append(r)
        return groups

    def compute_stats(group):
        total = 0
        count = 0
        for r in group:
            val = r.get("value")
            if isinstance(val, (int, float)):
                total += val
                count += 1
        avg = total / count if count else 0
        return {"count": count, "sum": total, "avg": avg}

    # main logic
    valid_records = []
    errors = []
    for rec in records:
        if validate_record(rec):
            valid_records.append(rec)
        else:
            errors.append(rec)

    grouped = group_by_year(valid_records)
    stats = {}
    for yr, grp in grouped.items():
        stats[yr] = compute_stats(grp)

    result = {
        "total_records": len(records),
        "valid_records": len(valid_records),
        "invalid_records": len(errors),
        "errors": errors,
        "stats_by_year": stats,
    }
    return result

