from typing import Any, Dict, Iterable, List, Optional

def process_records(records: Iterable[Dict[str, Any]], required_fields: List[str], transform: Optional[Any] = None) -> Dict[str, Any]:
    # Validate required fields
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record:
                return False
        return True

    # Apply transformation if provided
    def _apply_transform(record: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return record
        try:
            return transform(record)
        except Exception:
            return record

    # Aggregate counts by a key
    def _aggregate(records: List[Dict[str, Any]], key: str) -> Dict[Any, int]:
        counts: Dict[Any, int] = {}
        for rec in records:
            k = rec.get(key)
            if k is not None:
                counts[k] = counts.get(k, 0) + 1
        return counts

    # Write to JSON file
    def _write_json(data: Any, path: str) -> None:
        with open(path, 'w', encoding='utf-8') as f:
            json.dump(data, f, ensure_ascii=False, indent=2)

    valid_records: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for rec in records:
        if not isinstance(rec, dict):
            errors.append({'error': 'not a dict', 'record': rec})
            continue
        if not _validate(rec):
            errors.append({'error': 'missing fields', 'record': rec})
            continue
        transformed = _apply_transform(rec)
        valid_records.append(transformed)

    # Example aggregation by 'category'
    category_counts = _aggregate(valid_records, 'category')

    # Prepare output
    output = {
