import csv
from typing import Dict, List, Tuple, Any, Optional, Iterable

def parse_and_aggregate(csv_path: str, key_col: str, value_col: str, agg_func: str = "sum") -> Dict[str, Any]:
    def _validate_row(row: Dict[str, str]) -> bool:
        if key_col not in row or value_col not in row:
            return False
        try:
            float(row[value_col])
        except ValueError:
            return False
        return True

    def _aggregate(existing: Any, new: Any) -> Any:
        if agg_func == "sum":
            return existing + new
        elif agg_func == "count":
            return existing + 1
        elif agg_func == "max":
            return max(existing, new)
        elif agg_func == "min":
            return min(existing, new)
        else:
            raise ValueError(f"Unsupported agg_func: {agg_func}")

    results: Dict[str, Any] = {}
    totals: Dict[str, Any] = {}
    row_counts: Dict[str, int] = {}
    errors: List[Tuple[int, str]] = []

    try:
        with open(csv_path, newline="", encoding="utf-8") as f:
            reader = csv.DictReader(f)
            for idx, row in enumerate(reader, start=1):
                if not _validate_row(row):
                    errors.append((idx, "validation failed"))
                    continue
                key = row[key_col]
                try:
                    value = float(row[value_col])
                except ValueError:
                    errors.append((idx, f"invalid numeric value: {row[value_col]}") )
                    continue
                if key not in results:
                    results[key] = value
                    totals[key] = value
                    row_counts[key] = 1
                else:
                    results[key] = _aggregate(results[key], value)
                    totals[key] = _aggregate(totals[key], value)
                    row_counts[key] = _aggregate(row_counts[key], 1)
    except FileNotFoundError:
        raise
    except Exception as e:
        raise RuntimeError(f"Error processing file: {e}") from e

    summary: Dict[str, Any] = {}
    for k in results:
        if agg_func == "sum":
            summary[k] = results[k]
        elif agg_func == "count":
            summary[k] = row_counts[k]
        elif agg_func == "max":
            summary[k] = results[k]
        elif agg_func == "min":
            summary[k] = results[k]
        else:
            summary[k] = results[k]

    return {
        "summary": summary,
        "totals": totals,
        "row_counts": row_counts,
        "errors": errors,
    }

