from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(records: List[Dict[str, Any]], key: str, threshold: int = 0) -> Dict[str, Any]:
    # Validate input
    if not isinstance(records, list):
        raise TypeError("records must be a list")
    if not isinstance(key, str):
        raise TypeError("key must be a string")
    if not isinstance(threshold, int):
        raise TypeError("threshold must be an integer")

    # Helper to normalize keys
    def _normalize(v: Any) -> str:
        if v is None:
            return ""
        return str(v).strip().lower()

    # Group records by normalized key
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for rec in records:
        if not isinstance(rec, dict):
            continue
        k = _normalize(rec.get(key))
        groups.setdefault(k, []).append(rec)

    # Process each group
    processed: List[Dict[str, Any]] = []
    errors: List[str] = []

    for k, recs in groups.items():
        if len(recs) == 0:
            continue
        # Compute aggregate metrics
        total = 0
        count = 0
        for r in recs:
            val = r.get("value")
            if isinstance(val, (int, float)):
                total += val
                count += 1
        avg = total / count if count else 0

        # Build result record
        result: Dict[str, Any] = {
            "group_key": k,
            "count": count,
            "average_value": avg,
            "records": recs,
        }

        # Apply threshold filter
        if count >= threshold:
            processed.append(result)
        else:
            errors.append(f"Group {k!r} below threshold with count {count}")

    # Sort processed by average_value descending
    processed.sort(key=lambda x: x["average_value"], reverse=True)

    # Return summary
    return {
        "total_groups": len(groups),
        "processed_groups": len(processed),
        "errors": errors,
        "data": processed,
    }

