import json
from typing import Any, Dict, List, Optional, Callable


def process_dataset(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    optional_fields: Optional[List[str]] = None,
    transform_funcs: Optional[Dict[str, Callable[[Any], Any]]] = None,
    batch_size: int = 1000,
) -> Dict[str, Any]:
    # Validate that required fields are present
    def _validate(rec: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in rec or rec[field] is None:
                return False
        return True

    # Apply transformation functions to a record
    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        if not transform_funcs:
            return rec
        new_rec = dict(rec)
        for field, func in transform_funcs.items():
            if field in new_rec:
                try:
                    new_rec[field] = func(new_rec[field])
                except Exception:
                    new_rec[field] = None
        return new_rec

    # Aggregate a batch of records
    def _aggregate(batch: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {'count': 0}
        for rec in batch:
            agg['count'] += 1
            for field in optional_fields or []:
                val = rec.get(field)
                if val is not None:
                    agg.setdefault(field, []).append(val)
        return agg

    processed: List[Dict[str, Any]] = []
    aggregates: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append({'index': idx, 'error': 'not a dict'})
            continue
        if not _validate(rec):
            errors.append({'index': idx, 'error': 'missing required fields'})
            continue
        rec = _transform(rec)
        processed.append(rec)
        if len(processed) >= batch_size:
            aggregates.append(_aggregate(processed))
            processed.clear()

    if processed:
        aggregates.append(_aggregate(processed))

    summary = {
        'total_records': len(records),
        'valid_records': sum(1 for r in records if isinstance(r, dict) and _validate(r)),
        'invalid_records': len(errors),
        'aggregates': aggregates,
        'errors': errors,
    }

    return summary

