                total += val
                count += 1
                values.append(val)
        avg = total / count if count else None
        aggregates[key] = {
            "count": count,
            "total": total,
            "average": avg,
            "min": min(values) if values else None,
            "max": max(values) if values else None,
        }
    # Build result
    result: typing.Dict[str, typing.Any] = {
        "summary": aggregates,
        "records_processed": len(records),
        "categories": list(groups.keys()),
    }
    # Optional: filter categories with low count
    def _filter_low(count_threshold: int) -> None:
        for k in list(aggregates.keys()):
