import json
from typing import Any, Dict, Iterable, List, Optional

def process_dataset(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Optional[Dict[str, Any]] = None,
    max_records: Optional[int] = None,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record:
                return False
        return True

    def _apply_transform(record: Dict[str, Any]) -> Dict[str, Any]:
        if not transform_map:
            return record
        new_rec = dict(record)
        for key, func in transform_map.items():
            if key in new_rec:
                try:
                    new_rec[key] = func(new_rec[key])
                except Exception:
                    pass
        return new_rec

    def _serialize(record: Dict[str, Any]) -> str:
        try:
            return json.dumps(record, sort_keys=True)
        except Exception:
            return ""

    processed: List[Dict[str, Any]] = []
    seen_hashes: set = set()
    count = 0
    for rec in records:
        if max_records is not None and count >= max_records:
            break
        if not isinstance(rec, dict):
            continue
        if not _validate(rec):
            continue
        rec = _apply_transform(rec)
        rec_hash = _serialize(rec)
        if not rec_hash:
            continue
        if rec_hash in seen_hashes:
            continue
        seen_hashes.add(rec_hash)
        processed.append(rec)
        count += 1

    summary = {
        "total_input": count,
        "unique_records": len(processed),
        "fields_present": {field: sum(1 for r in processed if field in r) for field in required_fields},
    }

    return {
        "records": processed,
        "summary": summary,
    }

