def process_records(records, key, required_fields):
    def _normalize(value):
        if isinstance(value, str):
            return value.strip().lower()
        return value

    def _validate(record):
        missing = [f for f in required_fields if f not in record]
        if missing:
            return False, missing
        return True, None

    def _aggregate(acc, record):
        for k, v in record.items():
            if k not in acc:
                acc[k] = []
            acc[k].append(v)
        return acc

    def _deduplicate(records, key):
        seen = set()
        unique = []
        duplicates = []
        for rec in records:
            k_val = rec.get(key)
            if k_val in seen:
                duplicates.append(rec)
            else:
                seen.add(k_val)
                unique.append(rec)
        return unique, duplicates

    def _compute_key_frequency(records, key):
        freq = {}
        for rec in records:
            k_val = rec.get(key)
            freq[k_val] = freq.get(k_val, 0) + 1
        return freq

    valid_records = []
    errors = []
    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append((idx, "not a dict"))
            continue
        ok, missing = _validate(rec)
        if not ok:
            errors.append((idx, f"missing fields: {missing}"))
            continue
        if key in rec:
            rec[key] = _normalize(rec[key])
        else:
            rec[key] = None
        valid_records.append(rec)

    unique_records, duplicate_records = _deduplicate(valid_records, key)
    freq = _compute_key_frequency(unique_records, key)

    aggregated = {}
    for rec in unique_records:
        aggregated = _aggregate(aggregated, rec)

    stats = {
        "total": len(records),
        "valid": len(valid_records),
        "unique": len(unique_records),
        "duplicates": len(duplicate_records),
        "invalid": len(errors),
        "missing_fields": {f: sum(1 for e in errors if f in e[1]) for f in required_fields},
    }

    return {
        "records": unique_records,
        "duplicates": duplicate_records,
        "aggregated": aggregated,
        "errors": errors,
        "stats": stats,
        "frequency": freq,
    }

