import datetime
from typing import List, Dict, Any, Tuple

def process_transactions(transactions: List[Dict[str, Any]]) -> Dict[str, Any]:
    # Helper to parse dates
    def _parse_date(date_str: str) -> datetime.date:
        try:
            return datetime.datetime.strptime(date_str, "%Y-%m-%d").date()
        except Exception:
            return None

    # Validate a single transaction
    def _validate(tx: Dict[str, Any]) -> Tuple[bool, str]:
        if not isinstance(tx, dict):
            return False, "Transaction is not a dict"
        required = ["id", "amount", "currency", "date", "type"]
        for field in required:
            if field not in tx:
                return False, f"Missing field {field}"
        if not isinstance(tx["id"], int):
            return False, "id must be int"
        if not isinstance(tx["amount"], (int, float)):
            return False, "amount must be numeric"
        if not isinstance(tx["currency"], str):
            return False, "currency must be string"
        if not isinstance(tx["type"], str):
            return False, "type must be string"
        if _parse_date(tx["date"]) is None:
            return False, "invalid date format"
        return True, ""

    # Group by currency
    def _group_by_currency(valid_txs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for tx in valid_txs:
            cur = tx["currency"]
            groups.setdefault(cur, []).append(tx)
        return groups

    # Aggregate per group
    def _aggregate_group(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        earliest = None
        latest = None
        for tx in group:
            amt = float(tx["amount"])
            total += amt
            count += 1
            d = _parse_date(tx["date"])
            if d:
                if earliest is None or d < earliest:
                    earliest = d
                if latest is None or d > latest:
                    latest = d
        avg = total / count if count else 0.0
        return {
            "total_amount": total,
            "count": count,
            "average_amount": avg,
            "earliest_date": earliest.isoformat() if earliest else None,
            "latest_date": latest.isoformat() if latest else None
        }

    # Main processing
    valid_transactions: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, tx in enumerate(transactions):
        ok, msg = _validate(tx)
        if ok:
            valid_transactions.append(tx)
        else:
            errors.append((idx, msg))

    grouped = _group_by_currency(valid_transactions)

    summary: Dict[str, Any] = {}
    for cur, group in grouped.items():
        summary[cur] = _aggregate_group(group)

    result = {
        "summary": summary,
        "errors": errors,
        "total_transactions": len(transactions),
        "valid_transactions": len(valid_transactions),
        "invalid_transactions": len(errors)
    }
    return result

