import json
from typing import Any, Dict, Iterable, List, Optional

def process_data(
    data_source: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[float] = None,
    max_items: int = 1000,
) -> Dict[str, Any]:
    def _validate(row: Dict[str, Any]) -> bool:
        if not isinstance(row, dict):
            return False
        if key_field not in row or value_field not in row:
            return False
        if not isinstance(row[key_field], str):
            return False
        if not isinstance(row[value_field], (int, float)):
            return False
        return True

    def _transform(row: Dict[str, Any]) -> Dict[str, Any]:
        transformed = {
            "id": row[key_field].strip().lower(),
            "value": float(row[value_field]),
            "meta": {k: v for k, v in row.items() if k not in (key_field, value_field)},
        }
        return transformed

    def _aggregate(items: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        for itm in items:
            total += itm["value"]
            count += 1
        avg = total / count if count else 0.0
        return {"total": total, "count": count, "average": avg}

    processed: List[Dict[str, Any]] = []
    for raw in data_source:
        if not _validate(raw):
            continue
        transformed = _transform(raw)
        if threshold is not None and transformed["value"] < threshold:
            continue
        processed.append(transformed)
        if len(processed) >= max_items:
            break

    if not processed:
        return {"status": "empty", "items": []}

    summary = _aggregate(processed)
    result = {
        "status": "ok",
        "items": processed,
        "summary": summary,
    }
    return result

