from typing import Any, Dict, List, Optional, Tuple, Iterable

def process_records(
    records: List[Dict[str, Any]],
    key: str,
    required_fields: List[str],
    transform: Optional[Any] = None,
) -> Dict[str, Any]:
    def _validate(rec: Dict[str, Any]) -> bool:
        for f in required_fields:
            if f not in rec or rec[f] is None:
                return False
        return True

    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return rec
        try:
            return transform(rec)
        except Exception:
            return rec

    def _group_by(records: Iterable[Dict[str, Any]]) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for r in records:
            k = r.get(key)
            if k not in groups:
                groups[k] = []
            groups[k].append(r)
        return groups

    def _stats(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        count = len(group)
        if count == 0:
            return {"count": 0, "avg": None}
        total = 0
        for r in group:
            val = r.get("value")
            if isinstance(val, (int, float)):
                total += val
        avg = total / count if count else None
        return {"count": count, "avg": avg}

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []

    for rec in records:
        if _validate(rec):
            transformed = _transform(rec)
            valid_records.append(transformed)
        else:
            invalid_records.append(rec)

    grouped = _group_by(valid_records)

    stats_by_key: Dict[Any, Dict[str, Any]] = {}
    for k, grp in grouped.items():
        stats_by_key[k] = _stats(grp)

    result: Dict[str, Any] = {
        "valid_count": len(valid_records),
        "invalid_count": len(invalid_records),
        "grouped": grouped,
        "stats": stats_by_key,
    }

    if transform is not None:
        result["transformed"] = True
    else:
        result["transformed"] = False

    return result

