def process_dataset(records, required_fields, date_format="%Y-%m-%d"):
    # Validate a single record
    def _validate(rec):
        missing = [f for f in required_fields if f not in rec]
        if missing:
            return False, f"Missing fields: {missing}"
        return True, None

    # Clean string fields by stripping whitespace
    def _clean(rec):
        cleaned = {}
        for k, v in rec.items():
            if isinstance(v, str):
                cleaned[k] = v.strip()
            else:
                cleaned[k] = v
        return cleaned

    # Transform date strings into datetime.date objects
    def _transform_date(rec):
        if "date" in rec:
            try:
                import datetime
                rec["date"] = datetime.datetime.strptime(rec["date"], date_format).date()
            except Exception:
                rec["date"] = None
        return rec

    # Aggregate statistics for processed records
    def _aggregate(stats, rec):
        stats["total"] += 1
        status = rec.get("status")
        if status == "active":
            stats["active"] += 1
        elif status == "inactive":
            stats["inactive"] += 1
        else:
            stats["unknown_status"] += 1
        return stats

    # Compute field frequency across all records
    def _field_frequencies(recs):
        freq = {}
        for r in recs:
            for k in r:
                freq[k] = freq.get(k, 0) + 1
        return freq

    # Detect duplicate IDs
    def _find_duplicates(recs):
        seen = {}
        duplicates = []
        for r in recs:
            rid = r.get("id")
            if rid is None:
                continue
            if rid in seen:
                duplicates.append(rid)
            else:
                seen[rid] = True
        return list(set(duplicates))

    stats = {"total": 0, "active": 0, "inactive": 0, "unknown_status": 0}
    cleaned_records = []
    errors = []

    for idx, rec in enumerate(records):
        valid, err = _validate(rec)
        if not valid:
            errors.append({"index": idx, "error": err})
            continue
        rec = _clean(rec)
        rec = _transform_date(rec)
        cleaned_records.append(rec)
        stats = _aggregate(stats, rec)

    field_freq = _field_frequencies(cleaned_records)
    duplicates = _find_duplicates(cleaned_records)

    summary = {
        "records_processed": len(cleaned_records),
        "records_failed": len(errors),
        "stats": stats,
        "field_frequencies": field_freq,
        "duplicate_ids": duplicates,
        "errors": errors
    }

    return summary

