import json
from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_data(
    data: Iterable[Dict[str, Any]],
    filter_key: str,
    filter_value: Any,
    transform_func: Optional[Any] = None,
    batch_size: int = 100,
    max_errors: int = 10,
) -> Dict[str, Any]:
    def _filter(item: Dict[str, Any]) -> bool:
        return item.get(filter_key) == filter_value

    def _transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func:
            try:
                return transform_func(item)
            except Exception:
                return item
        return item

    def _serialize(batch: List[Dict[str, Any]]) -> str:
        return json.dumps(batch)

    def _compute_stats(batch: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {}
        for key in batch[0].keys():
            values = [item.get(key) for item in batch]
            stats[key] = {
                "count": sum(1 for v in values if v is not None),
                "unique": len(set(values)),
            }
        return stats

    results: List[Dict[str, Any]] = []
    batches: List[List[Dict[str, Any]]] = []
    current_batch: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, record in enumerate(data):
        if not isinstance(record, dict):
            errors.append((idx, "not a dict"))
            if len(errors) >= max_errors:
                break
            continue
        try:
            if not _filter(record):
                continue
            transformed = _transform(record)
            results.append(transformed)
            current_batch.append(transformed)
            if len(current_batch) >= batch_size:
                batches.append(current_batch)
                current_batch = []
        except Exception as e:
            errors.append((idx, str(e)))
            if len(errors) >= max_errors:
                break

    if current_batch:
        batches.append(current_batch)

    serialized_batches: List[str] = [_serialize(b) for b in batches]
    batch_stats: List[Dict[str, Any]] = [_compute_stats(b) for b in batches]

    summary = {
        "total_records": len(results),
        "batches_created": len(batches),
        "batch_size": batch_size,
        "filter_key": filter_key,
        "filter_value": filter_value,
        "errors_encountered": len(errors),
    }

    return {
        "summary": summary,
        "batches": serialized_batches,
        "batch_stats": batch_stats,
        "raw_results": results,
        "errors": errors,
    }

