from typing import Any, Dict, List, Tuple, Optional

def process_data(
    records: List[Dict[str, Any]],
    schema: Dict[str, type],
    batch_size: int = 100,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors: List[str] = []
        for key, typ in schema.items():
            if key not in record:
                errors.append(f"missing key {key}")
                continue
            val = record[key]
            if not isinstance(val, typ):
                errors.append(f"{key} expected {typ.__name__}, got {type(val).__name__}")
        return (len(errors) == 0, errors)

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        transformed = {}
        for key, val in record.items():
            if isinstance(val, str):
                transformed[key] = val.strip().lower()
            elif isinstance(val, (int, float)):
                transformed[key] = val
            else:
                transformed[key] = str(val)
        return transformed

    def _process_batch(batch: List[Dict[str, Any]]) -> Tuple[List[Dict[str, Any]], List[Tuple[Dict[str, Any], List[str]]]]:
        processed: List[Dict[str, Any]] = []
        failures: List[Tuple[Dict[str, Any], List[str]]] = []
        for rec in batch:
            valid, errs = _validate(rec)
            if not valid:
                failures.append((rec, errs))
                continue
            processed.append(_transform(rec))
        return processed, failures

    total_processed: List[Dict[str, Any]] = []
    total_failures: List[Tuple[Dict[str, Any], List[str]]] = []
    total_records = len(records)
    for start in range(0, total_records, batch_size):
        end = min(start + batch_size, total_records)
        batch = records[start:end]
        proc, fail = _process_batch(batch)
        total_processed.extend(proc)
        total_failures.extend(fail)

    summary = {
        "total_records": total_records,
        "processed": len(total_processed),
        "failed": len(total_failures),
        "errors": {"missing_key": 0, "type_mismatch": 0},
    }
    for _, errs in total_failures:
        for e in errs:
            if e.startswith("missing key"):
                summary["errors"]["missing_key"] += 1
            elif e.startswith("expected"):
                summary["errors"]["type_mismatch"] += 1

    return {
        "summary": summary,
        "data": total_processed,
        "failures": total_failures,
    }

