import json
from typing import Any, Dict, Iterable, List, Optional

def process_data(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Optional[Dict[str, Any]] = None,
    max_items: Optional[int] = None,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in rec or rec[field] is None:
                return False
        return True

    def _apply_transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        if not transform_map:
            return rec
        new_rec = dict(rec)
        for key, func in transform_map.items():
            if key in new_rec:
                try:
                    new_rec[key] = func(new_rec[key])
                except Exception:
                    new_rec[key] = None
        return new_rec

    def _aggregate(records: Iterable[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for rec in records:
            for k, v in rec.items():
                if isinstance(v, (int, float)):
                    agg.setdefault(k, 0)
                    agg[k] += v
                else:
                    agg.setdefault(k, set())
                    agg[k].add(v)
        for k, v in agg.items():
            if isinstance(v, set):
                agg[k] = list(v)
        return agg

    if not isinstance(records, list):
        raise TypeError("records must be a list")

    if max_items is not None and max_items < 0:
        raise ValueError("max_items must be non-negative")

    processed: List[Dict[str, Any]] = []
    errors: List[str] = []

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append(f"record {idx} is not a dict")
            continue
        if not _validate_record(rec):
            errors.append(f"record {idx} missing required fields")
            continue
        try:
            new_rec = _apply_transform(rec)
            processed.append(new_rec)
            if max_items is not None and len(processed) >= max_items:
                break
        except Exception as e:
            errors.append(f"record {idx} transform error: {e}")

    aggregated = _aggregate(processed)

    result = {
        "processed_count": len(processed),
        "error_count": len(errors),
        "errors": errors,
        "aggregated": aggregated,
        "raw_json": json.dumps(processed, indent=2),
    }
    return result

