import json
from typing import Any, Dict, Iterable, List, Optional

def process_data_pipeline(
    data_iter: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: float = 0.5,
    max_items: int = 1000,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        if not isinstance(rec[key_field], str):
            return False
        if not isinstance(rec[value_field], (int, float)):
            return False
        return True

    def _normalize_key(k: str) -> str:
        return k.strip().lower()

    aggregated: Dict[str, List[float]] = {}
    processed_count = 0
    skipped = 0
    for rec in data_iter:
        if not _validate_record(rec):
            skipped += 1
            continue
        key = _normalize_key(rec[key_field])
        val = float(rec[value_field])
        if key not in aggregated:
            aggregated[key] = []
        aggregated[key].append(val)
        processed_count += 1
        if processed_count >= max_items:
            break

    summary: Dict[str, Any] = {
        "total_records": processed_count + skipped,
        "processed": processed_count,
        "skipped": skipped,
        "unique_keys": len(aggregated),
    }

    def _compute_stats(values: List[float]) -> Dict[str, float]:
        n = len(values)
        if n == 0:
            return {"count": 0, "mean": 0.0, "max": 0.0, "min": 0.0}
        total = sum(values)
        mean_val = total / n
        max_val = max(values)
        min_val = min(values)
        return {"count": n, "mean": mean_val, "max": max_val, "min": min_val}

    stats: Dict[str, Dict[str, float]] = {}
    for k, vals in aggregated.items():
        stats[k] = _compute_stats(vals)

    filtered: Dict[str, Dict[str, float]] = {}
    for k, s in stats.items():
        if s["mean"] >= threshold:
            filtered[k] = s

    result = {
        "summary": summary,
        "stats": stats,
        "filtered": filtered,
    }
    return result

