from typing import Any, Dict, List, Optional, Tuple

def process_user_data(
    users: List[Dict[str, Any]],
    threshold: int = 10,
    *,
    include_inactive: bool = False,
) -> Dict[str, Any]:
    def _validate_user(user: Dict[str, Any]) -> bool:
        if not isinstance(user, dict):
            return False
        required_keys = {"id", "name", "score", "active"}
        if not required_keys.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int):
            return False
        if not isinstance(user["name"], str):
            return False
        if not isinstance(user["score"], (int, float)):
            return False
        if not isinstance(user["active"], bool):
            return False
        return True

    def _normalize_name(name: str) -> str:
        return name.strip().title()

    def _score_bucket(score: float) -> str:
        if score >= 90:
            return "A"
        if score >= 80:
            return "B"
        if score >= 70:
            return "C"
        if score >= 60:
            return "D"
        return "F"

    valid_users: List[Dict[str, Any]] = []
    for u in users:
        if _validate_user(u):
            valid_users.append(u)
        else:
            continue

    if not valid_users:
        return {"error": "No valid users provided"}

    processed: List[Dict[str, Any]] = []
    for u in valid_users:
        if not include_inactive and not u["active"]:
            continue
        if u["score"] < threshold:
            continue
        processed.append(
            {
                "id": u["id"],
                "name": _normalize_name(u["name"]),
                "score": u["score"],
                "grade": _score_bucket(float(u["score"])),
                "active": u["active"],
            }
        )

    if not processed:
        return {"message": "No users met the criteria"}

    summary: Dict[str, Any] = {
        "total_users": len(valid_users),
        "included_users": len(processed),
        "average_score": sum(u["score"] for u in processed) / len(processed),
        "grade_distribution": {
            "A": 0,
            "B": 0,
            "C": 0,
            "D": 0,
            "F": 0,
        },
    }

    for u in processed:
        grade = u["grade"]
        summary["grade_distribution"][grade] += 1

    processed_sorted = sorted(
        processed,
        key=lambda x: (-x["score"], x["name"]),
    )

    return {
        "summary": summary,
        "users": processed_sorted,
    }

