from typing import Any, Dict, List, Optional, Tuple

def process_user_data(
    users: List[Dict[str, Any]],
    min_age: int = 18,
    max_age: int = 99,
    required_fields: Optional[List[str]] = None,
) -> Dict[str, Any]:
    required_fields = required_fields or ["id", "name", "email", "age", "country"]

    def _normalize_email(email: str) -> str:
        e = email.strip().lower()
        if "@" not in e:
            return e
        local, domain = e.split("@", 1)
        local = local.replace("+", "")
        domain = domain.replace(".", "")
        return f"{local}@{domain}"

    def _validate_user(user: Dict[str, Any]) -> Tuple[bool, Optional[str]]:
        for field in required_fields:
            if field not in user:
                return False, f"missing field {field}"
        age = user.get("age")
        if not isinstance(age, int) or not (min_age <= age <= max_age):
            return False, f"invalid age {age}"
        email = user.get("email")
        if not isinstance(email, str) or "@" not in email:
            return False, f"invalid email {email}"
        return True, None

    def _aggregate_by_country(valid_users: List[Dict[str, Any]]) -> Dict[str, Dict[str, Any]]:
        country_stats: Dict[str, Dict[str, Any]] = {}
        for u in valid_users:
            c = u.get("country", "Unknown").strip()
            if c not in country_stats:
                country_stats[c] = {
                    "count": 0,
                    "total_age": 0,
                    "emails": set(),
                }
            country_stats[c]["count"] += 1
