        total = sum(r["amount"] for r in group)
        count = len(group)
        avg = total / count if count else 0.0
        return {"count": count, "total": total, "average": avg}

    def _median(values: List[float]) -> float:
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    valid_records: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, rec in enumerate(records):
        if _validate_record(rec):
            valid_records.append(rec)
        else:
            errors.append((idx, "invalid record"))

    groups = _group_by_type(valid_records)

    summary: Dict[str, Any] = {}
    for t, grp in groups.items():
        summary[t] = _summarize_group(grp)
        amounts = [r["amount"] for r in grp]
        summary[t]["median"] = _median(amounts)

    result: Dict[str, Any] = {
        "summary": summary,
        "errors": errors,
        "total_records": len(records),
        "valid_records": len(valid_records),
    }
    return result

