from typing import Any, Dict, Iterable, List, Optional, Tuple, Union

def analyze_dataset(
    records: Iterable[Dict[str, Any]],
    key: str,
    numeric_fields: List[str],
    category_fields: List[str],
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        for nf in numeric_fields:
            val = rec.get(nf)
            if val is None or not isinstance(val, (int, float)):
                return False
        for cf in category_fields:
            val = rec.get(cf)
            if val is None or not isinstance(val, str):
                return False
        return True

    def _aggregate_numeric(rec: Dict[str, Any]) -> None:
        for nf in numeric_fields:
            val = rec[nf]
            stats = numeric_stats[nf]
            stats['count'] += 1
            stats['sum'] += val
            if val < stats['min']:
                stats['min'] = val
            if val > stats['max']:
                stats['max'] = val

    def _aggregate_category(rec: Dict[str, Any]) -> None:
        for cf in category_fields:
            val = rec[cf]
            cat_counts[cf][val] = cat_counts[cf].get(val, 0) + 1

    numeric_stats: Dict[str, Dict[str, float]] = {}
    for nf in numeric_fields:
        numeric_stats[nf] = {'count': 0, 'sum': 0.0, 'min': float('inf'), 'max': float('-inf')}

    cat_counts: Dict[str, Dict[str, int]] = {}
    for cf in category_fields:
        cat_counts[cf] = {}

    total_records = 0
    valid_records = 0
    for rec in records:
        total_records += 1
        if not _validate_record(rec):
            continue
        valid_records += 1
        _aggregate_numeric(rec)
        _aggregate_category(rec)

    averages: Dict[str, float] = {}
    for nf, stats in numeric_stats.items():
        if stats['count'] > 0:
            averages[nf] = stats['sum'] / stats['count']
        else:
            averages[nf] = 0.0

    result: Dict[str, Any] = {
        'total_records': total_records,
        'valid_records': valid_records,
        'numeric_stats': numeric_stats,
        'averages': averages,
        'category_counts': cat_counts,
    }

    if threshold is not None:
        filtered: List[Dict[str, Any]] = []
        for rec in records:
            if not _validate_record(rec):
                continue
            if all(rec[nf] >= threshold for nf in numeric_fields):
                filtered.append(rec)
        result['filtered_records'] = filtered
        result['filtered_count'] = len(filtered)

    return result

