def process_transactions(
    transactions: List[Dict[str, Any]],
    min_amount: float = 0.0,
    max_amount: Optional[float] = None,
    categories: Optional[List[str]] = None,
) -> Dict[str, Any]:
    # Validate input structure
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "amount", "category", "timestamp"}
        if not isinstance(tx, dict):
            return False
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], (int, str)):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if not isinstance(tx["category"], str):
            return False
        if not isinstance(tx["timestamp"], (int, float)):
            return False
        return True

    # Filter by amount and category
    def _filter(tx: Dict[str, Any]) -> bool:
        amt = float(tx["amount"])
        if amt < min_amount:
            return False
        if max_amount is not None and amt > max_amount:
            return False
        if categories is not None and tx["category"] not in categories:
            return False
        return True

    # Group by category
    def _group_by_category(valid_txs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for tx in valid_txs:
            cat = tx["category"]
            groups.setdefault(cat, []).append(tx)
        return groups

    # Compute summary per category
    def _summarize(groups: Dict[str, List[Dict[str, Any]]]) -> Dict[str, Dict[str, Any]]:
        summary: Dict[str, Dict[str, Any]] = {}
        for cat, txs in groups.items():
            total = sum(float(t["amount"]) for t in txs)
            count = len(txs)
            avg = total / count if count else 0.0
            summary[cat] = {
                "total_amount": total,
                "transaction_count": count,
                "average_amount": avg,
                "ids": [t["id"] for t in txs],
            }
        return summary

    # Main processing pipeline
    valid_transactions: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []
    for idx, tx in enumerate(transactions):
        if not _validate(tx):
            errors.append((idx, "invalid structure"))
            continue
        if not _filter(tx):
            errors.append((idx, "filter out"))
            continue
        valid_transactions.append(tx)

    groups = _group_by_category(valid_transactions)
    summary = _summarize(groups)

    # Build final result
    result: Dict[str, Any] = {
        "summary_by_category": summary,
        "total_transactions": len(valid_transactions),
        "total_amount": sum(float(t["amount"]) for t in valid_transactions),
        "errors": errors,
    }

    # Optional: sort categories by total amount descending
    sorted_cats = sorted(
        result["summary_by_category"].items(),
        key=lambda kv: kv[1]["total_amount"],
        reverse=True,
    )
    result["sorted_categories"] = [cat for cat, _ in sorted_cats]

    return result

