from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(
    records: Iterable[Dict[str, Any]],
    group_key: str,
    agg_fields: List[str],
    filter_func: Optional[Any] = None,
) -> Tuple[Dict[str, Dict[str, Any]], List[str]]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if group_key not in rec:
            return False
        for f in agg_fields:
            if f not in rec:
                return False
        return True

    def _aggregate(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for f in agg_fields:
            values = [r[f] for r in group if isinstance(r[f], (int, float))]
            if values:
                agg[f] = sum(values) / len(values)
            else:
                agg[f] = None
        return agg

    def _format_error(rec: Dict[str, Any]) -> str:
        parts = []
        for k in rec:
            parts.append(f'{k}={rec[k]}')
        return f'invalid record: {" ".join(parts)}'

    groups: Dict[str, List[Dict[str, Any]]] = {}
    errors: List[str] = []

    for rec in records:
        if not _validate_record(rec):
            errors.append(_format_error(rec))
            continue
        if filter_func and not filter_func(rec):
            continue
        key = rec[group_key]
        groups.setdefault(key, []).append(rec)

    result: Dict[str, Dict[str, Any]] = {}
    for key, group in groups.items():
        result[key] = _aggregate(group)

    missing_keys = [k for k in agg_fields if k not in result]
    return result, missing_keys

