from typing import Any, Dict, Iterable, List, Optional, Tuple

def analyze_dataset(
    data: Iterable[Dict[str, Any]],
    required_fields: List[str],
    numeric_fields: List[str],
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    def _validate(row: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in row or row[field] is None:
                return False
        return True

    def _extract_numeric(row: Dict[str, Any]) -> Tuple[float, ...]:
        nums = []
        for field in numeric_fields:
            val = row.get(field)
            if isinstance(val, (int, float)):
                nums.append(float(val))
            else:
                nums.append(0.0)
        return tuple(nums)

    def _compute_stats(values: List[float]) -> Dict[str, float]:
        if not values:
            return {"count": 0, "mean": 0.0, "min": 0.0, "max": 0.0}
        total = sum(values)
        count = len(values)
        mean = total / count
        min_val = min(values)
        max_val = max(values)
        return {"count": count, "mean": mean, "min": min_val, "max": max_val}

    stats_per_field: Dict[str, Dict[str, float]] = {f: {"count":0,"sum":0.0} for f in numeric_fields}
    filtered_rows: List[Dict[str, Any]] = []
    for row in data:
        if not isinstance(row, dict):
            continue
        if not _validate(row):
            continue
        numeric_vals = _extract_numeric(row)
        if threshold is not None and any(v > threshold for v in numeric_vals):
            continue
        filtered_rows.append(row)
        for f, v in zip(numeric_fields, numeric_vals):
            stats_per_field[f]["count"] += 1
            stats_per_field[f]["sum"] += v

    final_stats: Dict[str, Any] = {}
    for f, s in stats_per_field.items():
        count = s["count"]
        sum_val = s["sum"]
        mean = sum_val / count if count else 0.0
        final_stats[f] = {"count": count, "sum": sum_val, "mean": mean}

    # Compute overall dataset stats
    overall_values: List[float] = []
    for row in filtered_rows:
        overall_values.extend(_extract_numeric(row))
    overall_stats = _compute_stats(overall_values)

    return {
        "filtered_count": len(filtered_rows),
        "numeric_field_stats": final_stats,
        "overall_stats": overall_stats,
        "sample_row": filtered_rows[0] if filtered_rows else None,
    }

