from typing import Any, Dict, Iterable, List, Optional, Tuple


def analyze_dataset(
    data: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[float] = None,
    normalize: bool = False,
) -> Tuple[Dict[str, int], Dict[str, float], List[str]]:
    # inner helper to validate record
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        if not isinstance(rec[key_field], str):
            return False
        if not isinstance(rec[value_field], (int, float)):
            return False
        return True

    # inner helper to normalize value
    def _normalize_value(val: float) -> float:
        if not normalize:
            return val
        # simple min-max scaling across dataset
        return (val - _min_val) / (_max_val - _min_val) if _max_val != _min_val else 0.0

    # first pass: gather stats
    counts: Dict[str, int] = {}
    sums: Dict[str, float] = {}
    min_vals: Dict[str, float] = {}
    max_vals: Dict[str, float] = {}

    for rec in data:
        if not _validate(rec):
            continue
        key = rec[key_field]
        val = float(rec[value_field])
        counts[key] = counts.get(key, 0) + 1
        sums[key] = sums.get(key, 0.0) + val
        if key not in min_vals or val < min_vals[key]:
            min_vals[key] = val
        if key not in max_vals or val > max_vals[key]:
            max_vals[key] = val

    # compute global min/max for normalization
    all_vals = [v for v in sums.values()]
    if all_vals:
        _min_val = min(all_vals)
        _max_val = max(all_vals)
    else:
        _min_val = _max_val = 0.0

    # second pass: compute averages and filter
    averages: Dict[str, float] = {}
    filtered_keys: List[str] = []
    for key, total in sums.items():
        avg = total / counts[key]
        if normalize:
            avg = _normalize_value(avg)
        averages[key] = avg
        if threshold is None or avg >= threshold:
            filtered_keys.append(key)

    # sort filtered keys by average descending
    filtered_keys.sort(key=lambda k: averages[k], reverse=True)

    return counts, averages, filtered_keys

