def process_records(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_fields: List[str],
    threshold: Optional[float] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    # Helper to convert values to float safely
    def _normalize_value(v: Any) -> float:
        try:
            return float(v)
        except (TypeError, ValueError):
            return 0.0

    # Aggregate values per group
    def _aggregate(group: List[Dict[str, Any]]) -> Dict[str, float]:
        agg: Dict[str, float] = {}
        for rec in group:
            for field in value_fields:
                agg[field] = agg.get(field, 0.0) + _normalize_value(rec.get(field))
        return agg

    # Validate and group records
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for rec in records:
        if not isinstance(rec, dict):
            continue
        key = rec.get(key_field)
        if key is None:
            continue
        key_str = str(key)
        groups.setdefault(key_str, []).append(rec)

    # Process each group
    filtered: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    for key, group in groups.items():
        agg = _aggregate(group)
        # Apply threshold filter if provided
        if threshold is not None:
            if agg.get(value_fields[0], 0.0) < threshold:
                continue
        filtered.append({key_field: key, **agg})
        counts[key] = len(group)

    # Sort results by primary value field descending
    filtered.sort(key=lambda r: r.get(value_fields[0], 0.0), reverse=True)

    # Compute summary statistics
    total_records = sum(counts.values())
    unique_keys = len(counts)
    avg_per_key = total_records / unique_keys if unique_keys else 0
    summary = {
        'total_records': total_records,
        'unique_keys': unique_keys,
        'average_per_key': avg_per_key,
    }

    # Return filtered list and counts per key
    return filtered, counts

# End of function

