from typing import List, Dict, Any, Optional, Tuple, Iterable

def process_transactions(transactions: List[Dict[str, Any]], threshold: float = 0.0) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _validate(tx: Dict[str, Any]) -> bool:
        required_keys = {"id", "amount", "currency", "status"}
        if not isinstance(tx, dict):
            return False
        if not required_keys.issubset(tx.keys()):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if tx["amount"] < 0:
            return False
        if tx["status"] not in {"pending", "completed", "failed"}:
            return False
        return True
    def _categorize(tx: Dict[str, Any]) -> str:
        amt = tx["amount"]
        if amt < 100:
            return "small"
        elif amt < 1000:
            return "medium"
        else:
            return "large"
    def _aggregate(accepted: List[Dict[str, Any]]) -> Dict[str, Any]:
        totals: Dict[str, float] = {}
        counts: Dict[str, int] = {}
        for tx in accepted:
            cat = _categorize(tx)
            amt = float(tx["amount"])
            totals[cat] = totals.get(cat, 0.0) + amt
            counts[cat] = counts.get(cat, 0) + 1
        return {"totals": totals, "counts": counts}
    accepted: List[Dict[str, Any]] = []
    rejected: List[Dict[str, Any]] = []
    for tx in transactions:
        if not _validate(tx):
            rejected.append(tx)
            continue
        if tx["amount"] < threshold:
            rejected.append(tx)
            continue
        accepted.append(tx)
    summary = _aggregate(accepted)
    result: Dict[str, Any] = {
        "accepted": accepted,
        "rejected": rejected,
        "summary": summary,
        "stats": {
            "total_transactions": len(transactions),
            "accepted_count": len(accepted),
            "rejected_count": len(rejected),
        },
    }
    return accepted, summary

