        if not isinstance(u["active"], bool):
            return False
        return True

    def _filter_user(u: Dict[str, Any]) -> bool:
        if not include_inactive and not u["active"]:
            return False
        if u["age"] < min_age:
            return False
        if max_age is not None and u["age"] > max_age:
            return False
        return True

    def _transform_user(u: Dict[str, Any]) -> Dict[str, Any]:
        return {
            "id": u["id"],
            "name": u["name"].strip().title(),
            "age": u["age"],
            "country": u["country"].strip().upper(),
            "active": u["active"],
        }

    valid_users: List[Dict[str, Any]] = []
    for raw in users:
        if not _validate_user(raw):
            continue
        if not _filter_user(raw):
            continue
        valid_users.append(_transform_user(raw))

    country_groups: Dict[str, List[Dict[str, Any]]] = {}
    for u in valid_users:
        country = u["country"]
        country_groups.setdefault(country, []).append(u)

    stats: Dict[str, Any] = {}
    for country, group in country_groups.items():
        ages = [u["age"] for u in group]
        avg_age = sum(ages) / len(ages) if ages else 0
        stats[country] = {
            "count": len(group),
            "average_age": round(avg_age, 2),
            "active_ratio": round(
                sum(1 for u in group if u["active"]) / len(group), 2
            ),
        }

    result = {
        "total_users": len(valid_users),
        "countries": list(country_groups.keys()),
        "stats_by_country": stats,
        "raw_input_count": len(users),
        "invalid_count": len(users) - len(valid_users),
    }
    return result

