from typing import Any, Dict, List, Tuple, Optional


def analyze_and_aggregate(
    data: List[Dict[str, Any]],
    min_score: float = 0.7,
    max_items: Optional[int] = None
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    # Validate each record
    def _is_valid(rec: Dict[str, Any]) -> bool:
        required = {"id", "value", "tags"}
        if not isinstance(rec, dict):
            return False
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["value"], (int, float)):
            return False
        if not isinstance(rec["tags"], list):
            return False
        return True

    # Compute a score based on value and tag count
    def _compute_score(rec: Dict[str, Any]) -> float:
        base = rec["value"]
        tag_bonus = 0.1 * len(rec["tags"])
        return base + tag_bonus

    # Aggregate tag frequencies
    def _aggregate_tags(valid: List[Dict[str, Any]]) -> Dict[str, int]:
        freq: Dict[str, int] = {}
        for rec in valid:
            for tag in rec["tags"]:
                if not isinstance(tag, str):
                    continue
                key = tag.strip().lower()
                if key:
                    freq[key] = freq.get(key, 0) + 1
        return freq

    # Optional helper: filter records by a specific tag
    def _filter_by_tag(records: List[Dict[str, Any]], tag: str) -> List[Dict[str, Any]]:
        tag_lower = tag.strip().lower()
        return [r for r in records if any(t.strip().lower() == tag_lower for t in r["tags"])]

    # Main processing
    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []

    for record in data:
        if _is_valid(record):
            valid_records.append(record)
        else:
            invalid_records.append(record)

    scored: List[Tuple[float, Dict[str, Any]]] = []
    for rec in valid_records:
        score = _compute_score(rec)
        scored.append((score, rec))

    scored.sort(key=lambda x: x[0], reverse=True)

    top_records: List[Dict[str, Any]] = []
    for score, rec in scored:
        if score >= min_score:
            top_records.append(rec)
            if max_items is not None and len(top_records) >= max_items:
                break

    tag_counts = _aggregate_tags(top_records)

    result = {
        "top_records": top_records,
        "tag_counts": tag_counts,
        "invalid_count": len(invalid_records),
        "total_valid": len(valid_records),
    }

    return top_records, tag_counts

