from typing import Any, Dict, List, Tuple, Optional


def compute_statistics(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        required = {"id", "value", "category"}
        if not isinstance(record, dict):
            return False
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["id"], int):
            return False
        if not isinstance(record["value"], (int, float)):
            return False
        if not isinstance(record["category"], str):
            return False
        return True

    def _aggregate(records: List[Dict[str, Any]]) -> Tuple[Dict[str, int], Dict[str, float], Dict[str, List[int]]]:
        counts: Dict[str, int] = {}
        sums: Dict[str, float] = {}
        ids_by_cat: Dict[str, List[int]] = {}
        for rec in records:
            cat = rec["category"]
            counts[cat] = counts.get(cat, 0) + 1
            sums[cat] = sums.get(cat, 0.0) + float(rec["value"])
            ids_by_cat.setdefault(cat, []).append(rec["id"])
        return counts, sums, ids_by_cat

    def _compute_averages(sums: Dict[str, float], counts: Dict[str, int]) -> Dict[str, float]:
        averages: Dict[str, float] = {}
        for cat, total in sums.items():
            averages[cat] = total / counts[cat] if counts[cat] else 0.0
        return averages

    valid_records: List[Dict[str, Any]] = []
    for r in records:
        if _validate(r):
            valid_records.append(r)

    if not valid_records:
        return {"error": "no valid records"}

    counts, sums, ids_by_cat = _aggregate(valid_records)
    averages = _compute_averages(sums, counts)

    # Build result
    result: Dict[str, Any] = {
        "total_records": len(records),
        "valid_records": len(valid_records),
        "categories": {},
        "summary": {
            "overall_average": sum(sums.values()) / sum(counts.values()) if counts else None,
            "max_category": None,
            "min_category": None,
        },
    }

    max_cat: Optional[str] = None
    min_cat: Optional[str] = None
    max_avg: float = float("-inf")
    min_avg: float = float("inf")

    for cat in counts:
        cat_info: Dict[str, Any] = {
            "count": counts[cat],
            "average_value": averages[cat],
            "ids": ids_by_cat[cat],
        }
        result["categories"][cat] = cat_info

        if averages[cat] > max_avg:
            max_avg = averages[cat]
            max_cat = cat
        if averages[cat] < min_avg:
            min_avg = averages[cat]
            min_cat = cat

    result["summary"]["max_category"] = max_cat
    result["summary"]["min_category"] = min_cat

    # Sort categories by count descending
    sorted_cats = sorted(counts.keys(), key=lambda c: counts[c], reverse=True)
    result["sorted_categories_by_count"] = sorted_cats

    # Provide a list of categories with high variance
    variances: Dict[str, float] = {}
    for cat in counts:
        values = [float(r["value"]) for r in valid_records if r["category"] == cat]
        mean = averages[cat]
        var = sum((v - mean) ** 2 for v in values) / len(values) if values else 0.0
        variances[cat] = var
    high_variance_cats = sorted(variances, key=variances.get, reverse=True)[:3]
    result["high_variance_categories"] = high_variance_cats

    return result

