def analyze_records(records: List[Dict[str, Any]], key: str, threshold: int = 0, min_value: Optional[float] = None, max_value: Optional[float] = None, compute_mode: bool = False, compute_median: bool = False, verbose: bool = False) -> Dict[str, Any]:
    def _log(msg: str) -> None:
        if verbose:
            print(msg)

    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        val = rec[key]
        if not isinstance(val, (int, float)):
            return False
        if min_value is not None and val < min_value:
            return False
        if max_value is not None and val > max_value:
            return False
        return True

    def _normalize(val: float) -> float:
        return float(val)

    def _group(records: List[Dict[str, Any]]) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for rec in records:
            k = rec[key]
            groups.setdefault(k, []).append(rec)
        return groups

    def _compute_stats(group: List[Dict[str, Any]]) -> Dict[str, float]:
        values = [_normalize(rec[key]) for rec in group]
        count = len(values)
        total = sum(values)
        avg = total / count if count else 0.0
        stats: Dict[str, float] = {'count': float(count), 'sum': total, 'avg': avg}
        if compute_median:
            sorted_vals = sorted(values)
            mid = count // 2
            if count % 2 == 0:
                median = (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
            else:
                median = sorted_vals[mid]
            stats['median'] = median
        if compute_mode:
            freq: Dict[float, int] = {}
            for v in values:
                freq[v] = freq.get(v, 0) + 1
            max_freq = max(freq.values()) if freq else 0
            modes = [v for v, f in freq.items() if f == max_freq]
            stats['mode'] = modes
        return stats

    def _format_stats(stats: Dict[str, Any]) -> Dict[str, Any]:
        formatted: Dict[str, Any] = {}
        for k, v in stats.items():
            if isinstance(v, list):
                formatted[k] = v
            else:
                formatted[k] = float(v)
        return formatted

    _log('Starting analysis')
    valid_records: List[Dict[str, Any]] = []
    for idx, rec in enumerate(records):
        if _validate(rec):
            valid_records.append(rec)
        if verbose and (idx + 1) % 100 == 0:
            _log(f'Processed {idx + 1} records')
    _log(f'Validation complete: {len(valid_records)} valid records')

    groups = _group(valid_records)
    _log(f'Grouped into {len(groups)} groups')

    stats_by_group: Dict[Any, Dict[str, Any]] = {}
    for k, grp in groups.items():
        if len(grp) < threshold:
            continue
        stats = _compute_stats(grp)
        stats_by_group[k] = _format_stats(stats)

    sorted_keys = sorted(stats_by_group.keys(), key=lambda k: stats_by_group[k]['avg'], reverse=True)
    sorted_stats = [(k, stats_by_group[k]) for k in sorted_keys]

    result: Dict[str, Any] = {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'groups': len(groups),
        'threshold': threshold,
        'min_value': min_value,
        'max_value': max_value,
        'stats': sorted_stats,
    }
    _log('Analysis complete')
    return result

