        for u in users:
            age = u["age"]
            if 18 <= age <= 25:
                groups["18-25"] += 1
            elif 26 <= age <= 35:
                groups["26-35"] += 1
            elif 36 <= age <= 45:
                groups["36-45"] += 1
            elif 46 <= age <= 55:
                groups["46-55"] += 1
            elif 56 <= age <= 65:
                groups["56-65"] += 1
            elif 66 <= age <= 75:
                groups["66-75"] += 1
            elif 76 <= age <= 85:
                groups["76-85"] += 1
            elif 86 <= age <= 99:
                groups["86-99"] += 1
        return groups

    age_distribution = _aggregate_by_age_group(valid_users)

    def _summarize_errors(errors: List[str]) -> Dict[str, Any]:
        return {"count": len(errors), "messages": errors[:10]}

    error_summary = _summarize_errors(errors)

    return valid_users, error_summary

