from typing import Any, Dict, List, Optional, Tuple


def analyze_text_data(
    records: List[Dict[str, Any]],
    min_word_length: int = 3,
    stopwords: Optional[List[str]] = None,
) -> Dict[str, Any]:
    # Normalize stopwords
    stop_set = {s.lower() for s in (stopwords or [])}

    # Helper to split and clean words
    def _tokenize(text: str) -> List[str]:
        words = []
        for raw in text.split():
            w = raw.strip(".,!?;:\\"'()[]{} ").lower()
            if len(w) < min_word_length or w in stop_set:
                continue
            words.append(w)
        return words

    # Accumulate word frequencies
    freq: Dict[str, int] = {}
    doc_words: Dict[str, List[str]] = {}

    for rec in records:
        doc_id = rec.get("id")
        if doc_id is None:
            continue
        text = rec.get("text", "")
        if not isinstance(text, str):
            continue
        tokens = _tokenize(text)
        doc_words[doc_id] = tokens
        for w in tokens:
            freq[w] = freq.get(w, 0) + 1

    # Compute top words
    top_n = 20
    top_words = sorted(freq.items(), key=lambda kv: (-kv[1], kv[0]))[:top_n]

    # Build co-occurrence matrix for top words
    cooc: Dict[Tuple[str, str], int] = {}
    top_set = {w for w, _ in top_words}

    for tokens in doc_words.values():
        seen = set()
        for w in tokens:
            if w not in top_set or w in seen:
                continue
            seen.add(w)
            for v in seen:
                if v == w:
                    continue
                key = tuple(sorted((w, v)))
                cooc[key] = cooc.get(key, 0) + 1

    # Prepare result
    result: Dict[str, Any] = {
        "total_documents": len(doc_words),
        "unique_words": len(freq),
        "top_words": [{"word": w, "count": c} for w, c in top_words],
        "cooccurrence": [
            {"pair": key, "count": count} for key, count in cooc.items()
        ],
    }

    # Optional: compute average words per doc
    total_words = sum(len(t) for t in doc_words.values())
    result["avg_words_per_doc"] = (
        total_words / len(doc_words) if doc_words else 0
    )

    # Return result
    return result

