from typing import Any, Dict, List, Tuple, Optional


def process_transactions(
    records: List[Dict[str, Any]],
    currency: str = "USD",
    min_amount: float = 0.0,
) -> Dict[str, Any]:
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        required = {"id", "amount", "currency", "category"}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], (int, str)):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if not isinstance(rec["currency"], str):
            return False
        if not isinstance(rec["category"], str):
            return False
        return True

    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        amt = float(rec["amount"])
        if rec["currency"] != currency:
            amt *= _exchange_rate(rec["currency"], currency)
        return {
            "id": rec["id"],
            "amount": amt,
            "currency": currency,
            "category": rec["category"],
        }

    def _exchange_rate(src: str, dst: str) -> float:
        rates = {
            ("USD", "EUR"): 0.85,
            ("EUR", "USD"): 1.18,
            ("USD", "JPY"): 110.0,
            ("JPY", "USD"): 0.0091,
        }
        return rates.get((src, dst), 1.0)

    def _aggregate_by_category(trans: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        cat_map: Dict[str, List[Dict[str, Any]]] = {}
        for t in trans:
            cat = t["category"].lower()
            cat_map.setdefault(cat, []).append(t)
        return cat_map

    def _compute_totals(cat_map: Dict[str, List[Dict[str, Any]]]) -> Dict[str, float]:
        totals: Dict[str, float] = {}
        for cat, items in cat_map.items():
            totals[cat] = sum(item["amount"] for item in items)
        return totals

    valid_records: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, rec in enumerate(records):
        if not _validate(rec):
            errors.append((idx, "validation failed"))
            continue
        amt = float(rec["amount"])
        if amt < min_amount:
            errors.append((idx, f"amount below minimum: {amt}"))
            continue
        try:
            transformed = _transform(rec)
            valid_records.append(transformed)
        except Exception as e:
            errors.append((idx, f"transformation error: {e}"))

    cat_map = _aggregate_by_category(valid_records)
    totals = _compute_totals(cat_map)

    summary: Dict[str, Any] = {
        "total_records": len(records),
        "valid_records": len(valid_records),
        "errors": errors,
        "categories": list(cat_map.keys()),
        "totals": totals,
    }

    return summary

