from typing import Any, Dict, Iterable, List, Optional


def analyze_records(
    records: List[Dict[str, Any]],
    group_key: str,
    value_key: str,
    threshold: float = 0.0,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if group_key not in rec or value_key not in rec:
            return False
        if not isinstance(rec[group_key], str):
            return False
        if not isinstance(rec[value_key], (int, float)):
            return False
        return True

    def _normalize_group_name(name: str) -> str:
        return name.strip().lower()

    groups: Dict[str, List[float]] = {}
    invalid_records: List[Dict[str, Any]] = []

    for rec in records:
        if not _validate_record(rec):
            invalid_records.append(rec)
            continue
        group = _normalize_group_name(rec[group_key])
        val = float(rec[value_key])
        groups.setdefault(group, []).append(val)

    stats: Dict[str, Dict[str, float]] = {}
    for group, values in groups.items():
        count = len(values)
        total = sum(values)
        avg = total / count if count else 0.0
        min_val = min(values) if values else 0.0
        max_val = max(values) if values else 0.0
        stats[group] = {
            "count": count,
            "total": total,
            "average": avg,
            "min": min_val,
            "max": max_val,
        }

    def _median(values: List[float]) -> float:
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    for group, s in stats.items():
        s["median"] = _median(groups[group])

    filtered_stats: Dict[str, Dict[str, float]] = {}
    for group, s in stats.items():
        if s["average"] >= threshold:
            filtered_stats[group] = s

    summary = {
        "total_records": len(records),
        "valid_records": len(records) - len(invalid_records),
        "invalid_records": len(invalid_records),
        "groups": len(groups),
        "filtered_groups": len(filtered_stats),
    }

    return {
        "summary": summary,
        "stats": stats,
        "filtered_stats": filtered_stats,
        "invalid_records": invalid_records,
    }

