from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_user_data(
    raw_users: Iterable[Dict[str, Any]],
    required_fields: List[str],
    email_domain: str,
    max_age: int,
) -> Tuple[List[Dict[str, Any]], List[str]]:
    """Process raw user data, validating and normalizing.
    """
    def _normalize_email(email: str) -> str:
        return email.strip().lower()

    def _validate_user(user: Dict[str, Any]) -> Optional[str]:
        missing = [f for f in required_fields if f not in user]
        if missing:
            return f"Missing fields: {', '.join(missing)}"
        email = user.get("email", "")
        if not isinstance(email, str) or email_domain not in email:
            return "Invalid email domain"
        age = user.get("age")
        if not isinstance(age, int) or age > max_age:
            return "Age out of bounds"
        return None

    def _transform(user: Dict[str, Any]) -> Dict[str, Any]:
        transformed = {
            "id": str(user.get("id", "")),
            "name": user.get("name", "").strip().title(),
            "email": _normalize_email(user.get("email", "")),
            "age": int(user.get("age", 0)),
            "tags": [t.strip().lower() for t in user.get("tags", []) if isinstance(t, str)],
        }
        return transformed

    valid_users: List[Dict[str, Any]] = []
    errors: List[str] = []

    for raw in raw_users:
        if not isinstance(raw, dict):
            errors.append("User record is not a dict")
            continue
        err = _validate_user(raw)
        if err:
            errors.append(f"User {raw.get('id', 'unknown')}: {err}")
            continue
        transformed = _transform(raw)
        valid_users.append(transformed)

    def _group_by_age(users: List[Dict[str, Any]]) -> Dict[int, List[Dict[str, Any]]]:
        groups: Dict[int, List[Dict[str, Any]]] = {}
        for u in users:
            age = u["age"]
