from typing import List, Dict, Optional, Any, Tuple

def analyze_records(records: List[Dict[str, Any]], threshold: float = 0.5) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        required = ['id', 'value', 'tags']
        for key in required:
            if key not in record:
                return False
        if not isinstance(record['id'], int):
            return False
        if not isinstance(record['value'], (int, float)):
            return False
        if not isinstance(record['tags'], list):
            return False
        return True

    def _compute_score(record: Dict[str, Any]) -> float:
        base = record['value']
        tag_bonus = sum(1 for t in record['tags'] if t.startswith('good'))
        return base + tag_bonus

    def _group_by_category(records: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in records:
            cat = rec.get('category', 'unknown')
            groups.setdefault(cat, []).append(rec)
        return groups

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []

    for rec in records:
        if _validate(rec):
            valid_records.append(rec)
        else:
            invalid_records.append(rec)

    scored: List[Tuple[float, Dict[str, Any]]] = []
    for rec in valid_records:
        score = _compute_score(rec)
        scored.append((score, rec))

    scored.sort(key=lambda x: x[0], reverse=True)

    top_records: List[Dict[str, Any]] = [rec for _, rec in scored[:10]]

    grouped = _group_by_category(valid_records)

    summary: Dict[str, Any] = {
        'total': len(records),
        'valid': len(valid_records),
        'invalid': len(invalid_records),
        'top_score': scored[0][0] if scored else None,
        'top_records': top_records,
        'by_category': {k: len(v) for k, v in grouped.items()},
    }

    def _format_summary() -> str:
        lines: List[str] = []
        lines.append('Total records: ' + str(summary['total']))
        lines.append('Valid records: ' + str(summary['valid']))
        lines.append('Invalid records: ' + str(summary['invalid']))
        lines.append('Highest score: ' + str(summary['top_score']))
        lines.append('Records per category:')
        for cat, count in summary['by_category'].items():
            lines.append('  ' + cat + ': ' + str(count))
        return '\\n'.join(lines)

    summary['report'] = _format_summary()

    return summary

