from typing import Any, Dict, Iterable, List, Optional, Tuple

def analyze_records(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[float] = None,
    max_values: int = 10,
) -> Dict[str, Any]:
    # Helper to convert value to float
    def _to_float(val: Any) -> float:
        if val is None:
            return 0.0
        try:
            return float(val)
        except Exception:
            return 0.0

    # Validate a single record
    def _is_valid(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        if rec[key_field] is None or rec[value_field] is None:
            return False
        return True

    # Group values by key
    def _group() -> Dict[str, List[float]]:
        groups: Dict[str, List[float]] = {}
        for rec in records:
            if not _is_valid(rec):
                continue
            k = str(rec[key_field]).strip()
            if not k:
                continue
            v = _to_float(rec[value_field])
            groups.setdefault(k, []).append(v)
        return groups

    # Compute statistics for a list of values
    def _stats(vals: List[float]) -> Tuple[float, float, int]:
        count = len(vals)
        total = sum(vals)
        avg = total / count if count else 0.0
        return avg, total, count

    # Filter groups by threshold
    def _filter(groups: Dict[str, List[float]]) -> Dict[str, List[float]]:
        if threshold is None:
            return groups
        filtered: Dict[str, List[float]] = {}
        for k, vals in groups.items():
            avg, _, _ = _stats(vals)
            if avg >= threshold:
                filtered[k] = vals
        return filtered

    # Build result dictionary
    def _build(groups: Dict[str, List[float]]) -> Dict[str, Any]:
        res: Dict[str, Any] = {}
        for k, vals in groups.items():
            avg, total, count = _stats(vals)
            res[k] = {
                "count": count,
                "total": total,
                "average": avg,
                "sample_values": vals[:max_values],
            }
        return res

    # Main logic
    grouped = _group()
    filtered = _filter(grouped)
    data = _build(filtered)

    # Prepare summary
    summary_stats: List[Tuple[str, float, int]] = []
    for k, vals in filtered.items():
        avg, _, count = _stats(vals)
        summary_stats.append((k, avg, count))
    summary_stats.sort(key=lambda x: (-x[1], x[0]))

    summary = {
        "total_keys": len(data),
        "top_keys": [k for k, _, _ in summary_stats[:5]],
        "threshold": threshold,
    }

    return {
        "data": data,
        "summary": summary,
        "details": summary_stats,
    }

