        required_keys = {"id", "name", "activity", "metadata"}
        if not isinstance(user, dict):
            return False
        if not required_keys.issubset(user.keys()):
            return False
        if not isinstance(user["activity"], Iterable):
            return False
        return True

    def _activity_score(activity: Iterable[Any]) -> int:
        score = 0
        for item in activity:
            if isinstance(item, dict):
                score += item.get("points", 0)
            elif isinstance(item, (int, float)):
                score += int(item)
        return score

    def _extract_metadata(metadata: Dict[str, Any]) -> Tuple[bool, str]:
        is_active = bool(metadata.get("active", False))
        region = str(metadata.get("region", "unknown")).lower()
        return is_active, region

    valid_users: List[Dict[str, Any]] = []
    for u in users:
        if _validate_user(u):
            valid_users.append(u)

    total_users = len(valid_users)
    if total_users == 0:
        return {
            "total_users": 0,
            "active_users": 0,
            "regions": {},
            "top_users": [],
            "error": "no valid users provided",
        }

    active_count = 0
    region_counts: Dict[str, int] = {}
    user_scores: List[Tuple[int, Dict[str, Any]]] = []

    for user in valid_users:
        score = _activity_score(user["activity"])
        is_active, region = _extract_metadata(user["metadata"])
        if is_active:
            active_count += 1
        region_counts[region] = region_counts.get(region, 0) + 1
        user_scores.append((score, user))

    user_scores.sort(key=lambda kv: kv[0], reverse=True)
    top_users = [u for _, u in user_scores[:threshold]]

    region_summary = {
        r: {
            "count": c,
            "percentage": round((c / total_users) * 100, 2),
        }
        for r, c in region_counts.items()
    }

    result: Dict[str, Any] = {
        "total_users": total_users,
        "active_users": active_count,
        "regions": region_summary,
        "top_users": top_users,
        "average_score": round(sum(s for s, _ in user_scores) / total_users, 2),
    }

    return result

