from typing import Any, Dict, List, Set, Tuple

def process_records(
    records: List[Dict[str, Any]],
    key_field: str,
    required_fields: Set[str],
    optional_fields: Set[str],
    aggregate_funcs: Dict[str, str] = None,
) -> Dict[str, Any]:
    if aggregate_funcs is None:
        aggregate_funcs = {}
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True
    def _clean(record: Dict[str, Any]) -> Dict[str, Any]:
        cleaned = {}
        for k, v in record.items():
            if isinstance(v, str):
                cleaned[k] = v.strip()
            else:
                cleaned[k] = v
        return cleaned
    def _aggregate(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg = {}
        for field, func in aggregate_funcs.items():
            values = [rec.get(field) for rec in group if rec.get(field) is not None]
            if not values:
                agg[field] = None
                continue
            if func == 'sum':
                agg[field] = sum(values)
            elif func == 'max':
                agg[field] = max(values)
            elif func == 'min':
                agg[field] = min(values)
            elif func == 'count':
                agg[field] = len(values)
            else:
                agg[field] = None
        return agg
    cleaned_records = []
    errors = []
    for rec in records:
        if not isinstance(rec, dict):
            errors.append(('invalid_type', rec))
            continue
        if not _validate(rec):
            errors.append(('missing_required', rec))
            continue
        cleaned_records.append(_clean(rec))
    groups = {}
    for rec in cleaned_records:
        key = rec.get(key_field)
        if key not in groups:
            groups[key] = []
        groups[key].append(rec)
    aggregated = {}
    for key, group in groups.items():
        aggregated[key] = _aggregate(group)
    stats = {
        'total_records': len(records),
        'valid_records': len(cleaned_records),
        'invalid_records': len(errors),
        'group_count': len(groups),
    }
    return {
        'cleaned': cleaned_records,
        'errors': errors,
        'aggregated': aggregated,
        'stats': stats,
    }

