from typing import List, Dict, Tuple, Optional, Any

def analyze_records(records: List[Dict[str, Any]], key: str, threshold: Optional[int] = None) -> Dict[str, Any]:
    # Validate a single record
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if key not in record:
            return False
        if not isinstance(record[key], (int, float)):
            return False
        return True

    # Group records by key
    def _group(records: List[Dict[str, Any]]) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for rec in records:
            if not _validate(rec):
                continue
            k = rec[key]
            if k not in groups:
                groups[k] = []
            groups[k].append(rec)
        return groups

    # Compute statistics for a group
    def _compute_stats(group: List[Dict[str, Any]]) -> Tuple[float, float]:
        values = [rec[key] for rec in group]
        if not values:
            return (0.0, 0.0)
        avg = sum(values) / len(values)
        max_val = max(values)
        return (avg, max_val)

    # Format stats into readable form
    def _format_stats(stats: Dict[Any, Tuple[float, float]]) -> List[Dict[str, Any]]:
        formatted: List[Dict[str, Any]] = []
        for k, (avg, max_val) in stats.items():
            formatted.append({'key': k, 'average': avg, 'max': max_val})
        return formatted

    # Main processing
    valid_records = [r for r in records if _validate(r)]
    groups = _group(valid_records)
    stats: Dict[Any, Tuple[float, float]] = {}
    for k, g in groups.items():
        stats[k] = _compute_stats(g)

    # Apply threshold filter if provided
    if threshold is not None:
        stats = {k: v for k, v in stats.items() if v[0] >= threshold}

    # Sort stats by average descending
    sorted_stats = sorted(stats.items(), key=lambda kv: kv[1][0], reverse=True)

    # Build final result
    result = {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'groups': len(groups),
        'statistics': _format_stats(dict(sorted_stats)),
    }

    return result

