from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_transactions(
    transactions: Iterable[Dict[str, Any]],
    min_amount: float = 0.0,
    categories: Optional[List[str]] = None,
) -> Dict[str, Any]:
    # inner helper
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "amount", "category", "timestamp"}
        if not isinstance(tx, dict):
            return False
        if not required.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], (int, str)):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if tx["amount"] < min_amount:
            return False
        if categories is not None and tx["category"] not in categories:
            return False
        if not isinstance(tx["timestamp"], str):
            return False
        return True

    # accumulate
    totals: Dict[str, float] = {}
    counts: Dict[str, int] = {}
    invalid: List[Dict[str, Any]] = []
    processed: List[Dict[str, Any]] = []

    for tx in transactions:
        if not _validate(tx):
            invalid.append(tx)
            continue
        cat = tx["category"]
        amt = float(tx["amount"])
        totals[cat] = totals.get(cat, 0.0) + amt
        counts[cat] = counts.get(cat, 0) + 1
        processed.append(tx)

    # compute averages
    averages: Dict[str, float] = {}
    for cat, total in totals.items():
        averages[cat] = total / counts[cat] if counts[cat] else 0.0

    # find top category
    top_category: Optional[str] = None
    top_amount: float = 0.0
    for cat, total in totals.items():
        if total > top_amount:
            top_amount = total
            top_category = cat

    # build result
    result: Dict[str, Any] = {
        "total_transactions": len(processed),
        "invalid_transactions": len(invalid),
        "category_totals": totals,
        "category_counts": counts,
        "category_averages": averages,
        "top_category": top_category,
        "top_amount": top_amount,
    }

    # optional: sort categories by total descending
    sorted_cats = sorted(totals.items(), key=lambda kv: kv[1], reverse=True)
    result["sorted_categories"] = [cat for cat, _ in sorted_cats]

    # handle edge cases
    if not processed:
        result["message"] = "No valid transactions processed."
    else:
        result["message"] = f"Processed {len(processed)} transactions."

    return result

