def process_records(
    records: List[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[float] = None,
) -> Tuple[Dict[str, List[Dict[str, Any]]], List[str]]:
    def _normalize_key(v: Any) -> str:
        if v is None:
            return ""
        return str(v).strip().lower()

    def _group_by_key(recs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in recs:
            if not isinstance(rec, dict):
                continue
            k = _normalize_key(rec.get(key_field))
            groups.setdefault(k, []).append(rec)
        return groups

    def _filter_group(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        if threshold is None:
            return group
        filtered: List[Dict[str, Any]] = []
        for rec in group:
            val = rec.get(value_field)
            try:
                num = float(val)
            except (TypeError, ValueError):
                continue
            if num >= threshold:
                filtered.append(rec)
        return filtered

    def _compute_stats(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        values: List[float] = []
        for rec in group:
            val = rec.get(value_field)
            try:
                num = float(val)
                values.append(num)
            except (TypeError, ValueError):
                continue
        if not values:
            return {"count": 0, "sum": 0.0, "avg": None}
        total = sum(values)
        avg = total / len(values)
        return {"count": len(values), "sum": total, "avg": avg}

    def _log_warning(msg: str) -> None:
        # Simple placeholder for logging
        print(f"WARNING: {msg}")

    groups = _group_by_key(records)

    valid_keys: List[str] = []
    for k, grp in list(groups.items()):
        filtered = _filter_group(grp)
        if not filtered:
            del groups[k]
            _log_warning(f"Group '{k}' removed due to empty after filtering")
        else:
            groups[k] = filtered
            valid_keys.append(k)

    # Compute statistics per group
    stats: Dict[str, Dict[str, Any]] = {}
    for k, grp in groups.items():
        stats[k] = _compute_stats(grp)

    # Sort groups by size descending
    sorted_keys = sorted(valid_keys, key=lambda x: len(groups[x]), reverse=True)

    # Return groups and sorted keys
    return groups, sorted_keys

