from typing import List, Dict, Tuple, Optional, Any


def analyze_and_filter(
    records: List[Dict[str, Any]],
    key: str,
    threshold: Optional[int] = None,
    verbose: bool = False,
) -> Tuple[List[Dict[str, Any]], Dict[str, int], List[str]]:
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        return True

    def _extract(rec: Dict[str, Any]) -> Any:
        return rec.get(key)

    def _log(msg: str) -> None:
        if verbose:
            print(msg)

    valid: List[Dict[str, Any]] = []
    counts: Dict[str, int] = {}
    errors: List[str] = []

    for idx, rec in enumerate(records):
        _log(f'Record {idx}: start')
        if not _validate(rec):
            errors.append(f'Record {idx} invalid: missing key {key}')
            _log(f'Record {idx} skipped due to validation')
            continue
        val = _extract(rec)
        if threshold is not None and isinstance(val, int) and val < threshold:
            _log(f'Record {idx} value {val} below threshold {threshold}')
            continue
        valid.append(rec)
        key_str = str(val)
        counts[key_str] = counts.get(key_str, 0) + 1
        _log(f'Record {idx} accepted with key {key_str}')

    try:
        valid.sort(key=lambda r: r[key])
    except Exception as e:
        _log(f'Sorting error: {e}')

    sorted_keys = sorted(counts.keys(), key=lambda k: counts[k], reverse=True)

    total_valid = len(valid)
    _log(f'Total valid records: {total_valid}')
    _log(f'Unique keys: {len(counts)}')

    numeric_vals = [rec[key] for rec in valid if isinstance(rec[key], (int, float))]
    median_val: Optional[float] = None
    if numeric_vals:
        numeric_vals.sort()
        mid = len(numeric_vals) // 2
        if len(numeric_vals) % 2 == 0:
            median_val = (numeric_vals[mid - 1] + numeric_vals[mid]) / 2.0
        else:
            median_val = numeric_vals[mid]
        _log(f'Median value: {median_val}')

    return valid, counts, sorted_keys

