from typing import Any, Dict, Iterable, List, Optional, Tuple, Union

def process_data(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: Optional[int] = None,
    max_items: Optional[int] = None,
) -> Tuple[Dict[str, int], List[Dict[str, Any]], Dict[str, Any]]:
    def _normalize_key(val: Any) -> str:
        if val is None:
            return ''
        return str(val).strip().lower()

    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        return True

    counts: Dict[str, int] = {}
    filtered: List[Dict[str, Any]] = []
    values_by_key: Dict[str, List[int]] = {}

    for rec in records:
        if not _validate_record(rec):
            continue
        k = _normalize_key(rec[key_field])
        v = rec[value_field]
        if threshold is not None:
            if not isinstance(v, int):
                continue
            if v < threshold:
                continue
        counts[k] = counts.get(k, 0) + 1
        filtered.append({'key': k, 'value': v, 'original': rec})
        if k not in values_by_key:
            values_by_key[k] = []
        values_by_key[k].append(int(v))

    def _sort_by_count(d: Dict[str, int]) -> List[Tuple[str, int]]:
        return sorted(d.items(), key=lambda kv: (-kv[1], kv[0]))

    sorted_counts = _sort_by_count(counts)

    result_counts: Dict[str, int] = {k: c for k, c in sorted_counts}

    def _average(values: List[int]) -> float:
        if not values:
            return 0.0
        return sum(values) / len(values)

    def _median(values: List[int]) -> float:
        if not values:
            return 0.0
        sorted_vals = sorted(values)
        mid = len(sorted_vals) // 2
        if len(sorted_vals) % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return float(sorted_vals[mid])

    def _percentile(values: List[int], pct: float) -> float:
        if not values:
            return 0.0
        sorted_vals = sorted(values)
        index = int(len(sorted_vals) * pct / 100.0)
        if index >= len(sorted_vals):
            index = len(sorted_vals) - 1
        return float(sorted_vals[index])

    averages: Dict[str, float] = {}
    medians: Dict[str, float] = {}
    percentiles: Dict[str, Dict[str, float]] = {}

    for k, vals in values_by_key.items():
        averages[k] = _average(vals)
        medians[k] = _median(vals)
        percentiles[k] = {
            'p25': _percentile(vals, 25.0),
            'p50': _percentile(vals, 50.0),
            'p75': _percentile(vals, 75.0),
        }

    summary: Dict[str, Any] = {
        'total_records': len(records),
        'unique_keys': len(counts),
        'max_items': max_items,
        'averages': averages,
        'medians': medians,
        'percentiles': percentiles,
    }

    filtered.sort(key=lambda x: x['value'], reverse=True)

    if max_items is not None:
        filtered = filtered[:max_items]
        result_counts = {k: v for k, v in result_counts.items() if k in [f['key'] for f in filtered]}

    return result_counts, filtered, summary

