import json
from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_data(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    max_items: int = 100,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        transformed: Dict[str, Any] = {}
        for key, value in record.items():
            if isinstance(value, str):
                transformed[key] = value.strip().lower()
            elif isinstance(value, (int, float)):
                transformed[key] = value
            else:
                transformed[key] = json.dumps(value)
        return transformed

    def _aggregate(agg: Dict[str, int], key: str) -> None:
        agg[key] = agg.get(key, 0) + 1

    processed: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []
    field_counts: Dict[str, int] = {}
    total_processed = 0

    for idx, rec in enumerate(records):
        if total_processed >= max_items:
            break
        if not isinstance(rec, dict):
            errors.append((idx, "record not a dict"))
            continue
        if not _validate(rec):
            errors.append((idx, "missing required field"))
            continue
        transformed = _transform(rec)
        processed.append(transformed)
        total_processed += 1
        for k in transformed:
            _aggregate(field_counts, k)

    summary: Dict[str, Any] = {
        "total_records": len(records),
        "processed": total_processed,
        "errors": len(errors),
        "field_counts": field_counts,
    }

    result: Dict[str, Any] = {
        "data": processed,
        "summary": summary,
        "error_details": errors,
    }

    return result

