def analyze_dataset(
    data: Iterable[Dict[str, Any]],
    key_field: str = 'id',
    value_field: str = 'value',
    min_count: int = 1,
) -> Dict[str, Any]:
    def _normalize(val: Any) -> str:
        if val is None:
            return ''
        return str(val).strip().lower()

    def _group_by(records: Iterable[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in records:
            if not isinstance(rec, dict):
                continue
            k = _normalize(rec.get(key_field))
            if not k:
                continue
            groups.setdefault(k, []).append(rec)
        return groups

    def _compute_stats(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = len(group)
        values: List[Any] = []
        for rec in group:
            v = rec.get(value_field)
            if v is not None:
                values.append(v)
        avg = sum(values) / total if values else 0
        return {
            'count': total,
            'average': avg,
            'sample': values[:5],
        }

    if not isinstance(data, Iterable):
        raise TypeError('data must be an iterable of dicts')

    grouped = _group_by(data)
    stats: Dict[str, Dict[str, Any]] = {}
    for k, grp in grouped.items():
        if len(grp) < min_count:
            continue
        stats[k] = _compute_stats(grp)

    summary = {
        'total_groups': len(stats),
        'unique_keys': sorted(stats.keys()),
        'overall_average': sum(s['average'] for s in stats.values()) / len(stats) if stats else 0,
    }

    return {
        'stats': stats,
        'summary': summary,
    }

