from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_transactions(
    records: List[Dict[str, Any]],
    threshold: float = 0.0,
    max_group_size: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _validate(rec: Dict[str, Any]) -> bool:
        required = {"id", "account", "amount", "currency"}
        if not isinstance(rec, dict):
            return False
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], (int, str)):
            return False
        if not isinstance(rec["account"], str):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if not isinstance(rec["currency"], str):
            return False
        return True

    def _normalize_amount(amount: Any) -> float:
        try:
            return float(amount)
        except Exception:
            return 0.0

    def _group_by_account(valid: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in valid:
            acc = rec["account"].strip().upper()
            groups.setdefault(acc, []).append(rec)
        return groups

    def _filter_by_threshold(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return [r for r in group if _normalize_amount(r["amount"]) >= threshold]

    def _limit_group(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        if max_group_size is None:
            return group
        return group[:max_group_size]

    def _aggregate(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        for r in group:
            amt = _normalize_amount(r["amount"])
            total += amt
            count += 1
        return {"count": count, "total": total}

    valid_records: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, rec in enumerate(records):
        if _validate(rec):
            valid_records.append(rec)
        else:
            errors.append((idx, "invalid record"))

    grouped = _group_by_account(valid_records)
    processed: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {}

    for acc, group in grouped.items():
        filtered = _filter_by_threshold(group)
        limited = _limit_group(filtered)
        agg = _aggregate(limited)
        processed.append({"account": acc, "transactions": limited, "summary": agg})
        stats[acc] = agg

    result = {
        "processed": processed,
        "stats": stats,
        "errors": errors,
        "total_records": len(records),
        "valid_records": len(valid_records),
        "invalid_records": len(errors),
    }
    return processed, result

