        if not include_inactive and not u.get("active", True):
            return False
        return True

    def _normalize(u: Dict[str, Any]) -> Dict[str, Any]:
        norm = dict(u)
        norm["name"] = norm["name"].strip().title()
        norm["email"] = norm.get("email", "").strip().lower()
        return norm

    valid_users: List[Dict[str, Any]] = []
    age_counts: Dict[str, int] = {}

    for raw in users:
        if not _validate_user(raw):
            continue
        if not _filter(raw):
            continue
        norm_user = _normalize(raw)
        valid_users.append(norm_user)
        age_bucket = f"{(norm_user["age"] // 10) * 10}s"
        age_counts[age_bucket] = age_counts.get(age_bucket, 0) + 1

    valid_users.sort(key=lambda x: (x["age"], x["name"]))
    return valid_users, age_counts

