def analyze_records(records: List[Dict[str, Any]], threshold: float = 0.5) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        required = {"id", "value", "tags"}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["value"], (int, float)):
            return False
        if not isinstance(rec["tags"], list):
            return False
        return True

