        norm: List[str] = []
        for t in tags:
            if isinstance(t, str):
                s = t.strip().lower()
                if s:
                    norm.append(s)
        return norm

    def _aggregate(records: List[Dict[str, Any]]) -> Tuple[Dict[int, float], Dict[str, int]]:
        sums: Dict[int, float] = {}
        tag_counts: Dict[str, int] = {}
        for rec in records:
            val = float(rec["value"])
            sums[rec["id"]] = sums.get(rec["id"], 0.0) + val
            for tag in rec["tags"]:
                tag_counts[tag] = tag_counts.get(tag, 0) + 1
        return sums, tag_counts

    def _filter_by_threshold(sums: Dict[int, float], threshold: float) -> List[int]:
        return [k for k, v in sums.items() if v >= threshold]

    valid_records: List[Dict[str, Any]] = []
    for rec in records:
        if _validate_record(rec):
            rec["tags"] = _normalize_tags(rec["tags"])
            valid_records.append(rec)

    sums, tag_counts = _aggregate(valid_records)
    ids_above = _filter_by_threshold(sums, threshold)

    result: Dict[str, Any] = {
