from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_dataset(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    numeric_field: str,
    category_field: str,
    min_value: Optional[float] = None,
    max_records: int = 5000,
) -> Tuple[Dict[str, int], Dict[str, List[Dict[str, Any]]], Dict[str, Any]]:
    def _normalize(val: Any) -> str:
        if val is None:
            return ""
        return str(val).strip().lower()

    def _is_valid(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or numeric_field not in rec or category_field not in rec:
            return False
        return True

    def _aggregate_counts(recs: List[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for r in recs:
            k = _normalize(r[key_field])
            counts[k] = counts.get(k, 0) + 1
        return counts

    def _group_by_category(recs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in recs:
            cat = _normalize(r[category_field])
            if cat not in groups:
                groups[cat] = []
            groups[cat].append(r)
        return groups

    def _median(values: List[float]) -> float:
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    valid_records: List[Dict[str, Any]] = []
    for rec in records:
        if not _is_valid(rec):
            continue
        try:
            num = float(rec[numeric_field])
        except (ValueError, TypeError):
            continue
        if min_value is not None and num < min_value:
            continue
        valid_records.append(rec)
        if len(valid_records) >= max_records:
            break

    counts = _aggregate_counts(valid_records)
    groups = _group_by_category(valid_records)

    numeric_values: List[float] = []
    for r in valid_records:
        try:
            numeric_values.append(float(r[numeric_field]))
        except (ValueError, TypeError):
            pass
    median_value = _median(numeric_values)

    top_counts = sorted(counts.items(), key=lambda kv: (-kv[1], kv[0]))[:10]
    summary = {
        "total_valid": len(valid_records),
        "unique_keys": len(counts),
        "median_numeric": median_value,
        "top_keys": [{"key": k, "count": c} for k, c in top_counts],
        "categories": {cat: len(lst) for cat, lst in groups.items()},
    }

    return counts, groups, summary

