            return item
        try:
            return transform(item)
        except Exception:
            return item

    def _passes_filter(item: Dict[str, Any]) -> bool:
        if filter_predicate is None:
            return True
        try:
            return bool(filter_predicate(item))
        except Exception:
            return False

    results: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {
        "total": 0,
        "filtered": 0,
        "transformed": 0,
        "unique_keys": set(),
    }

    for raw in data:
        stats["total"] += 1
        if not isinstance(raw, dict):
            continue
        if key not in raw:
            continue
        value = raw[key]
        norm = _normalize_value(value)
        raw[key] = norm
        if not _passes_filter(raw):
            stats["filtered"] += 1
            continue
        transformed = _apply_transform(raw)
        stats["transformed"] += 1
        results.append(transformed)
        stats["unique_keys"].add(norm)
        if len(results) >= max_items:
            break

    stats["unique_keys"] = len(stats["unique_keys"])
    summary = {
        "count": len(results),
        "stats": stats,
        "sample": results[:5],
