def process_transactions(records: List[Dict[str, Any]], threshold: float = 0.0) -> Dict[str, Any]:
    # validate a single record
    def _validate(rec: Dict[str, Any]) -> bool:
        required = {"id", "amount", "currency", "timestamp"}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if rec["amount"] < 0:
            return False
        return True

    # normalize fields
    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        rec = dict(rec)
        rec["amount"] = float(rec["amount"])
        rec["currency"] = rec["currency"].upper()
        rec["timestamp"] = int(rec["timestamp"])
        return rec

    # group by currency
    def _group_by_currency(recs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in recs:
            cur = r["currency"]
            groups.setdefault(cur, []).append(r)
        return groups

    # aggregate totals
    def _aggregate(group: List[Dict[str, Any]]) -> Tuple[float, int]:
        total = 0.0
        count = 0
        for r in group:
            total += r["amount"]
            count += 1
        return total, count

    valid_records: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append((idx, "not a dict"))
            continue
        if not _validate(rec):
            errors.append((idx, "validation failed"))
            continue
        valid_records.append(_normalize(rec))

    grouped = _group_by_currency(valid_records)

    summary: Dict[str, Any] = {}
    for cur, group in grouped.items():
        total, count = _aggregate(group)
        avg = total / count if count else 0.0
        summary[cur] = {
            "total_amount": total,
            "transaction_count": count,
            "average_amount": avg,
            "above_threshold": [r for r in group if r["amount"] > threshold],
        }

    result: Dict[str, Any] = {
        "summary": summary,
        "errors": errors,
        "total_transactions": len(valid_records),
        "unique_currencies": list(grouped.keys()),
    }
    return result

