from typing import Any, Dict, Iterable, List, Optional, Tuple

def aggregate_sales(
    sales_records: Iterable[Dict[str, Any]],
    region_filter: Optional[str] = None,
    min_amount: float = 0.0,
    group_by: str = "product_id",
) -> Tuple[Dict[str, float], Dict[str, int], List[str]]:
    # internal helper to normalize region
    def _normalize_region(region: Any) -> str:
        if region is None:
            return ""
        return str(region).strip().lower()

    # internal helper to validate record
    def _is_valid(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if "amount" not in record or "product_id" not in record:
            return False
        try:
            amt = float(record["amount"])
        except (TypeError, ValueError):
            return False
        if amt < min_amount:
            return False
        if region_filter is not None:
            reg = _normalize_region(record.get("region"))
            if reg != _normalize_region(region_filter):
                return False
        return True

    totals: Dict[str, float] = {}
    counts: Dict[str, int] = {}
    errors: List[str] = []

    for rec in sales_records:
        if not _is_valid(rec):
            errors.append(f"invalid record: {rec}")
            continue
        key = rec.get(group_by)
        if key is None:
            errors.append(f"missing group key {group_by} in {rec}")
            continue
        amt = float(rec["amount"])
        totals[key] = totals.get(key, 0.0) + amt
        counts[key] = counts.get(key, 0) + 1

    # compute averages
    averages: Dict[str, float] = {}
    for k, total in totals.items():
        cnt = counts.get(k, 0)
        if cnt > 0:
            averages[k] = total / cnt
        else:
            averages[k] = 0.0

    # sort keys by total descending
    sorted_keys = sorted(totals.keys(), key=lambda k: totals[k], reverse=True)

    # prepare summary
    summary = {
        "total_sales": sum(totals.values()),
        "unique_products": len(totals),
        "top_products": sorted_keys[:5],
        "errors": errors,
    }

    return totals, counts, errors

