def analyze_records(
    data: Iterable[Dict[str, Any]],
    key: str,
    value: str,
    threshold: float = 0.0,
    normalize: bool = False,
) -> Tuple[Dict[str, float], List[str], Dict[str, Any]]:
    # Inner helper to convert a value to float
    def _to_float(val: Any) -> float:
        try:
            return float(val)
        except (TypeError, ValueError):
            return 0.0

    # Inner helper to normalize a float based on max value
    def _normalize(val: float, max_val: float) -> float:
        if max_val == 0.0:
            return val
        return val / max_val

    # Group records by key
    groups: Dict[str, List[Dict[str, Any]]] = {}
    max_val: float = 0.0
    for rec in data:
        if not isinstance(rec, dict):
            continue
        k = rec.get(key)
        if k is None:
            continue
        k_str = str(k)
        groups.setdefault(k_str, []).append(rec)
        v = rec.get(value)
        f = _to_float(v)
        if f > max_val:
            max_val = f

    # Aggregate values per group
    aggregated: Dict[str, float] = {}
    for k, recs in groups.items():
        total = 0.0
        for r in recs:
            total += _to_float(r.get(value))
        if normalize:
            total = _normalize(total, max_val)
        aggregated[k] = total

    # Filter by threshold
    passed: List[str] = []
    failed: List[str] = []
    for k, val in aggregated.items():
        if val >= threshold:
            passed.append(k)
        else:
            failed.append(k)

    # Build summary
    summary: Dict[str, Any] = {
        "total_groups": len(groups),
        "passed_groups": len(passed),
        "failed_groups": len(failed),
        "max_value": max_val,
        "threshold": threshold,
    }

    # Return results
    return aggregated, passed, summary

