from typing import List, Tuple, Dict, Any, Set, Optional


def analyze_network(
    nodes: List[str],
    edges: List[Tuple[str, str, int]],
    start: str,
    threshold: int = 10,
) -> Dict[str, Any]:
    # Build adjacency list for undirected weighted graph
    adjacency: Dict[str, List[Tuple[str, int]]] = {node: [] for node in nodes}
    for src, dst, weight in edges:
        if src in adjacency and dst in adjacency:
            adjacency[src].append((dst, weight))
            adjacency[dst].append((src, weight))
    # Helper: Dijkstra's algorithm to compute shortest distances
    def dijkstra(source: str) -> Dict[str, int]:
        import heapq
        distances: Dict[str, int] = {node: float('inf') for node in nodes}
        distances[source] = 0
        heap: List[Tuple[int, str]] = [(0, source)]
        while heap:
            dist, node = heapq.heappop(heap)
            if dist > distances[node]:
                continue
            for neighbor, w in adjacency[node]:
                new_dist = dist + w
                if new_dist < distances[neighbor]:
                    distances[neighbor] = new_dist
                    heapq.heappush(heap, (new_dist, neighbor))
        return distances
    # Validate start node
    if start not in adjacency:
        return {"error": f"start node {start!r} not in graph"}
    # Compute distances from start
    distances = dijkstra(start)
    # Identify nodes within threshold distance
    reachable: Set[str] = {node for node, d in distances.items() if d <= threshold}
    # Build subgraph containing only reachable nodes
    subgraph: Dict[str, List[Tuple[str, int]]] = {}
    for node in reachable:
        subgraph[node] = [(nbr, w) for nbr, w in adjacency[node] if nbr in reachable]
    # Compute degree centrality for subgraph
    centrality: Dict[str, int] = {node: len(neigh) for node, neigh in subgraph.items()}
    # Determine most central node
    most_central: Optional[str] = None
    max_deg = -1
    for node, deg in centrality.items():
        if deg > max_deg:
            max_deg = deg
            most_central = node
    # Prepare result dictionary
    result: Dict[str, Any] = {
        "start": start,
        "threshold": threshold,
        "reachable_count": len(reachable),
        "most_central_node": most_central,
        "centrality": centrality,
        "subgraph": subgraph,
        "distances": distances,
    }
    return result

