from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_user_data(
    users: List[Dict[str, Any]],
    min_age: int = 0,
    max_age: Optional[int] = None,
    include_inactive: bool = False,
) -> Dict[str, Any]:
    def _normalize_name(name: str) -> str:
        return name.strip().title()

    def _is_active(user: Dict[str, Any]) -> bool:
        return bool(user.get("active", False))

    def _filter_age(user: Dict[str, Any]) -> bool:
        age = user.get("age")
        if age is None:
            return False
        if age < min_age:
            return False
        if max_age is not None and age > max_age:
            return False
        return True

    def _extract_stats(users: Iterable[Dict[str, Any]]) -> Tuple[int, int, int]:
        total = 0
        active = 0
        inactive = 0
        for u in users:
            total += 1
            if _is_active(u):
                active += 1
            else:
                inactive += 1
        return total, active, inactive

    filtered_users = []
    for u in users:
        if not _filter_age(u):
            continue
        if not include_inactive and not _is_active(u):
            continue
        u_copy = dict(u)
        u_copy["name"] = _normalize_name(u_copy.get("name", ""))
        filtered_users.append(u_copy)

    total, active_count, inactive_count = _extract_stats(filtered_users)

    age_distribution: Dict[int, int] = {}
    for u in filtered_users:
        age = u.get("age")
        if age is None:
            continue
        age_distribution[age] = age_distribution.get(age, 0) + 1

    top_domains: List[Tuple[str, int]] = []
    domain_counts: Dict[str, int] = {}
    for u in filtered_users:
        email = u.get("email")
        if not email or "@" not in email:
            continue
        domain = email.split("@")[-1].lower()
        domain_counts[domain] = domain_counts.get(domain, 0) + 1
    for d, c in sorted(domain_counts.items(), key=lambda kv: -kv[1])[:5]:
        top_domains.append((d, c))

    return {
        "total_users": total,
        "active_users": active_count,
        "inactive_users": inactive_count,
        "age_distribution": age_distribution,
        "top_email_domains": top_domains,
        "filtered_users": filtered_users,
    }

