from typing import List, Dict, Any, Optional, Tuple


def process_records(records: List[Dict[str, Any]], key: str, agg_field: str) -> Tuple[Dict[Any, int], List[Dict[str, Any]]]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec or agg_field not in rec:
            return False
        if not isinstance(rec[key], (str, int, float)):
            return False
        if not isinstance(rec[agg_field], (int, float)):
            return False
        return True

    def _normalize_key(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip().lower()
        return val

    aggregation: Dict[Any, int] = {}
    valid_records: List[Dict[str, Any]] = []

    for rec in records:
        if not _validate_record(rec):
            continue
        norm_key = _normalize_key(rec[key])
        agg_val = rec[agg_field]
        aggregation[norm_key] = aggregation.get(norm_key, 0) + int(agg_val)
        valid_records.append(rec)

    def _sort_by_key(d: Dict[Any, int]) -> List[Tuple[Any, int]]:
        return sorted(d.items(), key=lambda kv: (-kv[1], kv[0]))

    sorted_agg = _sort_by_key(aggregation)

    def _build_summary(sorted_items: List[Tuple[Any, int]]) -> List[Dict[str, Any]]:
        summary: List[Dict[str, Any]] = []
        for k, v in sorted_items:
            summary.append({"key": k, "total": v})
        return summary

    summary = _build_summary(sorted_agg)

    def _filter_records(records: List[Dict[str, Any]], min_total: Optional[int] = None) -> List[Dict[str, Any]]:
        if min_total is None:
            return records
        filtered: List[Dict[str, Any]] = []
        for rec in records:
            norm_key = _normalize_key(rec[key])
            if aggregation.get(norm_key, 0) >= min_total:
                filtered.append(rec)
        return filtered

    filtered_records = _filter_records(valid_records, min_total=None)

    return aggregation, filtered_records

