from typing import Any, Dict, Iterable, List, Optional, Tuple, Union


def process_records(
    records: Iterable[Dict[str, Any]],
    key: str,
    threshold: float = 0.5,
) -> Dict[str, Any]:
    # Validate input parameters
    if threshold < 0 or threshold > 1:
        raise ValueError("threshold must be between 0 and 1")

    def _normalize(value: Any) -> str:
        if value is None:
            return ""
        if isinstance(value, (int, float)):
            return f"{value:.4f}"
        return str(value).strip().lower()

    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if key not in record:
            return False
        val = record[key]
        if val is None:
            return False
        return True

    def _aggregate(records: List[Dict[str, Any]]) -> Dict[str, List[Any]]:
        agg: Dict[str, List[Any]] = {}
        for rec in records:
            k = _normalize(rec[key])
            if k not in agg:
                agg[k] = []
            agg[k].append(rec)
        return agg

    def _filter_by_threshold(agg: Dict[str, List[Any]]) -> Dict[str, List[Any]]:
        filtered: Dict[str, List[Any]] = {}
        for k, recs in agg.items():
            if len(recs) / total_records >= threshold:
                filtered[k] = recs
        return filtered

    # Main processing pipeline
    valid_records: List[Dict[str, Any]] = []
    for rec in records:
        if _validate(rec):
            valid_records.append(rec)

    total_records = len(valid_records)
    if total_records == 0:
        return {
            "status": "no_valid_records",
            "total": 0,
            "aggregated": {},
            "filtered": {},
        }

    aggregated = _aggregate(valid_records)
    filtered = _filter_by_threshold(aggregated)

    # Compute statistics
    stats: Dict[str, Any] = {
        "total_records": total_records,
        "unique_keys": len(aggregated),
        "filtered_keys": len(filtered),
    }

    # Prepare result structure
    result: Dict[str, Any] = {
        "status": "success",
        "stats": stats,
        "aggregated": aggregated,
        "filtered": filtered,
    }

    # Optional: add summary of top keys
    top_keys: List[Tuple[str, int]] = sorted(
        [(k, len(v)) for k, v in aggregated.items()],
        key=lambda x: -x[1],
    )[:5]
    result["top_keys"] = [
        {"key": k, "count": c} for k, c in top_keys
    ]

    return result

