from typing import Any, Dict, List, Optional, Tuple, Iterable


def process_records(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    max_records: Optional[int] = None,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> Tuple[bool, List[str]]:
        missing = [field for field in required_fields if field not in record]
        return (len(missing) == 0, missing)

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        transformed = {}
        for k, v in record.items():
            if isinstance(v, str):
                transformed[k] = v.strip()
            else:
                transformed[k] = v
        return transformed

    def _aggregate(stats: Dict[str, Any], record: Dict[str, Any]) -> None:
        for k, v in record.items():
            if isinstance(v, (int, float)):
                stats.setdefault(k, 0)
                stats[k] += v

    def _compute_percentiles(values: List[float]) -> Dict[str, float]:
        if not values:
            return {}
        sorted_vals = sorted(values)
        n = len(sorted_vals)
        def _percentile(p):
            idx = int(p * n)
            return sorted_vals[min(idx, n - 1)]
        return {
            "p25": _percentile(0.25),
            "p50": _percentile(0.5),
            "p75": _percentile(0.75),
        }

    def _filter_records(records: List[Dict[str, Any]], threshold: float) -> List[Dict[str, Any]]:
        filtered = []
        for rec in records:
            score = rec.get("score", 0)
            if isinstance(score, (int, float)) and score >= threshold:
                filtered.append(rec)
        return filtered

    processed: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {}
    errors: List[Dict[str, Any]] = []

    for idx, rec in enumerate(records):
        if max_records is not None and idx >= max_records:
            break
        valid, missing = _validate(rec)
        if not valid:
            errors.append({"index": idx, "missing": missing})
            continue
        transformed = _transform(rec)
        _aggregate(stats, transformed)
        processed.append(transformed)

    # Compute percentiles for numeric fields
    numeric_values: Dict[str, List[float]] = {}
    for rec in processed:
        for k, v in rec.items():
            if isinstance(v, (int, float)):
                numeric_values.setdefault(k, []).append(float(v))

    percentiles: Dict[str, Dict[str, float]] = {}
    for k, vals in numeric_values.items():
        percentiles[k] = _compute_percentiles(vals)

    # Filter records with score above median
    median_scores = [rec.get("score", 0) for rec in processed if isinstance(rec.get("score", 0), (int, float))]
    median = 0
    if median_scores:
        sorted_scores = sorted(median_scores)
        mid = len(sorted_scores) // 2
        median = sorted_scores[mid]
    filtered = _filter_records(processed, median)

    result = {
        "processed_count": len(processed),
        "filtered_count": len(filtered),
        "errors_count": len(errors),
        "stats": stats,
        "percentiles": percentiles,
        "errors": errors,
    }
    return result

