from typing import Any, Dict, Iterable, List, Optional, Tuple, Union

def process_dataset(
    data: Iterable[Dict[str, Any]],
    key: str,
    value: str,
    date_field: str,
    start_date: Optional[str] = None,
    end_date: Optional[str] = None,
    min_value: Optional[float] = None,
    *,
    normalize: bool = False,
    include_meta: bool = False,
) -> Tuple[Dict[str, int], List[Dict[str, Any]], float, Dict[str, Any]]:
    def _to_float(val: Any) -> float:
        try:
            return float(val)
        except (TypeError, ValueError):
            return 0.0

    def _parse_date(d: Any) -> Optional[str]:
        if isinstance(d, str):
            return d
        return None

    def _within_range(d: str) -> bool:
        if start_date and d < start_date:
            return False
        if end_date and d > end_date:
            return False
        return True

    counts: Dict[str, int] = {}
    filtered_records: List[Dict[str, Any]] = []
    total_val: float = 0.0
    record_count: int = 0

    for rec in data:
        if not isinstance(rec, dict):
            continue
        rec_key = rec.get(key)
        if rec_key is None:
            continue
        rec_val = rec.get(value)
        if rec_val is None:
            continue
        rec_date_raw = rec.get(date_field)
        rec_date = _parse_date(rec_date_raw)
        if rec_date is None or not _within_range(rec_date):
            continue
        val_float = _to_float(rec_val)
        if normalize:
            val_float = val_float / 100.0
        if min_value is not None and val_float < min_value:
            continue
        counts[rec_key] = counts.get(rec_key, 0) + 1
        total_val += val_float
        record_count += 1
        if include_meta:
            filtered_records.append(rec)
        else:
            filtered_records.append({key: rec_key, value: val_float, date_field: rec_date})

    avg_val = total_val / record_count if record_count else 0.0

    top_keys = sorted(counts.items(), key=lambda kv: kv[1], reverse=True)[:10]
    top_key_list = [k for k, _ in top_keys]

    summary_meta: Dict[str, Any] = {
        "records_processed": record_count,
        "unique_keys": len(counts),
        "average_value": avg_val,
        "top_keys": top_key_list,
        "date_range": {
            "start": start_date,
            "end": end_date,
        },
    }

    return counts, filtered_records, avg_val, summary_meta

