from typing import List, Dict, Any, Optional, Tuple, Iterable


def process_user_data(users: List[Dict[str, Any]], min_age: int = 0, include_inactive: bool = False) -> Dict[str, Any]:
    def _validate_user(user: Dict[str, Any]) -> bool:
        required_keys = {"id", "name", "age", "country", "active"}
        if not isinstance(user, dict):
            return False
        if not required_keys.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int):
            return False
        if not isinstance(user["name"], str):
            return False
        if not isinstance(user["age"], int):
            return False
        if not isinstance(user["country"], str):
            return False
        if not isinstance(user["active"], bool):
            return False
        return True

    def _compute_score(user: Dict[str, Any]) -> int:
        base = 10
        age_factor = max(0, user["age"] - 18)
        country_bonus = 5 if user["country"] in {"US", "CA"} else 0
        active_bonus = 20 if user["active"] else 0
        return base + age_factor + country_bonus + active_bonus

    def _aggregate_by_country(valid_users: List[Dict[str, Any]]) -> Dict[str, Dict[str, Any]]:
        country_stats: Dict[str, Dict[str, Any]] = {}
        for u in valid_users:
            c = u["country"]
            if c not in country_stats:
                country_stats[c] = {"count": 0, "total_score": 0, "users": []}
            country_stats[c]["count"] += 1
            country_stats[c]["total_score"] += _compute_score(u)
            country_stats[c]["users"].append(u["id"])
        for c, stats in country_stats.items():
            avg = stats["total_score"] / stats["count"] if stats["count"] else 0
            stats["average_score"] = avg
        return country_stats

    valid_users: List[Dict[str, Any]] = []
    for user in users:
        if not _validate_user(user):
            continue
        if user["age"] < min_age:
            continue
        if not include_inactive and not user["active"]:
            continue
        valid_users.append(user)

    aggregated = _aggregate_by_country(valid_users)

    overall = {
        "total_users": len(valid_users),
        "countries": len(aggregated),
        "country_stats": aggregated,
    }

    return overall

