from typing import List, Dict, Any, Optional, Tuple


def process_transactions(
    transactions: List[Dict[str, Any]],
    min_amount: float = 0.0,
    max_amount: Optional[float] = None,
    categories: Optional[List[str]] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _normalize_amount(amount: Any) -> float:
        try:
            return float(amount)
        except (TypeError, ValueError):
            return 0.0

    def _filter_by_category(txn: Dict[str, Any]) -> bool:
        if not categories:
            return True
        cat = txn.get("category")
        return cat in categories

    def _filter_by_amount(txn: Dict[str, Any]) -> bool:
        amt = _normalize_amount(txn.get("amount"))
        if amt < min_amount:
            return False
        if max_amount is not None and amt > max_amount:
            return False
        return True

    def _aggregate_by_month(txns: List[Dict[str, Any]]) -> Dict[str, float]:
        agg: Dict[str, float] = {}
        for t in txns:
            date = t.get("date")
            if not date:
                continue
            month = date[:7]
            amt = _normalize_amount(t.get("amount"))
            agg[month] = agg.get(month, 0.0) + amt
        return agg

    filtered: List[Dict[str, Any]] = []
    for txn in transactions:
        if not isinstance(txn, dict):
            continue
        if not _filter_by_category(txn):
            continue
        if not _filter_by_amount(txn):
            continue
        filtered.append(txn)

    aggregated = _aggregate_by_month(filtered)

