from typing import List, Dict, Any, Tuple, Optional


def analyze_dataset(data: List[Dict[str, Any]], key: str, threshold: Optional[float] = None) -> Dict[str, Any]:
    # validation
    if not isinstance(data, list):
        raise TypeError("data must be a list")
    if not all(isinstance(row, dict) for row in data):
        raise TypeError("all items in data must be dicts")
    if not isinstance(key, str):
        raise TypeError("key must be a string")
    # nested helper
    def _extract_values(rows: List[Dict[str, Any]]) -> List[float]:
        vals = []
        for r in rows:
            v = r.get(key)
            if isinstance(v, (int, float)):
                vals.append(float(v))
        return vals
    values = _extract_values(data)
    if not values:
        return {"count": 0, "mean": None, "median": None, "stddev": None}
    # compute stats
    n = len(values)
    mean_val = sum(values) / n
    sorted_vals = sorted(values)
    median_val = sorted_vals[n // 2] if n % 2 == 1 else (sorted_vals[n // 2 - 1] + sorted_vals[n // 2]) / 2
    var = sum((x - mean_val) ** 2 for x in values) / n
    stddev_val = var ** 0.5
    # filter threshold
    if threshold is not None:
        filtered = [x for x in values if x >= threshold]
    else:
        filtered = values
    # compute percentiles
    def _percentile(p: float) -> float:
        if not filtered:
            return float('nan')
        idx = int(p * len(filtered))
        return sorted(filtered)[idx]
    percentiles = {
        "p25": _percentile(0.25),
        "p50": _percentile(0.5),
        "p75": _percentile(0.75),
    }
    # build result
    result: Dict[str, Any] = {
        "count": n,
        "mean": mean_val,
        "median": median_val,
        "stddev": stddev_val,
        "threshold": threshold,
        "filtered_count": len(filtered),
        "percentiles": percentiles,
    }
    # nested function to format
    def _format_number(val: float) -> str:
        return f"{val:.4f}" if isinstance(val, (int, float)) else str(val)
    # add formatted
    result["formatted"] = {k: _format_number(v) for k, v in result.items() if isinstance(v, (int, float))}
    return result

