from typing import List, Dict, Tuple, Optional, Iterable, Any

def process_user_events(
    events: Iterable[Dict[str, Any]],
    external_lookup: Optional[Dict[str, Dict[str, Any]]] = None,
    min_events: int = 1,
) -> Dict[str, Any]:
    # nested helper to validate event
    def _validate(ev: Dict[str, Any]) -> bool:
        required = {"user_id", "timestamp", "action"}
        if not isinstance(ev, dict):
            return False
        if not required.issubset(ev.keys()):
            return False
        if not isinstance(ev.get("user_id"), str):
            return False
        if not isinstance(ev.get("timestamp"), (int, float)):
            return False
        if not isinstance(ev.get("action"), str):
            return False
        return True

    # nested helper to normalize timestamp
    def _normalize_ts(ts: Any) -> float:
        if isinstance(ts, (int, float)):
            return float(ts)
        try:
            return float(ts)
        except Exception:
            return 0.0

    # group events by user_id
    user_events: Dict[str, List[Dict[str, Any]]] = {}
    for ev in events:
        if not _validate(ev):
            continue
        uid = ev["user_id"]
        ev_copy = dict(ev)
        ev_copy["timestamp"] = _normalize_ts(ev_copy["timestamp"])
        user_events.setdefault(uid, []).append(ev_copy)

    # compute per-user stats
    user_stats: Dict[str, Dict[str, Any]] = {}
    for uid, evs in user_events.items():
        if len(evs) < min_events:
            continue
        evs.sort(key=lambda e: e["timestamp"])
        first_ts = evs[0]["timestamp"]
        last_ts = evs[-1]["timestamp"]
        duration = last_ts - first_ts
        actions = [e["action"] for e in evs]
        unique_actions = set(actions)
        user_stats[uid] = {
            "count": len(evs),
            "duration": duration,
            "first_ts": first_ts,
            "last_ts": last_ts,
            "unique_actions": list(unique_actions),
        }

    # merge with external lookup if provided
    if external_lookup:
        for uid, stats in user_stats.items():
            ext = external_lookup.get(uid)
            if ext:
                stats.update(ext)

    # build summary
    total_users = len(user_stats)
    total_events = sum(stats["count"] for stats in user_stats.values())
    avg_events_per_user = total_events / total_users if total_users else 0

    # find user with longest duration
    longest_user: Optional[str] = None
    longest_duration = -1.0
    for uid, stats in user_stats.items():
        if stats["duration"] > longest_duration:
            longest_duration = stats["duration"]
            longest_user = uid

    # return structured result
    return {
        "total_users": total_users,
        "total_events": total_events,
        "avg_events_per_user": avg_events_per_user,
        "longest_user": longest_user,
        "longest_duration": longest_duration,
        "user_stats": user_stats,
    }

