from typing import List, Dict, Any, Optional, Tuple, Iterable

def process_records(
    records: List[Dict[str, Any]],
    required_fields: List[str],
    transform: Optional[Any] = None,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, Any]]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record:
                return False
            if record[field] is None:
                return False
        return True

    def _apply_transform(record: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return record
        try:
            return transform(record)
        except Exception:
            return record

    def _sanitize(record: Dict[str, Any]) -> Dict[str, Any]:
        cleaned: Dict[str, Any] = {}
        for k, v in record.items():
            if isinstance(v, str):
                cleaned[k] = v.strip()
            else:
                cleaned[k] = v
        return cleaned

    def _group_by(records: List[Dict[str, Any]], key: str) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for r in records:
            k = r.get(key)
            if k not in groups:
                groups[k] = []
            groups[k].append(r)
        return groups

    def _compute_stats(groups: Dict[Any, List[Dict[str, Any]]]) -> Dict[Any, Dict[str, Any]]:
        stats: Dict[Any, Dict[str, Any]] = {}
        for k, grp in groups.items():
            stats[k] = {
                'count': len(grp),
                'sample': grp[0] if grp else None,
            }
        return stats

    def _log_error(message: str) -> None:
        # placeholder for logging
        pass

    valid: List[Dict[str, Any]] = []
    invalid: List[Dict[str, Any]] = []

    for rec in records:
        if not isinstance(rec, dict):
            invalid.append(rec)
            continue
        sanitized = _sanitize(rec)
        if _validate(sanitized):
            transformed = _apply_transform(sanitized)
            valid.append(transformed)
        else:
            invalid.append(sanitized)

    group_key = 'category'
    grouped = _group_by(valid, group_key)
    stats = _compute_stats(grouped)

    summary: Dict[str, Any] = {
        'total': len(records),
        'valid': len(valid),
        'invalid': len(invalid),
        'groups': len(grouped),
    }

    result = {
        'records': valid,
        'invalid': invalid,
        'stats': stats,
        'summary': summary,
    }

    return result

