def process_user_data(
    users: Iterable[Dict[str, Any]],
    age_threshold: int = 18,
    include_inactive: bool = False,
) -> Tuple[List[Dict[str, Any]], List[str], Dict[str, int]]:
    def _validate_user(user: Dict[str, Any]) -> bool:
        required = {"id", "name", "email", "age", "active"}
        if not isinstance(user, dict):
            return False
        if not required.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int):
            return False
        if not isinstance(user["name"], str) or not user["name"]:
            return False
        if not isinstance(user["email"], str) or "@" not in user["email"]:
            return False
        if not isinstance(user["age"], int) or user["age"] < 0:
            return False
        if not isinstance(user["active"], bool):
            return False
        return True

    def _normalize_email(email: str) -> str:
        return email.strip().lower()

    valid_users: List[Dict[str, Any]] = []
    invalid_ids: List[str] = []
    age_counts: Dict[str, int] = {"<18": 0, "18-30": 0, "31-50": 0, ">50": 0}

    for raw in users:
        if not _validate_user(raw):
            invalid_ids.append(str(raw.get("id", "unknown")))
            continue
        user = dict(raw)
        user["email"] = _normalize_email(user["email"])
        if not include_inactive and not user["active"]:
            continue
        if user["age"] < age_threshold:
            continue
        valid_users.append(user)
        if user["age"] < 18:
            age_counts["<18"] += 1
        elif 18 <= user["age"] <= 30:
            age_counts["18-30"] += 1
        elif 31 <= user["age"] <= 50:
            age_counts["31-50"] += 1
        else:
            age_counts[">50"] += 1

    def _sort_by_name(u: Dict[str, Any]) -> str:
        return u["name"].lower()

    valid_users.sort(key=_sort_by_name)

    return valid_users, invalid_ids, age_counts

