from typing import List, Dict, Any, Tuple, Optional, Set

def process_transactions(
    transactions: List[Dict[str, Any]],
    threshold: float,
    *,
    include_failed: bool = False,
    max_entries: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _validate_tx(tx: Dict[str, Any]) -> bool:
        required_keys = {"id", "amount", "status", "timestamp"}
        if not isinstance(tx, dict):
            return False
        if not required_keys.issubset(tx.keys()):
            return False
        if not isinstance(tx["id"], str):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if tx["status"] not in {"pending", "completed", "failed"}:
            return False
        if not isinstance(tx["timestamp"], str):
            return False
        return True

    def _parse_amount(amount: Any) -> Optional[float]:
        try:
            return float(amount)
        except (TypeError, ValueError):
            return None

    def _format_tx(tx: Dict[str, Any]) -> Dict[str, Any]:
        return {
            "transaction_id": tx["id"],
            "value": tx["amount"],
            "state": tx["status"],
            "time": tx["timestamp"],
        }

    valid_txs: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {
        "total": 0,
        "valid": 0,
        "invalid": 0,
        "failed": 0,
        "amount_sum": 0.0,
        "amount_count": 0,
    }

    for tx in transactions:
        stats["total"] += 1
        if not _validate_tx(tx):
            stats["invalid"] += 1
            continue
        stats["valid"] += 1
        amt = _parse_amount(tx["amount"])
        if amt is None:
            stats["invalid"] += 1
            continue
        if tx["status"] == "failed":
            stats["failed"] += 1
            if not include_failed:
                continue
        if amt < threshold:
            continue
        stats["amount_sum"] += amt
        stats["amount_count"] += 1
        valid_txs.append(_format_tx(tx))
        if max_entries is not None and len(valid_txs) >= max_entries:
            break

    avg_amount = (
        stats["amount_sum"] / stats["amount_count"]
        if stats["amount_count"] > 0
        else 0.0
    )
    stats["average_amount"] = avg_amount
    stats["processed"] = len(valid_txs)

    def _summarize_status() -> Dict[str, int]:
        status_counts: Dict[str, int] = {}
        for tx in valid_txs:
            status = tx["state"]
            status_counts[status] = status_counts.get(status, 0) + 1
        return status_counts

    stats["status_counts"] = _summarize_status()

    def _generate_report() -> str:
        lines: List[str] = []
        lines.append(f"Total transactions: {stats['total']}")
        lines.append(f"Valid transactions: {stats['valid']}")
        lines.append(f"Invalid transactions: {stats['invalid']}")
        lines.append(f"Failed transactions: {stats['failed']}")
        lines.append(f"Processed transactions: {stats['processed']}")
        lines.append(f"Average amount: {stats['average_amount']:.2f}")
        lines.append("Status distribution:")
        for status, count in sorted(stats['status_counts'].items()):
            lines.append(f"  {status}: {count}")
        return "\\n".join(lines)

    report = _generate_report()
    stats["report"] = report

    return valid_txs, stats

