from typing import List, Dict, Tuple, Optional, Any


def analyze_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: float = 0.5,
) -> Dict[str, Any]:
    def _normalize(val: Any) -> str:
        if val is None:
            return ""
        return str(val).strip().lower()

    def _validate(record: Dict[str, Any]) -> Tuple[bool, Optional[str]]:
        if not isinstance(record, dict):
            return False, "not a dict"
        if key not in record:
            return False, f"missing key {key}"
        if not isinstance(record[key], (int, float, str)):
            return False, f"invalid type for key {key}"
        return True, None

    def _median(values: List[float]) -> Optional[float]:
        if not values:
            return None
        sorted_vals = sorted(values)
        n = len(sorted_vals)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    def _aggregate(valid_records: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for rec in valid_records:
            k = _normalize(rec[key])
            if k not in agg:
                agg[k] = {"count": 0, "values": []}
            agg[k]["count"] += 1
            agg[k]["values"].append(rec.get("value"))
        return agg

    def _format_output(stats: Dict[str, Any]) -> List[Dict[str, Any]]:
        output: List[Dict[str, Any]] = []
        for k, data in stats.items():
            item: Dict[str, Any] = {"key": k, "count": data["count"]}
            if data["avg"] is not None:
                item["average"] = data["avg"]
            if data["median"] is not None:
                item["median"] = data["median"]
            output.append(item)
        return output

    valid: List[Dict[str, Any]] = []
    errors: List[str] = []

    for rec in records:
        ok, err = _validate(rec)
        if ok:
            valid.append(rec)
        else:
            errors.append(f"Record {rec} invalid: {err}")

    aggregated = _aggregate(valid)

    stats: Dict[str, Any] = {}
    for k, data in aggregated.items():
        vals = [v for v in data["values"] if isinstance(v, (int, float))]
        if vals:
            avg = sum(vals) / len(vals)
            med = _median(vals)
            stats[k] = {"count": data["count"], "avg": avg, "median": med}
        else:
            stats[k] = {"count": data["count"], "avg": None, "median": None}

    filtered = {k: v for k, v in stats.items() if v["avg"] is not None and v["avg"] >= threshold}

    formatted = _format_output(stats)

    return {
        "total_records": len(records),
        "valid_records": len(valid),
        "invalid_records": len(errors),
        "errors": errors,
        "statistics": stats,
        "filtered_statistics": filtered,
        "formatted_output": formatted,
    }

