def analyze_transactions(
    transactions: List[Dict[str, Any]],
    threshold: float = 100.0,
    include_details: bool = False,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        required_keys = {"id", "amount", "currency", "timestamp"}
        if not required_keys.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], (int, str)):
            return False
        if not isinstance(rec["amount"], (int, float)):
            return False
        if not isinstance(rec["currency"], str):
            return False
        if not isinstance(rec["timestamp"], str):
            return False
        return True

    def _aggregate(records: List[Dict[str, Any]]) -> Tuple[Dict[str, float], Dict[str, int]]:
        totals: Dict[str, float] = {}
        counts: Dict[str, int] = {}
        for rec in records:
            cur = rec["currency"]
            amt = float(rec["amount"])
            totals[cur] = totals.get(cur, 0.0) + amt
            counts[cur] = counts.get(cur, 0) + 1
        return totals, counts

    def _format_report(
        totals: Dict[str, float],
        counts: Dict[str, int],
        details: Optional[List[Dict[str, Any]]] = None,
    ) -> Dict[str, Any]:
        report: Dict[str, Any] = {}
        report["summary"] = {
            "total_currencies": len(totals),
            "total_transactions": sum(counts.values()),
            "average_per_currency": {
                cur: totals[cur] / counts[cur] if counts[cur] else 0.0
                for cur in totals
            },
        }
        if details is not None:
            report["details"] = details
        return report

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []
    for rec in transactions:
        if _validate_record(rec):
            valid_records.append(rec)
        else:
            invalid_records.append(rec)

    totals, counts = _aggregate(valid_records)

    high_value: List[Dict[str, Any]] = []
    for rec in valid_records:
        if float(rec["amount"]) >= threshold:
            high_value.append(rec)

    details: Optional[List[Dict[str, Any]]] = None
    if include_details:
        details = high_value

    report = _format_report(totals, counts, details)

    if invalid_records:
        report["invalid_records"] = {
            "count": len(invalid_records),
            "sample": invalid_records[:5],
        }

    return report

