def analyze_sales_data(
    sales: List[Dict[str, Any]],
    min_amount: float = 0.0,
    region_filter: Optional[str] = None,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        required = {"id", "amount", "region", "date"}
        if not isinstance(record, dict):
            return False
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["amount"], (int, float)):
            return False
        if record["amount"] < 0:
            return False
        return True

    def _parse_amount(amount: Any) -> float:
        try:
            return float(amount)
        except (TypeError, ValueError):
            return 0.0

    def _categorize(amount: float) -> str:
        if amount < 100:
            return "low"
        elif amount < 500:
            return "medium"
        else:
            return "high"

    totals: Dict[str, float] = {}
    counts: Dict[str, int] = {}
    categories: Dict[str, List[int]] = {"low": [], "medium": [], "high": []}
    region_totals: Dict[str, float] = {}
    region_counts: Dict[str, int] = {}
    filtered_records: List[Dict[str, Any]] = []

    for rec in sales:
        if not _validate(rec):
            continue
        amt = _parse_amount(rec["amount"])
        if amt < min_amount:
            continue
        if region_filter and rec["region"] != region_filter:
            continue
        filtered_records.append(rec)
        cat = _categorize(amt)
        categories[cat].append(rec["id"])
        totals[cat] = totals.get(cat, 0.0) + amt
