        region_totals[rec["region"]] = region_totals.get(rec["region"], 0.0) + amt
        region_counts[rec["region"]] = region_counts.get(rec["region"], 0) + 1

    overall_total = sum(totals.values())
    overall_count = sum(counts.values())

    def _compute_average(total: float, count: int) -> float:
        return total / count if count else 0.0

    averages: Dict[str, float] = {
        cat: _compute_average(totals[cat], counts[cat]) for cat in totals
    }

    region_averages: Dict[str, float] = {
        reg: _compute_average(region_totals[reg], region_counts[reg])
        for reg in region_totals
    }

    result: Dict[str, Any] = {
        "overall_total": overall_total,
        "overall_count": overall_count,
        "category_totals": totals,
        "category_counts": counts,
        "category_averages": averages,
        "region_totals": region_totals,
        "region_counts": region_counts,
        "region_averages": region_averages,
        "categories": categories,
        "filtered_records": filtered_records,
    }

    return result

