from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_user_data(
    records: List[Dict[str, Any]],
    *,
    required_fields: Optional[List[str]] = None,
    max_age: Optional[int] = None,
    normalize_email: bool = True,
) -> Dict[str, Any]:
    if required_fields is None:
        required_fields = ["id", "name", "email", "age"]

    def _validate(record: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors: List[str] = []
        for field in required_fields:
            if field not in record:
                errors.append(f"missing field {field!r}")
            elif record[field] is None:
                errors.append(f"null value for {field!r}")
        if "email" in record and not isinstance(record["email"], str):
            errors.append("email must be string")
        if "age" in record:
            try:
                age_val = int(record["age"])
                if age_val < 0:
                    errors.append("age cannot be negative")
            except (TypeError, ValueError):
                errors.append("age must be integer")
        return (len(errors) == 0, errors)

    def _normalize_email_address(email: str) -> str:
        return email.strip().lower()

    def _process(record: Dict[str, Any]) -> Dict[str, Any]:
        processed: Dict[str, Any] = {}
        processed["id"] = record["id"]
        processed["name"] = record["name"].strip()
        if normalize_email and "email" in record:
            processed["email"] = _normalize_email_address(record["email"])
        else:
            processed["email"] = record.get("email")
        if "age" in record:
            processed["age"] = int(record["age"])
        return processed

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Tuple[Dict[str, Any], List[str]]] = []

    for rec in records:
        is_valid, errs = _validate(rec)
        if is_valid:
            processed = _process(rec)
            if max_age is not None and processed.get("age", 0) > max_age:
                invalid_records.append((rec, [f"age {processed['age']} exceeds max_age {max_age}"]))
            else:
                valid_records.append(processed)
        else:
            invalid_records.append((rec, errs))

    summary = {
        "total_records": len(records),
        "valid_records": len(valid_records),
        "invalid_records": len(invalid_records),
        "max_age": max_age,
    }

    return {
        "summary": summary,
        "data": valid_records,
        "errors": [
            {"record": rec, "issues": issues}
            for rec, issues in invalid_records
        ],
    }

