from typing import Any, Dict, Iterable, List, Optional, Tuple, Union


def process_records(
    records: Iterable[Dict[str, Any]],
    key: str,
    required_fields: List[str],
    transform: Optional[Any] = None,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], List[str], Dict[str, int]]:
    def _validate(record: Dict[str, Any]) -> bool:
        for f in required_fields:
            if f not in record or record[f] is None:
                return False
        return True

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return record
        return transform(record)

    def _group_by(records_list: List[Dict[str, Any]]) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for r in records_list:
            k = r.get(key)
            if k not in groups:
                groups[k] = []
            groups[k].append(r)
        return groups

    def _compute_stats(groups: Dict[Any, List[Dict[str, Any]]]) -> Dict[str, int]:
        stats: Dict[str, int] = {}
        stats['total_groups'] = len(groups)
        stats['total_records'] = sum(len(v) for v in groups.values())
        return stats

    valid: List[Dict[str, Any]] = []
    invalid: List[Dict[str, Any]] = []
    errors: List[str] = []

    for rec in records:
        if not isinstance(rec, dict):
            errors.append(f"invalid record type: {type(rec)}")
            continue
        if not _validate(rec):
            invalid.append(rec)
            continue
        try:
            transformed = _transform(rec)
            valid.append(transformed)
        except Exception as e:
            errors.append(f"error transforming record {rec.get(key)}: {e}")
            invalid.append(rec)

    grouped = _group_by(valid)
    stats = _compute_stats(grouped)

    return valid, invalid, errors, stats

