from typing import Any, Dict, List, Optional, Tuple, Iterable


def analyze_and_transform(
    data: List[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: float = 0.5,
    *,
    normalize: bool = True,
    max_items: Optional[int] = None
) -> Dict[str, Any]:
    # Validate inputs
    if not isinstance(data, list):
        raise TypeError("data must be a list")
    if not isinstance(key_field, str) or not isinstance(value_field, str):
        raise TypeError("key_field and value_field must be strings")
    if not isinstance(threshold, (float, int)):
        raise TypeError("threshold must be numeric")
    if normalize and not isinstance(normalize, bool):
        raise TypeError("normalize must be bool")
    if max_items is not None and not isinstance(max_items, int):
        raise TypeError("max_items must be int or None")

    # Helper to compute stats
    def _stats(values: Iterable[float]) -> Tuple[float, float, int]:
        n = 0
        total = 0.0
        for v in values:
            if not isinstance(v, (int, float)):
                continue
            total += float(v)
            n += 1
        avg = total / n if n else 0.0
        return avg, total, n

    # Helper to normalize values
    def _normalize_value(v: float) -> float:
        return (v - min_val) / (max_val - min_val) if max_val > min_val else 0.0

    # Build mapping from key to list of values
    mapping: Dict[Any, List[float]] = {}
    for record in data:
        if not isinstance(record, dict):
            continue
        k = record.get(key_field)
        v = record.get(value_field)
        if k is None or v is None:
            continue
        if not isinstance(v, (int, float)):
            continue
        mapping.setdefault(k, []).append(float(v))

    # Compute global min/max for normalization
    all_values: List[float] = []
    for vals in mapping.values():
        all_values.extend(vals)
    if not all_values:
        return {"error": "no valid values found"}

    min_val = min(all_values)
    max_val = max(all_values)

    # Process each key
    results: List[Dict[str, Any]] = []
    for k, vals in mapping.items():
        avg, total, count = _stats(vals)
        if count == 0:
            continue
        if avg < threshold:
            continue
        if normalize:
            norm_vals = [_normalize_value(v) for v in vals]
            avg_norm = sum(norm_vals) / len(norm_vals)
        else:
            norm_vals = vals
            avg_norm = avg
        item: Dict[str, Any] = {
            "key": k,
            "count": count,
            "average": avg,
            "average_normalized": avg_norm,
            "values": norm_vals,
        }
        results.append(item)
        if max_items is not None and len(results) >= max_items:
            break

    # Sort results by average descending
    results.sort(key=lambda x: x["average"], reverse=True)

    return {
        "summary": {
            "total_keys": len(mapping),
            "filtered_keys": len(results),
            "threshold": threshold,
            "normalize": normalize,
        },
        "data": results,
    }

