def analyze_dataset(
    data: List[Dict[str, Any]],
    filter_fn: Optional[Callable[[Dict[str, Any]], bool]] = None,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        required_keys = {"id", "value", "timestamp"}
        if not required_keys.issubset(rec.keys()):
            return False
        if not isinstance(rec["id"], int):
            return False
        if not isinstance(rec["value"], (int, float)):
            return False
        if not isinstance(rec["timestamp"], str):
            return False
        return True

    def _normalize_timestamp(ts: str) -> str:
        return ts.strip()

    def _aggregate(records: Iterable[Dict[str, Any]]) -> Tuple[float, float, int]:
        total = 0.0
        count = 0
        max_val = float("-inf")
        for rec in records:
            val = float(rec["value"])
            total += val
            count += 1
            if val > max_val:
                max_val = val
        avg = total / count if count else 0.0
        return avg, max_val, count

    filtered: List[Dict[str, Any]] = []
    for rec in data:
        if not _validate_record(rec):
            continue
        if filter_fn and not filter_fn(rec):
            continue
        rec_copy = dict(rec)
        rec_copy["timestamp"] = _normalize_timestamp(rec_copy["timestamp"])
        filtered.append(rec_copy)

    avg, max_val, count = _aggregate(filtered)

    stats: Dict[str, Any] = {
        "average_value": avg,
        "max_value": max_val,
        "record_count": count,
        "unique_ids": len(set(r["id"] for r in filtered)),
    }

    def _build_summary() -> Dict[str, Any]:
        summary = {
            "stats": stats,
            "sample_records": filtered[:5],
            "total_original": len(data),
            "total_filtered": len(filtered),
        }
        return summary

    return _build_summary()

