from typing import List, Dict, Any, Tuple, Optional


def compute_stats(records: List[Dict[str, Any]], key: str, agg: str = "sum") -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if key not in record:
            return False
        return True

    def _extract_value(record: Dict[str, Any]) -> Any:
        return record.get(key)

    def _is_numeric(val: Any) -> bool:
        return isinstance(val, (int, float))

    def _aggregate(values: List[Any]) -> Any:
        if agg == "sum":
            return sum(v for v in values if _is_numeric(v))
        elif agg == "avg":
            nums = [v for v in values if _is_numeric(v)]
            return sum(nums) / len(nums) if nums else None
        elif agg == "max":
            nums = [v for v in values if _is_numeric(v)]
            return max(nums) if nums else None
        elif agg == "min":
            nums = [v for v in values if _is_numeric(v)]
            return min(nums) if nums else None
        else:
            raise ValueError(f"Unsupported aggregation: {agg}")

    values: List[Any] = []
    invalid_count = 0
    for rec in records:
        if not _validate(rec):
            invalid_count += 1
            continue
        val = _extract_value(rec)
        values.append(val)

    result: Dict[str, Any] = {
        "count": len(values),
        "invalid": invalid_count,
        "aggregation": None,
    }

    if values:
        try:
            result["aggregation"] = _aggregate(values)
        except Exception as e:
            result["aggregation_error"] = str(e)
    else:
        result["aggregation"] = None

    return result

