def process_data(records: Iterable[Dict[str, Any]], threshold: float = 0.5) -> Tuple[Dict[str, int], List[Dict[str, Any]]]:
    # Inner helper to normalize string values
    def _normalize(val: Any) -> str:
        if val is None:
            return ""
        return str(val).strip().lower()

    # Validate required fields and types
    def _validate(record: Dict[str, Any]) -> bool:
        required = {"id", "value", "category"}
        if not required.issubset(record.keys()):
            return False
        if not isinstance(record["value"], (int, float)):
            return False
        return True

    # Aggregate counts per category
    def _aggregate(records: Iterable[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for rec in records:
            cat = _normalize(rec.get("category"))
            counts[cat] = counts.get(cat, 0) + 1
        return counts

    # Filter records by threshold
    def _filter(records: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for rec in records:
            if rec.get("value", 0) >= threshold:
                filtered.append(rec)
        return filtered

    # Compute mean value per category
    def _compute_stats(records: Iterable[Dict[str, Any]]) -> Dict[str, float]:
        sums: Dict[str, float] = {}
        counts: Dict[str, int] = {}
        for rec in records:
            cat = _normalize(rec.get("category"))
            val = float(rec.get("value", 0))
            sums[cat] = sums.get(cat, 0.0) + val
            counts[cat] = counts.get(cat, 0) + 1
        means: Dict[str, float] = {}
        for cat in sums:
            means[cat] = sums[cat] / counts[cat]
        return means

    # Format aggregated data into list of dicts
    def _format_output(counts: Dict[str, int], means: Dict[str, float]) -> List[Dict[str, Any]]:
        output: List[Dict[str, Any]] = []
        for cat in counts:
            output.append({
                "category": cat,
                "count": counts[cat],
                "mean_value": means.get(cat, 0.0)
            })
        return output

    # Main processing
    valid_records: List[Dict[str, Any]] = []
    for rec in records:
        if _validate(rec):
            valid_records.append(rec)

    aggregated_counts = _aggregate(valid_records)
    filtered_records = _filter(valid_records)
    mean_stats = _compute_stats(valid_records)
    formatted = _format_output(aggregated_counts, mean_stats)

    # Return aggregated counts and filtered records
    return aggregated_counts, filtered_records

