from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_transactions(
    transactions: List[Dict[str, Any]],
    min_amount: float = 0.0,
    max_amount: Optional[float] = None,
    categories: Optional[Iterable[str]] = None,
) -> Dict[str, Any]:
    # validate input
    if not isinstance(transactions, list):
        raise TypeError("transactions must be a list")
    if categories is not None and not isinstance(categories, Iterable):
        raise TypeError("categories must be iterable")
    cat_set = {str(c).lower() for c in categories} if categories else None

    # inner helper to normalize transaction
    def _normalize(tx: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        try:
            amt = float(tx.get("amount", 0))
            if amt < min_amount:
                return None
            if max_amount is not None and amt > max_amount:
                return None
            cat = str(tx.get("category", "")).lower()
            if cat_set is not None and cat not in cat_set:
                return None
            return {
                "id": str(tx.get("id", "")),
                "amount": amt,
                "category": cat,
                "timestamp": str(tx.get("timestamp", "")),
            }
        except Exception:
            return None

    # process each transaction
    processed: List[Dict[str, Any]] = []
    for tx in transactions:
        norm = _normalize(tx)
        if norm:
            processed.append(norm)

    # aggregate by category
    totals: Dict[str, float] = {}
    counts: Dict[str, int] = {}
    for tx in processed:
        cat = tx["category"]
        totals[cat] = totals.get(cat, 0.0) + tx["amount"]
        counts[cat] = counts.get(cat, 0) + 1

    # compute overall stats
    total_amount = sum(totals.values())
    total_count = sum(counts.values())

    # prepare result
    result: Dict[str, Any] = {
        "total_amount": total_amount,
        "total_count": total_count,
        "by_category": [],
    }

    # inner helper to format category summary
    def _format_cat(cat: str) -> Dict[str, Any]:
        return {
            "category": cat,
            "count": counts.get(cat, 0),
            "amount": totals.get(cat, 0.0),
            "average": totals.get(cat, 0.0) / counts.get(cat, 1),
        }

    for cat in sorted(totals.keys()):
        result["by_category"].append(_format_cat(cat))

    # sort by amount descending
    result["by_category"].sort(key=lambda x: x["amount"], reverse=True)

    return result

