from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_user_data(
    users: Iterable[Dict[str, Any]],
    required_fields: List[str],
    email_domain: str,
    max_age: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, Any]]:
    def _validate_user(user: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in user or user[field] is None:
                return False
        if "email" in user and not isinstance(user["email"], str):
            return False
        return True

    def _normalize_email(email: str) -> str:
        return email.strip().lower()

    def _is_valid_email(email: str) -> bool:
        if "@" not in email:
            return False
        local, domain = email.split("@", 1)
        return domain == email_domain

    def _filter_age(user: Dict[str, Any]) -> bool:
        if max_age is None:
            return True
        age = user.get("age")
        if age is None:
            return False
        try:
            return int(age) <= max_age
        except (TypeError, ValueError):
            return False

    valid_users: List[Dict[str, Any]] = []
    invalid_users: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {
        "total": 0,
        "valid": 0,
        "invalid": 0,
        "emails_checked": 0,
        "emails_valid": 0,
    }

    for raw in users:
        stats["total"] += 1
        if not isinstance(raw, dict):
            invalid_users.append({"raw": raw, "reason": "not a dict"})
            stats["invalid"] += 1
            continue
        if not _validate_user(raw):
            invalid_users.append({"user": raw, "reason": "missing required fields"})
            stats["invalid"] += 1
            continue
        if "email" in raw:
            stats["emails_checked"] += 1
            email = _normalize_email(raw["email"])
            if not _is_valid_email(email):
                invalid_users.append({"user": raw, "reason": "invalid email domain"})
                stats["invalid"] += 1
                continue
            raw["email"] = email
            stats["emails_valid"] += 1
        if not _filter_age(raw):
            invalid_users.append({"user": raw, "reason": "age exceeds limit"})
            stats["invalid"] += 1
            continue
        valid_users.append(raw)
        stats["valid"] += 1

    return valid_users, invalid_users, stats

