from typing import List, Dict, Any, Optional, Tuple, Iterable, Set


def aggregate_user_activity(
    logs: List[Dict[str, Any]],
    user_id_key: str = "user_id",
    action_key: str = "action",
    timestamp_key: str = "timestamp",
    actions_of_interest: Optional[Set[str]] = None,
) -> Tuple[Dict[str, Dict[str, int]], Dict[str, Any]]:
    # inner functions
    def _parse_timestamp(ts: Any) -> Optional[int]:
        if isinstance(ts, int):
            return ts
        if isinstance(ts, str):
            try:
                return int(ts)
            except ValueError:
                return None
        return None

    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if user_id_key not in rec or action_key not in rec or timestamp_key not in rec:
            return False
        if not isinstance(rec[user_id_key], str):
            return False
        if not isinstance(rec[action_key], str):
            return False
        if _parse_timestamp(rec[timestamp_key]) is None:
            return False
        return True

    def _is_action_of_interest(action: str) -> bool:
        if actions_of_interest is None:
            return True
        return action in actions_of_interest

    # main aggregation
    user_stats: Dict[str, Dict[str, int]] = {}
    error_logs: List[Dict[str, Any]] = []
    for entry in logs:
        if not _validate_record(entry):
            error_logs.append(entry)
            continue
        uid = entry[user_id_key]
        act = entry[action_key]
        ts = _parse_timestamp(entry[timestamp_key])
        if ts is None:
            error_logs.append(entry)
            continue
        if not _is_action_of_interest(act):
            continue
        if uid not in user_stats:
            user_stats[uid] = {"total_actions": 0, "unique_actions": 0, "first_seen": ts, "last_seen": ts}
        user_stats[uid]["total_actions"] += 1
        if act not in user_stats[uid]:
            user_stats[uid][act] = 1
        else:
            user_stats[uid][act] += 1
        if ts < user_stats[uid]["first_seen"]:
            user_stats[uid]["first_seen"] = ts
        if ts > user_stats[uid]["last_seen"]:
            user_stats[uid]["last_seen"] = ts

    # compute unique action counts
    for uid, stats in user_stats.items():
        unique = 0
        for key in list(stats.keys()):
            if key not in ("total_actions", "first_seen", "last_seen"):
                unique += 1
        stats["unique_actions"] = unique

    summary = {
        "total_users": len(user_stats),
        "total_actions": sum(s["total_actions"] for s in user_stats.values()),
        "errors": len(error_logs),
        "error_sample": error_logs[:5],
    }

    return user_stats, summary

