from typing import Any, Dict, Iterable, List, Optional, Tuple


def analyze_dataset(
    data: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: float = 0.0,
    include_missing: bool = False,
) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        return True

    def _normalize_value(val: Any) -> Optional[float]:
        if val is None:
            return None
        try:
            return float(val)
        except (TypeError, ValueError):
            return None

    def _group_by_key(records: List[Dict[str, Any]]) -> Dict[Any, List[float]]:
        groups: Dict[Any, List[float]] = {}
        for r in records:
            k = r[key_field]
            v = r[value_field]
            if k not in groups:
                groups[k] = []
            groups[k].append(v)
        return groups

    def _compute_stats(values: List[float]) -> Tuple[float, float, int]:
        if not values:
            return (0.0, 0.0, 0)
        total = sum(values)
        count = len(values)
        avg = total / count
        return (avg, total, count)

    valid_records: List[Dict[str, Any]] = []
    missing_records: List[Dict[str, Any]] = []
    for rec in data:
        if not _validate_record(rec):
            continue
        val = _normalize_value(rec[value_field])
        if val is None:
            if include_missing:
                missing_records.append(rec)
            continue
        if val < threshold:
            continue
        rec[value_field] = val
        valid_records.append(rec)

    grouped = _group_by_key(valid_records)
    stats: Dict[Any, Dict[str, Any]] = {}
    for k, vals in grouped.items():
        avg, total, count = _compute_stats(vals)
        stats[k] = {
            "average": avg,
            "total": total,
            "count": count,
            "values": vals,
        }

    overall_avg = 0.0
    overall_total = 0.0
    overall_count = 0
    for s in stats.values():
        overall_total += s["total"]
        overall_count += s["count"]
    if overall_count > 0:
        overall_avg = overall_total / overall_count

    result: Dict[str, Any] = {
        "stats_by_key": stats,
        "overall_average": overall_avg,
        "overall_total": overall_total,
        "overall_count": overall_count,
        "missing_records": missing_records,
        "valid_record_count": len(valid_records),
    }
    return result

