from typing import Any, Dict, Iterable, List, Optional, Tuple

def compute_statistics(
    data: List[Dict[str, Any]],
    numeric_fields: List[str],
    string_fields: List[str],
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    def _validate_row(row: Dict[str, Any]) -> bool:
        if not isinstance(row, dict):
            return False
        for field in numeric_fields:
            if field in row and not isinstance(row[field], (int, float)):
                return False
        for field in string_fields:
            if field in row and not isinstance(row[field], str):
                return False
        return True

    def _row_stats(row: Dict[str, Any]) -> Tuple[float, int]:
        total = 0.0
        count = 0
        for field in numeric_fields:
            val = row.get(field)
            if isinstance(val, (int, float)):
                total += float(val)
                count += 1
        avg = total / count if count else 0.0
        return avg, count

    overall_sum = 0.0
    overall_count = 0
    string_counts: Dict[str, int] = {}
    filtered_rows: List[Dict[str, Any]] = []

    for r in data:
        if not _validate_row(r):
            continue
        avg, cnt = _row_stats(r)
        if threshold is not None and avg < threshold:
            continue
        filtered_rows.append(r)
        overall_sum += avg
        overall_count += cnt
        for field in string_fields:
            val = r.get(field)
            if isinstance(val, str):
                string_counts[val] = string_counts.get(val, 0) + 1

    overall_avg = overall_sum / overall_count if overall_count else 0.0

    result: Dict[str, Any] = {
        "total_rows": len(data),
        "filtered_rows": len(filtered_rows),
        "overall_average": overall_avg,
        "string_counts": string_counts,
    }

    if threshold is not None:
        result["threshold"] = threshold

    return result

