from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_user_data(
    raw_records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Optional[Dict[str, Any]] = None,
    batch_size: int = 100,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, Any]]:
    """Process raw user records, validate, transform, and batch them.
    Returns a tuple of (valid_batches, invalid_records, stats)."""
    transform_map = transform_map or {}
    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {
        "total": 0,
        "valid": 0,
        "invalid": 0,
        "batches": 0,
    }

    def _is_valid(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _apply_transform(record: Dict[str, Any]) -> Dict[str, Any]:
        out = dict(record)
        for key, func in transform_map.items():
            if key in out and callable(func):
                try:
                    out[key] = func(out[key])
                except Exception:
                    out[key] = None
        return out

    def _batch(records: List[Dict[str, Any]]) -> List[List[Dict[str, Any]]]:
        return [records[i:i+batch_size] for i in range(0, len(records), batch_size)]

    for rec in raw_records:
        stats["total"] += 1
        if not isinstance(rec, dict):
            invalid_records.append({"error": "not a dict", "record": rec})
            stats["invalid"] += 1
            continue
        if not _is_valid(rec):
            invalid_records.append({"error": "missing field", "record": rec})
            stats["invalid"] += 1
            continue
        transformed = _apply_transform(rec)
        valid_records.append(transformed)
        stats["valid"] += 1

    batches = _batch(valid_records)
    stats["batches"] = len(batches)

    return batches, invalid_records, stats

