from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_transactions(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    id_field: str = "id",
    amount_field: str = "amount",
    currency_field: str = "currency",
    max_amount: Optional[float] = None,
) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, Any]]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record:
                return False
        if not isinstance(record.get(id_field), (int, str)):
            return False
        if not isinstance(record.get(amount_field), (int, float)):
            return False
        if not isinstance(record.get(currency_field), str):
            return False
        return True

    def _normalize(record: Dict[str, Any]) -> Dict[str, Any]:
        norm = dict(record)
        norm[id_field] = str(record[id_field]).strip()
        norm[amount_field] = float(record[amount_field])
        norm[currency_field] = record[currency_field].upper().strip()
        return norm

    def _filter_by_amount(record: Dict[str, Any]) -> bool:
        if max_amount is None:
            return True
        return record[amount_field] <= max_amount

    valid: List[Dict[str, Any]] = []
    invalid: List[Dict[str, Any]] = []
    totals: Dict[str, float] = {}
    count_by_currency: Dict[str, int] = {}

    for rec in records:
        if not isinstance(rec, dict):
            invalid.append({"error": "not a dict", "record": rec})
            continue
        if not _validate(rec):
            invalid.append({"error": "validation failed", "record": rec})
            continue
        norm_rec = _normalize(rec)
        if not _filter_by_amount(norm_rec):
            invalid.append({"error": "amount exceeds limit", "record": norm_rec})
            continue
        valid.append(norm_rec)
        cur = norm_rec[currency_field]
        amt = norm_rec[amount_field]
        totals[cur] = totals.get(cur, 0.0) + amt
        count_by_currency[cur] = count_by_currency.get(cur, 0) + 1

    summary: Dict[str, Any] = {
        "total_records": len(records),
        "valid_records": len(valid),
        "invalid_records": len(invalid),
        "totals_by_currency": totals,
        "count_by_currency": count_by_currency,
    }

    def _sort_by_amount(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return sorted(records, key=lambda r: r[amount_field], reverse=True)

    sorted_valid = _sort_by_amount(valid)

    return sorted_valid, invalid, summary

