from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_data(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: float = 0.5,
    max_items: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _normalize_key(v: Any) -> str:
        if v is None:
            return ""
        return str(v).strip().lower()

    def _filter_record(rec: Dict[str, Any]) -> bool:
        val = rec.get(value_field)
        if val is None:
            return False
        try:
            return float(val) >= threshold
        except (TypeError, ValueError):
            return False

    def _aggregate(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        agg: Dict[str, Any] = {}
        for rec in records:
            k = _normalize_key(rec.get(key_field))
            if k not in agg:
                agg[k] = {"count": 0, "sum": 0.0}
            agg[k]["count"] += 1
            try:
                agg[k]["sum"] += float(rec.get(value_field, 0))
            except (TypeError, ValueError):
                pass
        return agg

    filtered: List[Dict[str, Any]] = []
    for rec in records:
        if not isinstance(rec, dict):
            continue
        if _filter_record(rec):
            filtered.append(rec)
            if max_items is not None and len(filtered) >= max_items:
                break

    aggregated = _aggregate(filtered)

    summary: Dict[str, Any] = {
        "total_records": len(list(records)),
        "filtered_records": len(filtered),
        "unique_keys": len(aggregated),
        "aggregated": aggregated,
    }

    return filtered, summary

