def process_records(records: List[Dict[str, Any]], key: str, threshold: float = 0.5) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, Any]]:
    # inner defs
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        return True

    def _score(rec: Dict[str, Any]) -> float:
        val = rec.get(key)
        if isinstance(val, (int, float)):
            return float(val)
        try:
            return float(val)
        except Exception:
            return 0.0

    # main logic
    valid: List[Dict[str, Any]] = []
    invalid: List[Dict[str, Any]] = []
    stats: Dict[str, Any] = {"total": 0, "valid": 0, "invalid": 0, "average": 0.0}

    for rec in records:
        stats["total"] += 1
        if _validate_record(rec):
            valid.append(rec)
            stats["valid"] += 1
        else:
            invalid.append(rec)
            stats["invalid"] += 1

    if stats["valid"] > 0:
        avg = sum(_score(r) for r in valid) / stats["valid"]
        stats["average"] = avg
    else:
        avg = 0.0

    # filter by threshold
    filtered: List[Dict[str, Any]] = []
    for rec in valid:
        if _score(rec) >= threshold * avg:
            filtered.append(rec)

    # sort
    filtered.sort(key=lambda r: _score(r), reverse=True)

    # summary
    summary = {
        "filtered_count": len(filtered),
        "filtered_avg": sum(_score(r) for r in filtered) / len(filtered) if filtered else 0.0,
        "threshold": threshold,
    }

    return filtered, invalid, {"stats": stats, "summary": summary}

