from typing import List, Dict, Optional, Tuple, Iterable, Any


def process_transactions(
    transactions: List[Dict[str, Any]],
    min_amount: float = 0.0,
    categories: Optional[Iterable[str]] = None,
) -> Dict[str, Any]:
    # inner helper functions
    def _normalize_amount(amount: Any) -> float:
        try:
            return float(amount)
        except (TypeError, ValueError):
            return 0.0

    def _is_valid_txn(txn: Dict[str, Any]) -> bool:
        if not isinstance(txn, dict):
            return False
        required = {"id", "amount", "category", "timestamp"}
        if not required.issubset(txn.keys()):
            return False
        if _normalize_amount(txn["amount"]) < min_amount:
            return False
        if categories is not None and txn["category"] not in categories:
            return False
        return True

    def _aggregate_by_category(
        acc: Dict[str, float], txn: Dict[str, Any]
    ) -> None:
        cat = txn["category"]
        acc[cat] = acc.get(cat, 0.0) + _normalize_amount(txn["amount"])

    def _aggregate_by_month(
        acc: Dict[str, float], txn: Dict[str, Any]
    ) -> None:
        ts = txn["timestamp"]
        month = ts[:7]
        acc[month] = acc.get(month, 0.0) + _normalize_amount(txn["amount"])

    # main logic
    valid_txns: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, txn in enumerate(transactions):
        if _is_valid_txn(txn):
            valid_txns.append(txn)
        else:
            errors.append((idx, "invalid transaction"))

    category_totals: Dict[str, float] = {}
    month_totals: Dict[str, float] = {}

    for txn in valid_txns:
        _aggregate_by_category(category_totals, txn)
        _aggregate_by_month(month_totals, txn)

    # compute overall stats
    total_amount = sum(category_totals.values())
    txn_count = len(valid_txns)
    avg_amount = total_amount / txn_count if txn_count else 0.0

    # find top category
    top_category: Optional[str] = None
    top_amount: float = 0.0
    for cat, amt in category_totals.items():
        if amt > top_amount:
            top_amount = amt
            top_category = cat

    # find month with highest spend
    top_month: Optional[str] = None
    top_month_amount: float = 0.0
    for month, amt in month_totals.items():
        if amt > top_month_amount:
            top_month_amount = amt
            top_month = month

    return {
        "total_transactions": txn_count,
        "total_amount": total_amount,
        "average_amount": avg_amount,
        "top_category": top_category,
        "top_category_amount": top_amount,
        "top_month": top_month,
        "top_month_amount": top_month_amount,
        "errors": errors,
        "category_breakdown": category_totals,
        "monthly_breakdown": month_totals,
    }

