from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_and_aggregate(
    data: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    filter_func: Optional[Any] = None,
    transform_func: Optional[Any] = None,
    max_items: Optional[int] = None,
) -> Tuple[Dict[str, List[Any]], Dict[str, int], List[str]]:
    """Process data items, filter, transform, and aggregate by key."""
    aggregated: Dict[str, List[Any]] = {}
    counts: Dict[str, int] = {}
    errors: List[str] = []

    def _safe_get(item: Dict[str, Any], field: str) -> Any:
        try:
            return item.get(field)
        except Exception as exc:
            errors.append(f"error getting field {field!r}: {exc}")
            return None

    def _apply_transform(val: Any) -> Any:
        if transform_func is None:
            return val
        try:
            return transform_func(val)
        except Exception as exc:
            errors.append(f"transform error on {val!r}: {exc}")
            return val

    def _apply_filter(val: Any) -> bool:
        if filter_func is None:
            return True
        try:
            return bool(filter_func(val))
        except Exception as exc:
            errors.append(f"filter error on {val!r}: {exc}")
            return False

    processed: List[Tuple[str, Any]] = []

    for idx, item in enumerate(data):
        if max_items is not None and idx >= max_items:
            break
        key = _safe_get(item, key_field)
        if key is None:
            errors.append(f"missing key field {key_field!r} in item {idx}")
            continue
        val = _safe_get(item, value_field)
        if val is None:
            errors.append(f"missing value field {value_field!r} in item {idx}")
            continue
        val = _apply_transform(val)
        if not _apply_filter(val):
            continue
        processed.append((str(key), val))

    for key, val in processed:
        if key not in aggregated:
            aggregated[key] = []
            counts[key] = 0
        aggregated[key].append(val)
        counts[key] += 1

    for key, lst in aggregated.items():
        aggregated[key] = sorted(lst, key=lambda x: (x is None, x))

    return aggregated, counts, errors

