from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_user_data(
    users: List[Dict[str, Any]],
    min_age: int = 0,
    include_inactive: bool = False,
) -> Dict[str, Any]:
    def _validate(user: Dict[str, Any]) -> bool:
        if not isinstance(user, dict):
            return False
        required = {"id", "name", "age", "active"}
        if not required.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int):
            return False
        if not isinstance(user["name"], str):
            return False
        if not isinstance(user["age"], int):
            return False
        if not isinstance(user["active"], bool):
            return False
        return True

    def _compute_score(user: Dict[str, Any]) -> float:
        base = user["age"] * 0.5
        bonus = 10 if user["active"] else -5
        return base + bonus

    def _aggregate(stats: List[Tuple[int, float]]) -> Dict[str, Any]:
        total = 0
        count = 0
        min_score = float("inf")
        max_score = float("-inf")
        for age, score in stats:
            total += score
            count += 1
            if score < min_score:
                min_score = score
            if score > max_score:
                max_score = score
        avg = total / count if count else 0.0
        return {
            "count": count,
            "average_score": avg,
            "min_score": min_score if count else None,
            "max_score": max_score if count else None,
        }

    valid_users: List[Dict[str, Any]] = []
    for u in users:
        if not _validate(u):
            continue
        if u["age"] < min_age:
            continue
        if not include_inactive and not u["active"]:
            continue
        valid_users.append(u)

    scored: List[Tuple[int, float]] = []
    for v in valid_users:
        score = _compute_score(v)
        scored.append((v["age"], score))

    stats = _aggregate(scored)

    result: Dict[str, Any] = {
        "total_users": len(users),
        "valid_users": len(valid_users),
        "stats": stats,
        "users_by_age": {},
    }

    for age, score in scored:
        age_key = str(age)
        if age_key not in result["users_by_age"]:
            result["users_by_age"][age_key] = []
        result["users_by_age"][age_key].append(score)

    return result

