from typing import Any, Dict, Iterable, List, Optional, Tuple


def aggregate_and_filter(
    records: Iterable[Dict[str, Any]],
    key: str,
    value_key: str,
    min_value: float = 0.0,
    group_by: Optional[List[str]] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    group_by = group_by or []

    def _normalize(val: Any) -> float:
        if val is None:
            return 0.0
        try:
            return float(val)
        except (TypeError, ValueError):
            return 0.0

    def _filter(rec: Dict[str, Any]) -> bool:
        v = _normalize(rec.get(value_key))
        return v >= min_value

    def _make_group_key(rec: Dict[str, Any]) -> Tuple:
        return tuple(rec.get(g, None) for g in group_by)

    def _update_agg(agg: Dict[str, float], val: float) -> None:
        agg["count"] += 1
        agg["sum"] += val
        if agg["min"] is None or val < agg["min"]:
            agg["min"] = val
        if agg["max"] is None or val > agg["max"]:
            agg["max"] = val

    rec_list = list(records)
    aggregates: Dict[Tuple, Dict[str, float]] = {}
    filtered: List[Dict[str, Any]] = []

    for rec in rec_list:
        if not isinstance(rec, dict):
            continue
        if not _filter(rec):
            continue
        filtered.append(rec)
        gkey = _make_group_key(rec)
        if gkey not in aggregates:
            aggregates[gkey] = {"count": 0.0, "sum": 0.0, "min": None, "max": None}
        val = _normalize(rec.get(value_key))
        _update_agg(aggregates[gkey], val)

    summary: Dict[str, Any] = {}
    for gkey, agg in aggregates.items():
        avg = agg["sum"] / agg["count"] if agg["count"] else 0.0
        summary[gkey] = {
            "count": int(agg["count"]),
            "sum": agg["sum"],
            "min": agg["min"],
            "max": agg["max"],
            "average": avg,
        }

    def _format_summary() -> List[Dict[str, Any]]:
        formatted: List[Dict[str, Any]] = []
        for gkey, data in summary.items():
            entry: Dict[str, Any] = {}
            for idx, field in enumerate(group_by):
                entry[field] = gkey[idx]
            entry.update(data)
            formatted.append(entry)
        return formatted

    formatted_summary = _format_summary()

    result = {
        "filtered_records": filtered,
        "summary": formatted_summary,
        "stats": {
            "total_records": len(rec_list),
            "filtered_count": len(filtered),
            "groups": len(summary),
        },
    }

    return result["filtered_records"], result["summary"]

