from typing import Any, Dict, List, Tuple, Optional

def process_data(
    records: List[Dict[str, Any]],
    threshold: float,
    *,
    normalize: bool = True,
    max_items: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        required = {'id', 'value', 'tags'}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec['id'], int):
            return False
        if not isinstance(rec['value'], (int, float)):
            return False
        if not isinstance(rec['tags'], list):
            return False
        return True

    def _normalize_value(val: Any) -> float:
        try:
            return float(val)
        except Exception:
            return 0.0

    def _clean_tag(tag: Any) -> Optional[str]:
        if not isinstance(tag, str):
            return None
        cleaned = tag.strip().lower()
        if not cleaned:
            return None
        return cleaned

    def _compute_stats(values: List[float]) -> Dict[str, float]:
        if not values:
            return {'min': 0.0, 'max': 0.0, 'avg': 0.0}
        total = sum(values)
        return {
            'min': min(values),
            'max': max(values),
            'avg': total / len(values),
        }

    filtered: List[Dict[str, Any]] = []
    tag_counts: Dict[str, int] = {}
    values: List[float] = []

    for rec in records:
        if not _validate_record(rec):
            continue
        val = _normalize_value(rec['value'])
        if normalize:
            val = val / 100.0
        if val < threshold:
            continue
        cleaned_tags = []
        for t in rec['tags']:
            ct = _clean_tag(t)
            if ct:
                cleaned_tags.append(ct)
        new_rec = {
            'id': rec['id'],
            'value': val,
            'tags': cleaned_tags,
        }
        filtered.append(new_rec)
        values.append(val)
        for tag in cleaned_tags:
            tag_counts[tag] = tag_counts.get(tag, 0) + 1

    if max_items is not None:
        filtered = filtered[:max_items]
        values = values[:max_items]

    stats = _compute_stats(values)

    sorted_tags = sorted(tag_counts.items(), key=lambda kv: (-kv[1], kv[0]))
    tag_summary = {tag: count for tag, count in sorted_tags[:10]}

    result = {
        'records': filtered,
        'stats': stats,
        'top_tags': tag_summary,
    }
    return result['records'], result['top_tags']

