from typing import List, Dict, Any, Tuple, Iterable

def compute_statistics(records: List[Dict[str, Any]], numeric_fields: List[str]) -> Dict[str, Any]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        for field in numeric_fields:
            if field not in rec:
                return False
            if not isinstance(rec[field], (int, float)):
                return False
        return True

    def _compute_field_stats(values: List[float]) -> Tuple[float, float, float, int]:
        if not values:
            return (0.0, 0.0, 0.0, 0)
        n = len(values)
        total = sum(values)
        mean = total / n
        sq_diff = sum((x - mean) ** 2 for x in values)
        stddev = (sq_diff / n) ** 0.5
        return (mean, stddev, min(values), max(values))

    def _aggregate_stats(field: str, recs: Iterable[Dict[str, Any]]) -> Dict[str, Any]:
        vals: List[float] = []
        for rec in recs:
            vals.append(float(rec[field]))
        mean, stddev, min_val, max_val = _compute_field_stats(vals)
        return {
            'field': field,
            'count': len(vals),
            'mean': mean,
            'stddev': stddev,
            'min': min_val,
            'max': max_val
        }

    valid_records: List[Dict[str, Any]] = []
    for rec in records:
        if _validate_record(rec):
            valid_records.append(rec)
        else:
            continue

    stats_per_field: List[Dict[str, Any]] = []
    for field in numeric_fields:
        field_stats = _aggregate_stats(field, valid_records)
        stats_per_field.append(field_stats)

    overall_stats: Dict[str, Any] = {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'invalid_records': len(records) - len(valid_records),
        'field_stats': stats_per_field
    }

    return overall_stats
    # End of function

