from typing import Dict, List, Tuple, Optional, Iterable, Any

def process_records(records: List[Dict[str, Any]], key: str, transform: Optional[Any] = None) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _normalize(value: Any) -> Any:
        if isinstance(value, str):
            return value.strip().lower()
        return value

    def _apply_transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return item
        try:
            return transform(item)
        except Exception:
            return item

    def _aggregate_counts(normalized_items: List[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for itm in normalized_items:
            k = _normalize(itm.get(key))
            if k is None:
                continue
            counts[k] = counts.get(k, 0) + 1
        return counts

    if not isinstance(records, Iterable):
        raise TypeError('records must be an iterable of dicts')

    processed: List[Dict[str, Any]] = []
    for rec in records:
        if not isinstance(rec, dict):
            continue
        norm_rec = {k: _normalize(v) for k, v in rec.items()}
        transformed = _apply_transform(norm_rec)
        processed.append(transformed)

    counts = _aggregate_counts(processed)

    # Filter out records with missing key after normalization
    filtered: List[Dict[str, Any]] = []
    for rec in processed:
        if _normalize(rec.get(key)) is not None:
            filtered.append(rec)

    # Sort by count descending, then by key ascending
    sorted_keys = sorted(counts.items(), key=lambda kv: (-kv[1], kv[0]))
    sorted_counts = {k: v for k, v in sorted_keys}

    # Compute summary statistics
    total = sum(sorted_counts.values())
    unique = len(sorted_counts)
    summary = {'total': total, 'unique': unique}
    # Attach summary to result as metadata
    # Since we cannot return more than two items, we embed summary in counts dict
    sorted_counts['_summary'] = summary
    return filtered, sorted_counts

