def aggregate_sales(
    records: Iterable[Dict[str, Any]],
    min_amount: float = 0.0,
    region_key: str = "region",
    amount_key: str = "amount",
    include_zero: bool = False,
) -> Tuple[Dict[str, float], Dict[str, float], List[Dict[str, Any]]]:
    def _normalize_region(r: str) -> str:
        return r.strip().title()

    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if region_key not in rec or amount_key not in rec:
            return False
        try:
            amt = float(rec[amount_key])
        except (TypeError, ValueError):
            return False
        if amt < min_amount and not include_zero:
            return False
        return True

    def _aggregate(
        acc: Dict[str, float], rec: Dict[str, Any]
    ) -> Dict[str, float]:
        region = _normalize_region(str(rec[region_key]))
        amt = float(rec[amount_key])
        acc[region] = acc.get(region, 0.0) + amt
        return acc

    def _count(
        acc: Dict[str, int], rec: Dict[str, Any]
    ) -> Dict[str, int]:
        region = _normalize_region(str(rec[region_key]))
        acc[region] = acc.get(region, 0) + 1
        return acc

    totals: Dict[str, float] = {}
    counts: Dict[str, int] = {}
    invalids: List[Dict[str, Any]] = []

    for rec in records:
        if _validate_record(rec):
            totals = _aggregate(totals, rec)
            counts = _count(counts, rec)
        else:
            invalids.append(rec)

    averages: Dict[str, float] = {}
    for region, total in totals.items():
        avg = total / counts.get(region, 1)
        averages[region] = round(avg, 2)

    sorted_totals = dict(sorted(totals.items(), key=lambda kv: kv[1], reverse=True))
    sorted_counts = dict(sorted(counts.items(), key=lambda kv: kv[1], reverse=True))
    sorted_averages = dict(sorted(averages.items(), key=lambda kv: kv[1], reverse=True))

    return sorted_totals, sorted_averages, invalids

