def process_user_records(
    users: Iterable[Dict[str, Any]],
    required_fields: List[str],
    email_domain: Optional[str] = None,
    max_age: Optional[int] = None,
) -> Dict[str, Any]:
    # inner validation
    def _validate_user(user: Dict[str, Any]) -> Tuple[bool, List[str]]:
        errors = []
        for field in required_fields:
            if field not in user:
                errors.append(f\"missing field: {field}\")
        if \"email\" in user:
            if not isinstance(user[\"email\"], str) or \"@\" not in user[\"email\"]:
                errors.append(\"invalid email format\")
            elif email_domain and not user[\"email\"].endswith(f\"@{email_domain}\")):
                errors.append(f\"email domain mismatch: {email_domain}\")
        if \"age\" in user:
            try:
                age = int(user[\"age\"])
                if max_age is not None and age > max_age:
                    errors.append(f\"age exceeds max: {max_age}\")
            except (ValueError, TypeError):
                errors.append(\"age not an integer\")
        return (len(errors) == 0, errors)

    def _normalize_user(user: Dict[str, Any]) -> Dict[str, Any]:
        norm = {}
        for k, v in user.items():
            if isinstance(v, str):
                norm[k] = v.strip()
            else:
                norm[k] = v
        return norm

    valid_users: List[Dict[str, Any]] = []
    invalid_users: List[Tuple[Dict[str, Any], List[str]]] = []

    for raw in users:
        if not isinstance(raw, dict):
            continue
        user = _normalize_user(raw)
        is_valid, errs = _validate_user(user)
        if is_valid:
            valid_users.append(user)
        else:
            invalid_users.append((user, errs))

    # aggregate stats
    age_sum = 0
    age_count = 0
    for u in valid_users:
        age = u.get(\"age\")
        if isinstance(age, int):
            age_sum += age
            age_count += 1

    avg_age = age_sum / age_count if age_count else None

    # group by country
    country_counts: Dict[str, int] = {}
    for u in valid_users:
        country = u.get(\"country\", \"Unknown\")
        country_counts[country] = country_counts.get(country, 0) + 1

    # sort countries by count descending
    sorted_countries = sorted(country_counts.items(), key=lambda kv: -kv[1])

    return {
        \"valid_count\": len(valid_users),
        \"invalid_count\": len(invalid_users),
        \"average_age\": avg_age,
        \"country_distribution\": sorted_countries,
        \"invalid_records\": [
            {\"user\": u, \"errors\": e} for u, e in invalid_users
        ],
    }

