from typing import Any, Callable, Dict, Iterable, List, Mapping, Optional, Tuple

def aggregate_and_filter(
    records: List[Dict[str, Any]],
    filter_func: Callable[[Dict[str, Any]], bool],
    group_by: str,
    max_group_size: Optional[int] = None,
    allow_missing: bool = False,
) -> Dict[str, List[Dict[str, Any]]]:
    # Validate top-level arguments
    if not isinstance(records, list):
        raise TypeError("records must be a list")
    if not callable(filter_func):
        raise TypeError("filter_func must be callable")
    if not isinstance(group_by, str):
        raise TypeError("group_by must be a string")
    if max_group_size is not None:
        if not isinstance(max_group_size, int) or max_group_size <= 0:
            raise ValueError("max_group_size must be a positive integer or None")
    if not isinstance(allow_missing, bool):
        raise TypeError("allow_missing must be a bool")

    # Helper to extract grouping key
    def _extract_key(item: Dict[str, Any]) -> str:
        if not isinstance(item, dict):
            raise TypeError("Each record must be a dict")
        val = item.get(group_by)
        if val is None:
            if allow_missing:
                return "__missing__"
            else:
                raise KeyError(f"Missing key '{group_by}' in record {item}")
        return str(val)

    # Helper to validate individual record structure
    def _validate_record(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        for k, v in item.items():
            if not isinstance(k, str):
                return False
            if isinstance(v, (list, dict)):
                return False
        return True

    # Grouping phase
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for rec in records:
        try:
            if not _validate_record(rec):
                continue
            key = _extract_key(rec)
            groups.setdefault(key, []).append(rec)
        except Exception:
            continue

    # Filtering and size limiting
    result: Dict[str, List[Dict[str, Any]]] = {}
    for key, items in groups.items():
        filtered: List[Dict[str, Any]] = []
        for itm in items:
            try:
                if filter_func(itm):
                    filtered.append(itm)
            except Exception:
                continue
        if max_group_size is not None:
            filtered = filtered[:max_group_size]
        if filtered:
            result[key] = filtered

    # Summary statistics
    summary: Dict[str, Any] = {
        "total_records": len(records),
        "unique_groups": len(groups),
        "filtered_groups": len(result),
        "max_group_size": max_group_size,
        "allow_missing": allow_missing,
    }

    # Attach summary under a reserved key
    result["__summary__"] = summary
    return result

