from typing import Any, Callable, Dict, Iterable, List, Optional


def process_records(
    records: List[Dict[str, Any]],
    group_by: str,
    agg_funcs: Dict[str, Callable[[List[Any]], Any]],
    filter_predicate: Optional[Callable[[Dict[str, Any]], bool]] = None,
) -> Dict[str, Any]:
    def _validate_record(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if group_by not in record:
            return False
        for key in agg_funcs:
            if key not in record:
                return False
        return True

    def _aggregate_group(values: List[Any]) -> Any:
        return {k: f([v[k] for v in values]) for k, f in agg_funcs.items()}

    def _format_result(group_key: Any, agg_result: Dict[str, Any]) -> Dict[str, Any]:
        return {"group": group_key, "aggregates": agg_result}

    if not isinstance(records, list):
        raise TypeError("records must be a list of dictionaries")
    if not isinstance(group_by, str):
        raise TypeError("group_by must be a string")
    if not isinstance(agg_funcs, dict):
        raise TypeError("agg_funcs must be a dict of callables")

    grouped: Dict[Any, List[Dict[str, Any]]] = {}
    for rec in records:
        if not _validate_record(rec):
            continue
        if filter_predicate and not filter_predicate(rec):
            continue
        key = rec[group_by]
        if key not in grouped:
            grouped[key] = []
        grouped[key].append(rec)

    aggregated_results: List[Dict[str, Any]] = []
    for key, recs in grouped.items():
        if not recs:
            continue
        agg_res = _aggregate_group(recs)
        formatted = _format_result(key, agg_res)
        aggregated_results.append(formatted)

    stats = {
        "total_records": len(records),
        "valid_records": sum(len(v) for v in grouped.values()),
        "groups": len(grouped),
    }

    return {"results": aggregated_results, "stats": stats}

