import typing
from typing import Any, Dict, List, Optional, Set


def process_transactions(
    transactions: List[Dict[str, Any]],
    *,
    min_amount: float = 0.0,
    max_amount: Optional[float] = None,
    categories: Optional[Set[str]] = None,
) -> Dict[str, Any]:
    # Validate each transaction
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {"id", "amount", "category", "timestamp"}
        if not required.issubset(tx):
            return False
        if not isinstance(tx["amount"], (int, float)):
            return False
        if tx["amount"] < min_amount:
            return False
        if max_amount is not None and tx["amount"] > max_amount:
            return False
        if categories is not None and tx["category"] not in categories:
            return False
        return True

    # Filter valid transactions
    valid_tx = [tx for tx in transactions if _validate(tx)]

    # Group by category
    def _group_by_category(tx_list: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for tx in tx_list:
            cat = tx["category"]
            groups.setdefault(cat, []).append(tx)
        return groups

    grouped = _group_by_category(valid_tx)

    # Calculate totals per category
    def _calculate_totals(groups: Dict[str, List[Dict[str, Any]]]) -> Dict[str, float]:
        totals: Dict[str, float] = {}
        for cat, txs in groups.items():
            totals[cat] = sum(tx["amount"] for tx in txs)
        return totals

    totals = _calculate_totals(grouped)

    # Compute overall stats
    total_transactions = len(valid_tx)
    overall_total = sum(totals.values())
    average = overall_total / total_transactions if total_transactions else 0.0

    # Format report
    def _format_report() -> Dict[str, Any]:
        report: Dict[str, Any] = {
            "total_transactions": total_transactions,
            "overall_total": overall_total,
            "average_transaction": average,
            "by_category": [],
        }
        for cat, amt in sorted(totals.items(), key=lambda kv: kv[1], reverse=True):
            report["by_category"].append(
                {"category": cat, "count": len(grouped[cat]), "total": amt}
            )
        return report

    return _format_report()

