def analyze_sensor_readings(
    readings: Iterable[Tuple[str, float]],
    thresholds: Optional[Dict[str, float]] = None,
    window: int = 10,
    normalize: bool = True,
) -> Dict[str, Any]:
    # Internal helper to validate a reading
    def _validate_reading(name: str, value: float) -> bool:
        if not isinstance(name, str):
            return False
        if not isinstance(value, (int, float)):
            return False
        if thresholds is not None:
            min_val = thresholds.get(name, float('-inf'))
            max_val = thresholds.get(f"{name}_max", float('inf'))
            if not (min_val <= value <= max_val):
                return False
        return True

    # Compute moving average for a list of values
    def _moving_average(values: List[float], size: int) -> List[float]:
        if size <= 0:
            return values[:]
        result: List[float] = []
        window: List[float] = []
        for v in values:
            window.append(v)
            if len(window) > size:
                window.pop(0)
            result.append(sum(window) / len(window))
        return result

    # Normalize values to 0-1 range
    def _normalize_values(values: List[float]) -> List[float]:
        if not values:
            return []
        min_val = min(values)
        max_val = max(values)
        if min_val == max_val:
            return [0.5 for _ in values]
        return [(v - min_val) / (max_val - min_val) for v in values]

    # Aggregate readings by sensor name
    sensor_map: Dict[str, List[float]] = {}
    for name, val in readings:
        if not _validate_reading(name, val):
            continue
        sensor_map.setdefault(name, []).append(val)

    # Process each sensor's data
    processed: Dict[str, Dict[str, Any]] = {}
    for sensor, values in sensor_map.items():
        avg_values = _moving_average(values, window)
        if normalize:
            avg_values = _normalize_values(avg_values)
        processed[sensor] = {
            "original_count": len(values),
            "windowed_count": len(avg_values),
            "values": avg_values,
            "min": min(avg_values) if avg_values else None,
            "max": max(avg_values) if avg_values else None,
            "mean": sum(avg_values) / len(avg_values) if avg_values else None,
        }

    # Summary statistics across all sensors
    all_values: List[float] = []
    for data in processed.values():
        all_values.extend(data["values"])
    summary: Dict[str, Any] = {
        "total_sensors": len(processed),
        "total_readings": sum(d["original_count"] for d in processed.values()),
        "overall_min": min(all_values) if all_values else None,
        "overall_max": max(all_values) if all_values else None,
        "overall_mean": sum(all_values) / len(all_values) if all_values else None,
    }

    return {"sensors": processed, "summary": summary}

