from typing import List, Dict, Any, Optional, Tuple

def process_user_data(
    users: List[Dict[str, Any]],
    required_fields: List[str],
    email_domain: Optional[str] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _validate_user(user: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in user or user[field] is None:
                return False
        return True

    def _normalize_email(email: str) -> str:
        return email.strip().lower()

    def _filter_by_domain(users: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        if email_domain is None:
            return users
        domain = email_domain.lower()
        return [u for u in users if u.get('email', '').lower().endswith('@' + domain)]

    def _aggregate_stats(valid_users: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {
            'total': len(valid_users),
            'by_country': {},
            'by_age_group': {},
        }
        for u in valid_users:
            country = u.get('country', 'Unknown')
            stats['by_country'][country] = stats['by_country'].get(country, 0) + 1
            age = u.get('age')
            if isinstance(age, int):
                if age < 18:
                    group = 'child'
                elif age < 35:
                    group = 'young_adult'
                elif age < 60:
                    group = 'adult'
                else:
                    group = 'senior'
                stats['by_age_group'][group] = stats['by_age_group'].get(group, 0) + 1
        return stats

    cleaned_users: List[Dict[str, Any]] = []
    errors: List[str] = []

    for idx, user in enumerate(users):
        if not isinstance(user, dict):
            errors.append(f'User at index {idx} is not a dict')
            continue
        if not _validate_user(user):
            errors.append(f'User at index {idx} missing required fields')
            continue
        email = user.get('email')
        if isinstance(email, str):
            user['email'] = _normalize_email(email)
        cleaned_users.append(user)

    filtered_users = _filter_by_domain(cleaned_users)
    stats = _aggregate_stats(filtered_users)
    stats['errors'] = errors

    return filtered_users, stats

