import datetime
from typing import Any, Dict, Iterable, List, Optional, Tuple


def analyze_transactions(
    transactions: Iterable[Dict[str, Any]],
    start_date: Optional[datetime.date] = None,
    end_date: Optional[datetime.date] = None,
    min_amount: float = 0.0,
) -> Dict[str, Any]:
    def _parse_date(d: Any) -> Optional[datetime.date]:
        if isinstance(d, datetime.date):
            return d
        if isinstance(d, str):
            try:
                return datetime.datetime.strptime(d, "%Y-%m-%d").date()
            except ValueError:
                return None
        return None

    def _validate(tx: Dict[str, Any]) -> Tuple[bool, str]:
        if not isinstance(tx, dict):
            return False, "not a dict"
        if "id" not in tx or "amount" not in tx or "date" not in tx:
            return False, "missing required keys"
        try:
            amt = float(tx["amount"])
        except Exception:
            return False, "invalid amount"
        if amt < min_amount:
            return False, "amount below threshold"
        dt = _parse_date(tx["date"])
        if dt is None:
            return False, "invalid date"
        if start_date and dt < start_date:
            return False, "before start_date"
        if end_date and dt > end_date:
            return False, "after end_date"
        return True, ""

    def _aggregate(valid_txs: List[Dict[str, Any]]) -> Dict[str, Any]:
        totals: Dict[str, float] = {}
        counts: Dict[str, int] = {}
        for tx in valid_txs:
            cat = tx.get("category", "uncategorized")
            amt = float(tx["amount"])
            totals[cat] = totals.get(cat, 0.0) + amt
            counts[cat] = counts.get(cat, 0) + 1
        return {"totals": totals, "counts": counts}

    def _format_report(agg: Dict[str, Any]) -> str:
        lines: List[str] = []
        lines.append("Transaction Report")
        lines.append("===================")
        lines.append("")
        lines.append("Category Summary:")
        for cat, total in sorted(agg["totals"].items(), key=lambda kv: kv[1], reverse=True):
            lines.append(f"- {cat}: ${total:,.2f} ({agg['counts'][cat]} transactions)")
        lines.append("")
        lines.append("End of Report")
        return "\n".join(lines)

    valid_transactions: List[Dict[str, Any]] = []
    invalid_transactions: List[Tuple[Dict[str, Any], str]] = []

    for tx in transactions:
        ok, msg = _validate(tx)
        if ok:
            valid_transactions.append(tx)
        else:
            invalid_transactions.append((tx, msg))

    agg = _aggregate(valid_transactions)
    report = _format_report(agg)

    result: Dict[str, Any] = {
        "valid_count": len(valid_transactions),
        "invalid_count": len(invalid_transactions),
        "aggregation": agg,
        "report": report,
        "errors": [msg for _, msg in invalid_transactions],
    }

    return result

