from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_user_data(
    users: Iterable[Dict[str, Any]],
    min_age: int = 0,
    max_age: Optional[int] = None,
    include_inactive: bool = False,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    # inner helper
    def _validate_user(user: Dict[str, Any]) -> bool:
        if not isinstance(user, dict):
            return False
        required = {"id", "name", "age", "active"}
        if not required.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int):
            return False
        if not isinstance(user["name"], str):
            return False
        if not isinstance(user["age"], int):
            return False
        if not isinstance(user["active"], bool):
            return False
        return True

    def _filter_user(user: Dict[str, Any]) -> bool:
        if not include_inactive and not user["active"]:
            return False
        if user["age"] < min_age:
            return False
        if max_age is not None and user["age"] > max_age:
            return False
        return True

    def _normalize_user(user: Dict[str, Any]) -> Dict[str, Any]:
        norm = {
            "id": int(user["id"]),
            "name": user["name"].strip().title(),
            "age": int(user["age"]),
            "active": bool(user["active"]),
        }
        return norm

    valid_users: List[Dict[str, Any]] = []
    age_counts: Dict[int, int] = {}

    for raw in users:
        if not _validate_user(raw):
            continue
        if not _filter_user(raw):
            continue
        norm = _normalize_user(raw)
        valid_users.append(norm)
        age = norm["age"]
        age_counts[age] = age_counts.get(age, 0) + 1

    # compute age distribution buckets
    buckets: Dict[str, int] = {}
    for age, count in age_counts.items():
        if age < 20:
            bucket = "0-19"
        elif age < 30:
            bucket = "20-29"
        elif age < 40:
            bucket = "30-39"
        elif age < 50:
            bucket = "40-49"
        elif age < 60:
            bucket = "50-59"
        else:
            bucket = "60+"
        buckets[bucket] = buckets.get(bucket, 0) + count

    # sort valid users by age descending, then name ascending
    valid_users.sort(key=lambda u: (-u["age"], u["name"]))

    # summary
    summary = {
        "total_users": len(valid_users),
        "age_distribution": buckets,
        "active_count": sum(1 for u in valid_users if u["active"]),
        "inactive_count": sum(1 for u in valid_users if not u["active"]),
    }

    return valid_users, summary

