from typing import List, Dict, Any, Optional, Tuple

def process_records(records: List[Dict[str, Any]], key: str, threshold: int = 0) -> Tuple[List[Dict[str, Any]], List[Dict[str, Any]], Dict[str, int]]:
    def _normalize(v: Any) -> str:
        if v is None:
            return ""
        return str(v).strip().lower()

    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if key not in record:
            return False
        return True

    def _group(records: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for r in records:
            k = _normalize(r.get(key))
            groups.setdefault(k, []).append(r)
        return groups

    def _filter_group(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return [r for r in group if r.get('value', 0) >= threshold]

    def _compute_stats(total: int, valid: int, invalid: int, groups: int, filtered: int) -> Dict[str, int]:
        return {
            'total': total,
            'valid': valid,
            'invalid': invalid,
            'groups': groups,
            'filtered_groups': filtered,
        }

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []

    for rec in records:
        if _validate(rec):
            valid_records.append(rec)
        else:
            invalid_records.append(rec)

    grouped = _group(valid_records)

    filtered_groups: Dict[str, List[Dict[str, Any]]] = {}
    for k, g in grouped.items():
        filtered = _filter_group(g)
        if filtered:
            filtered_groups[k] = filtered

    stats = _compute_stats(
        total=len(records),
        valid=len(valid_records),
        invalid=len(invalid_records),
        groups=len(grouped),
        filtered=len(filtered_groups),
    )

    flattened: List[Dict[str, Any]] = []
    for g in filtered_groups.values():
        flattened.extend(g)

    return flattened, invalid_records, stats

