from typing import Any, Dict, List, Tuple, Optional

def analyze_transactions(
    transactions: List[Dict[str, Any]],
    threshold: float,
    *,
    include_categories: Optional[List[str]] = None,
) -> Dict[str, Any]:
    def _validate(tx: Dict[str, Any]) -> bool:
        required = {'id', 'amount', 'category', 'timestamp'}
        if not required.issubset(tx):
            return False
        try:
            float(tx['amount'])
            float(tx['timestamp'])
        except (TypeError, ValueError):
            return False
        return True

    def _normalize_category(cat: str) -> str:
        return cat.strip().lower()

    def _group_by_category(valid_txs: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for tx in valid_txs:
            cat = _normalize_category(tx['category'])
            if include_categories and cat not in [c.lower() for c in include_categories]:
                continue
            groups.setdefault(cat, []).append(tx)
        return groups

    def _summarize_group(group: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = sum(float(tx['amount']) for tx in group)
        count = len(group)
        avg = total / count if count else 0.0
        return {'total': total, 'count': count, 'average': avg}

    valid_txs: List[Dict[str, Any]] = [tx for tx in transactions if _validate(tx)]

    grouped = _group_by_category(valid_txs)

    summary: Dict[str, Any] = {}
    for cat, group in grouped.items():
        cat_summary = _summarize_group(group)
        if cat_summary['total'] >= threshold:
            summary[cat] = cat_summary

    overall_total = sum(s['total'] for s in summary.values())
    overall_count = sum(s['count'] for s in summary.values())
    overall_avg = overall_total / overall_count if overall_count else 0.0

    result = {
        'summary_by_category': summary,
        'overall': {'total': overall_total, 'count': overall_count, 'average': overall_avg},
        'validated_count': len(valid_txs),
        'invalid_count': len(transactions) - len(valid_txs),
    }
    return result

