from typing import Any, Dict, Iterable, List, Optional

def analyze_data(
    data: List[Dict[str, Any]],
    min_score: float,
    group_key: str,
    value_key: str,
) -> Dict[str, Any]:
    def _to_float(val: Any) -> float:
        try:
            return float(val)
        except Exception:
            return 0.0

    def _passes(record: Dict[str, Any]) -> bool:
        score = _to_float(record.get('score'))
        return score >= min_score

    def _group(records: Iterable[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in records:
            key = str(rec.get(group_key, 'unknown')).strip()
            if not key:
                key = 'unknown'
            groups.setdefault(key, []).append(rec)
        return groups

    def _compute_stats(group_records: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = 0.0
        count = 0
        min_val = None
        max_val = None
        for rec in group_records:
            val = _to_float(rec.get(value_key))
            total += val
            count += 1
            if min_val is None or val < min_val:
                min_val = val
            if max_val is None or val > max_val:
                max_val = val
        avg = total / count if count else 0.0
        return {
            'count': count,
            'total': total,
            'average': avg,
            'min': min_val,
            'max': max_val,
        }

    filtered = [r for r in data if _passes(r)]
    groups = _group(filtered)
    stats_per_group: Dict[str, Dict[str, Any]] = {}
    for gkey, recs in groups.items():
        stats_per_group[gkey] = _compute_stats(recs)

    overall = {
        'total_records': len(data),
        'filtered_records': len(filtered),
        'groups': stats_per_group,
    }

    return overall

