from typing import Any, Dict, Iterable, List, Optional, Tuple, Union

def analyze_user_activity(
    events: Iterable[Dict[str, Any]],
    user_id: str,
    max_events: int = 1000,
    filter_actions: Optional[List[str]] = None,
    time_window: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int], float]:
    def _clean_value(v: Any) -> Any:
        if isinstance(v, str):
            return v.strip()
        return v

    def _normalize_event(ev: Dict[str, Any]) -> Dict[str, Any]:
        norm: Dict[str, Any] = {}
        for k, v in ev.items():
            norm[k] = _clean_value(v)
        return norm

    def _matches_filter(ev: Dict[str, Any]) -> bool:
        if filter_actions is None:
            return True
        action = ev.get('action')
        return action in filter_actions if action is not None else False

    def _within_window(ts: Union[int, float]) -> bool:
        if time_window is None:
            return True
        return 0 <= ts <= time_window

    def _extract_timestamp(ev: Dict[str, Any]) -> Optional[float]:
        ts = ev.get('timestamp')
        if ts is None:
            return None
        try:
            return float(ts)
        except (TypeError, ValueError):
            return None

    def _sort_by_time(ev_list: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return sorted(ev_list, key=lambda e: _extract_timestamp(e) or 0.0)

    def _compute_durations(ev_list: List[Dict[str, Any]]) -> List[float]:
        durations: List[float] = []
        prev_ts: Optional[float] = None
        for ev in ev_list:
            ts = _extract_timestamp(ev)
            if ts is None:
                continue
            if prev_ts is not None:
                durations.append(ts - prev_ts)
            prev_ts = ts
        return durations

    def _aggregate_counts(ev_list: List[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for ev in ev_list:
            action = ev.get('action')
            if action:
                counts[action] = counts.get(action, 0) + 1
        return counts

    raw_events: List[Dict[str, Any]] = []
    for raw in events:
        if len(raw_events) >= max_events:
            break
        if not isinstance(raw, dict):
            continue
        if raw.get('user_id') != user_id:
            continue
        ev = _normalize_event(raw)
        if not _matches_filter(ev):
            continue
        ts = _extract_timestamp(ev)
        if ts is None or not _within_window(ts):
            continue
        raw_events.append(ev)

    sorted_events = _sort_by_time(raw_events)
    durations = _compute_durations(sorted_events)
    avg_duration = sum(durations) / len(durations) if durations else 0.0
    action_counts = _aggregate_counts(sorted_events)

    return sorted_events, action_counts, avg_duration

