from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_data(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_field: str,
    threshold: float = 0.5,
    max_groups: Optional[int] = None,
) -> Tuple[Dict[str, List[Dict[str, Any]]], Dict[str, Any]]:
    def _normalize_key(v: Any) -> str:
        if v is None:
            return ""
        return str(v).strip().lower()

    def _extract_value(rec: Dict[str, Any]) -> float:
        val = rec.get(value_field)
        try:
            return float(val)
        except (TypeError, ValueError):
            return 0.0

    def _group_records() -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in records:
            if not isinstance(rec, dict):
                continue
            k = _normalize_key(rec.get(key_field))
            if k not in groups:
                groups[k] = []
            groups[k].append(rec)
        return groups

    def _filter_by_threshold(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for rec in group:
            val = _extract_value(rec)
            if val >= threshold:
                filtered.append(rec)
        return filtered

    def _sort_group(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return sorted(group, key=lambda r: _extract_value(r), reverse=True)

    groups = _group_records()
    processed: Dict[str, List[Dict[str, Any]]] = {}
    stats: Dict[str, Any] = {
        "total_records": 0,
        "unique_keys": 0,
        "filtered_records": 0,
        "max_groups_used": None,
    }

    for k, recs in groups.items():
        stats["total_records"] += len(recs)
        filtered = _filter_by_threshold(recs)
        stats["filtered_records"] += len(filtered)
        if filtered:
            processed[k] = _sort_group(filtered)

    stats["unique_keys"] = len(processed)
    if max_groups is not None:
        keys = sorted(processed.keys(), key=lambda k: len(processed[k]), reverse=True)
        selected_keys = keys[:max_groups]
        processed = {k: processed[k] for k in selected_keys}
        stats["max_groups_used"] = len(selected_keys)
    else:
        stats["max_groups_used"] = len(processed)

    return processed, stats

