from typing import List, Dict, Tuple, Any, Optional

def analyze_dataset(
    data: List[Dict[str, Any]],
    numeric_fields: List[str],
    categorical_fields: List[str],
    threshold: float = 0.1,
) -> Dict[str, Any]:
    def _validate_row(row: Dict[str, Any]) -> bool:
        for f in numeric_fields:
            if f not in row:
                return False
            if not isinstance(row[f], (int, float)):
                return False
        for f in categorical_fields:
            if f not in row:
                return False
        return True

    def _aggregate_numeric(rows: List[Dict[str, Any]]) -> Dict[str, Tuple[float, float]]:
        stats: Dict[str, Tuple[float, float]] = {}
        for f in numeric_fields:
            values = [float(r[f]) for r in rows]
            if values:
                mean = sum(values) / len(values)
                var = sum((x - mean) ** 2 for x in values) / len(values)
                stats[f] = (mean, var)
        return stats

    def _mode(values: List[Any]) -> Any:
        freq: Dict[Any, int] = {}
        for v in values:
            freq[v] = freq.get(v, 0) + 1
        max_count = max(freq.values())
        modes = [k for k, v in freq.items() if v == max_count]
        return modes[0] if len(modes) == 1 else modes

    def _aggregate_categorical(rows: List[Dict[str, Any]]) -> Dict[str, Any]:
        cat_stats: Dict[str, Any] = {}
        for f in categorical_fields:
            values = [r[f] for r in rows]
            cat_stats[f] = _mode(values)
        return cat_stats

    def _filter_rows(rows: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for r in rows:
            if _validate_row(r):
                filtered.append(r)
        return filtered

    filtered_data = _filter_rows(data)
    if not filtered_data:
        return {"error": "No valid rows"}

    numeric_stats = _aggregate_numeric(filtered_data)
    categorical_stats = _aggregate_categorical(filtered_data)

    out: Dict[str, Any] = {
        "numeric_stats": numeric_stats,
        "categorical_stats": categorical_stats,
        "row_count": len(filtered_data),
    }

    if threshold > 0:
        out["threshold_info"] = {
            "threshold": threshold,
            "above_threshold": [
                r for r in filtered_data
                if any(float(r[f]) > threshold for f in numeric_fields)
            ],
        }

    return out

