from typing import Any, Dict, Iterable, List, Optional, Tuple

def analyze_data(
    records: Iterable[Dict[str, Any]],
    key: str,
    numeric_fields: List[str],
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    def _normalize(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip()
        return val

    def _extract_numeric(row: Dict[str, Any]) -> Tuple[float, ...]:
        nums = []
        for field in numeric_fields:
            v = row.get(field)
            try:
                nums.append(float(v))
            except (TypeError, ValueError):
                nums.append(0.0)
        return tuple(nums)

    def _median(values: List[float]) -> float:
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    def _mode(values: List[float]) -> float:
        freq: Dict[float, int] = {}
        for v in values:
            freq[v] = freq.get(v, 0) + 1
        max_count = 0
        mode_val = 0.0
        for v, c in freq.items():
            if c > max_count:
                max_count = c
                mode_val = v
        return mode_val

    groups: Dict[Any, List[Dict[str, Any]]] = {}
    for rec in records:
        k = _normalize(rec.get(key))
        groups.setdefault(k, []).append(rec)

    stats: Dict[Any, Dict[str, Any]] = {}
    for k, recs in groups.items():
        total = len(recs)
        sums = [0.0] * len(numeric_fields)
        all_vals: List[List[float]] = [[] for _ in numeric_fields]
        for r in recs:
            nums = _extract_numeric(r)
            for i, n in enumerate(nums):
                sums[i] += n
                all_vals[i].append(n)
        avgs = [s / total if total else 0.0 for s in sums]
        medians = [_median(vals) for vals in all_vals]
        modes = [_mode(vals) for vals in all_vals]
        stats[k] = {
            "count": total,
            "sum": sums,
            "avg": avgs,
            "median": medians,
            "mode": modes,
        }

    if threshold is not None:
        filtered = {
            k: v
            for k, v in stats.items()
            if any(a > threshold for a in v["avg"])
        }
    else:
        filtered = stats

    result = {
        "groups": len(groups),
        "records": sum(len(v) for v in groups.values()),
        "stats": filtered,
    }
    return result

