from typing import Any, Dict, List, Optional, Tuple


def process_user_data(
    users: List[Dict[str, Any]],
    threshold: int = 10,
    include_inactive: bool = False,
) -> Tuple[Dict[str, int], List[Dict[str, Any]]]:
    def _validate_user(user: Dict[str, Any]) -> bool:
        required = {"id", "name", "age", "email"}
        if not isinstance(user, dict):
            return False
        if not required.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int) or user["id"] <= 0:
            return False
        if not isinstance(user["name"], str) or not user["name"]:
            return False
        if not isinstance(user["age"], int) or user["age"] < 0:
            return False
        if not isinstance(user["email"], str) or "@" not in user["email"]:
            return False
        return True

    def _normalize_email(email: str) -> str:
        return email.strip().lower()

    def _is_active(user: Dict[str, Any]) -> bool:
        return user.get("active", True)

    valid_users: List[Dict[str, Any]] = []
    for u in users:
        if _validate_user(u):
            if include_inactive or _is_active(u):
                u["email"] = _normalize_email(u["email"])
                valid_users.append(u)

    age_buckets: Dict[str, int] = {
        "0-18": 0,
        "19-35": 0,
        "36-55": 0,
        "56+": 0,
    }

    for v in valid_users:
        age = v["age"]
        if age <= 18:
            age_buckets["0-18"] += 1
        elif age <= 35:
            age_buckets["19-35"] += 1
        elif age <= 55:
            age_buckets["36-55"] += 1
        else:
            age_buckets["56+"] += 1

    top_domains: Dict[str, int] = {}
    for v in valid_users:
        domain = v["email"].split("@")[-1]
        top_domains[domain] = top_domains.get(domain, 0) + 1

    sorted_domains = sorted(top_domains.items(), key=lambda kv: -kv[1])[:threshold]
    top_domain_list = [
        {"domain": d, "count": c} for d, c in sorted_domains
    ]

    return age_buckets, top_domain_list

