from typing import Any, Dict, List, Optional, Tuple

def process_records(records: List[Dict[str, Any]], filter_key: str, filter_value: Any, group_by: str) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        if not isinstance(record, dict):
            return False
        if filter_key not in record:
            return False
        if group_by not in record:
            return False
        return True

    def _matches(record: Dict[str, Any]) -> bool:
        return record.get(filter_key) == filter_value

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = {}
        for k, v in record.items():
            if isinstance(v, str):
                new_rec[k] = v.strip()
            else:
                new_rec[k] = v
        return new_rec

    def _aggregate(groups: Dict[str, List[Dict[str, Any]]]) -> Dict[str, Dict[str, Any]]:
        result = {}
        for key, recs in groups.items():
            count = len(recs)
            sum_vals = 0
            for r in recs:
                val = r.get('value')
                if isinstance(val, (int, float)):
                    sum_vals += val
            result[key] = {'count': count, 'sum': sum_vals}
        return result

    valid_records: List[Dict[str, Any]] = []
    for rec in records:
        if _validate(rec) and _matches(rec):
            transformed = _transform(rec)
            valid_records.append(transformed)

    groups: Dict[str, List[Dict[str, Any]]] = {}
    for rec in valid_records:
        key = rec.get(group_by)
        if key not in groups:
            groups[key] = []
        groups[key].append(rec)

    aggregated = _aggregate(groups)

    return {
        'total_records': len(records),
        'valid_records': len(valid_records),
        'groups': aggregated,
        'errors': {
            'invalid': len(records) - len(valid_records)
        }
    }

