from typing import Any, Dict, Iterable, List, Optional, Tuple


def aggregate_and_filter(
    data: List[Dict[str, Any]],
    filter_key: str,
    threshold: int,
    group_by: str,
    transform: Optional[Any] = None,
    include_stats: bool = True,
    sort_values: bool = False,
) -> Dict[str, Any]:
    def _is_valid(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if filter_key not in item:
            return False
        val = item[filter_key]
        if val is None:
            return False
        try:
            return int(val) >= threshold
        except (ValueError, TypeError):
            return False

    def _group_key(item: Dict[str, Any]) -> Any:
        return item.get(group_by)

    def _apply_transform(values: List[Any]) -> List[Any]:
        if transform is None:
            return values
        return [transform(v) for v in values]

    def _median(values: List[Any]) -> Any:
        n = len(values)
        if n == 0:
            return None
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2
        return sorted_vals[mid]

    def _mode(values: List[Any]) -> Any:
        freq: Dict[Any, int] = {}
        for v in values:
            freq[v] = freq.get(v, 0) + 1
        if not freq:
            return None
        max_count = max(freq.values())
        modes = [k for k, v in freq.items() if v == max_count]
        return modes[0] if len(modes) == 1 else modes

    grouped: Dict[Any, List[Any]] = {}
    for entry in data:
        if not _is_valid(entry):
            continue
        key = _group_key(entry)
        if key not in grouped:
            grouped[key] = []
        grouped[key].append(entry[filter_key])

    result: Dict[str, Any] = {}
    for key, values in grouped.items():
        transformed = _apply_transform(values)
        if sort_values:
            transformed.sort()
        group_stats: Dict[str, Any] = {
            "count": len(transformed),
            "sum": sum(transformed),
        }
        if include_stats:
            group_stats["average"] = (
                sum(transformed) / len(transformed) if transformed else None
            )
            group_stats["median"] = _median(transformed)
            group_stats["mode"] = _mode(transformed)
        group_stats["values"] = transformed
        result[key] = group_stats

    summary: Dict[str, Any] = {
        "total_entries": len(data),
        "valid_entries": sum(len(v) for v in grouped.values()),
        "groups": len(grouped),
        "grouped_data": result,
    }
    return summary

