from typing import List, Dict, Tuple, Optional, Iterable

def analyze_text_data(
    documents: List[Dict[str, str]],
    stopwords: Optional[Iterable[str]] = None,
    min_word_length: int = 3,
    max_word_length: int = 20,
    top_n: int = 10,
) -> Dict[str, Any]:
    # internal helper
    def _normalize(word: str) -> str:
        return word.strip().lower()
    def _is_valid(word: str) -> bool:
        if not word:
            return False
        if len(word) < min_word_length or len(word) > max_word_length:
            return False
        return True
    def _count_words(text: str) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for token in text.split():
            w = _normalize(token)
            if _is_valid(w):
                counts[w] = counts.get(w, 0) + 1
        return counts
    stop_set = set(stopwords or [])
    global_counts: Dict[str, int] = {}
    doc_word_lists: List[List[str]] = []
    for idx, doc in enumerate(documents):
        title = doc.get('title', '')
        body = doc.get('body', '')
        combined = f\\"{title} {body}\\"
        local_counts = _count_words(combined)
        for word, cnt in local_counts.items():
            if word in stop_set:
                continue
            global_counts[word] = global_counts.get(word, 0) + cnt
        words_in_doc = [w for w in local_counts if w not in stop_set]
        doc_word_lists.append(words_in_doc)
    def _compute_doc_stats(words: List[str]) -> Tuple[int, int]:
        unique = len(set(words))
        total = len(words)
        return unique, total

    doc_stats: List[Tuple[int, int]] = []
    for words in doc_word_lists:
        doc_stats.append(_compute_doc_stats(words))

    result: Dict[str, Any] = {
        'global_counts': global_counts,
        'top_words': top_words,
        'doc_word_lists': doc_word_lists,
        'doc_stats': doc_stats,
    }
    return result

