def process_user_data(
    users: List[Dict[str, Any]],
    *,
    min_age: int = 0,
    include_inactive: bool = False
) -> Dict[str, Any]:
    def _validate_user(user: Dict[str, Any]) -> bool:
        if not isinstance(user, dict):
            return False
        required = {"id", "name", "age", "country", "active"}
        if not required.issubset(user.keys()):
            return False
        if not isinstance(user["id"], int):
            return False
        if not isinstance(user["name"], str):
            return False
        if not isinstance(user["age"], int):
            return False
        if not isinstance(user["country"], str):
            return False
        if not isinstance(user["active"], bool):
            return False
        return True

    def _filter_users() -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for u in users:
            if not _validate_user(u):
                continue
            if u["age"] < min_age:
                continue
            if not include_inactive and not u["active"]:
                continue
            filtered.append(u)
        return filtered

    def _group_by_country(filtered: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for u in filtered:
            c = u["country"]
            groups.setdefault(c, []).append(u)
        return groups

    def _compute_stats(groups: Dict[str, List[Dict[str, Any]]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {}
        total_users = 0
        total_age = 0
        for country, users_in_country in groups.items():
            count = len(users_in_country)
            ages = [u["age"] for u in users_in_country]
            avg_age = sum(ages) / count if count else 0
            stats[country] = {
                "count": count,
                "average_age": avg_age,
                "min_age": min(ages) if ages else None,
                "max_age": max(ages) if ages else None,
            }
            total_users += count
            total_age += sum(ages)
        overall_avg = total_age / total_users if total_users else 0
        stats["overall"] = {
            "total_users": total_users,
            "average_age": overall_avg,
        }
        return stats

    filtered_users = _filter_users()
    grouped = _group_by_country(filtered_users)
    statistics = _compute_stats(grouped)

    result: Dict[str, Any] = {
        "filtered_count": len(filtered_users),
        "grouped_by_country": grouped,
        "statistics": statistics,
    }
    return result

