import typing
from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(
    records: Iterable[Dict[str, Any]],
    key: str,
    required_fields: List[str],
    transform: Optional[Any] = None,
) -> Tuple[Dict[str, List[Dict[str, Any]]], List[str]]:
    def _validate(rec: Dict[str, Any]) -> bool:
        for f in required_fields:
            if f not in rec or rec[f] is None:
                return False
        return True

    def _apply_transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return rec
        try:
            return transform(rec)
        except Exception:
            return rec

    groups: Dict[str, List[Dict[str, Any]]] = {}
    errors: List[str] = []

    for rec in records:
        if not isinstance(rec, dict):
            errors.append(f'invalid record type: {type(rec)}')
            continue
        if not _validate(rec):
            errors.append(f'missing required fields in record: {rec}')
            continue
        k = str(rec.get(key, '')).strip()
        if not k:
            errors.append(f'empty key in record: {rec}')
            continue
        rec = _apply_transform(rec)
        groups.setdefault(k, []).append(rec)

    def _sort_group(group: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return sorted(group, key=lambda r: r.get('timestamp', 0))

    for k, lst in groups.items():
        groups[k] = _sort_group(lst)

    def _compute_stats() -> Dict[str, Any]:
        stats: Dict[str, Any] = {}
        stats['total_records'] = sum(len(v) for v in groups.values())
        stats['unique_keys'] = len(groups)
        stats['errors'] = len(errors)
        return stats

    def _merge_groups(other: Dict[str, List[Dict[str, Any]]]) -> None:
        for k, lst in other.items():
            if k in groups:
                groups[k].extend(lst)
                groups[k] = _sort_group(groups[k])
            else:
                groups[k] = lst

    # Example usage of merge: merge with an empty dict to illustrate
    _merge_groups({})

    stats = _compute_stats()

    return groups, errors

