            cur = tx["currency"]
            amt = float(tx["amount"])
            totals[cur] = totals.get(cur, 0.0) + amt
        return totals

    # Format report
    def _format_report(totals: Dict[str, float]) -> List[str]:
        lines: List[str] = []
        for cur, total in sorted(totals.items()):
            lines.append(f"{cur}: {total:.2f}")
        return lines

    # Main logic
    if not isinstance(transactions, list):
        raise TypeError("transactions must be a list")
    valid: List[Dict[str, Any]] = []
    for tx in transactions:
        if _validate(tx):
            valid.append(tx)
    totals = _aggregate(valid)
    report_lines = _format_report(totals)
    # Filter by threshold
    filtered = {cur: amt for cur, amt in totals.items() if amt >= threshold}
    return {
        "total_transactions": len(transactions),
        "valid_transactions": len(valid),
        "filtered_transactions": len(filtered),
        "report": report_lines,
        "details": filtered,
    }

