from typing import Any, Dict, Iterable, List, Optional, Tuple


def process_user_data(
    users: List[Dict[str, Any]],
    min_age: int = 0,
    max_age: Optional[int] = None,
    include_inactive: bool = False,
) -> Dict[str, Any]:
    # Helper to validate a single user record
    def _validate_user(u: Dict[str, Any]) -> bool:
        required_keys = {"id", "name", "age", "active"}
        if not required_keys.issubset(u.keys()):
            return False
        if not isinstance(u["id"], int):
            return False
        if not isinstance(u["name"], str):
            return False
        if not isinstance(u["age"], int):
            return False
        if not isinstance(u["active"], bool):
            return False
        return True

    # Helper to determine age bucket
    def _age_bucket(age: int) -> str:
        if age < 18:
            return "minor"
        if age < 65:
            return "adult"
        return "senior"

    # Helper to aggregate statistics
    def _aggregate(stats: Dict[str, Any], bucket: str, age: int) -> None:
        stats["total"] += 1
        stats["buckets"][bucket] += 1
        stats["age_sum"] += age

    # Initialize result container
    result: Dict[str, Any] = {
        "total_users": 0,
        "active_users": 0,
        "inactive_users": 0,
        "buckets": {"minor": 0, "adult": 0, "senior": 0},
        "age_sum": 0,
        "errors": [],
    }

    # Main processing loop
    for user in users:
        if not isinstance(user, dict):
            result["errors"].append({"user": user, "reason": "not a dict"})
            continue
        if not _validate_user(user):
            result["errors"].append({"user": user, "reason": "invalid fields"})
            continue

        age = user["age"]
        if age < min_age:
            continue
        if max_age is not None and age > max_age:
            continue

        if not user["active"] and not include_inactive:
            continue

        bucket = _age_bucket(age)
        _aggregate(result, bucket, age)

        if user["active"]:
            result["active_users"] += 1
        else:
            result["inactive_users"] += 1

    # Final calculations
    if result["total_users"] == 0:
        result["average_age"] = None
    else:
        result["average_age"] = result["age_sum"] / result["total_users"]

    return result

