from typing import List, Dict, Any, Optional, Tuple


def process_records(
    records: List[Dict[str, Any]],
    key: str,
    required_fields: List[str],
    value_field: str = "value",
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _normalize(value: Any) -> Any:
        if isinstance(value, str):
            return value.strip()
        return value

    def _validate(rec: Dict[str, Any]) -> bool:
        for f in required_fields:
            if f not in rec or rec[f] is None:
                return False
        return True

    def _compute_stats(valid: List[Dict[str, Any]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {}
        total = len(valid)
        stats["total"] = total
        if total == 0:
            stats["average"] = None
            return stats
        sum_val = 0.0
        for r in valid:
            val = r.get(value_field)
            if isinstance(val, (int, float)):
                sum_val += float(val)
        stats["average"] = sum_val / total
        return stats

    def _merge_records(existing: Dict[str, Any], new: Dict[str, Any]) -> Dict[str, Any]:
        merged = dict(existing)
        for k, v in new.items():
            if k not in merged or merged[k] is None:
                merged[k] = v
        return merged

    processed: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []
    seen_keys: Dict[str, Dict[str, Any]] = {}

    for rec in records:
        rec = {k: _normalize(v) for k, v in rec.items()}
        if not _validate(rec):
            errors.append({"record": rec, "error": "missing required fields"})
            continue
        key_val = rec.get(key)
        if key_val is None:
            errors.append({"record": rec, "error": f"missing key {key}"})
            continue
        if key_val in seen_keys:
            merged = _merge_records(seen_keys[key_val], rec)
            seen_keys[key_val] = merged
        else:
            seen_keys[key_val] = rec

    for k, v in seen_keys.items():
        processed.append(v)

    stats = _compute_stats(processed)

    result = {
        "processed": processed,
        "errors": errors,
        "stats": stats,
    }
    return processed, stats

