from typing import Any, Dict, Iterable, List, Optional, Tuple, Callable

def analyze_and_transform(
    data: Iterable[Dict[str, Any]],
    key: str,
    value_field: str,
    filter_func: Optional[Callable[[Dict[str, Any]], bool]] = None,
    transform_func: Optional[Callable[[Dict[str, Any]], Dict[str, Any]]] = None,
    limit: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int], float]:
    def _normalize(v: Any) -> Any:
        if isinstance(v, str):
            return v.strip()
        return v

    def _filter(rec: Dict[str, Any]) -> bool:
        if filter_func is None:
            return True
        try:
            return filter_func(rec)
        except Exception:
            return False

    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func is None:
            return rec
        try:
            return transform_func(rec)
        except Exception:
            return rec

    def _aggregate(records: List[Dict[str, Any]]) -> Dict[str, int]:
        agg: Dict[str, int] = {}
        for r in records:
            k = r.get(key)
            if k is None:
                continue
            agg[str(k)] = agg.get(str(k), 0) + 1
        return agg

    processed: List[Dict[str, Any]] = []
    seen_keys: Dict[str, int] = {}
    count = 0
    for rec in data:
        if not isinstance(rec, dict):
            continue
        rec = {k: _normalize(v) for k, v in rec.items()}
        if not _filter(rec):
            continue
        rec = _transform(rec)
        processed.append(rec)
        count += 1
        if limit is not None and count >= limit:
            break

    aggregated = _aggregate(processed)

    def _sort_by_value(records: List[Dict[str, Any]]) -> List[Dict[str, Any]]:
        def _key_func(r: Dict[str, Any]) -> Any:
            val = r.get(value_field)
            if isinstance(val, (int, float)):
                return val
            try:
                return float(val)
            except Exception:
                return 0.0
        return sorted(records, key=_key_func, reverse=True)

    sorted_records = _sort_by_value(processed)

    total_value = 0.0
    for r in sorted_records:
        val = r.get(value_field)
        try:
            total_value += float(val)
        except Exception:
            pass

    avg_value = total_value / len(sorted_records) if sorted_records else 0.0

    return sorted_records, aggregated, avg_value

