from typing import Any, Dict, Iterable, List, Optional, Tuple


def analyze_data(
    data: Iterable[Dict[str, Any]],
    key: str,
    numeric_fields: List[str],
    threshold: Optional[float] = None,
) -> Dict[str, Any]:
    # Validate the input types
    if not isinstance(data, Iterable):
        raise TypeError("data must be an iterable of dictionaries")
    if not isinstance(key, str):
        raise TypeError("key must be a string")
    if not isinstance(numeric_fields, list):
        raise TypeError("numeric_fields must be a list of field names")
    if threshold is not None and not isinstance(threshold, (int, float)):
        raise TypeError("threshold must be a number or None")

    # Helper to compute basic statistics for a list of numbers
    def _stats(values: List[float]) -> Tuple[float, float, int]:
        if not values:
            return (0.0, 0.0, 0)
        total = sum(values)
        count = len(values)
        avg = total / count
        variance = sum((x - avg) ** 2 for x in values) / count
        return (avg, variance, count)

    # Helper to format statistics into a readable dict
    def _format_stats(avg: float, var: float, count: int) -> Dict[str, float]:
        return {
            "average": round(avg, 4),
            "variance": round(var, 6),
            "count": count,
        }

    # Helper to decide if a group's average exceeds threshold
    def _passes_threshold(group_stats: Dict[str, Dict[str, float]]) -> bool:
        if threshold is None:
            return True
        for field in numeric_fields:
            if group_stats[field]["average"] > threshold:
                return True
        return False

    # Group the data by the specified key
    groups: Dict[Any, List[Dict[str, Any]]] = {}
    for item in data:
        if not isinstance(item, dict):
            continue
        k = item.get(key)
        if k is None:
            continue
        groups.setdefault(k, []).append(item)

    # Process each group to compute statistics
    group_results: Dict[Any, Dict[str, Any]] = {}
    for k, items in groups.items():
        numeric_values: Dict[str, List[float]] = {field: [] for field in numeric_fields}
        for itm in items:
            for field in numeric_fields:
                val = itm.get(field)
                if isinstance(val, (int, float)):
                    numeric_values[field].append(float(val))
        stats_for_group: Dict[str, Dict[str, float]] = {}
        for field, vals in numeric_values.items():
            avg, var, cnt = _stats(vals)
            stats_for_group[field] = _format_stats(avg, var, cnt)
        group_results[k] = {
            "stats": stats_for_group,
            "item_count": len(items),
        }

    # Compute global statistics across all data
    global_values: Dict[str, List[float]] = {field: [] for field in numeric_fields}
    for item in data:
        if not isinstance(item, dict):
            continue
        for field in numeric_fields:
            val = item.get(field)
            if isinstance(val, (int, float)):
                global_values[field].append(float(val))
    global_stats: Dict[str, Dict[str, float]] = {}
    for field, vals in global_values.items():
        avg, var, cnt = _stats(vals)
        global_stats[field] = _format_stats(avg, var, cnt)

    # Apply threshold filtering if requested
    if threshold is not None:
        filtered_results: Dict[Any, Dict[str, Any]] = {}
        for k, res in group_results.items():
            if _passes_threshold(res["stats"]):
                filtered_results[k] = res
        group_results = filtered_results

    # Assemble final output
    total_items = sum(res["item_count"] for res in group_results.values())
    output: Dict[str, Any] = {
        "grouped_stats": group_results,
        "global_stats": global_stats,
        "num_groups": len(group_results),
        "total_items": total_items,
    }
    return output

