from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    transform: Optional[Any] = None,
    filter_predicate: Optional[Any] = None,
) -> Tuple[List[Dict[str, Any]], List[str]]:
    # Helper to normalize key
    def _normalize_key(value: Any) -> str:
        if value is None:
            return ""
        return str(value).strip().lower()

    # Helper to apply transformation
    def _apply_transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return rec
        try:
            return transform(rec)
        except Exception as exc:
            raise ValueError(f"Transform failed for record {rec}") from exc

    # Helper to evaluate filter
    def _passes_filter(rec: Dict[str, Any]) -> bool:
        if filter_predicate is None:
            return True
        try:
            return filter_predicate(rec)
        except Exception:
            return False

    processed: List[Dict[str, Any]] = []
    errors: List[str] = []

    for idx, rec in enumerate(records):
        if not isinstance(rec, dict):
            errors.append(f"Record at index {idx} is not a dict")
            continue
        key_val = rec.get(key_field)
        norm_key = _normalize_key(key_val)
        if not norm_key:
            errors.append(f"Record at index {idx} missing key field '{key_field}'")
            continue
        try:
            rec = _apply_transform(rec)
        except Exception as exc:
            errors.append(f"Record at index {idx} transform error: {exc}")
            continue
        if not _passes_filter(rec):
            continue
        rec["_normalized_key"] = norm_key
        processed.append(rec)

    # Sort processed by normalized key
    processed.sort(key=lambda r: r["_normalized_key"])

    # Build index mapping key to list of records
    index: Dict[str, List[Dict[str, Any]]] = {}
    for rec in processed:
        key = rec["_normalized_key"]
        index.setdefault(key, []).append(rec)

    # Prepare summary
    summary: List[str] = [
        f"Total processed: {len(processed)}",
        f"Unique keys: {len(index)}",
        f"Errors: {len(errors)}",
    ]

    return processed, errors

