from typing import List, Dict, Any, Optional, Tuple, Iterable

def analyze_records(
    records: List[Dict[str, Any]],
    key: str,
    threshold: Optional[int] = None,
) -> Tuple[Dict[str, int], List[Dict[str, Any]], Dict[str, Any]]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key not in rec:
            return False
        return True

    def _group_records(valids: Iterable[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for rec in valids:
            k = rec[key]
            if k not in groups:
                groups[k] = []
            groups[k].append(rec)
        return groups

    def _extract_numeric_fields(rec: Dict[str, Any]) -> List[float]:
        nums: List[float] = []
        for v in rec.values():
            if isinstance(v, (int, float)):
                nums.append(float(v))
        return nums

    def _compute_average(nums: List[float]) -> float:
        if not nums:
            return 0.0
        return sum(nums) / len(nums)

    def _compute_variance(nums: List[float]) -> float:
        if not nums:
            return 0.0
        mean = _compute_average(nums)
        var = sum((x - mean) ** 2 for x in nums) / len(nums)
        return var

    def _compute_stats(groups: Dict[str, List[Dict[str, Any]]]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {}
        total = 0
        for k, lst in groups.items():
            count = len(lst)
            total += count
            nums: List[float] = []
            for rec in lst:
                nums.extend(_extract_numeric_fields(rec))
            avg = _compute_average(nums)
            var = _compute_variance(nums)
            stats[k] = {
                "count": count,
                "average_numeric": avg,
                "variance_numeric": var,
                "sample": lst[0] if lst else None,
            }
        stats["total_groups"] = len(groups)
        stats["total_records"] = total
        return stats

    valid_records: List[Dict[str, Any]] = []
    for r in records:
        if _validate_record(r):
            valid_records.append(r)

    groups = _group_records(valid_records)

    if threshold is not None:
        groups = {k: v for k, v in groups.items() if len(v) >= threshold}

    stats = _compute_stats(groups)

    filtered_records: List[Dict[str, Any]] = []
    for recs in groups.values():
        filtered_records.extend(recs)

    return groups, filtered_records, stats

