def analyze_sales_data(records: List[Dict[str, Any]]) -> Dict[str, Any]:
    def _clean_value(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip()
        return val

    def _validate_record(rec: Dict[str, Any]) -> bool:
        required = {"order_id", "product", "region", "quantity", "price"}
        if not required.issubset(rec.keys()):
            return False
        if not isinstance(rec["quantity"], int) or rec["quantity"] <= 0:
            return False
        if not isinstance(rec["price"], (int, float)) or rec["price"] < 0:
            return False
        return True

    def _aggregate_by_product(recs: List[Dict[str, Any]]) -> Dict[str, int]:
        prod_counts: Dict[str, int] = {}
        for r in recs:
            prod = _clean_value(r["product"])
            prod_counts[prod] = prod_counts.get(prod, 0) + r["quantity"]
        return prod_counts

    def _aggregate_by_region(recs: List[Dict[str, Any]]) -> Dict[str, float]:
        region_sales: Dict[str, float] = {}
        for r in recs:
            reg = _clean_value(r["region"])
            amount = r["quantity"] * r["price"]
            region_sales[reg] = region_sales.get(reg, 0.0) + amount
        return region_sales

    def _compute_metrics(prod_counts: Dict[str, int], region_sales: Dict[str, float]) -> Dict[str, Any]:
        total_orders = sum(prod_counts.values())
        top_product = max(prod_counts.items(), key=lambda kv: kv[1])[0] if prod_counts else None
        top_region = max(region_sales.items(), key=lambda kv: kv[1])[0] if region_sales else None
        return {
            "total_orders": total_orders,
            "top_product": top_product,
            "top_region": top_region,
            "product_counts": prod_counts,
            "region_sales": region_sales,
        }

    cleaned: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []

    for idx, rec in enumerate(records):
        cleaned_rec = {k: _clean_value(v) for k, v in rec.items()}
        if _validate_record(cleaned_rec):
            cleaned.append(cleaned_rec)
        else:
            errors.append((idx, "validation_failed"))

    prod_counts = _aggregate_by_product(cleaned)
    region_sales = _aggregate_by_region(cleaned)
    metrics = _compute_metrics(prod_counts, region_sales)

    return {
        "metrics": metrics,
        "errors": errors,
        "record_count": len(records),
        "valid_count": len(cleaned),
    }

