from typing import Any, Dict, Iterable, List, Optional, Tuple

def aggregate_and_validate(
    data: Iterable[Dict[str, Any]],
    key_col: str,
    value_col: str,
    min_value: Optional[int] = None,
    max_value: Optional[int] = None,
    transform: Optional[Any] = None,
    filter_pred: Optional[Any] = None,
) -> Tuple[Dict[str, Any], List[str]]:
    def _normalize(k: Any) -> str:
        if k is None:
            return ''
        return str(k).strip().lower()

    def _flatten(v: Any) -> List[Any]:
        if isinstance(v, list):
            res: List[Any] = []
            for item in v:
                res.extend(_flatten(item))
            return res
        return [v]

    def _within_bounds(val: Any) -> bool:
        if min_value is not None and val < min_value:
            return False
        if max_value is not None and val > max_value:
            return False
        return True

    def _apply_transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return item
        return transform(item)

    def _passes_filter(item: Dict[str, Any]) -> bool:
        if filter_pred is None:
            return True
        return filter_pred(item)

    stats: Dict[str, Any] = {
        'total_records': 0,
        'valid_records': 0,
        'invalid_records': 0,
        'duplicate_keys': 0,
        'missing_fields': 0,
        'value_out_of_bounds': 0,
    }
    result: Dict[str, Any] = {}
    errors: List[str] = []

    for idx, rec in enumerate(data, start=1):
        stats['total_records'] += 1
        if not isinstance(rec, dict):
            stats['invalid_records'] += 1
            errors.append(f'non-dict record at position {idx}')
            continue
        key_raw = rec.get(key_col)
        val_raw = rec.get(value_col)
        if key_raw is None or val_raw is None:
            stats['missing_fields'] += 1
            errors.append(f'missing key or value in record {idx}')
            continue
        key = _normalize(key_raw)
        if not key:
            stats['invalid_records'] += 1
            errors.append(f'empty key after normalization in record {idx}')
            continue
        if key in result:
            stats['duplicate_keys'] += 1
            errors.append(f'duplicate key {key} at record {idx}')
            continue
        flat_vals = _flatten(val_raw)
        for val in flat_vals:
            if not isinstance(val, (int, float)):
                stats['invalid_records'] += 1
                errors.append(f'invalid value type in record {idx}')
                continue
            if not _within_bounds(val):
                stats['value_out_of_bounds'] += 1
                errors.append(f'value {val} out of bounds in record {idx}')
                continue
            item = {'key': key, 'value': val}
            if not _passes_filter(item):
                continue
            item = _apply_transform(item)
            result[key] = item
            stats['valid_records'] += 1
            break

    stats['unique_keys'] = len(result)
    return result, errors

