def compute_statistics(
    data: Iterable[Dict[str, Any]],
    key: str,
    numeric_fields: List[str],
    threshold: Optional[float] = None,
) -> Tuple[Dict[str, float], List[Dict[str, Any]]]:
    # Validate inputs
    if not isinstance(data, Iterable):
        raise TypeError("data must be an iterable of dicts")
    if not isinstance(key, str):
        raise TypeError("key must be a string")
    if not isinstance(numeric_fields, list):
        raise TypeError("numeric_fields must be a list of strings")
    for nf in numeric_fields:
        if not isinstance(nf, str):
            raise TypeError(f"numeric field {nf!r} is not a string")

    # Helper to extract numeric value
    def _get_numeric(row: Dict[str, Any], field: str) -> Optional[float]:
        val = row.get(field)
        if val is None:
            return None
        try:
            return float(val)
        except (TypeError, ValueError):
            return None

    # Group rows by key
    groups: Dict[str, List[Dict[str, Any]]] = {}
    for row in data:
        if not isinstance(row, dict):
            continue
        k = row.get(key)
        if k is None:
            continue
        k_str = str(k)
        groups.setdefault(k_str, []).append(row)

    # Compute statistics per group
    stats: Dict[str, float] = {}
    filtered: List[Dict[str, Any]] = []

    for group_key, rows in groups.items():
        count = len(rows)
        if count == 0:
            continue
        sum_vals = {f: 0.0 for f in numeric_fields}
        valid_counts = {f: 0 for f in numeric_fields}
        for r in rows:
            for f in numeric_fields:
                num = _get_numeric(r, f)
                if num is not None:
                    sum_vals[f] += num
                    valid_counts[f] += 1
        # Calculate averages
        avg_vals = {}
        for f in numeric_fields:
            if valid_counts[f] > 0:
                avg_vals[f] = sum_vals[f] / valid_counts[f]
            else:
                avg_vals[f] = float('nan')
        # Store stats
        stats[group_key] = sum(avg_vals.values()) / len(numeric_fields)

        # Filter rows if threshold provided
        if threshold is not None:
            for r in rows:
                total = sum(_get_numeric(r, f) or 0.0 for f in numeric_fields)
                if total >= threshold:
                    filtered.append(r)

    return stats, filtered

