        norm_rec = _normalize(rec)
        processed.append(norm_rec)
        count += 1

    def _summarize(records: List[Dict[str, Any]]) -> Dict[str, Any]:
        summary: Dict[str, Any] = {}
        for rec in records:
            for k, v in rec.items():
                if isinstance(v, (int, float)):
                    summary.setdefault(k, 0)
                    summary[k] += v
        return summary

    summary = _summarize(processed)

    def _filter_by_threshold(records: List[Dict[str, Any]], field: str, threshold: float) -> List[Dict[str, Any]]:
        filtered: List[Dict[str, Any]] = []
        for rec in records:
            val = rec.get(field)
            if isinstance(val, (int, float)) and val >= threshold:
                filtered.append(rec)
        return filtered

    if 'score' in summary:
        processed = _filter_by_threshold(processed, 'score', 50.0)

    return processed, errors, summary

