from typing import Any, Dict, Iterable, List, Optional, Tuple, Union


def process_records(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    merge_fields: List[str],
    required_fields: List[str],
    max_items: Optional[int] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    def _normalize(val: Any) -> str:
        if val is None:
            return ""
        return str(val).strip().lower()

    def _validate(rec: Dict[str, Any]) -> bool:
        for f in required_fields:
            if f not in rec or rec[f] is None:
                return False
        return True

    def _merge(base: Dict[str, Any], other: Dict[str, Any]) -> Dict[str, Any]:
        merged = dict(base)
        for f in merge_fields:
            if f in other and other[f] is not None:
                merged[f] = other[f]
        return merged

    index: Dict[str, List[Dict[str, Any]]] = {}
    errors: List[str] = []

    for rec in records:
        if not isinstance(rec, dict):
            errors.append("record not a dict")
            continue
        if not _validate(rec):
            errors.append(f"missing required fields in {rec}")
            continue
        k = _normalize(rec.get(key_field))
        if k not in index:
            index[k] = []
        index[k].append(rec)

    merged_list: List[Dict[str, Any]] = []
    for k, recs in index.items():
        if len(recs) == 1:
            merged_list.append(recs[0])
        else:
            base = recs[0]
            for other in recs[1:]:
                base = _merge(base, other)
            merged_list.append(base)

    if max_items is not None:
        merged_list = merged_list[:max_items]

    summary = {
        "total_records": sum(len(v) for v in index.values()),
        "unique_keys": len(index),
        "merged_count": len(merged_list),
        "errors": errors,
    }

    return merged_list, summary

