from typing import Iterable, Dict, Any, List, Optional, Tuple

def analyze_records(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    min_occurrence: int = 1,
    max_occurrence: Optional[int] = None,
    include_fields: Optional[List[str]] = None,
) -> Dict[str, Any]:
    # Helper to normalize key values
    def _normalize(value: Any) -> str:
        if value is None:
            return ""
        return str(value).strip().lower()

    # Validate record structure
    def _validate(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec:
            return False
        return True

    # Aggregate counts per key
    def _aggregate() -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for rec in records:
            if not _validate(rec):
                continue
            k = _normalize(rec[key_field])
            if not k:
                continue
            counts[k] = counts.get(k, 0) + 1
        return counts

    # Filter keys by occurrence bounds
    def _filter_keys(counts: Dict[str, int]) -> List[str]:
        filtered: List[str] = []
        for k, c in counts.items():
            if c < min_occurrence:
                continue
            if max_occurrence is not None and c > max_occurrence:
                continue
            filtered.append(k)
        return filtered

    # Extract summary statistics
    def _summary(counts: Dict[str, int]) -> Dict[str, Any]:
        total_keys = len(counts)
        total_records = sum(counts.values())
        avg_per_key = total_records / total_keys if total_keys else 0
        return {
            "total_keys": total_keys,
            "total_records": total_records,
            "average_per_key": avg_per_key,
        }

    # Build detailed report for each key
    def _detailed_report(keys: List[str], counts: Dict[str, int]) -> List[Dict[str, Any]]:
        report: List[Dict[str, Any]] = []
        for k in keys:
            recs: List[Dict[str, Any]] = []
            for rec in records:
                if not _validate(rec):
                    continue
                if _normalize(rec[key_field]) == k:
                    if include_fields:
                        filtered_rec = {f: rec.get(f) for f in include_fields}
                    else:
                        filtered_rec = dict(rec)
                    recs.append(filtered_rec)
            report.append({"key": k, "count": counts[k], "records": recs})
        return report

    # Main execution
    counts = _aggregate()
    keys = _filter_keys(counts)
    stats = _summary(counts)
    details = _detailed_report(keys, counts)

    return {
        "statistics": stats,
        "keys": keys,
        "details": details,
        "parameters": {
            "key_field": key_field,
            "min_occurrence": min_occurrence,
            "max_occurrence": max_occurrence,
            "include_fields": include_fields,
        },
    }

