from typing import Any, Dict, Iterable, List, Optional, Tuple


def transform_and_aggregate(
    records: List[Dict[str, Any]],
    key_field: str,
    value_field: str,
    filter_predicate: Optional[Any] = None,
    max_records: Optional[int] = None,
) -> Dict[str, Any]:
    def _normalize_key(v: Any) -> str:
        if v is None:
            return ""
        return str(v).strip().lower()

    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if key_field not in rec or value_field not in rec:
            return False
        if not isinstance(rec[key_field], (str, int, float)):
            return False
        if not isinstance(rec[value_field], (int, float)):
            return False
        return True

    def _apply_filter(rec: Dict[str, Any]) -> bool:
        if filter_predicate is None:
            return True
        try:
            return bool(filter_predicate(rec))
        except Exception:
            return False

    def _aggregate(
        acc: Dict[str, Tuple[float, int]],
        key: str,
        value: float,
    ) -> None:
        if key in acc:
            total, count = acc[key]
            acc[key] = (total + value, count + 1)
        else:
            acc[key] = (value, 1)

    aggregated: Dict[str, Tuple[float, int]] = {}
    processed_count = 0
    for rec in records:
        if not _validate_record(rec):
            continue
        if not _apply_filter(rec):
            continue
        key = _normalize_key(rec[key_field])
        value = float(rec[value_field])
        _aggregate(aggregated, key, value)
        processed_count += 1
        if max_records is not None and processed_count >= max_records:
            break

    result: Dict[str, Any] = {}
    for key, (total, count) in aggregated.items():
        avg = total / count if count else 0.0
        result[key] = {
            "total": total,
            "count": count,
            "average": avg,
        }

    return {
        "summary": result,
        "records_processed": processed_count,
        "unique_keys": len(aggregated),
    }

