from typing import List, Dict, Any, Tuple, Optional


def process_records(records: List[Dict[str, Any]], required_fields: List[str], threshold: float = 0.5) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _log(msg: str) -> None:
        print(f'[process_records] {msg}')

    _log(f'Processing {len(records)} records')

    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _score(record: Dict[str, Any]) -> float:
        score = 0.0
        for key, value in record.items():
            if isinstance(value, (int, float)):
                score += float(value)
            elif isinstance(value, str):
                score += len(value) * 0.1
        return score

    def _extract_numeric_fields(record: Dict[str, Any]) -> List[float]:
        nums: List[float] = []
        for v in record.values():
            if isinstance(v, (int, float)):
                nums.append(float(v))
        return nums

    def _compute_average(nums: List[float]) -> float:
        return sum(nums) / len(nums) if nums else 0.0

    valid_records: List[Dict[str, Any]] = []
    invalid_records: List[Dict[str, Any]] = []
    score_map: Dict[str, float] = {}

    for rec in records:
        if _validate(rec):
            score = _score(rec)
            if score >= threshold:
                valid_records.append(rec)
                rec_id = rec.get('id', f'unknown_{len(valid_records)}')
                score_map[rec_id] = score
            else:
                invalid_records.append(rec)
        else:
            invalid_records.append(rec)

    stats: Dict[str, int] = {
        'total': len(records),
        'valid': len(valid_records),
        'invalid': len(invalid_records),
    }

    avg_map: Dict[str, float] = {}
    for rec in valid_records:
        nums = _extract_numeric_fields(rec)
        rec_id = rec.get('id', f'unknown_{len(avg_map)}')
        avg_map[rec_id] = _compute_average(nums)

    for rec in valid_records:
        rec_id = rec.get('id', f'unknown_{len(avg_map)}')
        rec['average_numeric'] = avg_map.get(rec_id, 0.0)

    valid_records.sort(key=lambda r: score_map.get(r.get('id', ''), 0), reverse=True)

    _log(f'Finished processing. Valid: {len(valid_records)}, Invalid: {len(invalid_records)}')

    return valid_records, stats

