from typing import Any, Dict, Iterable, List, Optional, Tuple

def process_records(
    records: Iterable[Dict[str, Any]],
    key_field: str,
    value_fields: List[str],
    threshold: Optional[float] = None,
    normalize: bool = True,
) -> Tuple[Dict[str, float], List[Dict[str, Any]], Dict[str, Any]]:
    def _normalize_value(v: Any) -> float:
        try:
            return float(v)
        except Exception:
            return 0.0

    def _aggregate(acc: Dict[str, float], key: str, val: float) -> None:
        acc[key] = acc.get(key, 0.0) + val

    def _median(values: List[float]) -> float:
        n = len(values)
        if n == 0:
            return 0.0
        sorted_vals = sorted(values)
        mid = n // 2
        if n % 2 == 0:
            return (sorted_vals[mid - 1] + sorted_vals[mid]) / 2.0
        return sorted_vals[mid]

    summary: Dict[str, float] = {}
    filtered: List[Dict[str, Any]] = []
    errors: List[str] = []
    per_key_values: Dict[str, List[float]] = {}

    for rec in records:
        if not isinstance(rec, dict):
            errors.append(f'invalid record type: {type(rec)}')
            continue

        key = rec.get(key_field)
        if key is None:
            errors.append('missing key field')
            continue

        if not isinstance(key, str):
            key = str(key)

        total_val = 0.0
        for vf in value_fields:
            val = rec.get(vf)
            if val is None:
                continue
            num = _normalize_value(val)
            if normalize:
                num = num / 100.0
            total_val += num

        if threshold is not None and total_val < threshold:
            continue

        _aggregate(summary, key, total_val)

        if key not in per_key_values:
            per_key_values[key] = []
        per_key_values[key].append(total_val)

        filtered.append(rec)

    median_per_key: Dict[str, float] = {}
    for k, vals in per_key_values.items():
        median_per_key[k] = _median(vals)

    result = {
        'summary': summary,
        'filtered_records': filtered,
        'metadata': {
            'record_count': len(records),
            'filtered_count': len(filtered),
            'error_count': len(errors),
            'errors': errors,
            'median_per_key': median_per_key,
        },
    }
    return summary, filtered, result

