from typing import Any, Dict, Iterable, List, Optional, Tuple, Callable

def process_records(
    records: Iterable[Dict[str, Any]],
    required_fields: List[str],
    transform_map: Optional[Dict[str, Callable[[Any], Any]]] = None,
    group_by: Optional[str] = None,
    max_records: Optional[int] = None,
    verbose: bool = False,
) -> Dict[str, Any]:
    def _validate(record: Dict[str, Any]) -> bool:
        for field in required_fields:
            if field not in record or record[field] is None:
                return False
        return True

    def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
        if not transform_map:
            return record
        new_rec = {}
        for key, val in record.items():
            if key in transform_map:
                func = transform_map[key]
                try:
                    new_val = func(val)
                except Exception:
                    new_val = val
                new_rec[key] = new_val
            else:
                new_rec[key] = val
        return new_rec

    def _group(records: List[Dict[str, Any]], key: str) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for rec in records:
            k = rec.get(key)
            if k not in groups:
                groups[k] = []
            groups[k].append(rec)
        return groups

    processed: List[Dict[str, Any]] = []
    errors: List[Tuple[int, str]] = []
    count = 0
    for idx, rec in enumerate(records):
        if max_records is not None and count >= max_records:
            break
        if not isinstance(rec, dict):
            errors.append((idx, "record is not a dict"))
            continue
        if not _validate(rec):
            errors.append((idx, "missing required fields"))
            continue
        try:
            new_rec = _transform(rec)
            processed.append(new_rec)
            count += 1
            if verbose and count % 100 == 0:
                print(f"Processed {count} records")
        except Exception as e:
            errors.append((idx, f"transform error: {e}"))

    stats: Dict[str, Any] = {
        "total_input": sum(1 for _ in records),
        "total_processed": count,
        "total_errors": len(errors),
    }

    result: Dict[str, Any] = {
        "stats": stats,
        "errors": errors,
        "data": processed,
    }

    if group_by:
        grouped = _group(processed, group_by)
        result["grouped"] = grouped
        result["group_counts"] = {k: len(v) for k, v in grouped.items()}

    return result

