    metrics: Optional[List[str]] = None,
    validator: Optional[Callable[[Dict[str, Any]], bool]] = None,
    aggregate: Optional[Callable[[List[Dict[str, Any]]], Dict[str, Any]]] = None,
) -> Tuple[Dict[str, List[Dict[str, Any]]], Dict[str, Any], List[Dict[str, Any]]]:

    def _is_valid(record: Dict[str, Any]) -> bool:
        if validator:
            try:
                return validator(record)
            except Exception:
                return False
        return True

    def _extract_metrics(record: Dict[str, Any]) -> Dict[str, Any]:
        if not metrics:
            return {}
        return {m: record.get(m) for m in metrics}

    grouped: Dict[str, List[Dict[str, Any]]] = {}
    invalids: List[Dict[str, Any]] = []
    errors: List[Dict[str, Any]] = []

    for rec in records:
        if not isinstance(rec, dict):
            errors.append({"error": "not a dict", "record": rec})
            continue
        if not _is_valid(rec):
            invalids.append(rec)
            continue
        if rec.get("status") != status_filter:
            continue
        role = rec.get(role_field)
        if role is None:
            errors.append({"error": "missing role", "record": rec})
            continue
        if role not in grouped:
            grouped[role] = []
        enriched = dict(rec)
        enriched.update(_extract_metrics(rec))
        grouped[role].append(enriched)

    aggregated: Dict[str, Any] = {}
    if aggregate:
        for role, items in grouped.items():
            try:
                aggregated[role] = aggregate(items)
            except Exception as e:
                errors.append({"error": str(e), "role": role})

    return grouped, aggregated, errors

