        if not _validate_user(user):
            continue
        if not _filter_user(user):
            continue
        valid_users.append(user)
        metrics.append(_compute_metrics(user))

    total_points = sum(m[0] for m in metrics)
    total_levels = sum(m[1] for m in metrics)
