from typing import Iterable, Dict, Any, List, Tuple, Optional, Callable


def process_data_pipeline(
    data: Iterable[Dict[str, Any]],
    *,
    filter_key: str,
    filter_value: Any,
    transform: Optional[Callable[[Dict[str, Any]], Dict[str, Any]]] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, int]]:
    def _filter(item: Dict[str, Any]) -> bool:
        return item.get(filter_key) == filter_value

    def _transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return item
        try:
            return transform(item)
        except Exception:
            return item

    def _aggregate(items: List[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for itm in items:
            for k, v in itm.items():
                if isinstance(v, str):
                    key = f'{k}:{v}'
                else:
                    key = f'{k}:{str(v)}'
                counts[key] = counts.get(key, 0) + 1
        return counts

    def _validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if filter_key not in item:
            return False
        return True

    def _log(message: str) -> None:
        # Simple logger placeholder
        print(message)

    filtered: List[Dict[str, Any]] = []
    for entry in data:
        if not _validate(entry):
            _log('Skipping invalid entry')
            continue
        if _filter(entry):
            transformed = _transform(entry)
            filtered.append(transformed)
        else:
            _log(f'Entry did not match filter: {entry}')

    aggregated = _aggregate(filtered)

    # Additional summary metrics
    summary: Dict[str, Any] = {
        'total_entries': len(list(data)),
        'filtered_count': len(filtered),
        'unique_keys': len(set(k for d in filtered for k in d.keys())),
    }

    # Attach summary to aggregated under a special key
    aggregated['__summary__'] = summary

    return filtered, aggregated

