from typing import List, Dict, Any, Optional, Tuple, Callable, Iterable

def analyze_data(
    data: List[Dict[str, Any]],
    filter_field: str,
    filter_value: Any,
    group_field: str,
    numeric_field: str,
    limit: Optional[int] = None,
    progress_callback: Optional[Callable[[int], None]] = None,
) -> Tuple[List[Dict[str, Any]], Dict[Any, int], int]:
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if filter_field not in rec or group_field not in rec or numeric_field not in rec:
            return False
        return True

    def _matches(rec: Dict[str, Any]) -> bool:
        return rec.get(filter_field) == filter_value

    def _safe_int(val: Any) -> int:
        try:
            return int(val)
        except Exception:
            return 0

    def _group_records(records: List[Dict[str, Any]]) -> Dict[Any, List[Dict[str, Any]]]:
        groups: Dict[Any, List[Dict[str, Any]]] = {}
        for r in records:
            key = r.get(group_field)
            groups.setdefault(key, []).append(r)
        return groups

    def _aggregate_group(group: List[Dict[str, Any]]) -> int:
        total = 0
        for r in group:
            total += _safe_int(r.get(numeric_field))
        return total

    def _compute_stats(values: List[int]) -> Dict[str, Any]:
        n = len(values)
        if n == 0:
            return {"mean": 0, "median": 0, "max": 0, "min": 0}
        sorted_vals = sorted(values)
        mean_val = sum(values) / n
        median_val = sorted_vals[n // 2] if n % 2 == 1 else (sorted_vals[n // 2 - 1] + sorted_vals[n // 2]) / 2
        return {"mean": mean_val, "median": median_val, "max": sorted_vals[-1], "min": sorted_vals[0]}

    valid_records = [r for r in data if _validate_record(r)]
    if progress_callback:
        progress_callback(len(valid_records))

    filtered = [r for r in valid_records if _matches(r)]
    if progress_callback:
        progress_callback(len(filtered))

    grouped = _group_records(filtered)
    aggregated: Dict[Any, int] = {}
    for key, grp in grouped.items():
        aggregated[key] = _aggregate_group(grp)

    sorted_agg = sorted(aggregated.items(), key=lambda kv: kv[1], reverse=True)
    top_entries = sorted_agg[:limit] if limit is not None else sorted_agg

    result: List[Dict[str, Any]] = []
    for key, total in top_entries:
        group_stats = _compute_stats([_safe_int(r.get(numeric_field)) for r in grouped[key]])
        result.append({
            "group": key,
            "total": total,
            "count": len(grouped[key]),
            "stats": group_stats,
        })

    total_processed = len(valid_records)
    return result, aggregated, total_processed

