from typing import List, Dict, Any, Tuple, Optional, Iterable, Set


def analyze_sales(
    sales_records: List[Dict[str, Any]],
    min_amount: float = 0.0,
    categories: Optional[Iterable[str]] = None,
) -> Tuple[List[Dict[str, Any]], Dict[str, Any]]:
    # Prepare category filter set
    cat_set: Set[str] = set()
    if categories is not None:
        for c in categories:
            cat_set.add(str(c).strip().lower())
    # Validation helper
    def _validate(rec: Dict[str, Any]) -> bool:
        required = {"id", "amount", "category", "timestamp"}
        if not isinstance(rec, dict):
            return False
        return required.issubset(rec.keys())
    # Normalization helper
    def _normalize(rec: Dict[str, Any]) -> Dict[str, Any]:
        rec = dict(rec)
        try:
            rec["amount"] = float(rec.get("amount", 0))
        except (TypeError, ValueError):
            rec["amount"] = 0.0
        rec["category"] = str(rec.get("category", "unknown")).strip().lower()
        try:
            rec["timestamp"] = int(rec.get("timestamp", 0))
        except (TypeError, ValueError):
            rec["timestamp"] = 0
        return rec
    # Aggregate totals per category
    def _aggregate_by_category(records: List[Dict[str, Any]]) -> Dict[str, float]:
        totals: Dict[str, float] = {}
        for r in records:
            cat = r["category"]
            totals[cat] = totals.get(cat, 0.0) + r["amount"]
        return totals
    # Aggregate totals per day (Unix day)
    def _aggregate_by_day(records: List[Dict[str, Any]]) -> Dict[str, float]:
        totals: Dict[str, float] = {}
        for r in records:
            day = r["timestamp"] // 86400
            totals[str(day)] = totals.get(str(day), 0.0) + r["amount"]
        return totals
    # Compute average per category
    def _average_by_category(totals: Dict[str, float], counts: Dict[str, int]) -> Dict[str, float]:
        avg: Dict[str, float] = {}
        for cat, total in totals.items():
            cnt = counts.get(cat, 1)
            avg[cat] = total / cnt
        return avg
    # Count occurrences per category
    def _count_by_category(records: List[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for r in records:
            cat = r["category"]
            counts[cat] = counts.get(cat, 0) + 1
        return counts
    # Format summary
    def _format_summary(
        cat_totals: Dict[str, float],
        cat_counts: Dict[str, int],
        day_totals: Dict[str, float],
    ) -> Dict[str, Any]:
        return {
            "total_sales": sum(cat_totals.values()),
            "by_category": {
                "totals": cat_totals,
                "counts": cat_counts,
                "averages": _average_by_category(cat_totals, cat_counts),
            },
            "by_day": day_totals,
        }
    valid: List[Dict[str, Any]] = []
    invalid: List[Dict[str, Any]] = []
    for rec in sales_records:
        if _validate(rec):
            norm = _normalize(rec)
            if norm["amount"] < min_amount:
                continue
            if cat_set and norm["category"] not in cat_set:
                continue
            valid.append(norm)
        else:
            invalid.append(rec)
    cat_totals = _aggregate_by_category(valid)
    cat_counts = _count_by_category(valid)
    day_totals = _aggregate_by_day(valid)
    summary = _format_summary(cat_totals, cat_counts, day_totals)
    return valid, summary

