from typing import Any, Dict, Iterable, List, Optional, Tuple


def aggregate_user_activity(
    events: List[Dict[str, Any]],
    user_id_key: str = "user_id",
    event_type_key: str = "event_type",
    timestamp_key: str = "timestamp",
    filter_event_types: Optional[Iterable[str]] = None,
) -> Dict[str, Any]:
    # nested helper functions
    def _normalize_event(event: Dict[str, Any]) -> Optional[Dict[str, Any]]:
        # Validate required keys
        if not isinstance(event, dict):
            return None
        if user_id_key not in event or event_type_key not in event or timestamp_key not in event:
            return None
        uid = event[user_id_key]
        etype = event[event_type_key]
        ts = event[timestamp_key]
        if not isinstance(uid, (str, int)):
            return None
        if not isinstance(etype, str):
            return None
        if not isinstance(ts, (int, float)):
            return None
        return {
            "user_id": str(uid),
            "event_type": etype,
            "timestamp": float(ts),
        }

    def _group_by_user(events: List[Dict[str, Any]]) -> Dict[str, List[Dict[str, Any]]]:
        groups: Dict[str, List[Dict[str, Any]]] = {}
        for ev in events:
            uid = ev["user_id"]
            groups.setdefault(uid, []).append(ev)
        return groups

    def _aggregate_user_events(user_events: List[Dict[str, Any]]) -> Dict[str, Any]:
        total = len(user_events)
        types: Dict[str, int] = {}
        earliest = None
        latest = None
        for ev in user_events:
            etype = ev["event_type"]
            types[etype] = types.get(etype, 0) + 1
            ts = ev["timestamp"]
            if earliest is None or ts < earliest:
                earliest = ts
            if latest is None or ts > latest:
                latest = ts
        return {
            "count": total,
            "event_type_counts": types,
            "first_event_ts": earliest,
            "last_event_ts": latest,
        }

    # Main processing
    normalized: List[Dict[str, Any]] = []
    for ev in events:
        norm = _normalize_event(ev)
        if norm is None:
            continue
        if filter_event_types is not None and norm["event_type"] not in filter_event_types:
            continue
        normalized.append(norm)

    user_groups = _group_by_user(normalized)

    aggregated: Dict[str, Any] = {}
    for uid, uevs in user_groups.items():
        aggregated[uid] = _aggregate_user_events(uevs)

    # Summary
    total_users = len(aggregated)
    total_events = sum(v["count"] for v in aggregated.values())

    return {
        "total_users": total_users,
        "total_events": total_events,
        "user_stats": aggregated,
    }

