from typing import List, Dict, Any, Optional, Tuple, Iterable

def analyze_and_aggregate(
    data: List[Dict[str, Any]],
    group_key: str,
    value_key: str,
    min_count: int = 1,
    score_threshold: Optional[float] = None,
) -> Dict[str, Any]:
    # Validate each record
    def _is_valid(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        if group_key not in rec or value_key not in rec:
            return False
        if not isinstance(rec[group_key], (str, int, float)):
            return False
        if not isinstance(rec[value_key], (int, float)):
            return False
        return True

    # Compute score for a record
    def _compute_score(rec: Dict[str, Any]) -> float:
        val = rec[value_key]
        if isinstance(val, (int, float)):
            return float(val)
        try:
            return float(val)
        except Exception:
            return 0.0

    # Group records by key
    groups: Dict[Any, List[Dict[str, Any]]] = {}
    invalid_records: List[Dict[str, Any]] = []

    for record in data:
        if _is_valid(record):
            key = record[group_key]
            groups.setdefault(key, []).append(record)
        else:
            invalid_records.append(record)

    # Aggregate per group
    aggregated: List[Dict[str, Any]] = []

    for key, recs in groups.items():
        count = len(recs)
        if count < min_count:
            continue
        total_score = sum(_compute_score(r) for r in recs)
        avg_score = total_score / count if count else 0.0
        if score_threshold is not None and avg_score < score_threshold:
            continue
        aggregated.append(
            {
                "group": key,
                "count": count,
                "total_score": total_score,
                "average_score": avg_score,
            }
        )

    # Sort aggregated results
    aggregated.sort(key=lambda x: x["average_score"], reverse=True)

    # Build final result
    result: Dict[str, Any] = {
        "aggregated": aggregated,
        "invalid_count": len(invalid_records),
        "total_records": len(data),
        "valid_records": len(data) - len(invalid_records),
    }

    # Optional: compute percentiles
    def _percentile(values: List[float], pct: float) -> float:
        if not values:
            return 0.0
        sorted_vals = sorted(values)
        k = (len(sorted_vals) - 1) * pct
        f = int(k)
        c = k - f
        if f + 1 < len(sorted_vals):
            return sorted_vals[f] + (sorted_vals[f + 1] - sorted_vals[f]) * c
        return sorted_vals[f]

    scores = [rec["average_score"] for rec in aggregated]
    result["percentiles"] = {
        "p25": _percentile(scores, 0.25),
        "p50": _percentile(scores, 0.5),
        "p75": _percentile(scores, 0.75),
    }

    return result

