import time
from contextlib import contextmanager
from typing import Iterable, Dict, Any

def timed(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        elapsed = time.time() - start
        print(f'{func.__name__} took {elapsed:.4f}s')
        return result
    return wrapper

@timed
def analyze_data(
    data: Iterable[float],
    threshold: float = 0.0,
    log_path: str = 'analysis.log',
) -> Dict[str, Any]:
    def _validate(item):
        if not isinstance(item, (int, float)):
            raise ValueError(f'Invalid data type: {type(item)}')
        return float(item)

    def _filter():
        for val in data:
            try:
                num = _validate(val)
            except ValueError:
                continue
            if num >= threshold:
                yield num

    @contextmanager
    def _log_file(path):
        f = open(path, 'a')
        try:
            yield f
        finally:
            f.close()

    stats: Dict[str, Any] = {
        'count': 0,
        'sum': 0.0,
        'mean': None,
        'max': None,
        'min': None,
        'median': None,
        'mode': None,
    }

    values: list[float] = []

    with _log_file(log_path) as log:
        for num in _filter():
            stats['count'] += 1
            stats['sum'] += num
            values.append(num)
            if stats['max'] is None or num > stats['max']:
                stats['max'] = num
            if stats['min'] is None or num < stats['min']:
                stats['min'] = num
            log.write(f'Processed {num}\n')

    if stats['count'] > 0:
        stats['mean'] = stats['sum'] / stats['count']
        values.sort()
        mid = stats['count'] // 2
        if stats['count'] % 2 == 0:
            stats['median'] = (values[mid - 1] + values[mid]) / 2.0
        else:
            stats['median'] = values[mid]
        freq: Dict[float, int] = {}
        for v in values:
            freq[v] = freq.get(v, 0) + 1
        max_freq = max(freq.values())
        modes = [k for k, v in freq.items() if v == max_freq]
        stats['mode'] = modes if len(modes) > 1 else modes[0]
    else:
        stats['mean'] = 0.0
        stats['median'] = 0.0
        stats['mode'] = None

    return stats

