def stream_processor(source_iterable, *, filter_func=None, transform_func=None, max_items=None):
    import contextlib
    import tempfile
    import os
    import time

    # Path for temporary log file
    log_file_path = None

    # Nested validator
    def _is_valid(item):
        if item is None:
            return False
        if isinstance(item, (int, float)):
            return True
        if isinstance(item, str):
            return bool(item.strip())
        return False

    # Nested transformer
    def _apply_transform(item):
        if transform_func is None:
            return item
        try:
            return transform_func(item)
        except Exception:
            return None

    # Decorator for logging
    def _log_call(func):
        def wrapper(*args, **kwargs):
            with open(log_file_path, 'a') as log_f:
                log_f.write(f"[{time.strftime('%Y-%m-%d %H:%M:%S')}] Call {func.__name__} args={args} kwargs={kwargs}\n")
            result = func(*args, **kwargs)
            with open(log_file_path, 'a') as log_f:
                log_f.write(f"[{time.strftime('%Y-%m-%d %H:%M:%S')}] {func.__name__} returned {result}\n")
            return result
        return wrapper

    # Context manager to ensure log file cleanup
    @contextlib.contextmanager
    def _log_file_manager():
        nonlocal log_file_path
        with tempfile.NamedTemporaryFile(delete=False, mode='w', suffix='.log') as tmp:
            log_file_path = tmp.name
        try:
            yield
        finally:
            if log_file_path and os.path.exists(log_file_path):
                os.remove(log_file_path)

    # Helper to count processed items
    def _count_items():
        return sum(1 for _ in source_iterable)

    # Main generator logic
    @contextlib.contextmanager
    def _processing_context():
        with _log_file_manager():
            yield

    with _processing_context():
        processed_count = 0
        for idx, raw_item in enumerate(source_iterable):
            if max_items is not None and processed_count >= max_items:
                break
            if not _is_valid(raw_item):
                continue
            if filter_func is not None and not filter_func(raw_item):
                continue
            transformed = _apply_transform(raw_item)
            if transformed is None:
                continue
            processed_count += 1
            yield transformed

    # After generator exhausted, we could log summary
    # But since generator may not be fully consumed, we skip

