def stream_file_processor(file_path, *, filter_func=None, transform_func=None, include_line_no=False):
    import os
    import contextlib
    import time

    def log_decorator(func):
        def wrapper(*args, **kwargs):
            print(f'Entering {func.__name__}')
            result = func(*args, **kwargs)
            print(f'Exiting {func.__name__}')
            return result
        return wrapper

    @log_decorator
    def _open_file(path):
        return open(path, 'r', encoding='utf-8')

    @log_decorator
    def _read_lines(file_obj):
        for line in file_obj:
            yield line.rstrip('\n')

    @log_decorator
    def _filter_and_transform(lines):
        for line in lines:
            if filter_func and not filter_func(line):
                continue
            if transform_func:
                line = transform_func(line)
            yield line

    @contextlib.contextmanager
    def _timing_context(name):
        start = time.time()
        print(f'Starting {name}')
        try:
            yield
        finally:
            elapsed = time.time() - start
            print(f'Finished {name} in {elapsed:.3f}s')

    if not os.path.exists(file_path):
        raise FileNotFoundError(f'File {file_path} does not exist')

    line_no = 0
    with _timing_context('file_processing'):
        with contextlib.ExitStack() as stack:
            f = stack.enter_context(_open_file(file_path))
            lines = _read_lines(f)
            processed = _filter_and_transform(lines)
            for out_line in processed:
                line_no += 1
                if include_line_no:
                    yield f'{line_no}: {out_line}'
                else:
                    yield out_line

    print(f'Total lines processed: {line_no}')

