import time
from functools import wraps
from contextlib import contextmanager
from typing import Iterable, Iterator, Dict, Any, Callable, List

def log_call(func: Callable) -> Callable:
    @wraps(func)
    def wrapper(*args, **kwargs):
        print(f"Entering {func.__name__}")
        result = func(*args, **kwargs)
        print(f"Exiting {func.__name__}")
        return result
    return wrapper

@contextmanager
def timed_section(name: str):
    start = time.time()
    yield
    end = time.time()
    print(f"{name} took {end - start:.4f}s")

def _validate_record(record: Dict[str, Any]) -> bool:
    if not isinstance(record, dict):
        return False
    required = {"id", "value"}
    if not required.issubset(record.keys()):
        return False
    if not isinstance(record["id"], int):
        return False
    if not isinstance(record["value"], (int, float)):
        return False
    return True

def _transform(record: Dict[str, Any]) -> Dict[str, Any]:
    new = dict(record)
    new["value"] = round(new["value"] * 1.1, 2)
    new["processed_at"] = time.time()
    return new

def _batch_generator(iterable: Iterable[Dict[str, Any]], batch_size: int) -> Iterator[List[Dict[str, Any]]]:
    batch: List[Dict[str, Any]] = []
    for item in iterable:
        batch.append(item)
        if len(batch) == batch_size:
            yield batch
            batch = []
    if batch:
        yield batch

@log_call
def process_data_stream(data: Iterable[Dict[str, Any]], batch_size: int = 10) -> Iterator[Dict[str, Any]]:
    with timed_section("process_data_stream"):
        for batch in _batch_generator(data, batch_size):
            with timed_section(f"batch_{batch[0]['id'] if batch else 'unknown'}"):
                for rec in batch:
                    if not _validate_record(rec):
                        continue
                    transformed = _transform(rec)
                    yield transformed
            # End of batch context
        # End of data loop
    # End of timed_section

