import logging
from typing import Any, Dict, Iterable, Iterator, List, Optional
from contextlib import ExitStack

logging.basicConfig(level=logging.INFO)

def log_calls(func):
    def wrapper(*args, **kwargs):
        logging.info(f"Entering {func.__name__}")
        result = func(*args, **kwargs)
        logging.info(f"Exiting {func.__name__}")
        return result
    return wrapper

@log_calls
def process_data(file_paths: List[str], threshold: int = 10, max_items: Optional[int] = None) -> List[Dict[str, Any]]:
    def _parse_line(line: str) -> Optional[Dict[str, Any]]:
        parts = line.strip().split(',')
        if len(parts) < 2:
            return None
        try:
            value = int(parts[0])
        except ValueError:
            return None
        return {'value': value, 'label': parts[1]}

    def _filter(item: Dict[str, Any]) -> bool:
        return item['value'] >= threshold

    def _aggregate(items: Iterable[Dict[str, Any]]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for itm in items:
            key = itm['label']
            counts[key] = counts.get(key, 0) + 1
        return counts

    def _process_file(path: str) -> Iterator[Dict[str, Any]]:
        with open(path, 'r') as f:
            for line in f:
                parsed = _parse_line(line)
                if parsed is None:
                    continue
                if not _filter(parsed):
                    continue
                yield parsed

    all_results: List[Dict[str, Any]] = []
    items_yielded = 0
    for path in file_paths:
        for item in _process_file(path):
            all_results.append(item)
            items_yielded += 1
            if max_items is not None and items_yielded >= max_items:
                break
        if max_items is not None and items_yielded >= max_items:
            break

    aggregated = _aggregate(all_results)
    logging.info(f"Aggregated counts: {aggregated}")
    return all_results

