import time
from contextlib import contextmanager
from typing import Callable, Iterable, Iterator, List, Optional


def log_execution(func):
    def wrapper(*args, **kwargs):
        print(f"[LOG] Start {func.__name__}")
        result = func(*args, **kwargs)
        print(f"[LOG] End {func.__name__}")
        return result
    return wrapper


def time_it(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        elapsed = time.time() - start
        print(f"[TIME] {func.__name__} took {elapsed:.4f}s")
        return result
    return wrapper


@log_execution
@time_it
def read_and_process(
    file_path: str,
    transform: Callable[[str], str],
    filter_func: Optional[Callable[[str], bool]] = None,
    max_lines: Optional[int] = None,
) -> List[str]:
    @contextmanager
    def _line_counter():
        count = 0
        try:
            yield lambda: count
        finally:
            print(f"[COUNTER] Processed {count} lines")

    def _read_lines() -> Iterator[str]:
        with open(file_path, 'r', encoding='utf-8') as f:
            for line in f:
                yield line.rstrip('\n')

    def _apply_transform(lines: Iterable[str]) -> Iterator[str]:
        for line in lines:
            yield transform(line)

    def _apply_filter(lines: Iterable[str]) -> Iterator[str]:
        for line in lines:
            if filter_func is None or filter_func(line):
                yield line

    def _limit(lines: Iterable[str]) -> Iterator[str]:
        count = 0
        for line in lines:
            if max_lines is not None and count >= max_lines:
                break
            yield line
            count += 1

    with _line_counter() as get_count:
        lines = _read_lines()
        lines = _apply_transform(lines)
        lines = _apply_filter(lines)
        lines = _limit(lines)
        result = []
        for line in lines:
            result.append(line)
            get_count()
        return result

