def stream_processor(data_iterable, *, transform=None, filter_func=None, max_items=None):
    # nested functions
    def _validate(item):
        if item is None:
            raise ValueError("None item")
        return item

    def _default_transform(x):
        return x

    def _default_filter(x):
        return True

    transform = transform or _default_transform
    filter_func = filter_func or _default_filter

    # context manager for timing
    from contextlib import contextmanager
    import time

    @contextmanager
    def _timing(label):
        start = time.time()
        try:
            yield
        finally:
            elapsed = time.time() - start
            print(f"[{label}] elapsed: {elapsed:.4f}s")

    # decorator to log yield
    def _log_yield(func):
        def wrapper(*args, **kwargs):
            for value in func(*args, **kwargs):
                print(f"[yield] {value!r}")
                yield value
        return wrapper

    @ _log_yield
    def _generator():
        count = 0
        for raw in data_iterable:
            try:
                item = _validate(raw)
                item = transform(item)
                if filter_func(item):
                    yield item
                    count += 1
                    if max_items is not None and count >= max_items:
                        break
            except Exception as e:
                print(f"[error] {e!r}")
                continue

    with _timing("stream_processing"):
        for val in _generator():
            yield val

