import asyncio
from typing import Any, Dict, Iterable, List, Optional
from contextlib import asynccontextmanager

async def fetch_and_process(urls: List[str], max_items: int = 100) -> Dict[str, Any]:
    if not isinstance(urls, list):
        raise TypeError("urls must be a list")
    if not all(isinstance(u, str) for u in urls):
        raise ValueError("all urls must be strings")
    if not isinstance(max_items, int) or max_items <= 0:
        raise ValueError("max_items must be positive integer")

    async def _fetch(url: str) -> str:
        if not url.startswith("http"):
            raise ValueError(f"Invalid URL: {url}")
        await asyncio.sleep(0.1)
        return f"data from {url}"

    def _process_items(raw_data: str) -> Iterable[Dict[str, Any]]:
        parts = raw_data.split()
        for idx, part in enumerate(parts):
            yield {
                "index": idx,
                "word": part,
                "length": len(part),
            }

    def _filter_results(items: Iterable[Dict[str, Any]]) -> List[Dict[str, Any]]:
        return [i for i in items if i["length"] >= 3]

    def _aggregate(items: List[Dict[str, Any]]) -> Dict[int, int]:
        agg: Dict[int, int] = {}
        for i in items:
            l = i["length"]
            agg[l] = agg.get(l, 0) + 1
        return agg

    @asynccontextmanager
    async def _log_context(action: str):
        print(f"Starting {action}")
        try:
            yield
        finally:
            print(f"Finished {action}")

    results: List[Dict[str, Any]] = []
    errors: List[str] = []
    fetched = 0

    async with _log_context("fetch_and_process_loop"):
        for url in urls:
            try:
                data = await _fetch(url)
                fetched += 1
                raw_items = _process_items(data)
                filtered = _filter_results(raw_items)
                for item in filtered:
                    results.append(item)
                    if len(results) >= max_items:
                        return {
                            "results": results,
                            "fetched": fetched,
                            "errors": errors,
                            "status": "limit_reached",
                            "aggregation": _aggregate(results),
                        }
            except Exception as e:
                errors.append(str(e))
                continue

    return {
        "results": results,
        "fetched": fetched,
        "errors": errors,
        "status": "completed",
        "aggregation": _aggregate(results),
    }

