import time
from contextlib import ExitStack
from typing import Iterable, Iterator, List, Dict, Any


def timer(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f\"{func.__name__} executed in {end-start:.3f}s\")
        return result
    return wrapper

@timer
def process_and_log(
    data_iter: Iterable[str],
    output_path: str,
    batch_size: int = 50,
    filter_func: Any = None,
    transform_func: Any = None,
) -> Dict[str, Any]:
    def _parse_line(line: str) -> Dict[str, Any]:
        parts = line.strip().split(',')
        if len(parts) < 2:
            raise ValueError(\"Line must contain at least two comma-separated values\")
        return {\"key\": parts[0], \"value\": parts[1]}

    def _filter(item: Dict[str, Any]) -> bool:
        if filter_func is None:
            return True
        return filter_func(item)

    def _transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func is None:
            return item
        return transform_func(item)

    def _batch_generator() -> Iterator[List[Dict[str, Any]]]:
        batch: List[Dict[str, Any]] = []
        for raw in data_iter:
            try:
                parsed = _parse_line(raw)
            except Exception:
                continue
            if not _filter(parsed):
                continue
            transformed = _transform(parsed)
            batch.append(transformed)
            if len(batch) >= batch_size:
                yield batch
                batch = []
        if batch:
            yield batch

    written = 0
    processed = 0
    errors = 0
    with ExitStack() as stack:
        out_file = stack.enter_context(open(output_path, \"w\", encoding=\"utf-8\"))
        for batch in _batch_generator():
            for item in batch:
                try:
                    out_file.write(f\"{item['key']},{item['value']}\n\")
                    written += 1
                except Exception:
                    errors += 1
            processed += len(batch)

    return {
        \"written\": written,
        \"processed\": processed,
        \"errors\": errors,
        \"output\": output_path,
    }

