from typing import Iterable, List, Callable, Any, Tuple
import time
import contextlib

# Decorator to log execution time

def log_execution(func: Callable[..., Any]) -> Callable[..., Any]:
    def wrapper(*args, **kwargs):
        start = time.time()
        print(f"[START] {func.__name__}")
        result = func(*args, **kwargs)
        end = time.time()
        print(f"[END] {func.__name__} took {end - start:.4f}s")
        return result
    return wrapper

# Helper to parse a line into an integer, defaulting to 0 on failure

def _parse_line(line: str) -> int:
    try:
        return int(line.strip())
    except Exception:
        return 0

# Generator that yields processed integers from a chunk of lines

def _process_chunk(lines: Iterable[str]) -> Iterable[int]:
    for line in lines:
        yield _parse_line(line)

# Generator that splits an iterable into fixed-size chunks

def _chunk_lines(lines: Iterable[str], size: int) -> Iterable[List[str]]:
    chunk: List[str] = []
    for line in lines:
        chunk.append(line)
        if len(chunk) >= size:
            yield chunk
            chunk = []
    if chunk:
        yield chunk

# Function to read lines from a file lazily

def read_file(path: str) -> Iterable[str]:
    with open(path, 'r') as f:
        for line in f:
            yield line

# Compute statistics on a list of integers

def compute_stats(values: List[int]) -> Tuple[int, int, float]:
    if not values:
        return (0, 0, 0.0)
    total = sum(values)
    count = len(values)
    return (min(values), max(values), total / count)

# Filter out zero values from a list

def filter_nonzero(values: List[int]) -> List[int]:
    return [v for v in values if v != 0]

# Main processing function using the decorator and generators

@log_execution
def process_data(lines: Iterable[str]) -> List[int]:
    processed: List[int] = []
    buffer: List[int] = []
    chunk_size = 200
    for chunk in _chunk_lines(lines, chunk_size):
        for num in _process_chunk(chunk):
            buffer.append(num)
            if len(buffer) >= 100:
                processed.extend(buffer)
                buffer.clear()
    if buffer:
        processed.extend(buffer)
    # Remove zeros and compute stats
    cleaned = filter_nonzero(processed)
    min_val, max_val, avg_val = compute_stats(cleaned)
    print(f"Processed {len(processed)} items, cleaned to {len(cleaned)} items.")
    print(f"Stats -> min: {min_val}, max: {max_val}, avg: {avg_val:.2f}")
    return cleaned

# Function to write results to a file using contextlib for redirection

def write_results(output_path: str, data: List[int]) -> None:
    with contextlib.redirect_stdout(open(output_path, 'w')):
        for idx, val in enumerate(data, 1):
            print(f"{idx}: {val}")

# Entry point that ties everything together

def main(file_path: str, output_path: str) -> None:
    lines = read_file(file_path)
    processed = process_data(lines)
    write_results(output_path, processed)

# If this module is run directly, execute main with sample paths

if __name__ == "__main__":
    import sys
    if len(sys.argv) != 3:
        print("Usage: python script.py <input_file> <output_file>")
        sys.exit(1)
    input_file, output_file = sys.argv[1], sys.argv[2]
    main(input_file, output_file)

