def stream_processor(data_source, *, filter_func=None, transform_func=None, max_items=None, batch_size=100):
    from contextlib import contextmanager
    import sys

    @contextmanager
    def _log_context(name):
        print(f\"[{name}] start\")
        try:
            yield
        finally:
            print(f\"[{name}] end\")

    def _log_call(func):
        def wrapper(*args, **kwargs):
            print(f\"Calling {func.__name__} with args={args} kwargs={kwargs}\")
            result = func(*args, **kwargs)
            print(f\"{func.__name__} returned {result}\")
            return result
        return wrapper

    @ _log_call
    def _filter(item):
        if filter_func is None:
            return True
        try:
            return filter_func(item)
        except Exception as e:
            print(f\"Filter error: {e}\", file=sys.stderr)
            return False

    @ _log_call
    def _transform(item):
        if transform_func is None:
            return item
        try:
            return transform_func(item)
        except Exception as e:
            print(f\"Transform error: {e}\", file=sys.stderr)
            return item

    def _batch(iterable, size):
        it = iter(iterable)
        while True:
            batch = []
            try:
                for _ in range(size):
                    batch.append(next(it))
            except StopIteration:
                if batch:
                    yield batch
                break
            yield batch

    processed_count = 0
    for batch in _batch(data_source, batch_size):
        for raw in batch:
            if not _filter(raw):
                continue
            transformed = _transform(raw)
            yield transformed
            processed_count += 1
            if max_items is not None and processed_count >= max_items:
                with _log_context(\"early_termination\"):
                    print(f\"Reached max_items: {max_items}\")
                return

    with _log_context(\"finalization\"):
        print(f\"Total processed: {processed_count}\")

