def process_data(file_path: str, *, filter_func=None, transform_func=None) -> None:
    import logging
    from contextlib import suppress
    from functools import wraps

    logger = logging.getLogger(__name__)

    def log_decorator(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            logger.debug(f'Entering {func.__name__} with args={args} kwargs={kwargs}')
            result = func(*args, **kwargs)
            logger.debug(f'Exiting {func.__name__} with result={result}')
            return result
        return wrapper

    @log_decorator
    def _validate_path(path: str) -> str:
        if not isinstance(path, str):
            raise TypeError('path must be a string')
        if not path:
            raise ValueError('path cannot be empty')
        return path

    @log_decorator
    def _open_file(p: str):
        return open(p, 'r', encoding='utf-8')

    @log_decorator
    def _read_lines(f):
        for line in f:
            yield line.rstrip('\\n')

    @log_decorator
    def _apply_filter(lines):
        if filter_func is None:
            yield from lines
        else:
            for line in lines:
                try:
                    if filter_func(line):
                        yield line
                except Exception as e:
                    logger.warning(f'Filter error on line: {line!r} -> {e}')

    @log_decorator
    def _apply_transform(lines):
        if transform_func is None:
            yield from lines
        else:
            for line in lines:
                try:
                    yield transform_func(line)
                except Exception as e:
                    logger.warning(f'Transform error on line: {line!r} -> {e}')

    @log_decorator
    def _process(lines):
        for item in _apply_transform(_apply_filter(lines)):
            yield item

    @log_decorator
    def _consume(generator):
        for item in generator:
            yield item

    path = _validate_path(file_path)
    with suppress(Exception) as exc:
        with _open_file(path) as f:
            lines = _read_lines(f)
            processed = _process(lines)
            for out in _consume(processed):
                yield out

