from typing import Any, Dict, Iterable, List

def log_calls(func):
    def wrapper(*args, **kwargs):
        print(f"Calling {func.__name__} with args={args} kwargs={kwargs}")
        result = func(*args, **kwargs)
        print(f"{func.__name__} returned {result}")
        return result
    return wrapper

@log_calls
def process_files(
    file_paths: List[str],
    patterns: List[str],
    case_sensitive: bool = False,
    max_per_file: int = 5,
) -> Dict[str, List[str]]:
    import re
    from contextlib import ExitStack

    if not isinstance(file_paths, list) or not all(isinstance(p, str) for p in file_paths):
        raise ValueError("file_paths must be a list of strings")
    if not isinstance(patterns, list) or not all(isinstance(p, str) for p in patterns):
        raise ValueError("patterns must be a list of strings")
    if not isinstance(case_sensitive, bool):
        raise ValueError("case_sensitive must be bool")
    if not isinstance(max_per_file, int) or max_per_file <= 0:
        raise ValueError("max_per_file must be positive int")

    flags = 0 if case_sensitive else re.IGNORECASE
    compiled_patterns = [re.compile(p, flags) for p in patterns]

    def _match_line(line: str) -> bool:
        for pat in compiled_patterns:
            if pat.search(line):
                return True
        return False

    def _line_generator(file_obj: Any) -> Iterable[str]:
        for raw in file_obj:
            yield raw.rstrip('\n')

    results: Dict[str, List[str]] = {}
    with ExitStack() as stack:
        files = [stack.enter_context(open(fp, 'r', encoding='utf-8')) for fp in file_paths]
        for fp, fobj in zip(file_paths, files):
            matches: List[str] = []
            for line in _line_generator(fobj):
                if _match_line(line):
                    matches.append(line)
                    if len(matches) >= max_per_file:
                        break
            results[fp] = matches
    return results

