def process_items(
    data_iterable,
    output_path=None,
    filter_func=None,
    transform_func=None,
    max_items=None,
):
    import contextlib
    import logging
    import os
    from typing import Any, Dict, Iterable, List, Optional

    logging.basicConfig(
        level=logging.INFO,
        format='%(asctime)s %(levelname)s:%(message)s',
    )

    def log_execution(fn):
        def wrapper(*args, **kwargs):
            logging.info(f"Starting {fn.__name__}")
            try:
                result = fn(*args, **kwargs)
                logging.info(f"Finished {fn.__name__}")
                return result
            except Exception as e:
                logging.exception(f"Error in {fn.__name__}")
                raise
        return wrapper

    def validate_item(item: Any) -> bool:
        if item is None:
            return False
        if isinstance(item, str) and not item.strip():
            return False
        return True

    def handle_error(item: Any, exc: Exception) -> None:
        logging.warning(f"Skipping item {item!r} due to error: {exc}")

    def compute_stats(items: List[Any]) -> Dict[str, Any]:
        total = len(items)
        unique = len(set(items))
        return {
            "total": total,
            "unique": unique,
            "duplicate_ratio": (total - unique) / total if total else 0,
        }

    def dedupe(items: List[Any]) -> List[Any]:
        seen = set()
        unique_items = []
        for itm in items:
            if itm not in seen:
                seen.add(itm)
                unique_items.append(itm)
        return unique_items

    @log_execution
    def _generator() -> Iterable[Any]:
        count = 0
        for raw in data_iterable:
            if not validate_item(raw):
                continue
            if filter_func and not filter_func(raw):
                continue
            try:
                item = transform_func(raw) if transform_func else raw
            except Exception as e:
                handle_error(raw, e)
                continue
            yield item
            count += 1
            if max_items and count >= max_items:
                break

    processed_items: List[Any] = []
    with contextlib.ExitStack() as stack:
        out_file = None
        if output_path:
            try:
                out_file = open(output_path, 'w', encoding='utf-8')
                stack.enter_context(out_file)
            except Exception as e:
                logging.error(f"Failed to open output file {output_path}: {e}")
                raise
        for itm in _generator():
            processed_items.append(itm)
            if out_file:
                try:
                    out_file.write(f"{itm}\n")
                except Exception as e:
                    logging.error(f"Failed to write item {itm!r}: {e}")
        stats = compute_stats(processed_items)
        unique_items = dedupe(processed_items)
        if out_file:
            try:
                out_file.write("\n--- Stats ---\n")
                for k, v in stats.items():
                    out_file.write(f"{k}: {v}\n")
                out_file.write("\n--- Unique Items ---\n")
                for u in unique_items:
                    out_file.write(f"{u}\n")
            except Exception as e:
                logging.error(f"Failed to write stats: {e}")
    result = {
        "total_processed": len(processed_items),
        "unique_count": len(unique_items),
        "stats": stats,
        "output_path": output_path,
    }
    return result

