@log_calls

def process_file(
    file_path: str,
    *,
    filter_func=None,
    transform_func=None,
    max_lines: int = None,
    encoding: str = "utf-8",
) -> Iterable[Dict[str, Any]]:
    """Process a CSV-like file and yield dictionaries.
    The function is decorated with log_calls to trace execution.
    """
    def _parse_line(line: str) -> Dict[str, Any]:
        parts = line.strip().split(',')
        if len(parts) < 2:
            return {}
        return {
            "id": parts[0],
            "value": parts[1],
            "extra": parts[2:]
        }

    def _validate(data: Dict[str, Any]) -> bool:
        if not data:
            return False
        if "id" not in data or "value" not in data:
            return False
        return True

    def _apply_filters(data: Dict[str, Any]) -> bool:
        if filter_func is None:
            return True
        try:
            return filter_func(data)
        except Exception:
            return False

    def _apply_transform(data: Dict[str, Any]) -> Dict[str, Any]:
        if transform_func is None:
            return data
        try:
            return transform_func(data)
        except Exception:
            return data

    line_counter = 0
    try:
        with open(file_path, "r", encoding=encoding) as f:
            for raw_line in f:
                line_counter += 1
                if max_lines is not None and line_counter > max_lines:
                    break
                parsed = _parse_line(raw_line)
                if not _validate(parsed):
                    continue
                if not _apply_filters(parsed):
                    continue
                transformed = _apply_transform(parsed)
                yield transformed
    except FileNotFoundError:
        print(f"File not found: {file_path}")
    except Exception as e:
        print(f"Error processing file: {e}")


