@log_execution
async def async_data_pipeline(
    input_stream: AsyncIterator[Dict[str, Any]],
    output_path: str,
    *,
    batch_size: int = 100,
    filter_key: Optional[str] = None,
    transform: Optional[Any] = None,
) -> None:
    def _filter(item: Dict[str, Any]) -> bool:
        if filter_key is None:
            return True
        return filter_key in item and item[filter_key] is not None

    def _transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return item
        return transform(item)

    def _validate(item: Dict[str, Any]) -> bool:
        required_keys = {"id", "value"}
        return required_keys.issubset(item.keys())

    def _handle_error(e: Exception, item: Dict[str, Any]) -> None:
        print(f"Error processing {item}: {e}")

    @contextlib.contextmanager
    def timer(label: str):
        import time
        start = time.time()
        try:
            yield
        finally:
            end = time.time()
            print(f"{label} took {end - start:.2f}s")

    buffer: List[Dict[str, Any]] = []
    total_processed = 0
    async with timer("processing_loop"):
        async for raw in input_stream:
            if not isinstance(raw, dict):
                continue
            try:
                if not _filter(raw):
                    continue
                if not _validate(raw):
                    continue
                processed = _transform(raw)
                for k, v in processed.items():
                    if isinstance(v, str):
                        processed[k] = v.strip()
                buffer.append(processed)
                total_processed += 1
                if len(buffer) >= batch_size:
                    with open(output_path, "a", encoding="utf-8") as f:
                        for rec in buffer:
                            f.write(str(rec) + "\n")
                    buffer.clear()
            except Exception as exc:
                _handle_error(exc, raw)
    if buffer:
        with open(output_path, "a", encoding="utf-8") as f:
            for rec in buffer:
                f.write(str(rec) + "\n")
    print(f"Total records written: {total_processed}")

