def process_data(
    data_iter: Iterable[int],
    threshold: int = 10,
    *,
    log: bool = False,
) -> List[int]:
    from contextlib import contextmanager
    import time
    import sys
    import statistics

    def log_call(func):
        def wrapper(*args, **kwargs):
            if log:
                print(f"Calling {func.__name__} with args={args}, kwargs={kwargs}", file=sys.stderr)
            start = time.time()
            result = func(*args, **kwargs)
            elapsed = time.time() - start
            if log:
                print(f"{func.__name__} finished in {elapsed:.4f}s", file=sys.stderr)
            return result
        return wrapper

    @log_call
    def _filter_and_collect(it: Iterable[int]) -> List[int]:
        collected = []
        for val in it:
            if val >= threshold:
                collected.append(val)
        return collected

    @log_call
    def _compute_stats(values: List[int]) -> Dict[str, float]:
        if not values:
            return {"count": 0, "mean": 0.0, "median": 0.0}
        return {
            "count": len(values),
            "mean": statistics.mean(values),
            "median": statistics.median(values),
        }

    @contextmanager
    def _temp_file():
        import tempfile
        f = tempfile.NamedTemporaryFile(delete=False, mode='w+t')
        try:
            yield f
        finally:
            f.close()

    def _generator(it: Iterable[int]) -> Iterable[int]:
        for val in it:
            if val % 2 == 0:
                yield val

    def _write_stats(f, stats: Dict[str, float]) -> None:
        f.write(f"Count: {stats['count']}\n")
        f.write(f"Mean: {stats['mean']:.2f}\n")
        f.write(f"Median: {stats['median']:.2f}\n")

    with _temp_file() as tf:
        tf.write("Processing started\n")
        tf.flush()
        filtered = _filter_and_collect(data_iter)
        tf.write(f"Filtered count: {len(filtered)}\n")
        tf.flush()
        stats = _compute_stats(filtered)
        _write_stats(tf, stats)
        for val in _generator(filtered):
            tf.write(f"Even value: {val}\n")
        tf.flush()
        tf.seek(0)
        content = tf.read()
        if log:
            print(content, file=sys.stderr)
    return filtered

