import functools
import contextlib


def trace(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f'TRACE: {func.__name__} called')
        result = func(*args, **kwargs)
        print(f'TRACE: {func.__name__} finished')
        return result
    return wrapper


@trace
def process_records(records, key, threshold=5):
    def _validate(record):
        if not isinstance(record, dict):
            return False
        if key not in record:
            return False
        return True

    def _transform(record):
        val = record[key]
        if isinstance(val, (int, float)):
            return val * 2
        try:
            return float(val) * 2
        except Exception:
            return None

    def _format(item):
        return f'{item[\'original\']} -> {item[\'transformed\']}'

    def _stats():
        count = 0
        total = 0
        for rec in records:
            if not _validate(rec):
                continue
            transformed = _transform(rec)
            if transformed is None:
                continue
            if transformed > threshold:
                count += 1
                total += transformed
        avg = total / count if count else 0
        return {'count': count, 'average': avg}

    def _generator():
        for rec in records:
            if not _validate(rec):
                continue
            transformed = _transform(rec)
            if transformed is None:
                continue
            if transformed > threshold:
                yield {'original': rec, 'transformed': transformed}

    stats = _stats()

    with open('process.log', 'a') as log_file:
        with contextlib.redirect_stdout(log_file):
            for item in _generator():
                formatted = _format(item)
                print(formatted)
                yield item

    # After yielding all items, yield stats as final output
    yield {'stats': stats}

