def process_items(items: Iterable[Dict[str, Any]], filter_key: str, threshold: int) -> Iterable[Dict[str, Any]]:
    import logging
    from typing import Iterable, Dict, Any, Iterator
    from contextlib import contextmanager

    logging.basicConfig(level=logging.INFO, format='%(asctime)s - %(levelname)s - %(message)s')
    logger = logging.getLogger('process_items')

    @contextmanager
    def file_log(name: str):
        fh = logging.FileHandler(f'{name}.log')
        fh.setLevel(logging.INFO)
        formatter = logging.Formatter('%(asctime)s - %(levelname)s - %(message)s')
        fh.setFormatter(formatter)
        logger.addHandler(fh)
        try:
            yield
        finally:
            logger.removeHandler(fh)
            fh.close()

    def log_call(func):
        def wrapper(*args, **kwargs):
            logger.info(f'Entering {func.__name__}')
            result = func(*args, **kwargs)
            logger.info(f'Exiting {func.__name__}')
            return result
        return wrapper

    def validate(item: Dict[str, Any]) -> bool:
        if not isinstance(item, dict):
            return False
        if filter_key not in item:
            return False
        val = item.get(filter_key)
        if not isinstance(val, int):
            return False
        return True

    def transform(item: Dict[str, Any]) -> Dict[str, Any]:
        new_item = dict(item)
        new_item['processed'] = True
        new_item['value'] = item[filter_key] * 2
        return new_item

    def chunk(iterable: Iterable[Any], size: int) -> Iterator[List[Any]]:
        chunk = []
        for element in iterable:
            chunk.append(element)
            if len(chunk) == size:
                yield chunk
                chunk = []
        if chunk:
            yield chunk

    @log_call
    def generator() -> Iterable[Dict[str, Any]]:
        with file_log('process_items'):
            logger.info('Starting generator')
            count = 0
            for idx, item in enumerate(items):
                if not validate(item):
                    logger.warning(f'Item {idx} failed validation')
                    continue
                if item[filter_key] < threshold:
                    logger.debug(f'Item {idx} below threshold')
                    continue
                transformed = transform(item)
                logger.info(f'Yielding item {idx}')
                yield transformed
                count += 1
                if count % 10 == 0:
                    logger.info(f'Processed {count} items')
            logger.info('Generator finished')

    return generator()

