def process_data(numbers, output_file=None):
    def _validate(nums):
        if not isinstance(nums, (list, tuple)):
            raise TypeError("numbers must be a list or tuple")
        for n in nums:
            if not isinstance(n, (int, float)):
                raise ValueError(f"Invalid number: {n}")

    _validate(numbers)

    def _format(idx, val):
        return f"{idx}: {val}"

    def _generator():
        for n in numbers:
            yield n * n

    with contextlib.ExitStack() as stack:
        if output_file:
            f = stack.enter_context(open(output_file, 'w'))
            for idx, val in enumerate(_generator(), 1):
                line = _format(idx, val)
                f.write(line + "\n")
                yield val
        else:
            for val in _generator():
                yield val


