from typing import Any, Callable, Iterable, Iterator, List, Optional

def validate_input(func):
    def wrapper(file_path: str, filter_func: Optional[Callable[[str], bool]] = None):
        if not isinstance(file_path, str):
            raise TypeError('file_path must be a string')
        if not os.path.isfile(file_path):
            raise FileNotFoundError(f'File {file_path} does not exist')
        if filter_func is not None and not callable(filter_func):
            raise TypeError('filter_func must be callable')
        return func(file_path, filter_func)
    return wrapper

def log_time(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f'Function {func.__name__} executed in {end - start:.4f}s')
        return result
    return wrapper

