def process_data(file_path: str, filter_func: Optional[Callable[[str], bool]] = None) -> List[str]:
    def read_lines() -> Iterator[str]:
        with contextlib.closing(open(file_path, 'r', encoding='utf-8')) as f:
            for line in f:
                yield line
    def clean_line(line: str) -> str:
        return line.strip().lower()
    def chunk_lines(lines: Iterable[str], size: int = 1000) -> Iterator[List[str]]:
        chunk: List[str] = []
        for line in lines:
            chunk.append(line)
            if len(chunk) >= size:
                yield chunk
                chunk = []
        if chunk:
            yield chunk
    def process_chunk(chunk: List[str]) -> List[str]:
        processed: List[str] = []
        for line in chunk:
            cleaned = clean_line(line)
            if filter_func is None or filter_func(cleaned):
                processed.append(cleaned)
        return processed
    all_results: List[str] = []
    for chunk in chunk_lines(read_lines()):
        processed = process_chunk(chunk)
        all_results.extend(processed)
    return all_results

