import contextlib
from typing import Iterable, Iterator, Dict, Any, List, Set, Optional

def log_calls(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f"Entering {func.__name__}")
        result = func(*args, **kwargs)
        print(f"Exiting {func.__name__}")
        return result
    return wrapper

@log_calls
def process_records(
    records: Iterable[Dict[str, Any]],
    required_fields: Iterable[str],
    defaults: Optional[Dict[str, Any]] = None,
    batch_size: int = 10,
) -> Iterator[Dict[str, Any]]:
    required: Set[str] = set(required_fields)
    defaults = defaults or {}
    def _normalize_value(val: Any) -> Any:
        if isinstance(val, str):
            return val.strip()
        return val
    def _validate_record(rec: Dict[str, Any]) -> bool:
        if not isinstance(rec, dict):
            return False
        missing = required - rec.keys()
        if missing:
            return False
        return True
    def _clean_record(rec: Dict[str, Any]) -> Dict[str, Any]:
        cleaned: Dict[str, Any] = {}
        for k, v in rec.items():
            cleaned[k] = _normalize_value(v)
        return cleaned
    def _apply_defaults(rec: Dict[str, Any]) -> Dict[str, Any]:
        for k, v in defaults.items():
            rec.setdefault(k, v)
        return rec
    def _batch_generator() -> Iterator[List[Dict[str, Any]]]:
        batch: List[Dict[str, Any]] = []
        for rec in records:
            try:
                if not _validate_record(rec):
                    continue
                cleaned = _clean_record(rec)
                cleaned = _apply_defaults(cleaned)
                batch.append(cleaned)
                if len(batch) >= batch_size:
                    yield batch
                    batch = []
            except Exception:
                continue
        if batch:
            yield batch
    with contextlib.ExitStack() as stack:
        for batch in _batch_generator():
            for rec in batch:
                yield rec

