import time
from contextlib import contextmanager
from typing import Callable, Iterable, Iterator, Optional

# Decorator to log execution time of functions

def timed(func: Callable) -> Callable:
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"{func.__name__} executed in {end - start:.4f}s")
        return result
    return wrapper

# Context manager for timed blocks

@contextmanager
def timed_block(name: str):
    start = time.time()
    try:
        yield
    finally:
        end = time.time()
        print(f"{name} block took {end - start:.4f}s")

# Main processing function

@timed
def process_data(
    input_path: str,
    output_path: str,
    filter_func: Optional[Callable[[str], bool]] = None,
    chunk_size: int = 1024,
) -> None:
    # Open files safely
    @contextmanager
    def open_file(path: str, mode: str):
        f = open(path, mode)
        try:
            yield f
        finally:
            f.close()

    # Generator to read file in chunks
    def read_chunks(f) -> Iterator[str]:
        buffer = ''
        while True:
            data = f.read(chunk_size)
            if not data:
                if buffer:
                    yield buffer
                break
            buffer += data
            while '\n' in buffer:
                line, buffer = buffer.split('\n', 1)
                yield line
        if buffer:
            yield buffer

    # Validate and transform a line
    def process_line(line: str) -> Optional[str]:
        if filter_func and not filter_func(line):
            return None
        cleaned = line.strip()
        if not cleaned:
            return None
        return cleaned.upper()

    # Generator to process lines lazily
    def process_lines(lines: Iterable[str]) -> Iterator[str]:
        for l in lines:
            res = process_line(l)
            if res is not None:
                yield res

    # Write processed lines to output
    def write_lines(f, lines: Iterable[str]):
        for l in lines:
            f.write(l + '\n')

    # Main logic with nested context managers
    with open_file(input_path, 'r') as fin, open_file(output_path, 'w') as fout:
        with timed_block("reading and processing"):
            raw_lines = read_chunks(fin)
            processed = process_lines(raw_lines)
        with timed_block("writing output"):
            write_lines(fout, processed)

    # Final report
    print("Processing complete.")

