async def process_streams(streams: List[Awaitable[Any]], max_items: int, timeout: Optional[float] = None, filter_func: Optional[Callable[[Any], bool]] = None, progress_callback: Optional[Callable[[int], None]] = None) -> AsyncIterator[Any]:
    from contextlib import asynccontextmanager
    import asyncio
    from typing import Any, Awaitable, Callable, List, Optional

    # Validate inputs
    if not isinstance(streams, list):
        raise TypeError("streams must be a list")
    for s in streams:
        if not hasattr(s, "__aiter__"):
            raise TypeError("each stream must be async iterable")
    if not isinstance(max_items, int) or max_items <= 0:
        raise ValueError("max_items must be a positive integer")

    # Context manager to enforce timeout
    @asynccontextmanager
    async def _timeout_manager():
        if timeout is not None:
            try:
                yield
            except asyncio.TimeoutError:
                raise
        else:
            yield

    # Helper to fetch from a single stream
    async def _fetch_from(stream: Awaitable[Any], buffer: List[Any]) -> None:
        async for item in stream:
            buffer.append(item)
            if len(buffer) >= max_items:
                break

    # Helper to apply filter
    def _apply_filter(item: Any) -> bool:
        if filter_func is None:
            return True
        try:
            return filter_func(item)
        except Exception:
            return False

    buffers: List[List[Any]] = [[] for _ in streams]
    tasks: List[asyncio.Task] = [asyncio.create_task(_fetch_from(s, b)) for s, b in zip(streams, buffers)]

    yielded = 0

    try:
        async with _timeout_manager():
            while any(b for b in buffers) or any(not t.done() for t in tasks):
                for i, buffer in enumerate(buffers):
                    if buffer:
                        item = buffer.pop(0)
                        if _apply_filter(item):
                            yield item
                            yielded += 1
                            if progress_callback:
                                try:
                                    progress_callback(yielded)
                                except Exception:
                                    pass
                            if yielded >= max_items:
                                return
                await asyncio.sleep(0)
    finally:
        for t in tasks:
            t.cancel()
        await asyncio.gather(*tasks, return_exceptions=True)

