import contextlib
from typing import Iterable, Iterator, List, Tuple, Callable, Any

def log_call(func: Callable) -> Callable:
    def wrapper(*args: Any, **kwargs: Any) -> Any:
        print(f"Calling {func.__name__} with args={args} kwargs={kwargs}")
        result = func(*args, **kwargs)
        print(f"{func.__name__} returned {result}")
        return result
    return wrapper

@log_call
def process_numbers(limit: int, factor: float) -> List[int]:
    def number_generator() -> Iterator[int]:
        n = 0
        while n < limit:
            yield n
            n += 1

    def transform(nums: Iterable[int]) -> Iterator[int]:
        for num in nums:
            yield int(num * factor)

    def filter_even(nums: Iterable[int]) -> Iterator[int]:
        for num in nums:
            if num % 2 == 0:
                yield num

    @contextlib.contextmanager
    def timing(name: str):
        start = time.time()
        yield
        end = time.time()
        print(f"{name} took {end - start:.4f}s")

    def accumulate(nums: Iterable[int]) -> List[int]:
        acc = []
        for num in nums:
            acc.append(num)
        return acc

    with timing("number_generation"):
        numbers = number_generator()

    with timing("transformation"):
        transformed = transform(numbers)

    with timing("filtering"):
        evens = filter_even(transformed)

    with timing("accumulation"):
        result = accumulate(evens)

    return result

