from typing import Callable, Iterable, Optional, List

def log_calls(func):
    def wrapper(*args, **kwargs):
        print(f'Entering {func.__name__} with args={args} kwargs={kwargs}')
        result = func(*args, **kwargs)
        print(f'Exiting {func.__name__}')
        return result
    return wrapper

@log_calls
def process_file_lines(
    file_path: str,
    filter_func: Optional[Callable[[str], bool]] = None,
    batch_size: int = 10,
    skip_comments: bool = True,
) -> Iterable[List[str]]:
    def _validate_path(path: str) -> None:
        if not isinstance(path, str) or not path:
            raise ValueError('file_path must be a non-empty string')
        if not path.endswith('.txt'):
            raise ValueError('Only .txt files are supported')

    def _validate_batch(size: int) -> None:
        if not isinstance(size, int) or size <= 0:
            raise ValueError('batch_size must be a positive integer')

    def _process_line(line: str) -> str:
        cleaned = line.strip()
        if not cleaned:
            return ''
        if len(cleaned) > 200:
            cleaned = cleaned[:200]
        return cleaned

    def _is_comment(line: str) -> bool:
        return line.startswith('#')

    def _chunk(lines: Iterable[str], size: int) -> Iterable[List[str]]:
        chunk: List[str] = []
        for line in lines:
            chunk.append(line)
            if len(chunk) == size:
                yield chunk
                chunk = []
        if chunk:
            yield chunk

    _validate_path(file_path)
    _validate_batch(batch_size)

    with contextlib.closing(open(file_path, 'r', encoding='utf-8')) as f:
        processed_lines: List[str] = []
        for raw_line in f:
            if skip_comments and _is_comment(raw_line):
                continue
            processed = _process_line(raw_line)
            if not processed:
                continue
            if filter_func and not filter_func(processed):
                continue
            processed_lines.append(processed)
            if len(processed_lines) == batch_size:
                yield processed_lines
                processed_lines = []
        if processed_lines:
            yield processed_lines

