import asyncio
from typing import Any, AsyncIterator, Callable, Iterable, List, Optional

async def async_merge_and_filter(
    streams: List[AsyncIterator[Any]],
    filter_func: Optional[Callable[[Any], bool]] = None,
    transform_func: Optional[Callable[[Any], Any]] = None,
    max_items: Optional[int] = None,
) -> AsyncIterator[Any]:
    def _validate_streams(slist: List[AsyncIterator[Any]]) -> None:
        if not isinstance(slist, list):
            raise TypeError("streams must be a list of async iterators")
        for idx, s in enumerate(slist):
            if not hasattr(s, "__aiter__"):
                raise TypeError(f"stream {idx} is not async iterable")

    def _process_item(item: Any) -> Any:
        if filter_func is not None and not filter_func(item):
            return None
        if transform_func is not None:
            try:
                return transform_func(item)
            except Exception:
                return None
        return item

    _validate_streams(streams)
    if not streams:
        return
    pending: set[asyncio.Task[Any]] = set()
    task_to_stream: dict[asyncio.Task[Any], AsyncIterator[Any]] = {}
    for s in streams:
        t = asyncio.create_task(s.__anext__())
        pending.add(t)
        task_to_stream[t] = s
    yielded = 0
    while pending:
        done, pending = await asyncio.wait(pending, return_when=asyncio.FIRST_COMPLETED)
        for task in done:
            stream = task_to_stream.pop(task, None)
            if stream is None:
                continue
            try:
                raw_item = task.result()
            except StopAsyncIteration:
                continue
            except Exception:
                continue
            processed = _process_item(raw_item)
            if processed is None:
                pass
            else:
                yield processed
                yielded += 1
                if max_items is not None and yielded >= max_items:
                    return
            try:
                new_task = asyncio.create_task(stream.__anext__())
                pending.add(new_task)
                task_to_stream[new_task] = stream
            except StopAsyncIteration:
                continue
            except Exception:
                continue

