def process_text_files(file_paths: list[str], filter_func: callable) -> dict:
    import os
    import time
    from contextlib import ExitStack
    from typing import List, Dict, Any, Callable, Iterator

    def log_execution(func: Callable) -> Callable:
        def wrapper(*args, **kwargs):
            start = time.time()
            print(f"Starting {func.__name__} with args={args} kwargs={kwargs}")
            result = func(*args, **kwargs)
            end = time.time()
            print(f"Finished {func.__name__} in {end-start:.2f}s")
            return result
        return wrapper

    @log_execution
    def _inner(file_paths: List[str], filter_func: Callable[[str], bool]) -> Dict[str, Any]:
        stats: Dict[str, Any] = {
            "total_files": len(file_paths),
            "total_lines": 0,
            "filtered_lines": 0,
            "file_stats": {},
            "word_counts": {},
        }

        def _read_lines(file_path: str) -> Iterator[str]:
            with open(file_path, 'r', encoding='utf-8') as f:
                for line in f:
                    yield line.rstrip('\n')

        def _yield_words(line: str) -> Iterator[str]:
            for word in line.split():
                yield word.strip(".,!?:;()[]{}'\"\n\r\t").lower()

        def _count_words(lines: Iterator[str]) -> Dict[str, int]:
            counts: Dict[str, int] = {}
            for line in lines:
                for word in _yield_words(line):
                    if word:
                        counts[word] = counts.get(word, 0) + 1
            return counts

        def _merge_counts(total: Dict[str, int], part: Dict[str, int]) -> None:
            for k, v in part.items():
                total[k] = total.get(k, 0) + v

        with ExitStack() as stack:
            files = [stack.enter_context(open(fp, 'r', encoding='utf-8')) for fp in file_paths]
            for fp, f in zip(file_paths, files):
                file_stats: Dict[str, Any] = {"lines": 0, "filtered": 0}
                word_counts: Dict[str, int] = {}
                for line in _read_lines(fp):
                    file_stats["lines"] += 1
                    stats["total_lines"] += 1
                    if filter_func(line):
                        file_stats["filtered"] += 1
                        stats["filtered_lines"] += 1
                    word_counts.update(_count_words([line]))
                _merge_counts(stats["word_counts"], word_counts)
                stats["file_stats"][fp] = file_stats

        return stats

    return _inner(file_paths, filter_func)

