def process_data(input_path: str, output_path: str, *, threshold: float = 0.5) -> dict:
    import json
    import logging
    from contextlib import contextmanager
    from typing import Any, Dict, Generator, Iterable, List

    logger = logging.getLogger(__name__)
    logger.setLevel(logging.INFO)

    @contextmanager
    def open_file(path: str, mode: str = 'r'):
        f = open(path, mode, encoding='utf-8')
        try:
            yield f
        finally:
            f.close()

    def log_call(func):
        def wrapper(*args, **kwargs):
            logger.info(f"Calling {func.__name__} with args={args} kwargs={kwargs}")
            result = func(*args, **kwargs)
            logger.info(f"{func.__name__} returned {result}")
            return result
        return wrapper

    @log_call
    def _filter_items(items: Iterable[Dict[str, Any]]) -> Generator[Dict[str, Any], None, None]:
        for item in items:
            score = item.get('score')
            if isinstance(score, (int, float)) and score >= threshold:
                yield item

    def _parse_line(line: str) -> Dict[str, Any]:
        try:
            return json.loads(line)
        except json.JSONDecodeError:
            logger.warning(f"Failed to parse line: {line!r}")
            return {}

    def _read_input() -> Iterable[Dict[str, Any]]:
        with open_file(input_path, 'r') as f:
            for line in f:
                yield _parse_line(line)

    def _write_output(items: Iterable[Dict[str, Any]]) -> None:
        with open_file(output_path, 'w') as f:
            for item in items:
                f.write(json.dumps(item) + '\n')

    total_items = 0
    parsed_items: List[Dict[str, Any]] = []
    for itm in _read_input():
        total_items += 1
        parsed_items.append(itm)

    filtered_items = list(_filter_items(parsed_items))

    _write_output(filtered_items)

    summary: Dict[str, Any] = {
        'total_items': total_items,
        'filtered_items': len(filtered_items),
        'threshold': threshold,
    }
    return summary

