    import contextlib
    def validate_record(rec):
        if not isinstance(rec, dict):
            return False
        if 'id' not in rec or 'value' not in rec:
            return False
        if not isinstance(rec['id'], int):
            return False
        if not isinstance(rec['value'], (int, float)):
            return False
        return True
    def record_generator():
