        rec_copy = dict(rec)
        rec_copy['value'] = rec_copy['value'] * 2
        return rec_copy
    def filter_by_threshold(rec):
        return rec['value'] > threshold
    def write_temp(records):
        with open(temp_path, 'w', encoding='utf-8') as f:
            for rec in records:
                f.write(json.dumps(rec) + '\\n')
    def read_temp():
        with open(temp_path, 'r', encoding='utf-8') as f:
            for line in f:
                yield json.loads(line)
    def aggregate(records):
        total = 0
        count = 0
        for rec in records:
            total += rec['value']
            count += 1
        return {'count': count, 'total': total}
    with contextlib.ExitStack() as stack:
        stack.enter_context(open(temp_path, 'w'))
        transformed = (transform(r) for r in record_generator())
        filtered = (r for r in transformed if filter_by_threshold(r))
        write_temp(filtered)
        aggregated = aggregate(read_temp())
    if os.path.exists(temp_path):
        os.remove(temp_path)
    return aggregated

