def process_csv(file_path: str, filter_value: str, max_rows: int = 100) -> list:
    from contextlib import contextmanager
    import csv
    from typing import Any, Dict, Iterable, List

    # Decorator to log entry and exit of processing
    def log_process(func):
        def wrapper(*args, **kwargs):
            print(f"[LOG] Entering {func.__name__} with args={args} kwargs={kwargs}")
            result = func(*args, **kwargs)
            print(f"[LOG] Exiting {func.__name__} with {len(result)} records")
            return result
        return wrapper

    # Context manager for opening files safely
    @contextmanager
    def open_file(path: str):
        f = None
        try:
            f = open(path, newline='', encoding='utf-8')
            yield f
        finally:
            if f:
                f.close()

    # Generator that yields rows from CSV
    def row_generator() -> Iterable[Dict[str, Any]]:
        with open_file(file_path) as f:
            reader = csv.DictReader(f)
            for row in reader:
                yield row

    # Helper to decide if a row passes the filter
    def filter_row(row: Dict[str, Any]) -> bool:
        status = row.get('status')
        if status is None:
            return False
        return status.strip().lower() == filter_value.strip().lower()

    # Helper to transform a raw row into cleaned data
    def transform_row(row: Dict[str, Any]) -> Dict[str, Any]:
        cleaned: Dict[str, Any] = {}
        for key, value in row.items():
            if value is None:
                continue
            val = value.strip()
            if key == 'id':
                try:
                    cleaned[key] = int(val)
                except ValueError:
                    cleaned[key] = val
            elif key == 'amount':
                try:
                    cleaned[key] = float(val)
                except ValueError:
                    cleaned[key] = 0.0
            else:
                cleaned[key] = val
        return cleaned

    # Main processing function that will be decorated
    @log_process
    def process_rows() -> List[Dict[str, Any]]:
        results: List[Dict[str, Any]] = []
        processed_count = 0
        for raw_row in row_generator():
            if not filter_row(raw_row):
                continue
            transformed = transform_row(raw_row)
            results.append(transformed)
            processed_count += 1
            if processed_count >= max_rows:
                break
        return results

    # Execute processing and return results
    return process_rows()

