@timed
def process_file(file_path: str, filter_func: Optional[Any] = None, max_items: Optional[int] = None, encoding: str = 'utf-8') -> Iterator[Tuple[int, str]]:
    @contextmanager
    def open_file(path: str):
        f = open(path, 'r', encoding=encoding)
        try:
            yield f
        finally:
            f.close()

    def _parse_line(line: str, idx: int) -> Tuple[int, str]:
        cleaned = line.strip()
        return idx, cleaned

    def _filter(item: Tuple[int, str]) -> bool:
        if filter_func is None:
            return True
        return filter_func(item[1])

    def _validate_line(line: str) -> bool:
        if not line:
            return False
        if len(line) > 10000:
            return False
        return True

    count = 0
    with open_file(file_path) as f:
        for idx, raw_line in enumerate(f):
            if not _validate_line(raw_line):
                continue
            line = raw_line.rstrip('\n')
            item = _parse_line(line, idx)
            if not _filter(item):
                continue
            yield item
            count += 1
            if max_items is not None and count >= max_items:
                break

    # After generator exhaustion, we could log summary
    print(f"Processed {count} items from {file_path}")

