import asyncio
from typing import Any, AsyncIterator, Dict, Iterable, List, Optional

async def stream_processor(
    sources: List[AsyncIterator[Dict[str, Any]]],
    key_field: str,
    transform: Optional[Any] = None,
    max_items: int = 100,
    progress_callback: Optional[Any] = None,
) -> List[Dict[str, Any]]:
    """Process multiple async streams, merge by key, apply optional transform, and collect results."""
    buffers: List[List[Dict[str, Any]]] = [[] for _ in sources]
    active: List[bool] = [True] * len(sources)
    results: List[Dict[str, Any]] = []
    seen_keys: Dict[Any, int] = {}
    total_processed = 0

    def _normalize_key(item: Dict[str, Any]) -> Any:
        val = item.get(key_field)
        if val is None:
            return None
        return str(val).strip().lower()

    def _apply_transform(item: Dict[str, Any]) -> Dict[str, Any]:
        if transform is None:
            return item
        try:
            return transform(item)
        except Exception:
            return item

    async def _consume(idx: int) -> None:
        nonlocal total_processed
        it = sources[idx]
        try:
            async for record in it:
                if not active[idx]:
                    break
                buffers[idx].append(record)
                total_processed += 1
                if progress_callback and total_processed % 20 == 0:
                    progress_callback(total_processed)
        except asyncio.CancelledError:
            raise
        except Exception:
            active[idx] = False
        finally:
            active[idx] = False

    tasks = [asyncio.create_task(_consume(i)) for i in range(len(sources))]

    try:
        while len(results) < max_items and any(active):
            progressed = False
            for i in range(len(sources)):
                if buffers[i]:
                    item = buffers[i].pop(0)
                    key = _normalize_key(item)
                    if key is None:
                        continue
                    if key in seen_keys:
                        continue
                    seen_keys[key] = 1
                    transformed = _apply_transform(item)
                    results.append(transformed)
                    progressed = True
                    if len(results) >= max_items:
                        break
            if not progressed:
                await asyncio.sleep(0)
                if not any(active) and not any(buffers):
                    break
        return results
    finally:
        for t in tasks:
            if not t.done():
                t.cancel()
        await asyncio.gather(*tasks, return_exceptions=True)

