from typing import Any, AsyncIterator, Iterable, List, Optional, Tuple
import asyncio
import heapq
import functools
import contextlib

def log_call(func):
    @functools.wraps(func)
    async def wrapper(*args, **kwargs):
        print(f"Entering {func.__name__}")
        result = await func(*args, **kwargs)
        print(f"Exiting {func.__name__}")
        return result
    return wrapper

@contextlib.asynccontextmanager
async def progress_tracker(total: int):
    seen = 0
    try:
        yield lambda inc=1: _update(seen, inc, total)
    finally:
        pass


def _update(seen: int, inc: int, total: int):
    seen += inc
    if seen % 10 == 0 or seen == total:
        print(f"Processed {seen}/{total} items")

@log_call
async def merge_sorted_async_iterators(
    iterators: List[AsyncIterator[int]],
    max_items: Optional[int] = None,
    deduplicate: bool = False,
) -> AsyncIterator[int]:
    def _validate(it: Any) -> bool:
        return hasattr(it, "__anext__") and callable(it.__anext__)

    async with contextlib.AsyncExitStack() as stack:
        async_iters: List[AsyncIterator[int]] = []
        for it in iterators:
            if not _validate(it):
                raise TypeError("All elements must be async iterators")
            async_iters.append(await stack.enter_async_context(it))

        heap: List[Tuple[int, int, AsyncIterator[int]]] = []
        for idx, it in enumerate(async_iters):
            try:
                val = await it.__anext__()
                heapq.heappush(heap, (val, idx, it))
            except StopAsyncIteration:
                continue

        seen_total = sum(1 for _ in iterators)
        async with progress_tracker(seen_total) as progress:
            count = 0
            last_yielded: Optional[int] = None
            while heap:
                val, idx, it = heapq.heappop(heap)
                if deduplicate and last_yielded is not None and val == last_yielded:
                    pass
                else:
                    yield val
                    last_yielded = val
                    count += 1
                    progress()
                if max_items is not None and count >= max_items:
                    break
                try:
                    next_val = await it.__anext__()
                    heapq.heappush(heap, (next_val, idx, it))
                except StopAsyncIteration:
                    continue

