def analyze_text_files(file_paths, min_word_len=3):
    import contextlib
    from typing import Iterable, Iterator, Dict, List, Any

    def _normalize(word: str) -> str:
        return word.strip().lower()

    def _is_valid(word: str) -> bool:
        return len(word) >= min_word_len and word.isalpha()

    def _count_words(lines: Iterable[str]) -> Dict[str, int]:
        counts: Dict[str, int] = {}
        for line in lines:
            for raw in line.split():
                w = _normalize(raw)
                if _is_valid(w):
                    counts[w] = counts.get(w, 0) + 1
        return counts

    def _file_line_generator(path: str) -> Iterator[str]:
        try:
            with contextlib.closing(open(path, 'r', encoding='utf-8')) as f:
                for raw_line in f:
                    line = raw_line.rstrip('\n')
                    if line:
                        yield line
        except FileNotFoundError:
            yield ""

    def _write_summary(summary_path: str, data: Dict[str, Any]) -> None:
        try:
            with open(summary_path, 'w', encoding='utf-8') as out:
                out.write("Overall Word Counts:\n")
                for word, count in sorted(data["overall_word_counts"].items(), key=lambda kv: (-kv[1], kv[0])):
                    out.write(f"{word}: {count}\n")
                out.write("\nTop Words:\n")
                for item in data["top_words"]:
                    out.write(f"{item['word']}: {item['count']}\n")
                out.write("\nFile Stats:\n")
                for fp, stats in data["file_stats"].items():
                    out.write(f"{fp}: {stats}\n")
        except Exception:
            pass

    overall_counts: Dict[str, int] = {}
    per_file_stats: Dict[str, Any] = {}

    for file_path in file_paths:
        lines = list(_file_line_generator(file_path))
        if not lines:
            per_file_stats[file_path] = {"lines": 0, "words": 0, "unique_words": 0, "status": "missing or empty"}
            continue
        word_counts = _count_words(lines)
        per_file_stats[file_path] = {
            "lines": len(lines),
            "words": sum(len(l.split()) for l in lines),
            "unique_words": len(word_counts),
            "status": "processed",
        }
        for w, c in word_counts.items():
            overall_counts[w] = overall_counts.get(w, 0) + c

    top_words = sorted(overall_counts.items(), key=lambda kv: (-kv[1], kv[0]))[:20]
    result = {
        "overall_word_counts": overall_counts,
        "top_words": [{"word": w, "count": c} for w, c in top_words],
        "file_stats": per_file_stats,
        "total_files": len(file_paths),
        "processed_files": sum(1 for s in per_file_stats.values() if s["status"] == "processed"),
    }

    _write_summary("summary.txt", result)
    return result

