import time


def log_calls(func):
    def wrapper(*args, **kwargs):
        print(f"Calling {func.__name__} with args={args} kwargs={kwargs}")
        result = func(*args, **kwargs)
        print(f"{func.__name__} returned {result}")
        return result
    return wrapper


@contextmanager

def timer(name):
    start = time.time()
    try:
        yield
    finally:
        elapsed = time.time() - start
        print(f"{name} took {elapsed:.4f}s")


@log_calls

def process_data(data_iterable):
    def _filter_even(nums):
        for n in nums:
            if n % 2 == 0:
                yield n

    def _square(nums):
        for n in nums:
            yield n * n

    def _chunk(nums, size):
        chunk = []
        for n in nums:
            chunk.append(n)
            if len(chunk) == size:
                yield chunk
                chunk = []
        if chunk:
            yield chunk

    def _sum_chunks(chunks):
        for chunk in chunks:
            yield sum(chunk)

    with timer("process_data"):
        evens = _filter_even(data_iterable)
        squares = _square(evens)
        chunks = _chunk(squares, 5)
        sums = _sum_chunks(chunks)
        result = list(sums)
    return result


def main():
    data = range(1, 101)
    output = process_data(data)
    print("Output:", output)


if __name__ == "__main__":
    main()

