def process_data(
    source_iterable,
    filter_func=None,
    transform_func=None,
    max_items: int | None = None,
    *,
    verbose: bool = False,
) -> Any:
    """Process items from an iterable, optionally filtering, transforming, and limiting the output.
    Returns a generator yielding processed items.
    """
    from typing import Iterable, Callable, Any
    from contextlib import ExitStack

    # --- Parameter validation -------------------------------------------------
    if not isinstance(source_iterable, Iterable):
        raise TypeError("source_iterable must be an iterable")
    if filter_func is not None and not callable(filter_func):
        raise TypeError("filter_func must be callable or None")
    if transform_func is not None and not callable(transform_func):
        raise TypeError("transform_func must be callable or None")
    if max_items is not None and (not isinstance(max_items, int) or max_items <= 0):
        raise ValueError("max_items must be a positive integer or None")

    # --- Decorator for logging execution -------------------------------------
    def log_execution(func: Callable) -> Callable:
        def wrapper(*args, **kwargs):
            if verbose:
                print(f"[LOG] Starting execution of {func.__name__}")
            result = func(*args, **kwargs)
            if verbose:
                print(f"[LOG] Finished execution of {func.__name__}")
            return result
        return wrapper

    # --- Helper to apply filter ----------------------------------------------
    def _apply_filter(item: Any) -> bool:
        if filter_func is None:
            return True
        try:
            return bool(filter_func(item))
        except Exception as exc:
            if verbose:
                print(f"[WARN] Filter raised exception on {item!r}: {exc}")
            return False

    # --- Helper to apply transform -------------------------------------------
    def _apply_transform(item: Any) -> Any:
        if transform_func is None:
            return item
        try:
            return transform_func(item)
        except Exception as exc:
            if verbose:
                print(f"[WARN] Transform raised exception on {item!r}: {exc}")
            return None

    # --- Generator that yields processed items --------------------------------
    @log_execution
    def _generator() -> Any:
        count = 0
        with ExitStack() as stack:
            # In a realistic scenario, resources could be pushed onto the stack
            # For demonstration, we simply iterate over the source iterable.
            for raw_item in source_iterable:
                if not _apply_filter(raw_item):
                    continue
                transformed = _apply_transform(raw_item)
                if transformed is None:
