    from contextlib import contextmanager

    @contextmanager
    def open_output(path: str):
        f = open(path, 'w', encoding='utf-8')
        try:
            yield f
        finally:
            f.close()

    # Helper to validate a line
    def validate_line(line: str) -> bool:
        if skip_empty and not line.strip():
            return False
        if len(line) > 10000:
            return False
        return True

    # Helper to transform a line
    def transform_line(line: str) -> str:
        words = line.split()
        # Reverse words and capitalize
        transformed = [w[::-1].capitalize() for w in words]
        return ' '.join(transformed)

    # Main processing loop
    processed_count = 0
    errors = []
    with open_output(output_path) as out_f:
        for raw_line in read_lines(input_path):
            if processed_count >= max_lines:
                break
            try:
                if not validate_line(raw_line):
                    continue
                transformed = transform_line(raw_line)
                out_f.write(transformed + '\n')
                processed_count += 1
            except Exception as e:
                errors.append({'line': raw_line, 'error': str(e)})

    result = {
        'processed': processed_count,
        'errors': errors,
        'input': input_path,
        'output': output_path,
        'max_lines': max_lines,
        'skip_empty': skip_empty,
    }
    return result

