import contextlib
import functools
import time
from typing import Iterable, List, Tuple

# Decorator to log function entry and exit

def log_call(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f"Entering {func.__name__} with args={args} kwargs={kwargs}")
        result = func(*args, **kwargs)
        print(f"Exiting {func.__name__} with result length={len(result)}")
        return result
    return wrapper

# Context manager to time code blocks

@contextlib.contextmanager
def timer(name: str):
    start = time.time()
    yield
    end = time.time()
    print(f"{name} took {end - start:.4f}s")

# Main function using decorator, generator, and context manager

@log_call
def process_data(file_path: str, threshold: int) -> List[int]:
    # Validate threshold
    if not isinstance(threshold, int):
        raise TypeError("threshold must be an integer")
    if threshold < 0:
        raise ValueError("threshold must be non-negative")

    # Inner generator to parse lines into integers
    def _parse_lines(lines: Iterable[str]) -> Iterable[int]:
        for line in lines:
            line = line.strip()
            if not line:
                continue
            try:
                num = int(line)
            except ValueError:
                continue
            yield num

    # Inner generator to yield numbers in chunks
    def _chunk_generator(nums: Iterable[int], size: int = 100) -> Iterable[List[int]]:
        chunk: List[int] = []
        for n in nums:
            chunk.append(n)
            if len(chunk) >= size:
                yield chunk
                chunk = []
        if chunk:
            yield chunk

    # Inner function to filter numbers based on threshold
    def _filter_numbers(nums: Iterable[int]) -> List[int]:
        filtered: List[int] = []
        for n in nums:
            if n >= threshold:
                filtered.append(n)
        return filtered

    # Inner function to compute statistics on a list of numbers
    def _compute_stats(nums: List[int]) -> Tuple[int, int, int]:
        if not nums:
            return (0, 0, 0)
        total = sum(nums)
        count = len(nums)
        avg = total // count
        return (total, count, avg)

    results: List[int] = []
    stats: Tuple[int, int, int] = (0, 0, 0)

    try:
        with contextlib.closing(open(file_path, 'r', encoding='utf-8')) as f:
            lines = f.readlines()
            with timer("Parsing and filtering"):
                nums = _parse_lines(lines)
                filtered = _filter_numbers(nums)
                results = filtered
                stats = _compute_stats(filtered)
    except FileNotFoundError:
        print(f"File {file_path} not found.")
    except Exception as e:
        print(f"Error processing file: {e}")

    # Additional branching: if no results, warn
    if not results:
        print("No numbers met the threshold.")

    # Print statistics
    total, count, avg = stats
    print(f"Processed {count} numbers: total={total}, average={avg}")

    return results

