from contextlib import contextmanager
import time
import functools

def log_call(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print('Entering ' + func.__name__)
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print('Exiting ' + func.__name__ + ' after ' + str(round(end-start,2)) + 's')
        return result
    return wrapper

@contextmanager
def open_file(path, mode):
    f = open(path, mode)
    try:
        yield f
    finally:
        f.close()

@log_call
def process_data_stream(input_path: str, output_path: str, chunk_size: int = 1024):
    def _validate_path(path):
        if not isinstance(path, str) or not path:
            raise ValueError('Invalid path')
        return path

    def _read_chunks(file_obj):
        while True:
            data = file_obj.read(chunk_size)
            if not data:
                break
            yield data

    def _transform(chunk):
        return chunk.upper()

    def _write_chunks(file_obj, chunks):
        for c in chunks:
            file_obj.write(c)

    def _progress_tracker(total_chunks, processed_chunks):
        if processed_chunks % 10 == 0:
            print('Processed ' + str(processed_chunks) + '/' + str(total_chunks) + ' chunks')

    input_path = _validate_path(input_path)
    output_path = _validate_path(output_path)

    with open_file(input_path, 'r') as fin, open_file(output_path, 'w') as fout:
        chunks = list(_read_chunks(fin))
        total = len(chunks)
        transformed = (_transform(c) for c in chunks)
        _write_chunks(fout, transformed)
        for i in range(total):
            _progress_tracker(total, i+1)
            yield 'Chunk ' + str(i+1) + '/' + str(total) + ' processed'
        yield 'Processing complete'

