def process_file(file_path: str, transform: callable, *, verbose: bool = False) -> List[str]:
    from contextlib import contextmanager
    import time
    import functools

    @contextmanager
    def _timed_context(name: str):
        start = time.time()
        try:
            yield
        finally:
            elapsed = time.time() - start
            if verbose:
                print(f"{name} took {elapsed:.3f}s")

    def _log_call(func):
        @functools.wraps(func)
        def wrapper(*args, **kwargs):
            if verbose:
                print(f"Calling {func.__name__} with args={args} kwargs={kwargs}")
            result = func(*args, **kwargs)
            if verbose:
                print(f"{func.__name__} returned {result}")
            return result
        return wrapper

    @_log_call
    def _read_lines() -> List[str]:
        lines = []
        with _timed_context("file read"):
            with open(file_path, 'r', encoding='utf-8') as f:
                for line in f:
                    lines.append(line.rstrip('\\n'))
        return lines

    @_log_call
    def _process(lines: List[str]) -> List[str]:
        processed = []
        for idx, line in enumerate(lines):
            if not line.strip():
                continue
            try:
                new_line = transform(line)
                if new_line is None:
                    continue
                processed.append(new_line)
            except Exception as e:
                if verbose:
                    print(f"Error processing line {idx}: {e}")
        return processed

    @_log_call
    def _generator(lines: List[str]) -> Any:
        for line in lines:
            yield line

    lines = _read_lines()
    processed_lines = _process(lines)
    result = list(_generator(processed_lines))
    return result

