    from typing import Iterable, List, Callable, Optional
    import contextlib

    def log(func):
        def wrapper(*args, **kwargs):
            print(f"Calling {func.__name__} with args={args} kwargs={kwargs}")
            result = func(*args, **kwargs)
            print(f"{func.__name__} returned {result}")
            return result
        return wrapper

    @log
    def read_lines(file_obj) -> Iterable[str]:
        for line in file_obj:
            yield line.rstrip("\n")

    @log
    def filter_lines(lines: Iterable[str]) -> Iterable[str]:
        if filter_func is None:
            for l in lines:
                yield l
        else:
            for l in lines:
                if filter_func(l):
                    yield l

    @log
    def transform_lines(lines: Iterable[str]) -> Iterable[str]:
        if transform_func is None:
            for l in lines:
                yield l
        else:
            for l in lines:
                yield transform_func(l)

    def validate_line(line: str) -> bool:
        return len(line) > 0

    def compute_stats(lines: Iterable[str]) -> dict:
        count = 0
        total_len = 0
        for l in lines:
            count += 1
            total_len += len(l)
        avg_len = total_len / count if count else 0
        return {"count": count, "avg_len": avg_len}

    results: List[str] = []

    with contextlib.ExitStack() as stack:
        f_main = stack.enter_context(open(path, "r", encoding="utf-8"))
        lines_main = read_lines(f_main)
        lines_main = filter_lines(lines_main)
        lines_main = transform_lines(lines_main)
        for l in lines_main:
            if validate_line(l):
                results.append(l)

        if merge_with:
            f_merge = stack.enter_context(open(merge_with, "r", encoding="utf-8"))
            lines_merge = read_lines(f_merge)
            lines_merge = filter_lines(lines_merge)
            lines_merge = transform_lines(lines_merge)
            for l in lines_merge:
                if validate_line(l):
                    results.append(l)

    stats = compute_stats(results)
    print(f"Processed {stats['count']} lines, average length {stats['avg_len']:.2f}")
    return results

