import contextlib
import json
import os

def validate_input(func):
    def wrapper(records):
        if not isinstance(records, list):
            raise TypeError("records must be a list")
        for idx, rec in enumerate(records):
            if not isinstance(rec, dict):
                raise TypeError(f"record at index {idx} is not a dict")
            if "id" not in rec or "value" not in rec:
                raise ValueError(f"record at index {idx} missing required keys")
        return func(records)
    return wrapper

@validate_input
def process_records(records: List[Dict[str, Any]], batch_size: int = 10, output_file: Optional[str] = None) -> Iterator[Dict[str, Any]]:
    def _transform(rec: Dict[str, Any]) -> Dict[str, Any]:
        new_rec = dict(rec)
        new_rec["value"] = rec["value"] * 2
        new_rec["processed"] = True
        return new_rec

    def _log(msg: str) -> None:
        with contextlib.suppress(Exception):
            with open("process_log.txt", "a") as f:
                f.write(msg + "\n")

    def _batch_generator() -> Iterator[List[Dict[str, Any]]]:
        batch: List[Dict[str, Any]] = []
        for rec in records:
            try:
                transformed = _transform(rec)
                batch.append(transformed)
                if len(batch) >= batch_size:
                    yield batch
                    batch = []
            except Exception as e:
                _log(f"Error transforming record {rec.get('id', 'unknown')}: {e}")
                continue
        if batch:
            yield batch

    def _write_batch(batch: List[Dict[str, Any]]) -> None:
        if output_file is None:
            return
        with contextlib.suppress(Exception):
            with open(output_file, "a") as f:
                for item in batch:
                    f.write(json.dumps(item) + "\n")

    _log("Starting processing of records")
    for batch in _batch_generator():
        _log(f"Processing batch of size {len(batch)}")
        for item in batch:
            yield item
        _write_batch(batch)
    _log("Finished processing records")

