@validate_args
def process_files(file_paths, filter_func=None):
    import os
    from contextlib import suppress, ExitStack
    def _file_stat(path):
        try:
            size = os.path.getsize(path)
            mtime = os.path.getmtime(path)
            return {'path': path, 'size': size, 'mtime': mtime}
        except OSError:
            return None
    def _line_count(path):
        lines = 0
        with suppress(FileNotFoundError):
            with open(path, 'r', encoding='utf-8', errors='ignore') as f:
                for _ in f:
                    lines += 1
        return lines
    def _word_count(path):
        words = 0
        with suppress(FileNotFoundError):
            with open(path, 'r', encoding='utf-8', errors='ignore') as f:
                for line in f:
                    words += len(line.split())
        return words
    def _average_words_per_line(lines, words):
        return words / lines if lines else 0
    def _format_stat(stat):
        return f\\"{stat['path']}: size={stat['size']} bytes, mtime={stat['mtime']}, lines={stat['lines']}, words={stat['words']}, avg={stat['avg_words']:.2f}\\"
    def _yield_stats():
        for path in file_paths:
            stat = _file_stat(path)
            if stat is None:
                continue
            if filter_func and not filter_func(stat):
                continue
            lines = _line_count(path)
            words = _word_count(path)
            avg = _average_words_per_line(lines, words)
            stat.update({'lines': lines, 'words': words, 'avg_words': avg})
            yield stat
    def _collect_and_sort():
        stats = list(_yield_stats())
        stats.sort(key=lambda s: s['size'], reverse=True)
        return stats
    def _print_stats():
        for stat in _collect_and_sort():
