from typing import Iterable, Iterator, Callable, Any, List, Optional, Dict
from contextlib import contextmanager
import time

def stream_process(
    file_path: str,
    filter_func: Optional[Callable[[str], bool]] = None,
    transform_func: Optional[Callable[[str], str]] = None,
    max_lines: int = 1000,
    encoding: str = 'utf-8',
) -> Iterator[str]:
    @contextmanager
    def _open(file: str):
        f = open(file, 'r', encoding=encoding)
        try:
            yield f
        finally:
            f.close()

    def _default_filter(line: str) -> bool:
        return True

    def _default_transform(line: str) -> str:
        return line.strip()

    @contextmanager
    def _timer(label: str):
        start = time.time()
        try:
            yield
        finally:
            elapsed = time.time() - start
            print(f"{label} took {elapsed:.4f}s")

    filt = filter_func or _default_filter
    trans = transform_func or _default_transform

    line_count = 0
    processed = 0
    errors: List[str] = []

    with _timer("Processing"):
        with _open(file_path) as f:
            for raw_line in f:
                line_count += 1
                line = raw_line.rstrip('\n')
                try:
                    if not filt(line):
                        continue
                    transformed = trans(line)
                    if transformed == '':
                        continue
                    yield transformed
                    processed += 1
                    if processed >= max_lines:
                        break
                except Exception as e:
                    errors.append(f"Line {line_count}: {e}")

    if errors:
        print(f"Encountered {len(errors)} errors during processing:")
        for err in errors:
            print(err)

    print(f"Processed {processed} lines out of {line_count} total lines.")

