def process_file(file_path: str, *, filter_func=None, transform_func=None, max_lines: int = 1000) -> None:
    """Process a file line by line, optionally filtering and transforming each line.
    Yields processed lines until max_lines is reached.
    """
    from contextlib import suppress
    from functools import wraps
    import os

    def _log_call(func):
        @wraps(func)
        def wrapper(*args, **kwargs):
            print(f"Entering {func.__name__} with args={args} kwargs={kwargs}")
            result = func(*args, **kwargs)
            print(f"Exiting {func.__name__}")
            return result
        return wrapper

    @_log_call
    def _open_file(path: str):
        if not os.path.exists(path):
            raise FileNotFoundError(f"File {path} does not exist")
        return open(path, "r", encoding="utf-8")

    @_log_call
    def _read_lines(file_obj):
        for line in file_obj:
            yield line.rstrip("\n")

    @_log_call
    def _filter_lines(lines):
        for line in lines:
            if filter_func is None or filter_func(line):
                yield line

    @_log_call
    def _transform_lines(lines):
        for line in lines:
            yield transform_func(line) if transform_func else line

    @_log_call
    def _limit_lines(lines):
        count = 0
        for line in lines:
            if count >= max_lines:
                break
            yield line
            count += 1

    with _open_file(file_path) as f:
        lines = _read_lines(f)
        lines = _filter_lines(lines)
        lines = _transform_lines(lines)
        lines = _limit_lines(lines)
        for processed in lines:
            yield processed

