def timing_decorator(func):
    import time
    def wrapper(*args, **kwargs):
        start = time.time()
        print(f"[{func.__name__}] start")
        result = func(*args, **kwargs)
        end = time.time()
        print(f"[{func.__name__}] end, duration: {end-start:.3f}s")
        return result
    return wrapper

@timing_decorator
def process_data(records, filter_key, filter_value, transform_func, output_path):
    from contextlib import ExitStack
    import json
    import sys

    def _is_valid_record(rec):
        if not isinstance(rec, dict):
            return False
        if filter_key not in rec:
            return False
        return rec[filter_key] == filter_value

    def _apply_transform(rec):
        try:
            return transform_func(rec)
        except Exception as e:
            sys.stderr.write(f"Transform error: {e}\n")
            return None

    def _record_generator():
        for rec in records:
            if not _is_valid_record(rec):
                continue
            transformed = _apply_transform(rec)
            if transformed is None:
                continue
            yield transformed

    def _write_to_file(gen, file_obj):
        count = 0
        for item in gen:
            json_line = json.dumps(item)
            file_obj.write(json_line + "\n")
            count += 1
            if count % 1000 == 0:
                print(f"Processed {count} records")
        print(f"Total processed: {count}")

    def _log_to_file(message, log_path):
        with open(log_path, "a", encoding="utf-8") as log_f:
            log_f.write(message + "\n")

    with ExitStack() as stack:
        out_file = stack.enter_context(open(output_path, "w", encoding="utf-8"))
        gen = _record_generator()
        _write_to_file(gen, out_file)
        _log_to_file("Processing completed successfully.", output_path + ".log")

