import time
import contextlib
from typing import Iterable, Iterator, List, Optional

def timed(func):
    def wrapper(*args, **kwargs):
        start = time.time()
        result = func(*args, **kwargs)
        end = time.time()
        print(f"Function {func.__name__} executed in {end - start:.4f}s")
        return result
    return wrapper

def _filter(item):
    return item is not None and item != ''

def _transform(item):
    return item.upper()

def _chunk(iterable: Iterable[str], size: int) -> Iterator[List[str]]:
    chunk: List[str] = []
    for item in iterable:
        if _filter(item):
            chunk.append(_transform(item))
            if len(chunk) == size:
                yield chunk
                chunk = []
    if chunk:
        yield chunk

@timed
def process_and_write(data: Iterable[str], output_path: str, chunk_size: int = 3) -> None:
    with open(output_path, 'w') as f:
        for chunk in _chunk(data, chunk_size):
            for line in chunk:
                f.write(line + '\\n')
            f.flush()

def read_and_process(input_path: str) -> Iterator[str]:
    with open(input_path, 'r') as f:
        for line in f:
            line = line.strip()
            if _filter(line):
                yield _transform(line)

def main() -> None:
    sample_data = ['apple', '', 'banana', None, 'cherry', 'date', 'elderberry', 'fig', 'grape']
    process_and_write(sample_data, 'output.txt', chunk_size=4)
    for processed in read_and_process('output.txt'):
        print(processed)

if __name__ == "__main__":
    main()

