import asyncio
import contextlib
from typing import Any, AsyncIterator, Iterable, List, Optional

async def advanced_processor(
    streams: List[AsyncIterator[str]],
    max_items: int,
    *,
    filter_func: Optional[Any] = None,
    progress_callback: Optional[Any] = None,
    log_file: Optional[str] = None,
) -> List[str]:
    # Helper to validate a single item
    def _validate_item(item: str) -> bool:
        if not isinstance(item, str):
            return False
        if len(item) > 1024:
            return False
        return True

    # Decorator for logging entry and exit of async functions
    def log_decorator(func):
        async def wrapper(*args, **kwargs):
            if log_file:
                with open(log_file, 'a') as f:
                    f.write(f"[{func.__name__}] start\n")
            else:
                print(f"[{func.__name__}] start")
            try:
                result = await func(*args, **kwargs)
            except Exception as e:
                if log_file:
                    with open(log_file, 'a') as f:
                        f.write(f"[{func.__name__}] error: {e}\n")
                else:
                    print(f"[{func.__name__}] error: {e}")
                raise
            if log_file:
                with open(log_file, 'a') as f:
                    f.write(f"[{func.__name__}] end\n")
            else:
                print(f"[{func.__name__}] end")
            return result
        return wrapper

    @log_decorator
    async def _process_stream(it: AsyncIterator[str]) -> List[str]:
        collected: List[str] = []
        async for raw in it:
            try:
                item = str(raw).strip()
            except Exception:
                continue
            if not _validate_item(item):
                continue
            if filter_func:
                try:
                    if not filter_func(item):
                        continue
                except Exception:
                    continue
            collected.append(item)
            if progress_callback:
                try:
                    progress_callback(len(collected))
                except Exception:
                    pass
            if len(collected) >= max_items:
                break
        return collected

    async def _run_all() -> List[str]:
        tasks = [_process_stream(it) for it in streams]
        results = await asyncio.gather(*tasks, return_exceptions=True)
        merged: List[str] = []
        for res in results:
            if isinstance(res, Exception):
                continue
            merged.extend(res)
            if len(merged) >= max_items:
                merged = merged[:max_items]
                break
        return merged

    # Input validation
    if not isinstance(streams, list):
        raise TypeError("streams must be a list of async iterators")
    if not all(hasattr(s, "__aiter__") for s in streams):
        raise ValueError("All elements in streams must support async iteration")
    if not isinstance(max_items, int) or max_items <= 0:
        raise ValueError("max_items must be a positive integer")

    # Use context manager to ensure log file is opened if provided
    if log_file:
        with contextlib.ExitStack() as stack:
            stack.enter_context(open(log_file, 'a'))
            return await _run_all()
    else:
        return await _run_all()

