from typing import Any, Callable, Iterable, List, Dict, Tuple
import contextlib

def process_file(path: str, filter_func: Callable[[str], bool]) -> Tuple[List[str], Dict[str, int]]:
    def log_execution(func: Callable) -> Callable:
        def wrapper(*args: Any, **kwargs: Any) -> Any:
            print(f'Entering {func.__name__}')
            result = func(*args, **kwargs)
            print(f'Exiting {func.__name__}')
            return result
        return wrapper

    @log_execution
    def _read_lines(file_obj: Iterable[str]) -> Iterable[str]:
        for line in file_obj:
            yield line.rstrip('\\n')

    def _apply_filter(lines: Iterable[str]) -> Iterable[str]:
        for line in lines:
            if filter_func(line):
                yield line

    def _split_words(lines: Iterable[str]) -> Iterable[str]:
        for line in lines:
            for word in line.split():
                yield word

    def word_statistics(lines: Iterable[str]) -> Dict[str, int]:
        stats: Dict[str, int] = {}
        for word in _split_words(lines):
            stats[word] = stats.get(word, 0) + 1
        return stats

    with contextlib.closing(open(path, 'r', encoding='utf-8')) as f:
        raw_lines = _read_lines(f)
        filtered = _apply_filter(raw_lines)
        result = list(filtered)

    stats = word_statistics(result)

    return result, stats

# Example usage
if __name__ == '__main__':
    def sample_filter(line: str) -> bool:
        return len(line) > 0 and not line.startswith('#')

    file_path = 'sample.txt'
    lines, statistics = process_file(file_path, sample_filter)
    for l in lines:
        print(l)
    print('Word counts:', statistics)

